import React, { useState, useEffect } from 'react';
import { api, login as apiLogin, registerClinic, getMe } from '@/api';
import { getToken, setToken, removeToken, parseJwt } from '@/utils';
import AuthContext from './useAuth';
import { useTenantStore } from '@/store/tenant.store';

export default function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const initAuth = async () => {
            const token = getToken();

            if (token) {
                try {
                    // 1. Decode locally for fast UI
                    const decoded = parseJwt(token);
                    if (decoded) {
                        setUser({
                            username: decoded.sub,
                            role: decoded.role,
                            tenant_id: decoded.tenant_id
                        });
                    }

                    // 2. Verify with backend
                    try {
                        const res = await getMe();
                        if (res.data) {
                            setUser(prev => ({ ...prev, ...res.data }));
                            // Sync Tenant Store
                            if (res.data.tenant) {
                                useTenantStore.getState().setTenant(res.data.tenant);
                            }
                        }
                    } catch (e) {
                        console.warn("Failed to fetch full profile", e);
                    }
                } catch (err) {
                    console.error("Auth init failed", err);
                    removeToken();
                }
            }
            setLoading(false);
        };

        initAuth();
    }, []);

    const login = async (username, password, remember = true) => {
        setLoading(true);
        try {
            const res = await apiLogin(username, password);
            const { access_token, refresh_token, role } = res.data;

            setToken(access_token, refresh_token, remember);

            // Decoded User
            const decoded = parseJwt(access_token);
            setUser({
                username: decoded.sub,
                role: role,
                tenant_id: decoded.tenant_id
            });

            return res.data;
        } catch (err) {
            throw err;
        } finally {
            setLoading(false);
        }
    };

    const logout = () => {
        removeToken();
        setUser(null);
        window.location.href = '/';
    };

    const register = async (data) => {
        return registerClinic(data);
    };

    const value = {
        user,
        loading,
        login,
        logout,
        register,
        isAuthenticated: !!user
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && children}
        </AuthContext.Provider>
    );
}

import React, { useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/shared/ui';
import { Globe } from 'lucide-react';

const LanguageSwitcher = () => {
    const { t, i18n } = useTranslation();

    // Effect to update document direction when language changes
    useEffect(() => {
        document.documentElement.dir = i18n.language === 'ar' ? 'rtl' : 'ltr';
        document.documentElement.lang = i18n.language;
    }, [i18n.language]);

    const toggleLanguage = () => {
        const newLang = i18n.language === 'ar' ? 'en' : 'ar';
        i18n.changeLanguage(newLang);
    };

    return (
        <Button
            variant="ghost"
            size="sm"
            onClick={toggleLanguage}
            className="w-full justify-start gap-3 hover:bg-surface-hover text-text-secondary hover:text-primary transition-colors duration-200"
        >
            <Globe size={18} />
            <span className="font-medium text-sm">
                {i18n.language === 'ar' ? 'English' : 'العربية'}
            </span>
        </Button>
    );
};

export default LanguageSwitcher;

