                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </td>
                            </tr>
                        )) : (
                            <tr>
                                <td colSpan="8" className="p-10 text-center text-slate-500">لا توجد سجلات دفع حتى الآن</td>
                            </tr>
