import { Edit3, Save, X, Users, Activity, PlusCircle, Trash2 } from 'lucide-react';
import { api } from '@/api';

const PlansManager = () => {
    const [plans, setPlans] = useState([]);
    const [loading, setLoading] = useState(true);
    const [editingPlan, setEditingPlan] = useState(null);
    const [editedPlanData, setEditedPlanData] = useState({});

    // Create Mode State
    const [isCreating, setIsCreating] = useState(false);
    const [newPlanData, setNewPlanData] = useState({
        name: '',
        display_name_ar: '',
        price: 0,
        duration_days: 30,
        max_users: null,
        max_patients: null,
        features: '',
        is_ai_enabled: false,
        ai_daily_limit: 0,
        is_default: false
    });

    useEffect(() => {
        fetchPlans();
    }, []);

    const fetchPlans = async () => {
        try {
            setLoading(true);
            const res = await api.get('/api/v1/admin/plans');
            setPlans(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error("Failed to fetch plans", err);
        } finally {
            setLoading(false);
        }
    };

    const handleCreatePlan = async () => {
        if (!newPlanData.name || !newPlanData.display_name_ar) {
            alert('يرجى تعبئة الاسم والمعرف');
            return;
        }
        try {
            await api.post('/api/v1/admin/plans', newPlanData);
            setIsCreating(false);
            setNewPlanData({
                name: '',
                display_name_ar: '',
                price: 0,
                duration_days: 30,
                max_users: null,
                max_patients: null,
                features: '',
                is_ai_enabled: false,
                ai_daily_limit: 0,
                is_default: false
            });
            fetchPlans();
            alert('تم إنشاء الخطة بنجاح');
        } catch (err) {
            console.error(err);
            alert('فشل إنشاء الخطة: ' + (err.response?.data?.detail || err.message));
        }
    };

    const handleSavePlan = async (planId) => {
        try {
            await api.put(`/api/v1/admin/plans/${planId}`, editedPlanData);
            setEditingPlan(null);
            setEditedPlanData({});
            fetchPlans();
            alert('تم تعديل الخطة بنجاح');
        } catch (err) {
            console.error(err);
            alert('فشل التعديل: ' + (err.response?.data?.detail || err.message));
        }
    };

    const handleDeletePlan = async (planId) => {
        if (!window.confirm("هل أنت متأكد من حذف هذه الخطة؟")) return;
        try {
            await api.delete(`/api/v1/admin/plans/${planId}`);
            fetchPlans();
            alert('تم حذف الخطة بنجاح');
        } catch (err) {
            console.error(err);
            alert('فشل الحذف: ' + (err.response?.data?.detail || err.message));
        }
    };

    if (loading) return <div className="p-10 text-center text-slate-500 animate-pulse">جاري تحميل الخطط...</div>;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
            {plans.map(plan => (
                <div key={plan.id} className={`relative group bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border hover:border-indigo-500/50 transition-all duration-300 ${editingPlan === plan.id ? 'border-indigo-500 ring-4 ring-indigo-500/10 z-10 scale-105 shadow-2xl' : 'border-slate-100 dark:border-slate-800 shadow-lg'}`}>
                    {editingPlan === plan.id ? (
                        <div className="space-y-5 animate-fade-in">
                            <div className="flex items-center gap-2 mb-4 text-indigo-600 font-bold pb-4 border-b border-indigo-100 dark:border-indigo-900/30">
                                <Edit3 size={20} />
                                تعديل الخطة
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">اسم الخطة (للعرض)</label>
                                <input
                                    type="text"
                                    value={editedPlanData.display_name_ar ?? plan.display_name_ar}
                                    onChange={(e) => setEditedPlanData({ ...editedPlanData, display_name_ar: e.target.value })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all font-bold"
                                    placeholder="مثال: الباقة الذهبية"
                                />
                            </div>

                            <div className="flex gap-4">
                                <div className="flex-1">
                                    <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">السعر (ج.م)</label>
                                    <input
                                        type="number"
                                        value={editedPlanData.price ?? plan.price}
                                        onChange={(e) => setEditedPlanData({ ...editedPlanData, price: parseFloat(e.target.value) })}
                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                                    />
                                </div>
                                <div className="flex-1">
                                    <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">المدة (أيام)</label>
                                    <input
                                        type="number"
                                        value={editedPlanData.duration_days ?? plan.duration_days}
                                        onChange={(e) => setEditedPlanData({ ...editedPlanData, duration_days: parseInt(e.target.value) })}
                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-4">
                                <div className="flex-1">
                                    <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">مستخدمين</label>
                                    <input
                                        type="number"
                                        value={editedPlanData.max_users ?? plan.max_users ?? ''}
                                        onChange={(e) => setEditedPlanData({ ...editedPlanData, max_users: e.target.value ? parseInt(e.target.value) : null })}
                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold placeholder-slate-300"
                                        placeholder="∞"
                                    />
                                </div>
                                <div className="flex-1">
                                    <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">مرضى</label>
                                    <input
                                        type="number"
                                        value={editedPlanData.max_patients ?? plan.max_patients ?? ''}
                                        onChange={(e) => setEditedPlanData({ ...editedPlanData, max_patients: e.target.value ? parseInt(e.target.value) : null })}
                                        className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold placeholder-slate-300"
                                        placeholder="∞"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">المميزات (نص وصفي)</label>
                                <textarea
                                    value={editedPlanData.features ?? plan.features}
                                    onChange={(e) => setEditedPlanData({ ...editedPlanData, features: e.target.value })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none text-sm min-h-[80px]"
                                />
                            </div>

                            {/* AI Settings Section */}
                            <div className="bg-indigo-50 dark:bg-indigo-900/10 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-900/30">
                                <h4 className="font-bold text-indigo-600 mb-3 flex items-center gap-2">
                                    <Activity size={16} /> إعدادات الذكاء الاصطناعي
                                </h4>
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <label className="text-sm font-bold text-slate-600 dark:text-slate-300">تفعيل المساعد الذكي</label>
                                        <input
                                            type="checkbox"
                                            checked={editedPlanData.is_ai_enabled ?? plan.is_ai_enabled ?? false}
                                            onChange={(e) => setEditedPlanData({ ...editedPlanData, is_ai_enabled: e.target.checked })}
                                            className="w-5 h-5 accent-indigo-600 rounded-lg cursor-pointer"
                                        />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-slate-500 mb-1">الحد اليومي (0 = غير نشط)</label>
                                        <input
                                            type="number"
                                            value={editedPlanData.ai_daily_limit ?? plan.ai_daily_limit ?? 0}
                                            onChange={(e) => setEditedPlanData({ ...editedPlanData, ai_daily_limit: parseInt(e.target.value) })}
                                            className="w-full px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-sm"
                                        />
                                    </div>
                                </div>
                                {/* Default Setting */}
                                <div className="flex items-center justify-between pt-2 border-t border-indigo-100 dark:border-indigo-900/30 mt-2">
                                    <label className="text-sm font-bold text-slate-600 dark:text-slate-300">تعيين كخطة افتراضية</label>
                                    <input
                                        type="checkbox"
                                        checked={editedPlanData.is_default ?? plan.is_default ?? false}
                                        onChange={(e) => setEditedPlanData({ ...editedPlanData, is_default: e.target.checked })}
                                        className="w-5 h-5 accent-indigo-600 rounded-lg cursor-pointer"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3 pt-2">
                                <button onClick={() => handleSavePlan(plan.id)} className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white py-2.5 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/20 transition-all">
                                    <Save size={18} /> حفظ التعديلات
                                </button>
                                <button onClick={() => { setEditingPlan(null); setEditedPlanData({}); }} className="px-4 bg-slate-200 hover:bg-slate-300 dark:bg-slate-700 dark:hover:bg-slate-600 text-slate-600 dark:text-slate-300 rounded-xl font-bold transition-all">
                                    <X size={18} />
                                </button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="absolute top-0 left-0 w-full h-[140px] bg-gradient-to-br from-indigo-500 to-purple-600 rounded-t-[2.5rem] opacity-10 group-hover:opacity-15 transition-opacity" />
                            <div className="relative pt-4">
                                <div className="flex justify-between items-start mb-6">
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <h3 className="text-2xl font-black text-slate-800 dark:text-white mb-2">{plan.display_name_ar}</h3>
                                            {plan.is_default && (
                                                <span className="bg-indigo-500 text-white text-[10px] px-2 py-0.5 rounded-full font-bold mb-2">افتراضي</span>
                                            )}
                                        </div>
                                        <div className="flex items-baseline gap-1">
                                            <span className="text-4xl font-black text-indigo-600 dark:text-indigo-400">{plan.price}</span>
                                            <span className="text-sm font-bold text-slate-500">ج.م / {plan.duration_days} يوم</span>
                                        </div>
                                    </div>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={() => setEditingPlan(plan.id)}
                                            className="p-3 bg-white dark:bg-slate-800 hover:bg-indigo-50 dark:hover:bg-slate-700 text-indigo-600 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 transition-all hover:scale-110"
                                            title="تعديل الخطة"
                                        >
                                            <Edit3 size={20} />
                                        </button>
                                        <button
                                            onClick={() => handleDeletePlan(plan.id)}
                                            className="p-3 bg-white dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/20 text-red-500 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 transition-all hover:scale-110"
                                            title="حذف الخطة"
                                        >
                                            <Trash2 size={20} />
                                        </button>
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <div className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800/50 rounded-2xl">
                                        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 rounded-xl">
                                            <Users size={18} />
                                        </div>
                                        <div>
                                            <p className="text-xs text-slate-500 font-bold">المستخدمين</p>
                                            <p className="font-bold text-slate-700 dark:text-slate-200">{plan.max_users ? `${plan.max_users} مستخدم` : 'غير محدود'}</p>
                                        </div>
                                    </div>

                                    {/* AI Badge */}
                                    {plan.is_ai_enabled && (
                                        <div className="flex items-center gap-3 p-3 bg-indigo-50 dark:bg-indigo-900/10 rounded-2xl border border-indigo-100 dark:border-indigo-900/30">
                                            <div className="p-2 bg-indigo-100 dark:bg-indigo-900/40 text-indigo-600 rounded-xl">
                                                <Activity size={18} />
                                            </div>
                                            <div>
                                                <p className="text-xs text-indigo-500 font-bold flex items-center gap-1">
                                                    ذكاء اصطناعي <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                                                </p>
                                                <p className="font-bold text-indigo-700 dark:text-indigo-300">
                                                    {plan.ai_daily_limit > 0 ? `${plan.ai_daily_limit} طلب/يوم` : 'غير محدود'}
                                                </p>
                                            </div>
                                        </div>
                                    )}

                                    <div className="pt-4 border-t border-slate-100 dark:border-slate-800">
                                        <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed bg-slate-50/50 dark:bg-slate-800/20 p-4 rounded-2xl border border-dashed border-slate-200 dark:border-slate-700">
                                            {plan.features}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                </div>
            ))}

            {/* Add New Plan Card */}
            {isCreating ? (
                <div className="relative group bg-white dark:bg-slate-900 rounded-[2.5rem] p-8 border border-emerald-500 ring-4 ring-emerald-500/10 shadow-2xl animate-fade-in-up">
                    <div className="space-y-4">
                        <div className="flex items-center gap-2 mb-4 text-emerald-600 font-bold pb-4 border-b border-emerald-100 dark:border-emerald-900/30">
                            <PlusCircle size={20} />
                            إضافة خطة جديدة
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">المعرف (EN)</label>
                                <input
                                    type="text"
                                    value={newPlanData.name}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, name: e.target.value })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-sm"
                                    placeholder="gold_plan"
                                />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">الاسم (للعرض)</label>
                                <input
                                    type="text"
                                    value={newPlanData.display_name_ar}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, display_name_ar: e.target.value })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-sm"
                                    placeholder="الباقة الذهبية"
                                />
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <div className="flex-1">
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">السعر (ج.م)</label>
                                <input
                                    type="number"
                                    value={newPlanData.price}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, price: parseFloat(e.target.value) })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                                />
                            </div>
                            <div className="flex-1">
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">المدة (أيام)</label>
                                <input
                                    type="number"
                                    value={newPlanData.duration_days}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, duration_days: parseInt(e.target.value) })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                                />
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <div className="flex-1">
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">مستخدمين</label>
                                <input
                                    type="number"
                                    value={newPlanData.max_users || ''}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, max_users: e.target.value ? parseInt(e.target.value) : null })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold placeholder-slate-300"
                                    placeholder="∞"
                                />
                            </div>
                            <div className="flex-1">
                                <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">مرضى</label>
                                <input
                                    type="number"
                                    value={newPlanData.max_patients || ''}
                                    onChange={(e) => setNewPlanData({ ...newPlanData, max_patients: e.target.value ? parseInt(e.target.value) : null })}
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none font-bold placeholder-slate-300"
                                    placeholder="∞"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold text-slate-500 mb-1.5 mr-1">المميزات</label>
                            <textarea
                                value={newPlanData.features}
                                onChange={(e) => setNewPlanData({ ...newPlanData, features: e.target.value })}
                                className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-emerald-500 outline-none text-sm min-h-[80px]"
                                placeholder="دعم كامل، وصول لجميع الخصائص..."
                            />
                        </div>

                        {/* AI Settings Section for New Plan */}
                        <div className="bg-emerald-50 dark:bg-emerald-900/10 p-4 rounded-2xl border border-emerald-100 dark:border-emerald-900/30">
                            <h4 className="font-bold text-emerald-600 mb-3 flex items-center gap-2">
                                <Activity size={16} /> إعدادات الذكاء الاصطناعي
                            </h4>
                            <div className="space-y-3">
                                <div className="flex items-center justify-between">
                                    <label className="text-sm font-bold text-slate-600 dark:text-slate-300">تفعيل المساعد الذكي</label>
                                    <input
                                        type="checkbox"
                                        checked={newPlanData.is_ai_enabled || false}
                                        onChange={(e) => setNewPlanData({ ...newPlanData, is_ai_enabled: e.target.checked })}
                                        className="w-5 h-5 accent-emerald-600 rounded-lg cursor-pointer"
                                    />
                                </div>
                                <div className="flex items-center justify-between">
                                    <label className="text-sm font-bold text-slate-600 dark:text-slate-300">تعيين كخطة افتراضية</label>
                                    <input
                                        type="checkbox"
                                        checked={newPlanData.is_default || false}
                                        onChange={(e) => setNewPlanData({ ...newPlanData, is_default: e.target.checked })}
                                        className="w-5 h-5 accent-emerald-600 rounded-lg cursor-pointer"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 mb-1">الحد اليومي (0 = غير نشط)</label>
                                    <input
                                        type="number"
                                        value={newPlanData.ai_daily_limit || 0}
                                        onChange={(e) => setNewPlanData({ ...newPlanData, ai_daily_limit: parseInt(e.target.value) })}
                                        className="w-full px-3 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 focus:ring-2 focus:ring-emerald-500 outline-none font-bold text-sm"
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="flex gap-3 pt-2">
                            <button onClick={handleCreatePlan} className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white py-2.5 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/20 transition-all">
                                <PlusCircle size={18} /> إنشاء
                            </button>
                            <button onClick={() => setIsCreating(false)} className="px-4 bg-slate-200 hover:bg-slate-300 dark:bg-slate-700 dark:hover:bg-slate-600 text-slate-600 dark:text-slate-300 rounded-xl font-bold transition-all">
                                <X size={18} />
                            </button>
                        </div>
                    </div>
                </div>
            ) : (
                <button onClick={() => setIsCreating(true)} className="group border-3 border-dashed border-slate-200 dark:border-slate-700 rounded-[2.5rem] p-8 flex flex-col items-center justify-center gap-4 hover:border-indigo-400 hover:bg-indigo-50 dark:hover:bg-indigo-900/10 transition-all min-h-[400px]">
                    <div className="p-4 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-300">
                        <PlusCircle size={32} />
                    </div>
                    <p className="font-bold text-slate-500 group-hover:text-indigo-600 transition-colors">إضافة خطة جديدة</p>
                </button>
            )}
        </div>
    );
};

export default PlansManager;

import React, { useState, useEffect } from 'react';
import { api } from '@/api';
import { Shield, Lock, Unlock, AlertTriangle, CheckCircle, Search, Ban, History } from 'lucide-react';

export default function SecurityPanel() {
    const [stats, setStats] = useState(null);
    const [blockedIps, setBlockedIps] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showBlockModal, setShowBlockModal] = useState(false);

    // Form State
    const [blockForm, setBlockForm] = useState({ ip_address: '', reason: '' });

    useEffect(() => {
        fetchSecurityData();
    }, []);

    const fetchSecurityData = async () => {
        try {
            setLoading(true);
            const [statsRes, ipsRes] = await Promise.all([
                api.get('/api/v1/admin/security/stats'),
                api.get('/api/v1/admin/security/blocked-ips')
            ]);
            setStats(statsRes.data || null);
            setBlockedIps(Array.isArray(ipsRes.data) ? ipsRes.data : []);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleBlockIp = async () => {
        if (!blockForm.ip_address) return alert("الرجاء إدخال عنوان IP");
        try {
            await api.post('/api/v1/admin/security/ip-block', blockForm);
            setShowBlockModal(false);
            setBlockForm({ ip_address: '', reason: '' });
            fetchSecurityData();
            alert("تم حظر IP بنجاح");
        } catch (error) {
            alert("فشلت عملية الحظر");
        }
    };

    const handleUnblockIp = async (ip) => {
        if (!window.confirm("هل أنت متأكد من فك الحظر؟")) return;
        try {
            await api.delete(`/api/v1/admin/security/ip-block/${ip}`);
            fetchSecurityData();
        } catch (error) {
            alert("فشل فك الحظر");
        }
    };

    if (loading && !stats) return <div className="p-8 text-center text-slate-500">جاري تحميل البيانات الأمنية...</div>;

    return (
        <div className="space-y-8">
            {/* Header Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-2xl">
                        <Ban size={28} />
                    </div>
                    <div>
                        <p className="text-slate-500 dark:text-slate-400 font-bold text-sm">عناوين IP المحظورة</p>
                        <h3 className="text-3xl font-black text-slate-800 dark:text-white">{stats?.blocked_ips_count || 0}</h3>
                    </div>
                </div>

                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-orange-100 dark:bg-orange-900/30 text-orange-600 rounded-2xl">
                        <Lock size={28} />
                    </div>
                    <div>
                        <p className="text-slate-500 dark:text-slate-400 font-bold text-sm">حسابات مقفلة حالياً</p>
                        <h3 className="text-3xl font-black text-slate-800 dark:text-white">{stats?.locked_users?.length || 0}</h3>
                    </div>
                </div>

                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-yellow-100 dark:bg-yellow-900/30 text-yellow-600 rounded-2xl">
                        <AlertTriangle size={28} />
                    </div>
                    <div>
                        <p className="text-slate-500 dark:text-slate-400 font-bold text-sm">محاولات فاشلة حديثاً</p>
                        <h3 className="text-3xl font-black text-slate-800 dark:text-white">{stats?.recent_failures?.length || 0}</h3>
                    </div>
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-8">
                {/* Blocked IPs List */}
                <div className="flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
                    <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-gradient-to-r from-red-50 to-transparent dark:from-red-900/10">
                        <div className="flex items-center gap-3">
                            <Ban className="text-red-500" size={24} />
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white">قائمة الحظر (Blacklist)</h3>
                        </div>
                        <button
                            onClick={() => setShowBlockModal(true)}
                            className="px-4 py-2 bg-red-500 hover:bg-red-600 text-white rounded-xl font-bold text-sm shadow-lg shadow-red-500/20 transition-all"
                        >
                            حظر عنوان جديد
                        </button>
                    </div>

                    <div className="p-6">
                        {blockedIps.length === 0 ? (
                            <div className="text-center py-8 text-slate-400">
                                <CheckCircle className="mx-auto mb-2 text-emerald-500" size={32} />
                                <p>لا توجد عناوين محظورة حالياً</p>
                            </div>
                        ) : (
                            <div className="overflow-x-auto">
                                <table className="w-full">
                                    <thead>
                                        <tr className="text-right text-slate-500 text-sm">
                                            <th className="pb-4 font-bold">IP Address</th>
                                            <th className="pb-4 font-bold">السبب</th>
                                            <th className="pb-4 font-bold">بواسطة</th>
                                            <th className="pb-4 font-bold">تحكم</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                        {blockedIps.map(ip => (
                                            <tr key={ip.id} className="text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                                <td className="py-4 font-mono dir-ltr text-left pl-2">{ip.ip_address}</td>
                                                <td className="py-4">{ip.reason || '-'}</td>
                                                <td className="py-4 text-sm text-slate-500">{ip.blocked_by}</td>
                                                <td className="py-4">
                                                    <button
                                                        onClick={() => handleUnblockIp(ip.ip_address)}
                                                        className="p-2 text-emerald-500 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg transition-colors"
                                                        title="فك الحظر"
                                                    >
                                                        <Unlock size={18} />
                                                    </button>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                </div>

                {/* Recent Failed Logins */}
                <div className="lg:w-1/3 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
                    <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3">
                        <History className="text-slate-500" size={24} />
                        <h3 className="text-xl font-bold text-slate-800 dark:text-white">آخر المحاولات الفاشلة</h3>
                    </div>
                    <div className="p-4 max-h-[500px] overflow-y-auto space-y-3">
                        {stats?.recent_failures?.map(log => (
                            <div key={log.id} className="p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-700">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="font-mono text-sm bg-slate-200 dark:bg-slate-700 px-2 py-1 rounded text-slate-600 dark:text-slate-300">{log.ip_address}</span>
                                    <span className="text-xs text-slate-400 font-medium" dir="ltr">{new Date(log.created_at).toLocaleString()}</span>
                                </div>
                                <div className="text-sm text-slate-600 dark:text-slate-300 flex items-center gap-2">
                                    <AlertTriangle size={14} className="text-red-500" />
                                    <span>User ID: {log.user_id || 'Unknown'}</span>
                                </div>
                            </div>
                        ))}
                        {(!stats?.recent_failures || stats.recent_failures.length === 0) && (
                            <div className="text-center py-8 text-slate-400">
                                <p>سجل نظيف! لا توجد محاولات فاشلة.</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Block Modal */}
            {showBlockModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-6">
                        <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                            <Ban className="text-red-500" />
                            حظر عنوان IP جديد
                        </h3>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">IP Address</label>
                                <input
                                    type="text"
                                    dir="ltr"
                                    placeholder="192.168.1.1"
                                    value={blockForm.ip_address}
                                    onChange={(e) => setBlockForm({ ...blockForm, ip_address: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none font-mono"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">سبب الحظر</label>
                                <input
                                    type="text"
                                    placeholder="محاولات اختراق، سبام..."
                                    value={blockForm.reason}
                                    onChange={(e) => setBlockForm({ ...blockForm, reason: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none"
                                />
                            </div>
                            <div className="flex gap-3 mt-4">
                                <button
                                    onClick={handleBlockIp}
                                    className="flex-1 py-3 bg-red-500 hover:bg-red-600 text-white rounded-xl font-bold shadow-lg shadow-red-500/20"
                                >
                                    تأكيد الحظر
                                </button>
                                <button
                                    onClick={() => setShowBlockModal(false)}
                                    className="px-6 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold"
                                >
                                    إلغاء
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Save, AlertTriangle, Monitor, Megaphone } from 'lucide-react';
import { api } from '@/api';

const SettingsManager = () => {
    const [localSettings, setLocalSettings] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            setLoading(true);
            const res = await api.get('/api/v1/admin/settings');
            setLocalSettings(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error("Failed to fetch settings", err);
        } finally {
            setLoading(false);
        }
    };

    const handleToggleMaintenance = async () => {
        const setting = localSettings.find(s => s.key === 'maintenance_mode');
        // If not found, assume false and create it on toggle
        const currentValue = setting ? setting.value : 'false';

        const newValue = currentValue === 'true' ? 'false' : 'true';
        const confirmMsg = newValue === 'true'
            ? "هل أنت متأكد من تفعيل وضع الصيانة؟ سيتم منع جميع المستخدمين (غير المسؤولين) من الدخول."
            : "هل أنت متأكد من إيقاف وضع الصيانة؟";

        if (!window.confirm(confirmMsg)) return;

        await updateSetting('maintenance_mode', newValue);
    };

    const updateSetting = async (key, value) => {
        // Optimistic update
        setLocalSettings(prev => {
            const exists = prev.find(s => s.key === key);
            if (exists) {
                return prev.map(s => s.key === key ? { ...s, value } : s);
            } else {
                return [...prev, { key, value }];
            }
        });

        try {
            await api.put(`/api/v1/admin/settings/${key}`, { key, value, updated_at: new Date().toISOString() });
            alert("تم حفظ الإعدادات بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشل حفظ الإعدادات");
            // Revert changes on error would be ideal, but simple alert for now
            fetchSettings();
        }
    };

    const getSettingValue = (key) => {
        return localSettings.find(s => s.key === key)?.value || '';
    };

    const handleLocalChange = (key, newValue) => {
        setLocalSettings(prev => {
            const exists = prev.find(s => s.key === key);
            if (exists) {
                return prev.map(s => s.key === key ? { ...s, value: newValue } : s);
            } else {
                return [...prev, { key, value: newValue }];
            }
        });
    };

    if (loading && localSettings.length === 0) return <div className="p-10 text-center text-slate-500 animate-pulse">جاري تحميل الإعدادات...</div>;

    return (
        <div className="space-y-6 animate-fade-in-up">

            {/* Maintenance Mode Card */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex items-start justify-between">
                    <div className="flex gap-4">
                        <div className="w-12 h-12 rounded-2xl bg-rose-100 dark:bg-rose-900/30 flex items-center justify-center text-rose-600 dark:text-rose-400">
                            <AlertTriangle size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-slate-800 dark:text-white">وضع الصيانة (Maintenance Mode)</h3>
                            <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                                عند تفعيل هذا الوضع، لن يتمكن أي مستخدم (باستثناء Super Admin) من تسجيل الدخول إلى النظام.
                                <br />استخدم هذا الوضع عند إجراء تحديثات حرجة للنظام.
                            </p>
                        </div>
                    </div>

                    <button
                        onClick={handleToggleMaintenance}
                        className={`relative w-16 h-8 rounded-full transition-colors duration-300 ${getSettingValue('maintenance_mode') === 'true'
                            ? 'bg-rose-500'
                            : 'bg-slate-200 dark:bg-slate-700'
                            }`}
                    >
                        <span className={`absolute top-1 right-1 bg-white w-6 h-6 rounded-full shadow-sm transition-transform duration-300 ${getSettingValue('maintenance_mode') === 'true'
                            ? '-translate-x-8'
                            : 'translate-x-0'
                            }`} />
                    </button>
                </div>
            </div>

            {/* Global Banner Card */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex gap-4 mb-6">
                    <div className="w-12 h-12 rounded-2xl bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                        <Megaphone size={24} />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">تنويه عام (Global Announcement)</h3>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                            النص المكتوب هنا سيظهر كشريط تنبيه في أعلى الصفحة لجميع المستخدمين (قريباً).
                        </p>
                    </div>
                </div>

                <div className="space-y-4">
                    <textarea
                        className="w-full p-4 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 min-h-[100px] text-slate-700 dark:text-slate-300 font-medium"
                        placeholder="أدخل نص التنويه هنا..."
                        value={getSettingValue('global_announcement')}
                        onChange={(e) => handleLocalChange('global_announcement', e.target.value)}
                    />
                    <div className="flex justify-end">
                        <button
                            onClick={() => updateSetting('global_announcement', getSettingValue('global_announcement'))}
                            className="flex items-center gap-2 px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-500/30 transition-all"
                        >
                            <Save size={18} />
                            حفظ التغييرات
                        </button>
                    </div>
                </div>
            </div>

            {/* Support Info Card */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex gap-4 mb-6">
                    <div className="w-12 h-12 rounded-2xl bg-emerald-100 dark:bg-emerald-900/30 flex items-center justify-center text-emerald-600 dark:text-emerald-400">
                        <Monitor size={24} />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">بيانات الدعم الفني</h3>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">
                            تحديث أرقام التواصل وساعات العمل التي تظهر في صفحة الدعم الفني.
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-bold mb-2 text-slate-700 dark:text-slate-300">رقم الهاتف (للعرض)</label>
                        <input
                            type="text"
                            className="w-full p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700"
                            value={getSettingValue('support_phone')}
                            onChange={(e) => handleLocalChange('support_phone', e.target.value)}
                        />
                        <button onClick={() => updateSetting('support_phone', getSettingValue('support_phone'))} className="text-xs text-indigo-600 font-bold mt-2">حفظ</button>
                    </div>
                    <div>
                        <label className="block text-sm font-bold mb-2 text-slate-700 dark:text-slate-300">Whatsapp (أرقام فقط)</label>
                        <input
                            type="text"
                            className="w-full p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700"
                            value={getSettingValue('support_whatsapp')}
                            onChange={(e) => handleLocalChange('support_whatsapp', e.target.value)}
                        />
                        <button onClick={() => updateSetting('support_whatsapp', getSettingValue('support_whatsapp'))} className="text-xs text-indigo-600 font-bold mt-2">حفظ</button>
                    </div>
                    <div>
                        <label className="block text-sm font-bold mb-2 text-slate-700 dark:text-slate-300">البريد الإلكتروني</label>
                        <input
                            type="text"
                            className="w-full p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700"
                            value={getSettingValue('support_email')}
                            onChange={(e) => handleLocalChange('support_email', e.target.value)}
                        />
                        <button onClick={() => updateSetting('support_email', getSettingValue('support_email'))} className="text-xs text-indigo-600 font-bold mt-2">حفظ</button>
                    </div>
                    <div>
                        <label className="block text-sm font-bold mb-2 text-slate-700 dark:text-slate-300">ساعات العمل</label>
                        <input
                            type="text"
                            className="w-full p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700"
                            value={getSettingValue('support_working_hours')}
                            onChange={(e) => handleLocalChange('support_working_hours', e.target.value)}
                        />
                        <button onClick={() => updateSetting('support_working_hours', getSettingValue('support_working_hours'))} className="text-xs text-indigo-600 font-bold mt-2">حفظ</button>
                    </div>
                </div>
            </div>

        </div>
    );
};

export default SettingsManager;

