}

import React, { useState, useEffect } from 'react';
import { MessageSquare, AlertCircle, ShieldCheck, Trash2, Eye } from 'lucide-react';
import { api, updateMessageStatus, deleteSupportMessage } from '@/api';

const SupportInbox = () => {
    const [messages, setMessages] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchMessages();
    }, []);

    const fetchMessages = async () => {
        try {
            setLoading(true);
            const res = await api.get('/api/v1/support/messages');
            setMessages(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error("Failed to fetch support messages", err);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteMessage = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذه الرسالة؟')) return;
        try {
            await deleteSupportMessage(id);
            setMessages(prev => prev.filter(m => m.id !== id));
            alert('تم حذف الرسالة بنجاح');
        } catch (err) {
            console.error(err);
            alert('فشل حذف الرسالة');
        }
    };

    const handleViewMessage = async (msg) => {
        alert(`الرسالة:\n${msg.message}`);
        if (msg.status === 'unread') {
            try {
                await updateMessageStatus(msg.id, 'read');
                // Optimistic update
                setMessages(prev => prev.map(m => m.id === msg.id ? { ...m, status: 'read' } : m));
            } catch (err) {
                console.error("Failed to mark message as read", err);
            }
        }
    };

    if (loading) return <div className="p-10 text-center text-slate-500 animate-pulse">جاري تحميل الرسائل...</div>;

    const unreadCount = messages.filter(m => m.status === 'unread').length;
    const highPriorityCount = messages.filter(m => m.priority === 'high').length;

    return (
        <div className="space-y-8 animate-fade-in text-right">
            {/* Messages Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 font-bold text-sm mb-1">إجمالي الرسائل</p>
                        <p className="text-3xl font-black text-slate-800 dark:text-white">{messages.length}</p>
                    </div>
                    <div className="p-4 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 rounded-2xl">
                        <MessageSquare size={24} />
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 font-bold text-sm mb-1">رسائل غير مقروءة</p>
                        <p className="text-3xl font-black text-rose-600 dark:text-rose-400">{unreadCount}</p>
                    </div>
                    <div className="p-4 bg-rose-50 dark:bg-rose-900/20 text-rose-600 rounded-2xl">
                        <AlertCircle size={24} />
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl border border-slate-100 dark:border-slate-800 shadow-sm flex items-center justify-between">
                    <div>
                        <p className="text-slate-500 font-bold text-sm mb-1">أولوية عالية</p>
                        <p className="text-3xl font-black text-amber-600 dark:text-amber-400">{highPriorityCount}</p>
                    </div>
                    <div className="p-4 bg-amber-50 dark:bg-amber-900/20 text-amber-600 rounded-2xl">
                        <ShieldCheck size={24} />
                    </div>
                </div>
            </div>

            <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
                <div className="p-6 border-b border-slate-50 dark:border-slate-800 flex justify-between items-center">
                    <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                        <MessageSquare className="text-indigo-500" size={20} />
                        صندوق الوارد
                    </h3>
                    <span className="text-xs font-bold text-slate-400 bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-full">
                        {messages.length} رسالة
                    </span>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-right">
                        <thead className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-sm font-bold uppercase">
                            <tr>
                                <th className="p-6">التاريخ</th>
                                <th className="p-6">المرسل</th>
                                <th className="p-6">العيادة</th>
                                <th className="p-6">الموضوع</th>
                                <th className="p-6">الأولوية</th>
                                <th className="p-6">الحالة</th>
                                <th className="p-6 text-center">الإجراءات</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                            {messages.length > 0 ? messages.map(msg => (
                                <tr key={msg.id} className={`hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors ${msg.status === 'unread' ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}>
                                    <td className="p-6 text-sm text-slate-500">
                                        {new Date(msg.created_at).toLocaleString('ar-EG')}
                                    </td>
                                    <td className="p-6 font-bold text-slate-800 dark:text-slate-200">{msg.username}</td>
                                    <td className="p-6 font-medium text-indigo-600 dark:text-indigo-400">{msg.clinic_name}</td>
                                    <td className="p-6">
                                        <div className="flex flex-col">
                                            <span className="font-bold text-slate-800 dark:text-white">{msg.subject}</span>
                                            <span className="text-sm text-slate-400 truncate max-w-xs">{msg.message}</span>
                                        </div>
                                    </td>
                                    <td className="p-6">
                                        <span className={`px-3 py-1 rounded-full text-xs font-bold ${msg.priority === 'high' ? 'bg-rose-100 text-rose-700' :
                                            msg.priority === 'normal' ? 'bg-blue-100 text-blue-700' :
                                                'bg-slate-100 text-slate-700'
                                            }`}>
                                            {msg.priority === 'high' ? 'عالية' : msg.priority === 'normal' ? 'عادية' : 'منخفضة'}
                                        </span>
                                    </td>
                                    <td className="p-6">
                                        <span className={`px-3 py-1 rounded-lg text-xs font-bold ${msg.status === 'unread' ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                                            {msg.status === 'unread' ? 'غير مقروءة' : 'مقروءة'}
                                        </span>
                                    </td>
                                    <td className="p-6 text-center">
                                        <div className="flex items-center justify-center gap-2">
                                            <button
                                                onClick={() => handleViewMessage(msg)}
                                                className="p-2 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 text-indigo-600 rounded-xl transition-all"
                                                title="عرض التفاصيل"
                                            >
                                                <Eye size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDeleteMessage(msg.id)}
                                                className="p-2 hover:bg-rose-50 dark:hover:bg-rose-900/30 text-rose-500 rounded-xl transition-all"
                                                title="حذف الرسالة"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan="7" className="p-20 text-center text-slate-400 font-bold">
                                        لا توجد رسائل دعم فني حالياً 📬
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default SupportInbox;

import React, { useState, useEffect } from 'react';
import { api } from '@/api';
import { Activity, Server, Clock, CheckCircle, XCircle, Play } from 'lucide-react';

export default function SystemHealth() {
    const [jobs, setJobs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [runningTest, setRunningTest] = useState(false);

    useEffect(() => {
        fetchJobs();
        const interval = setInterval(fetchJobs, 10000); // Poll every 10s
        return () => clearInterval(interval);
    }, []);

    const fetchJobs = async () => {
        try {
            const res = await api.get('/api/v1/admin/security/jobs'); // Check endpoint path
            setJobs(res.data);
            setLoading(false);
        } catch (error) {
            console.error("Failed to fetch jobs", error);
        }
    };

    const runTestJob = async () => {
        setRunningTest(true);
        try {
            await api.post('/api/v1/admin/security/jobs/trigger-test');
            fetchJobs();
        } catch (error) {
            alert("فشل تشغيل المهمة التجريبية");
        } finally {
            setRunningTest(false);
        }
    };

    return (
        <div className="space-y-6 animate-fade-in-up">
            <div className="flex justify-between items-center">
                <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                    <Activity className="text-blue-500" />
                    حالة النظام والمهام الخلفية (Background Jobs)
                </h3>
                <button
                    onClick={runTestJob}
                    disabled={runningTest}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg shadow font-bold text-sm disabled:opacity-50"
                >
                    <Play size={16} />
                    {runningTest ? 'جاري التشغيل...' : 'تشغيل فحص يدوي'}
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-emerald-100 text-emerald-600 rounded-xl">
                        <CheckCircle size={32} />
                    </div>
                    <div>
                        <p className="text-sm text-slate-500 font-bold">نسبة النجاح (24h)</p>
                        <p className="text-2xl font-bold text-slate-800 dark:text-white">99.8%</p>
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-blue-100 text-blue-600 rounded-xl">
                        <Server size={32} />
                    </div>
                    <div>
                        <p className="text-sm text-slate-500 font-bold">آخر نسخ احتياطي</p>
                        <p className="text-2xl font-bold text-slate-800 dark:text-white">منذ 2 ساعة</p>
                    </div>
                </div>
                <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 flex items-center gap-4">
                    <div className="p-4 bg-purple-100 text-purple-600 rounded-xl">
                        <Clock size={32} />
                    </div>
                    <div>
                        <p className="text-sm text-slate-500 font-bold">متوسط زمن الاستجابة</p>
                        <p className="text-2xl font-bold text-slate-800 dark:text-white">45ms</p>
                    </div>
                </div>
            </div>

            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
                <table className="w-full text-right">
                    <thead className="bg-slate-50 dark:bg-slate-800 text-slate-500 font-bold text-sm">
                        <tr>
                            <th className="p-4">اسم المهمة</th>
                            <th className="p-4">الحالة</th>
                            <th className="p-4">الوقت المستغرق</th>
                            <th className="p-4">تاريخ البدء</th>
                            <th className="p-4">المُشغّل</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {jobs.map(job => (
                            <tr key={job.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                <td className="p-4 font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                                    <div className={`w-2 h-2 rounded-full ${job.status === 'success' ? 'bg-emerald-500' : job.status === 'running' ? 'bg-blue-500 animate-pulse' : 'bg-red-500'}`}></div>
                                    {job.job_name}
                                </td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded text-xs font-bold ${job.status === 'success' ? 'bg-emerald-100 text-emerald-700' :
                                        job.status === 'running' ? 'bg-blue-100 text-blue-700' :
                                            'bg-red-100 text-red-700'
                                        }`}>
                                        {job.status.toUpperCase()}
                                    </span>
                                </td>
                                <td className="p-4 text-slate-500 font-mono text-sm" dir="ltr">
                                    {job.duration_seconds.toFixed(2)}s
                                </td>
                                <td className="p-4 text-slate-500 text-sm" dir="ltr">
                                    {new Date(job.started_at).toLocaleString()}
                                </td>
                                <td className="p-4 text-slate-500 text-sm">
                                    {job.triggered_by}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {jobs.length === 0 && !loading && (
                    <div className="p-8 text-center text-slate-400">لا توجد سجلات للمهام مؤخراً.</div>
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Edit3, Clock, Trash2, Key, DollarSign, Activity } from 'lucide-react';
import { api } from '@/api';
import PaymentModal from './modals/PaymentModal';
import PasswordResetModal from './modals/PasswordResetModal';

export default function TenantsManager() {
    const [tenants, setTenants] = useState([]);
    const [plans, setPlans] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showPaymentModal, setShowPaymentModal] = useState(null);
    const [showPasswordResetModal, setShowPasswordResetModal] = useState(null);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            setLoading(true);
            const [tenantsRes, plansRes] = await Promise.all([
                api.get('/api/v1/admin/tenants'),
                api.get('/api/v1/admin/plans')
            ]);
            setTenants(Array.isArray(tenantsRes.data) ? tenantsRes.data : []);
            setPlans(Array.isArray(plansRes.data) ? plansRes.data : []);
        } catch (error) {
            console.error("Failed to fetch data", error);
        } finally {
            setLoading(false);
        }
    };

    const handlePlanChange = async (e, tenantId) => {
        const newPlanId = parseInt(e.target.value);
        if (!newPlanId) return;

        if (window.confirm('هل أنت متأكد من تغيير الخطة؟ سيتم احتساب المدة الجديدة بدءاً من اليوم.')) {
            try {
                await api.post(`/api/v1/admin/tenants/${tenantId}/assign-plan?plan_id=${newPlanId}`);
                fetchData();
                alert('تم تغيير الخطة بنجاح');
            } catch (err) {
                console.error(err);
                alert('فشل تغيير الخطة');
            }
        }
    };

    const handleArchiveTenant = async (tenantId) => {
        if (!window.confirm("هل أنت متأكد من أرشفة هذه العيادة؟ ستختفي من القائمة النشطة ويتم تعطيل دخول المستخدمين.")) return;
        try {
            await api.delete(`/api/v1/admin/tenants/${tenantId}`);
            fetchData();
            alert("تمت الأرشفة بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشلت عملية الأرشفة");
        }
    };

    const handleRestoreTenant = async (tenantId) => {
        if (!window.confirm("هل أنت متأكد من استعادة هذه العيادة؟")) return;
        try {
            await api.post(`/api/v1/admin/tenants/${tenantId}/restore`);
            fetchData();
            alert("تمت الاستعادة بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشلت عملية الاستعادة");
        }
    };

    const handlePermanentDelete = async (tenantId) => {
        if (!window.confirm("تحذير: هذا الإجراء لا يمكن التراجع عنه! سيتم حذف كل بيانات العيادة بما فيها المرضى والملفات. هل أنت متأكد تماماً؟")) return;
        try {
            await api.delete(`/api/v1/admin/tenants/${tenantId}/permanent`);
            fetchData();
            alert("تم الحذف النهائي بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشل الحذف النهائي: " + (error.response?.data?.detail || error.message));
        }
    };

    const getDaysRemaining = (endDate) => {
        if (!endDate) return null;
        const days = Math.ceil((new Date(endDate) - new Date()) / (1000 * 60 * 60 * 24));
        return days;
    };

    if (loading) return <div className="p-10 text-center text-slate-500 animate-pulse">جاري تحميل العيادات...</div>;

    return (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
            <div className="overflow-x-auto">
                <table className="w-full text-right">
                    <thead>
                        <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-slate-400 text-sm font-bold uppercase tracking-wider">
                            <th className="p-6">العيادة</th>
                            <th className="p-6">خطة الاشتراك</th>
                            <th className="p-6">حالة الاشتراك</th>
                            <th className="p-6">المدة المتبقية</th>
                            <th className="p-6">إجمالي المدفوعات</th>
                            <th className="p-6 text-center">إجراءات سريعة</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                        {tenants.map((tenant) => {
                            const daysLeft = getDaysRemaining(tenant.subscription_end_date);
                            const isDeleted = tenant.is_deleted;

                            return (
                                <tr key={tenant.id} className={`transition-colors ${isDeleted ? 'bg-red-50 dark:bg-red-900/10' : 'hover:bg-slate-50/50 dark:hover:bg-slate-800/50'}`}>
                                    <td className="p-6 font-bold text-slate-800 dark:text-slate-200">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${isDeleted ? 'bg-red-100 text-red-600' : 'bg-indigo-100 text-indigo-600 dark:bg-indigo-900/50 dark:text-indigo-400'}`}>
                                                {tenant.name.charAt(0)}
                                            </div>
                                            <div>
                                                {tenant.name}
                                                {isDeleted && <span className="mr-2 text-xs text-red-500 font-bold">(مؤرشف)</span>}
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-6">
                                        {!isDeleted ? (
                                            <div className="relative">
                                                <select
                                                    value={tenant.plan_id || ''}
                                                    onChange={(e) => handlePlanChange(e, tenant.id)}
                                                    className="appearance-none w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 py-2 pr-4 pl-10 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 font-medium cursor-pointer"
                                                >
                                                    <option value="" disabled>اختر خطة</option>
                                                    {plans.map(p => (
                                                        <option key={p.id} value={p.id}>{p.display_name_ar}</option>
                                                    ))}
                                                </select>
                                                <Edit3 size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                                            </div>
                                        ) : (
                                            <span className="text-slate-400">-</span>
                                        )}
                                    </td>
                                    <td className="p-6">
                                        <span className={`px-4 py-1.5 rounded-full text-xs font-bold inline-flex items-center gap-1.5 ${tenant.is_active && (!daysLeft || daysLeft > 0)
                                            ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400'
                                            : 'bg-rose-100 text-rose-700 dark:bg-rose-900/30 dark:text-rose-400'
                                            }`}>
                                            <span className={`w-2 h-2 rounded-full ${tenant.is_active && (!daysLeft || daysLeft > 0) ? 'bg-emerald-500' : 'bg-rose-500'
                                                }`} />
                                            {tenant.is_active && (!daysLeft || daysLeft > 0) ? 'نشط' : 'منتهي/معطل'}
                                        </span>
                                    </td>
                                    <td className="p-6">
                                        {daysLeft !== null ? (
