    });

    useEffect(() => {
        fetchPlans();
    }, []);

    const fetchPlans = async () => {
        try {
            const res = await api.get('/api/v1/admin/plans'); // Corrected path
            setPlans(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error("Failed to fetch plans", err);
        }
