                    </div>

                    <div>
                        <label className="block text-sm font-bold text-slate-500 mb-1.5">المبلغ المدفوع</label>
                        <input
                            type="number"
                            value={form.amount}
                            onChange={(e) => setForm({ ...form, amount: e.target.value })}
                            className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-bold text-slate-500 mb-1.5">وسيلة الدفع</label>
                        <div className="grid grid-cols-3 gap-3">
                            {[
                                { id: 'cash', label: 'نقدي', icon: Banknote },
                                { id: 'bank_transfer', label: 'تحويل', icon: Landmark },
                                { id: 'credit_card', label: 'بطاقة', icon: CreditCard }
                            ].map(method => (
                                <button
                                    key={method.id}
                                    onClick={() => setForm({ ...form, payment_method: method.id })}
                                    className={`flex flex-col items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${form.payment_method === method.id
                                        ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600'
                                        : 'border-slate-100 dark:border-slate-800 text-slate-400 hover:border-slate-300'
                                        }`}
                                >
                                    <method.icon size={20} />
                                    <span className="text-xs font-bold">{method.label}</span>
                                </button>
                            ))}
                        </div>
                    </div>

                    <button
                        onClick={handleSubmit}
                        disabled={loading}
                        className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg text-lg transition-all ${loading
                            ? 'bg-slate-300 cursor-not-allowed'
                            : 'bg-emerald-500 hover:bg-emerald-600 text-white shadow-emerald-500/20 hover:scale-[1.02]'}`}
                    >
                        <PlusCircle size={20} />
                        {loading ? 'جاري الحفظ...' : 'حفظ العملية'}
                    </button>
                </div>
            </div>
        </div>
    );
}

/**
 * AI Chat Component - Smart Dent Clinic
 * Floating chat interface for natural language queries with voice support
 * Features: Context Memory, Medical Scribe Mode
 */

import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, Send, X, Bot, User, Loader2, Sparkles, AlertCircle, Mic, MicOff, Calendar, Users, DollarSign, Building2, Volume2, VolumeX, FileEdit } from 'lucide-react';
import { sendAIQuery } from '@/api';
import { dentalAiAvatarBase64 as aiAvatar } from '@/assets/dentalAiAvatarBase64';
import { useVoiceInput } from '@/hooks/useVoiceInput';
import { useTextToSpeech } from '@/hooks/useTextToSpeech';
import { formatAIResponse } from '@/utils/aiResponseFormatter';
import { useTranslation } from 'react-i18next';

export default function AIChat() {
    const { t } = useTranslation();

    // Initial greeting in current language
    const [messages, setMessages] = useState([
        {
            role: 'assistant',
            content: t('ai_chat.welcome_message'),
            type: 'greeting'
        }
    ]);

    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [autoSendAfterSpeech, setAutoSendAfterSpeech] = useState(false);
    const [lastPatientName, setLastPatientName] = useState(null); // For context memory
    const [scribeMode, setScribeMode] = useState(false); // Medical Scribe Mode

    const messagesEndRef = useRef(null);
    const inputRef = useRef(null);

    // Custom Hooks
    const {
        isListening,
        toggleListening,
        stopListening,
        startListening,
        speechSupported,
        transcript
    } = useVoiceInput((finalText) => {
        if (finalText.trim()) {
            setAutoSendAfterSpeech(true);
        }
    });

    const {
        ttsEnabled,
        setTtsEnabled,
        speakText
    } = useTextToSpeech(false);

    // Sync transcript to input
    useEffect(() => {
        if (isListening) {
            setInput(transcript);
        }
    }, [transcript, isListening]);

    // Auto-scroll to bottom
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    // Focus input when opened
    useEffect(() => {
        if (isOpen) {
            inputRef.current?.focus();
        }
    }, [isOpen]);

    // Auto-send after speech recognition ends
    useEffect(() => {
        if (autoSendAfterSpeech && input.trim() && !isListening) {
            setAutoSendAfterSpeech(false);
            handleSend();
        }
    }, [autoSendAfterSpeech, isListening, input]);

    // Sync Scribe Mode with Microphone
    useEffect(() => {
        if (scribeMode) {
            if (!isListening) startListening();
        } else {
            if (isListening) stopListening();
        }
    }, [scribeMode]);

    const handleSend = async () => {
        if (!input.trim() || isLoading) return;

        // Stop listening if active
        if (isListening) {
            stopListening();
        }

        const userMessage = input.trim();
        setInput('');

        // Add user message
        setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
        setIsLoading(true);

        try {
            // Build conversation context (last 10 messages)
            const conversationContext = messages.slice(-10).map(m => ({
                role: m.role,
                content: m.content
            }));

            // Send query with context (Phase 1: Memory)
            const response = await sendAIQuery(userMessage, {
                context: conversationContext,
                last_patient_name: lastPatientName,
                scribe_mode: scribeMode
            });

            // Format response based on tool
            let assistantMessage = formatAIResponse(response.data);
            setMessages(prev => [...prev, assistantMessage]);

            // Text-to-Speech
            if (ttsEnabled && assistantMessage.content) {
                speakText(assistantMessage.content);
            }

            // Remember patient name for context
            if (response.data?.data?.patient?.name) {
                setLastPatientName(response.data.data.patient.name);
            } else if (response.data?.data?.patient_name) {
                setLastPatientName(response.data.data.patient_name);
            }
        } catch (err) {
            console.error('AI Query Error:', err);
            setMessages(prev => [...prev, {
                role: 'assistant',
                content: err.response?.data?.detail || t('ai_chat.chat.connection_error'),
                type: 'error'
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    // Quick action handler - transmits the exact query to backend
    const handleQuickAction = (displayLabel, queryText) => {
        // We display the queryText in input for clarity, but the button label was translated
        setInput(queryText);
        // Trigger send after a short delay
        setTimeout(() => {
            if (inputRef.current) {
                // const event = new KeyboardEvent('keypress', { key: 'Enter' }); 
                // Removed unused event
                handleSend();
            }
        }, 100);
    };

    const handleKeyPress = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    const getMessageStyle = (type) => {
        switch (type) {
            case 'error': return 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800';
            case 'warning': return 'bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800';
            case 'success': return 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800';
            default: return 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700';
        }
    };

    return (
        <>
            {/* Floating Button */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className={`fixed bottom-6 z-50 p-0 rounded-full shadow-2xl transition-all duration-300 ltr:right-6 rtl:left-6 ${isOpen
                    ? 'bg-slate-700 hover:bg-slate-800 rotate-90 w-14 h-14 flex items-center justify-center'
                    : 'bg-transparent animate-bounce-slow hover:scale-110'
                    }`}
            >
                {isOpen ? (
                    <X size={24} className="text-white" />
                ) : (
                    <img
                        src={aiAvatar}
                        alt="AI Assistant"
                        className="w-16 h-16 md:w-24 md:h-24 drop-shadow-2xl filter hover:brightness-110 transition-all transform hover:scale-105"
                    />
                )}
            </button>

            {/* Chat Window */}
            {isOpen && (
                <div className="fixed bottom-24 z-50 w-96 max-w-[calc(100vw-3rem)] h-[500px] max-h-[70vh] bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 flex flex-col overflow-hidden animate-in slide-in-from-bottom-4 duration-300 ltr:right-6 rtl:left-6">
                    {/* Header */}
                    <div className="bg-gradient-to-r from-violet-600 to-indigo-600 p-4 flex items-center gap-3">
                        <div className="bg-white/10 rounded-full border border-white/20 w-12 h-12 flex items-center justify-center overflow-hidden shrink-0">
                            <img src={aiAvatar} alt="AI" className="w-full h-full object-cover" />
                        </div>
                        <div className="flex-1">
                            <h3 className="text-white font-bold">{t('ai_chat.title')}</h3>
                            <p className="text-violet-200 text-xs">{t('ai_chat.subtitle')}</p>
                        </div>
                        {isListening && (
                            <div className="flex items-center gap-1 bg-red-500 text-white px-2 py-1 rounded-full text-xs animate-pulse">
                                <Mic size={12} />
                                <span>{t('ai_chat.listening')}</span>
                            </div>
                        )}
                        {/* TTS Toggle */}
                        <button
                            onClick={() => setTtsEnabled(!ttsEnabled)}
                            className={`p-2 rounded-lg transition-all ${ttsEnabled ? 'bg-green-500 text-white' : 'bg-white/20 text-white/70 hover:bg-white/30'}`}
                            title={ttsEnabled ? t('ai_chat.toggle_sound_off') : t('ai_chat.toggle_sound_on')}
                        >
                            {ttsEnabled ? <Volume2 size={16} /> : <VolumeX size={16} />}
                        </button>
                    </div>

                    {/* Quick Actions */}
                    <div className="px-3 py-2 border-b border-slate-200 dark:border-slate-700 flex gap-2 overflow-x-auto">
                        <button
                            onClick={() => handleQuickAction(t('ai_chat.quick_actions.appointments'), t('ai_chat.quick_queries.appointments'))}
                            className="flex items-center gap-1 px-3 py-1.5 bg-violet-100 dark:bg-violet-900/30 text-violet-700 dark:text-violet-300 rounded-full text-xs whitespace-nowrap hover:bg-violet-200 dark:hover:bg-violet-900/50 transition-all"
                        >
                            <Calendar size={12} />
                            <span>{t('ai_chat.quick_actions.appointments')}</span>
                        </button>
                        <button
                            onClick={() => handleQuickAction(t('ai_chat.quick_actions.debtors'), t('ai_chat.quick_queries.debtors'))}
                            className="flex items-center gap-1 px-3 py-1.5 bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300 rounded-full text-xs whitespace-nowrap hover:bg-amber-200 dark:hover:bg-amber-900/50 transition-all"
                        >
                            <DollarSign size={12} />
                            <span>{t('ai_chat.quick_actions.debtors')}</span>
                        </button>
                        <button
                            onClick={() => handleQuickAction(t('ai_chat.quick_actions.staff'), t('ai_chat.quick_queries.staff'))}
                            className="flex items-center gap-1 px-3 py-1.5 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-full text-xs whitespace-nowrap hover:bg-blue-200 dark:hover:bg-blue-900/50 transition-all"
                        >
                            <Users size={12} />
                            <span>{t('ai_chat.quick_actions.staff')}</span>
                        </button>
                        <button
                            onClick={() => handleQuickAction(t('ai_chat.quick_actions.clinic'), t('ai_chat.quick_queries.clinic'))}
                            className="flex items-center gap-1 px-3 py-1.5 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 rounded-full text-xs whitespace-nowrap hover:bg-emerald-200 dark:hover:bg-emerald-900/50 transition-all"
                        >
                            <Building2 size={12} />
                            <span>{t('ai_chat.quick_actions.clinic')}</span>
                        </button>
                        {/* Medical Scribe Mode Toggle */}
                        <button
                            onClick={() => setScribeMode(!scribeMode)}
                            className={`flex items-center gap-1 px-3 py-1.5 rounded-full text-xs whitespace-nowrap transition-all ${scribeMode
                                ? 'bg-rose-500 text-white animate-pulse'
                                : 'bg-rose-100 dark:bg-rose-900/30 text-rose-700 dark:text-rose-300 hover:bg-rose-200 dark:hover:bg-rose-900/50'
                                }`}
                            title={t('ai_chat.scribe_mode.tooltip')}
                        >
                            <FileEdit size={12} />
                            <span>{scribeMode ? t('ai_chat.scribe_mode.button_active') : t('ai_chat.scribe_mode.button_inactive')}</span>
                        </button>
                    </div>

                    {/* Scribe Mode Banner */}
                    {scribeMode && (
                        <div className="px-3 py-2 bg-gradient-to-r from-rose-500 to-pink-500 text-white text-xs flex items-center justify-between">
                            <span>{t('ai_chat.scribe_mode.banner')}</span>
                            <button
                                onClick={() => setScribeMode(false)}
                                className="px-2 py-0.5 bg-white/20 rounded hover:bg-white/30"
                            >
                                {t('ai_chat.scribe_mode.stop')}
                            </button>
                        </div>
                    )}

                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-4">
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] ${msg.role === 'user'
                                    ? 'bg-gradient-to-r from-violet-600 to-indigo-600 text-white rounded-2xl rounded-br-sm'
                                    : `${getMessageStyle(msg.type)} border rounded-2xl rounded-bl-sm`
                                    } p-3 shadow-sm`}>
                                    {msg.role === 'assistant' && (
                                        <div className="flex items-center gap-2 mb-2 text-violet-600 dark:text-violet-400">
                                            <Bot size={16} />
                                            <span className="text-xs font-bold">{t('ai_chat.chat.assistant_label')}</span>
                                        </div>
                                    )}
                                    <div className={`text-sm whitespace-pre-wrap ${msg.role === 'user' ? '' : 'text-slate-700 dark:text-slate-300'}`}>
                                        {msg.content.split('**').map((part, i) =>
                                            i % 2 === 1 ? <strong key={i}>{part}</strong> : part
                                        )}
                                    </div>
                                    {/* Smart Suggestions */}
                                    {msg.suggestions && msg.suggestions.length > 0 && (
                                        <div className="mt-3 pt-2 border-t border-slate-200 dark:border-slate-600 flex flex-wrap gap-2">
                                            {msg.suggestions.map((suggestion, si) => (
                                                <button
                                                    key={si}
                                                    onClick={() => handleQuickAction(suggestion, suggestion)}
                                                    className="text-xs px-2 py-1 bg-violet-100 dark:bg-violet-900/30 text-violet-700 dark:text-violet-300 rounded-full hover:bg-violet-200 dark:hover:bg-violet-900/50 transition-all"
                                                >
                                                    💡 {suggestion}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}

                        {isLoading && (
                            <div className="flex justify-start">
                                <div className="bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-sm p-4 flex items-center gap-2">
                                    <Loader2 size={16} className="animate-spin text-violet-600" />
                                    <span className="text-sm text-slate-500">{t('ai_chat.processing')}</span>
                                </div>
                            </div>
                        )}

                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input with Voice */}
                    <div className="p-3 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50">
                        <div className="flex gap-2">
                            {/* Voice Button */}
                            {speechSupported && (
                                <button
                                    onClick={toggleListening}
                                    disabled={isLoading}
                                    className={`px-4 py-3 rounded-xl transition-all ${isListening
                                        ? 'bg-red-500 text-white animate-pulse'
                                        : 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-600'
                                        } disabled:opacity-50`}
                                >
                                    {isListening ? <MicOff size={20} /> : <Mic size={20} />}
                                </button>
                            )}

                            <input
                                ref={inputRef}
                                type="text"
                                value={input}
                                onChange={(e) => setInput(e.target.value)}
                                onKeyPress={handleKeyPress}
                                placeholder={isListening ? t('ai_chat.chat.input_listening') : t('ai_chat.chat.input_placeholder')}
                                className="flex-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-violet-500 disabled:opacity-50"
                                disabled={isLoading}
                                dir="auto"
                            />
                            <button
                                onClick={handleSend}
                                disabled={!input.trim() || isLoading}
                                className="bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-4 py-3 rounded-xl hover:shadow-lg hover:scale-105 transition-all disabled:opacity-50 disabled:hover:scale-100 md:w-auto"
                            >
                                <Send size={20} />
                            </button>
                        </div>
                        <div className="text-center mt-2">
                            <p className="text-[10px] text-slate-400">
                                {t('ai_chat.chat.powered_by')} • {speechSupported ? t('ai_chat.chat.voice_enabled') : t('ai_chat.chat.voice_unsupported')}
                            </p>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getProfitability } from '@/api/analytics';
import KPIGrid from './components/KPIGrid';
import ProfitChart from './components/ProfitChart';
import AiAdvisor from './components/AiAdvisor';
import ProcedureCostAnalysis from './components/ProcedureCostAnalysis';
import GeneralCostAnalysis from './components/GeneralCostAnalysis';
import { Calendar, PieChart, Activity } from 'lucide-react';
import { useTranslation } from 'react-i18next';

const SmartDashboard = () => {
    const { t } = useTranslation();
    const [period, setPeriod] = useState('30d');
    const [activeTab, setActiveTab] = useState('financials'); // financials, procedures

    const { data, isLoading, error } = useQuery({
        queryKey: ['profitability', period],
        queryFn: () => getProfitability(period),
        refetchOnWindowFocus: false,
        staleTime: 5 * 60 * 1000 // 5 minutes
    });

    return (
        <div className="p-4 md:p-8 space-y-6 max-w-[1920px] mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
            {/* Header Area */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight">{t('analytics.dashboard.title')}</h1>
                    <p className="text-slate-500 mt-1 font-medium">{t('analytics.dashboard.subtitle')}</p>
                </div>

                <div className="flex flex-wrap items-center gap-3">
                    {/* Period Selector */}
                    <div className="flex bg-white dark:bg-slate-800 rounded-xl p-1.5 border border-slate-200 dark:border-slate-700 shadow-sm">
                        {['7d', '30d', '90d'].map((p) => (
                            <button
                                key={p}
                                onClick={() => setPeriod(p)}
                                className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${period === p
                                    ? 'bg-indigo-600 text-white shadow-md shadow-indigo-200 dark:shadow-none'
                                    : 'text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700 hover:text-slate-900'
                                    }`}
                            >
                                {p === '7d' ? t('analytics.dashboard.periods.week') : p === '30d' ? t('analytics.dashboard.periods.month') : t('analytics.dashboard.periods.three_months')}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Main Tabs */}
            <div className="border-b border-slate-200 dark:border-slate-700 mb-6">
                <div className="flex space-x-8 rtl:space-x-reverse overflow-x-auto">
                    <button
                        onClick={() => setActiveTab('financials')}
                        className={`pb-4 px-2 text-sm font-bold transition-all border-b-2 flex items-center gap-2 whitespace-nowrap ${activeTab === 'financials'
                            ? 'border-indigo-600 text-indigo-600'
                            : 'border-transparent text-slate-500 hover:text-slate-800 hover:border-slate-300'
                            }`}
                    >
                        <PieChart size={18} />
                        {t('analytics.dashboard.tabs.financials')}
                    </button>
                    <button
                        onClick={() => setActiveTab('procedures')}
                        className={`pb-4 px-2 text-sm font-bold transition-all border-b-2 flex items-center gap-2 whitespace-nowrap ${activeTab === 'procedures'
                            ? 'border-indigo-600 text-indigo-600'
                            : 'border-transparent text-slate-500 hover:text-slate-800 hover:border-slate-300'
                            }`}
                    >
                        <Activity size={18} />
                        {t('analytics.dashboard.tabs.procedures')}
                    </button>
                </div>
            </div>

            {/* Error State */}
            {error && (
                <div className="bg-red-50 text-red-600 p-4 rounded-xl border border-red-100 flex items-center justify-center font-bold">
                    {t('analytics.dashboard.error_loading')} {error.message}
                </div>
            )}

            {/* Tab: Financial Overview */}
            {activeTab === 'financials' && (
                <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                    {isLoading && !data ? (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                                {[1, 2, 3, 4].map(i => <div key={i} className="h-32 bg-slate-100 dark:bg-slate-800 rounded-2xl animate-pulse"></div>)}
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="h-[450px] bg-slate-100 dark:bg-slate-800 rounded-2xl animate-pulse"></div>
                                <div className="md:col-span-2 h-[450px] bg-slate-100 dark:bg-slate-800 rounded-2xl animate-pulse"></div>
                            </div>
                        </div>
                    ) : (() => {
                        const safeData = {
                            revenue: data?.revenue || 0,
                            net_profit: data?.net_profit || 0,
                            margin_percent: data?.margin_percent || 0,
                            total_costs: data?.total_costs || 0,
                            breakdown: {
                                expenses: data?.breakdown?.expenses || 0,
                                material_costs: data?.breakdown?.material_costs || 0,
                                lab_costs: data?.breakdown?.lab_costs || 0,
                            },
                            ...data
                        };

                        return (
                            <>
                                <KPIGrid data={safeData} />
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                    <div className="lg:col-span-1 h-full">
                                        <ProfitChart data={safeData} />
                                    </div>
                                    <div className="lg:col-span-2 h-full">
                                        <AiAdvisor stats={safeData} />
                                    </div>
                                </div>
                            </>
                        );
                    })()}
                </div>
            )}

            {/* Tab: Procedure Analytics */}
            {activeTab === 'procedures' && (
                <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
                    {/* Top: General Analysis (All Procedures) */}
                    <GeneralCostAnalysis />

                    <div className="border-t border-slate-200 dark:border-slate-700 my-8"></div>

                    {/* Bottom: Detailed Single Procedure Analysis */}
                    <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-dashed border-slate-200 dark:border-slate-800">
                        <div className="mb-4">
                            <h3 className="text-lg font-bold text-slate-700 dark:text-slate-300">{t('analytics.general_analysis.table.title')}</h3>
                            <p className="text-sm text-slate-500">{t('analytics.general_analysis.table.subtitle')}</p>
                        </div>
                        <ProcedureCostAnalysis />
                    </div>
                </div>
            )}
        </div>
    );
};

export default SmartDashboard;

import React, { useState } from 'react';
import { Sparkles, Brain, RefreshCw } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { analyzeClinic } from '@/api/analytics';
import { showToast } from '@/shared/ui/Toast';

const AiAdvisor = ({ stats }) => {
    const { t } = useTranslation();
    const [insights, setInsights] = useState(null);
    const [loading, setLoading] = useState(false);

    const handleAnalyze = async () => {
        if (!stats) return;
        setLoading(true);
        try {
            const data = await analyzeClinic(stats);
            setInsights(data.insights);
        } catch (err) {
            console.error(err);
            showToast('error', t('analytics.advisor.error') + ' ' + (err.response?.data?.message || err.message));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-gradient-to-br from-indigo-50/50 to-purple-50/50 backdrop-blur-sm p-6 rounded-2xl border border-indigo-100/50 shadow-sm relative overflow-hidden h-full min-h-[400px]">
            {/* Header */}
            <div className="flex justify-between items-center mb-6 relative z-10">
                <div className="flex items-center gap-3">
                    <div className="p-2.5 bg-indigo-600 rounded-xl text-white shadow-lg shadow-indigo-200">
                        <Brain size={24} />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-indigo-900">{t('analytics.advisor.title')}</h3>
                        <p className="text-xs text-indigo-500 font-medium">{t('analytics.advisor.subtitle')}</p>
                    </div>
                </div>
                <button
                    onClick={handleAnalyze}
                    disabled={loading || !stats}
                    className="flex items-center gap-2 text-sm font-bold text-indigo-600 hover:bg-white/80 bg-white/40 px-4 py-2 rounded-xl transition-all active:scale-95 disabled:opacity-50 border border-indigo-100"
                >
                    {loading ? <RefreshCw className="animate-spin" size={16} /> : <Sparkles size={16} />}
                    {insights ? t('analytics.advisor.refresh') : t('analytics.advisor.start')}
                </button>
            </div>

            {/* Content */}
            <div className="relative z-10">
                {loading ? (
                    <div className="space-y-4 animate-pulse py-4">
                        <div className="h-4 bg-indigo-200/50 rounded-lg w-3/4"></div>
                        <div className="h-4 bg-indigo-200/50 rounded-lg w-1/2"></div>
                        <div className="h-4 bg-indigo-200/50 rounded-lg w-5/6"></div>
                        <div className="h-4 bg-indigo-200/50 rounded-lg w-2/3"></div>
                    </div>
                ) : insights ? (
                    <div className="prose prose-sm prose-indigo max-w-none text-indigo-900 leading-loose font-medium bg-white/60 p-5 rounded-2xl border border-indigo-50/50 shadow-sm whitespace-pre-line">
                        {insights}
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center text-indigo-400 py-20 border-2 border-dashed border-indigo-200/50 rounded-2xl bg-white/20">
                        <Sparkles size={48} className="mb-4 opacity-50 text-indigo-300" />
                        <p className="text-base font-medium text-indigo-800">{t('analytics.advisor.ready_title')}</p>
                        <p className="text-xs text-indigo-500 mt-2 max-w-[200px] text-center">{t('analytics.advisor.ready_desc')}</p>
                    </div>
                )}
            </div>

            {/* Background Decoration */}
            <div className="absolute top-0 right-0 -mt-20 -mr-20 w-64 h-64 bg-purple-200 rounded-full blur-3xl opacity-20 pointer-events-none"></div>
            <div className="absolute bottom-0 left-0 -mb-20 -ml-20 w-64 h-64 bg-indigo-200 rounded-full blur-3xl opacity-20 pointer-events-none"></div>
        </div>
    );
};

export default AiAdvisor;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { getAllProceduresFinancials } from '@/api/financials';
import { TrendingDown, TrendingUp, AlertTriangle, DollarSign, Activity, ArrowUpDown } from 'lucide-react';

const GeneralCostAnalysis = () => {
    const { t } = useTranslation();
    const [data, setData] = useState([]);
    const [loading, setLoading] = useState(true);
    const [sortConfig, setSortConfig] = useState({ key: 'margin_percent', direction: 'asc' });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            const res = await getAllProceduresFinancials();
            if (Array.isArray(res.data)) {
                setData(res.data);
            } else {
                console.error("GeneralCostAnalysis: API returned non-array", res.data);
                setData([]);
            }
        } catch (err) {
            console.error("Failed to load general analysis", err);
        } finally {
            setLoading(false);
        }
    };

    const handleSort = (key) => {
        let direction = 'asc';
        if (sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    const isDataArray = Array.isArray(data);

    // Sort logic
    const sortedData = isDataArray ? [...data].sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) {
            return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (a[sortConfig.key] > b[sortConfig.key]) {
            return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
    }) : [];

    const getMarginColor = (percent) => {
        if (percent < 30) return 'text-red-600 bg-red-50 dark:bg-red-900/20';
        if (percent < 50) return 'text-amber-600 bg-amber-50 dark:bg-amber-900/20';
        return 'text-emerald-600 bg-emerald-50 dark:bg-emerald-900/20';
    };

    const averages = isDataArray && data.length > 0 ? {
        margin: data.reduce((acc, curr) => acc + curr.margin_percent, 0) / data.length,
        cost: data.reduce((acc, curr) => acc + curr.cost, 0) / data.length
    } : { margin: 0, cost: 0 };

    if (loading) return <div className="p-12 text-center text-slate-500 animate-pulse">{t('analytics.general_analysis.loading')}</div>;

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center gap-4">
                    <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-xl text-blue-600 dark:text-blue-400">
                        <Activity size={24} />
                    </div>
                    <div>
                        <div className="text-sm text-slate-500 font-bold">{t('analytics.general_analysis.total_procedures')}</div>
                        <div className="text-2xl font-black text-slate-800 dark:text-white">{data.length}</div>
                    </div>
                </div>

                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center gap-4">
                    <div className={`p-3 rounded-xl ${averages.margin < 30 ? 'bg-red-50 text-red-600' : 'bg-emerald-50 text-emerald-600'}`}>
                        {averages.margin < 30 ? <TrendingDown size={24} /> : <TrendingUp size={24} />}
                    </div>
                    <div>
                        <div className="text-sm text-slate-500 font-bold">{t('analytics.general_analysis.avg_margin')}</div>
                        <div className={`text-2xl font-black ${averages.margin < 30 ? 'text-red-600' : 'text-emerald-600'}`}>
                            {averages.margin.toFixed(1)}%
                        </div>
                    </div>
                </div>

                <div className="bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm flex items-center gap-4">
                    <div className="p-3 bg-amber-50 dark:bg-amber-900/20 rounded-xl text-amber-600 dark:text-amber-400">
                        <DollarSign size={24} />
                    </div>
                    <div>
                        <div className="text-sm text-slate-500 font-bold">{t('analytics.general_analysis.avg_cost')}</div>
                        <div className="text-2xl font-black text-slate-800 dark:text-white">{averages.cost.toFixed(0)} <span className="text-xs font-normal text-slate-400">{t('analytics.general_analysis.currency')}</span></div>
                    </div>
                </div>
            </div>

            {/* Analysis Table */}
            <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden">
                <div className="p-4 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center">
                    <h3 className="font-bold text-slate-800 dark:text-white">{t('analytics.general_analysis.table.title')}</h3>
                    <div className="text-xs text-slate-400">{t('analytics.general_analysis.table.subtitle')}</div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm">
                        <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-bold text-xs uppercase">
                            <tr>
                                <th className="p-4 text-right cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('name')}>
                                    <div className="flex items-center gap-1">{t('analytics.general_analysis.table.procedure')} <ArrowUpDown size={12} /></div>
                                </th>
                                <th className="p-4 text-center cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('price')}>
                                    <div className="flex items-center justify-center gap-1">{t('analytics.general_analysis.table.price')} <ArrowUpDown size={12} /></div>
                                </th>
                                <th className="p-4 text-center cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('cost')}>
                                    <div className="flex items-center justify-center gap-1">{t('analytics.general_analysis.table.cost_ai')} <ArrowUpDown size={12} /></div>
                                </th>
                                <th className="p-4 text-center cursor-pointer hover:text-indigo-600 transition-colors" onClick={() => handleSort('margin_percent')}>
                                    <div className="flex items-center justify-center gap-1">{t('analytics.general_analysis.table.margin')} <ArrowUpDown size={12} /></div>
                                </th>
                                <th className="p-4 text-center">{t('analytics.general_analysis.table.materials_used')}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                            {sortedData.map((item) => (
                                <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                                    <td className="p-4 font-bold text-slate-700 dark:text-slate-200">{item.name}</td>
                                    <td className="p-4 text-center text-slate-600 dark:text-slate-300">{item.price}</td>
                                    <td className="p-4 text-center font-mono text-slate-600 dark:text-slate-300">{item.cost}</td>
                                    <td className="p-4 text-center">
                                        <span className={`px-2 py-1 rounded-lg text-xs font-bold ${getMarginColor(item.margin_percent)}`}>
                                            {item.margin_percent}%
                                        </span>
                                    </td>
                                    <td className="p-4 text-center text-slate-500">
                                        <div className="flex items-center justify-center gap-1">
                                            {item.materials_count}
                                            <span className="text-[10px] text-slate-300">{t('analytics.general_analysis.table.material_count')}</span>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default GeneralCostAnalysis;

import { useTranslation } from 'react-i18next';
import { TrendingUp, TrendingDown, DollarSign, Activity } from 'lucide-react';

const StatCard = ({ title, value, subtext, trend, color, icon: Icon }) => (
    <div className="bg-surface p-6 rounded-2xl border border-border/50 shadow-sm relative overflow-hidden group hover:shadow-md transition-all">
        <div className={`absolute -right-4 -top-4 p-4 opacity-5 group-hover:opacity-10 transition-opacity transform rotate-12 ${color}`}>
            <Icon size={100} />
        </div>
        <div className="relative z-10">
            <div className="flex justify-between items-start mb-4">
                <div className={`p-2 rounded-lg bg-surface-hover ${color}`}>
                    <Icon size={20} />
                </div>
            </div>
            <h3 className="text-2xl font-bold text-text-primary tracking-tight mb-1">{value}</h3>
            <p className="text-text-secondary text-sm font-medium mb-1">{title}</p>
            {subtext && <p className="text-xs text-text-tertiary mt-2">{subtext}</p>}
