import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { getProcedures } from '@/api';
import { getProcedureFinancials } from '@/api/financials';
import { updateMaterial } from '@/api/inventory';
import { Package, Search, TrendingUp, AlertTriangle, CheckCircle } from 'lucide-react';

const ProcedureCostAnalysis = () => {
    const { t } = useTranslation();
    const [procedures, setProcedures] = useState([]);
    const [selectedProcedure, setSelectedProcedure] = useState(null);
    const [analysis, setAnalysis] = useState(null);
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState('analysis'); // analysis, coverage

    useEffect(() => {
        loadProcedures();
    }, []);

    useEffect(() => {
        if (selectedProcedure) {
            loadFinancials(selectedProcedure);
        } else {
            setAnalysis(null);
        }
    }, [selectedProcedure]);

    const loadProcedures = async () => {
        try {
            const res = await getProcedures();
            setProcedures(res.data || []);
        } catch (err) {
            console.error("Failed to load procedures", err);
        }
    };

    const loadFinancials = async (procId) => {
        setLoading(true);
        try {
            const res = await getProcedureFinancials(procId);
            setAnalysis(res.data);
        } catch (err) {
            console.error("Failed to load financials", err);
            setAnalysis(null);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-white dark:bg-slate-800 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-700 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                <div>
                    <h2 className="text-xl font-bold flex items-center gap-2 text-slate-800 dark:text-white">
                        <TrendingUp className="text-indigo-600" />
                        {t('analytics.procedure_analysis.title')}
                    </h2>
                    <p className="text-sm text-slate-500 mt-1">{t('analytics.procedure_analysis.subtitle')}</p>
                </div>

                <div className="w-full md:w-64">
                    <select
                        className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl font-bold text-sm outline-none focus:border-indigo-500"
                        onChange={(e) => setSelectedProcedure(e.target.value)}
                        value={selectedProcedure || ''}
                    >
                        <option value="">{t('analytics.procedure_analysis.select_placeholder')}</option>
                        {procedures.map(p => (
                            <option key={p.id} value={p.id}>{p.name}</option>
                        ))}
                    </select>
                </div>
            </div>

            {!selectedProcedure ? (
                <div className="text-center py-12 text-slate-400 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border border-dashed border-slate-200">
                    <Search className="mx-auto mb-2 opacity-50" size={32} />
                    <p>{t('analytics.procedure_analysis.empty_state')}</p>
                </div>
            ) : loading ? (
                <div className="py-12 text-center text-slate-500 animate-pulse">{t('analytics.procedure_analysis.loading')}</div>
            ) : analysis ? (
                <>
                    {/* Tabs Header */}
                    <div className="flex gap-2 border-b mb-6 overflow-x-auto">
                        <button
                            onClick={() => setActiveTab('analysis')}
                            className={`pb-3 px-4 text-sm font-bold transition-colors border-b-2 whitespace-nowrap ${activeTab === 'analysis' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                        >
                            {t('analytics.procedure_analysis.tabs.cost_smart')}
                        </button>
                        <button
                            onClick={() => setActiveTab('coverage')}
                            className={`pb-3 px-4 text-sm font-bold transition-colors border-b-2 whitespace-nowrap ${activeTab === 'coverage' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                        >
                            {t('analytics.procedure_analysis.tabs.consumption')}
                        </button>
                    </div>

                    {/* ANALYSIS TAB */}
                    {activeTab === 'analysis' && (
                        <div className="animate-in fade-in slide-in-from-right-4 space-y-4">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                                {/* Service Price */}
                                <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-700 text-center shadow-sm">
                                    <div className="text-xs text-slate-500 font-bold mb-1">{t('analytics.procedure_analysis.metrics.service_price')}</div>
                                    <div className="text-2xl font-black text-slate-800 dark:text-white">{analysis.current_price}</div>
                                    <div className="text-[10px] text-slate-400">{t('analytics.general_analysis.currency')}</div>
                                </div>

                                {/* Actual Cost (AI) */}
                                <div className="bg-indigo-50 dark:bg-indigo-900/20 p-4 rounded-2xl border border-indigo-100 dark:border-indigo-800 text-center shadow-sm relative overflow-hidden">
                                    <div className="absolute top-0 right-0 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-bl-lg">AI Learn</div>
                                    <div className="text-xs text-indigo-800 dark:text-indigo-300 font-bold mb-1">{t('analytics.procedure_analysis.metrics.actual_cost')}</div>
                                    <div className="text-2xl font-black text-indigo-700 dark:text-indigo-400">{analysis.total_actual_cost}</div>
                                    <div className="text-[10px] text-indigo-400">{t('analytics.procedure_analysis.metrics.actual_margin')}</div>
                                </div>

                                {/* Actual Profit */}
                                <div className={`p-4 rounded-2xl border text-center shadow-sm ${analysis.actual_profit_margin < 0 ? 'bg-red-50 border-red-100 text-red-700' : 'bg-emerald-50 border-emerald-100 text-emerald-700'}`}>
                                    <div className="text-xs font-bold mb-1 opacity-80">{t('analytics.procedure_analysis.metrics.actual_profit')}</div>
                                    <div className="text-2xl font-black mb-1">{analysis.actual_profit_margin}</div>
                                    <div className="text-[10px] opacity-70">{analysis.actual_margin_percentage}%</div>
                                </div>
                            </div>

                            {/* Suggestions */}
                            {analysis.actual_margin_percentage < 30 && (
                                <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex gap-3 items-start text-amber-800">
                                    <AlertTriangle className="shrink-0" size={20} />
                                    <div>
                                        <h4 className="font-bold">{t('analytics.procedure_analysis.alerts.low_margin')}</h4>
                                        <p className="text-sm mt-1">
                                            {t('analytics.procedure_analysis.alerts.low_margin_desc')}
                                        </p>
                                    </div>
                                </div>
                            )}

                            <div className="bg-slate-50 dark:bg-slate-900/30 rounded-xl p-4 border border-slate-200 dark:border-slate-700">
                                <h4 className="font-bold text-sm text-slate-600 dark:text-slate-300 mb-3 flex justify-between">
                                    <span>{t('analytics.procedure_analysis.comparison.title')}</span>
                                    <span className="text-xs font-normal bg-indigo-100 dark:bg-indigo-900 text-indigo-700 dark:text-indigo-300 px-2 py-1 rounded">{t('analytics.procedure_analysis.comparison.ai_samples')}: {analysis.breakdown?.[0]?.sample_size || 0}+</span>
                                </h4>
                                <div className="space-y-2">
                                    {(analysis.breakdown || []).map((item, idx) => (
                                        <div key={idx} className="flex flex-col sm:flex-row justify-between items-center text-sm p-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-100 dark:border-slate-700 hover:shadow-sm transition-shadow gap-3">
                                            <div className="flex-1 text-center sm:text-right w-full">
                                                <div className="font-bold text-slate-700 dark:text-slate-200">{item.material_name}</div>
                                                <div className="text-xs text-slate-400 mt-0.5">{item.unit_cost} ج.م / {item.base_unit}</div>
                                            </div>

                                            {/* Comparison Grid */}
                                            <div className="flex bg-slate-50 dark:bg-slate-900 rounded-lg p-1 gap-4 text-center w-full sm:w-auto justify-center">
                                                <div className="px-2 border-r border-slate-200 dark:border-slate-700">
                                                    <div className="text-[10px] text-slate-400">{t('analytics.procedure_analysis.comparison.weight_score')}</div>
                                                    <div className="font-bold text-slate-600 dark:text-slate-300">{item.weight_used} <span className="text-[9px] font-normal">{t('analytics.procedure_analysis.comparison.points')}</span></div>
                                                    {/* Cost removed as Score is unitless */}
                                                </div>
                                                <div className="px-2">
                                                    <div className="text-[10px] text-indigo-500 font-bold">{t('analytics.procedure_analysis.comparison.ai_projected')}</div>
                                                    <div className="font-bold text-indigo-700 dark:text-indigo-400">{item.actual_usage} <span className="text-[9px] font-normal">{item.base_unit}</span></div>
                                                    <div className="text-[10px] text-indigo-600 dark:text-indigo-500">{item.actual_cost} {t('analytics.general_analysis.currency')}</div>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* COVERAGE TAB */}
                    {activeTab === 'coverage' && (
                        <div className="animate-in fade-in slide-in-from-right-4">
                            <div className="bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-100 dark:border-indigo-800 p-4 rounded-xl mb-6">
                                <h4 className="font-bold text-indigo-900 dark:text-indigo-100 flex items-center gap-2 mb-2">
                                    <Package size={18} />
                                    {t('analytics.procedure_analysis.coverage.title')}
                                </h4>
                                <p className="text-sm text-indigo-700 dark:text-indigo-300">
                                    {t('analytics.procedure_analysis.coverage.desc')} <strong>{t('analytics.procedure_analysis.coverage.desc_bold')}</strong>.
                                    <br />
                                    <span className="font-bold text-red-600 dark:text-red-400">{t('analytics.procedure_analysis.coverage.important')}</span> {t('analytics.procedure_analysis.coverage.desc_continued')}
                                </p>
                            </div>

                            <div className="border border-slate-200 dark:border-slate-700 rounded-2xl overflow-hidden shadow-sm overflow-x-auto">
                                <table className="w-full text-sm">
                                    <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-bold text-xs uppercase">
                                        <tr>
                                            <th className="p-4 text-right">{t('analytics.procedure_analysis.coverage.table.material')}</th>
                                            <th className="p-4 text-center">{t('analytics.procedure_analysis.coverage.table.actual_usage')}</th>
                                            <th className="p-4 text-center">{t('analytics.procedure_analysis.coverage.table.pack_size')}</th>
                                            <th className="p-4 text-center bg-indigo-50/50 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300">{t('analytics.procedure_analysis.coverage.table.coverage')}</th>
                                            <th className="p-4 text-center">{t('analytics.procedure_analysis.coverage.table.pack_cost')}</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-slate-100 dark:divide-slate-800 bg-white dark:bg-slate-800">
                                        {(analysis.breakdown || []).map((item, idx) => (
                                            <tr key={idx} className="hover:bg-slate-50/50 dark:hover:bg-slate-700/50 transition">
                                                <td className="p-4 font-bold text-slate-700 dark:text-slate-200">{item.material_name}</td>
                                                <td className="p-4 text-center text-slate-500 dark:text-slate-400" dir="ltr">
                                                    {item.actual_usage > 0 ? (
                                                        <span>{item.actual_usage} {item.base_unit}</span>
                                                    ) : (
                                                        <span className="text-amber-500 text-xs italic">{t('analytics.procedure_analysis.coverage.waiting_ai')}</span>
                                                    )}
                                                </td>
                                                <td className="p-4 text-center">
                                                    <div className="flex items-center justify-center gap-2">
                                                        <input
                                                            type="number"
                                                            step="0.1"
                                                            defaultValue={item.pack_size}
                                                            onBlur={async (e) => {
                                                                const newVal = parseFloat(e.target.value);
                                                                if (newVal && newVal !== item.pack_size) {
                                                                    try {
                                                                        await updateMaterial(item.material_id, { packaging_ratio: newVal });
                                                                        loadFinancials(selectedProcedure); // Reload analysis
                                                                    } catch (err) {
                                                                        alert(t('analytics.procedure_analysis.update_fail'));
                                                                    }
                                                                }
                                                            }}
                                                            className="w-16 p-1 text-center border rounded bg-white dark:bg-slate-700 dark:border-slate-600 focus:border-indigo-500 outline-none font-bold"
                                                        />
                                                        <span className="text-xs text-slate-400">{item.base_unit}</span>
                                                    </div>
                                                </td>
                                                <td className={`p-4 text-center font-bold text-lg ${item.coverage_per_pack < 1 ? 'text-amber-600 bg-amber-50 dark:bg-amber-900/20 dark:text-amber-400' : 'text-indigo-600 dark:text-indigo-400 bg-indigo-50/30 dark:bg-indigo-900/20'}`}>
                                                    {isFinite(item.coverage_per_pack) ? (item.coverage_per_pack < 1 ? item.coverage_per_pack.toFixed(1) : Math.floor(item.coverage_per_pack)) : 0} <span className="text-xs font-normal text-slate-400">{t('analytics.procedure_analysis.coverage.patient_unit')}</span>
                                                    {item.coverage_per_pack < 1 && <div className="text-[10px] text-amber-600 dark:text-amber-400 font-normal mt-0.5">{t('analytics.procedure_analysis.coverage.usage_exceeds')}</div>}
                                                </td>
                                                <td className="p-4 text-center text-slate-600 dark:text-slate-300 font-mono">{item.cost_per_pack} {t('analytics.general_analysis.currency')}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}
                </>
            ) : null}
        </div>
    );
};

export default ProcedureCostAnalysis;

import { Banknote } from 'lucide-react';
import { Card, EmptyState, Badge } from '@/shared/ui';

import { useTranslation } from 'react-i18next';

const PaymentsTab = ({ payments, navigate }) => {
    const { t } = useTranslation();
    return (
        <Card className="overflow-hidden">
            <div className="p-6 border-b border-border flex items-center gap-4 bg-surface">
                <div className="w-1.5 h-8 bg-primary rounded-full"></div>
                <h3 className="font-black text-xl text-text-primary">{t('billing.payments.title')}</h3>
            </div>
            <div className="overflow-x-auto">
                {payments.length > 0 ? (
                    <table className="w-full text-right align-middle text-sm">
                        <thead className="bg-surface-hover text-text-secondary font-bold text-xs uppercase tracking-widest border-b border-border">
                            <tr>
                                <th className="p-4">{t('billing.payments.patient')}</th>
                                <th className="p-4">{t('billing.payments.date')}</th>
                                <th className="p-4">{t('billing.payments.amount')}</th>
                                <th className="p-4">{t('billing.payments.notes')}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {payments.map(pay => (
                                <tr key={pay.id} className="hover:bg-surface-hover transition-all group">
                                    <td className="p-4">
                                        <button onClick={() => navigate(`/patients/${pay.patient_id}`)} className="flex flex-col items-start hover:opacity-80 transition-opacity text-right">
                                            <span className="font-black text-primary hover:underline">{pay.patient_name || '---'}</span>
                                            <span className="text-xs text-text-secondary font-bold">#{pay.patient_id}</span>
                                        </button>
                                    </td>
                                    <td className="p-4 text-text-secondary font-bold" dir="ltr">
                                        {new Date(pay.date).toLocaleString('ar-EG', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' })}
                                    </td>
                                    <td className="p-4">
                                        <span className="font-black text-lg text-success">{pay.amount}</span>
                                    </td>
                                    <td className="p-4 text-text-secondary font-medium">{pay.notes || '---'}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                ) : (
                    <EmptyState
                        icon={Banknote}
                        title={t('billing.payments.no_data')}
                        description={t('billing.payments.no_data_desc')}
                    />
                )}
            </div>
        </Card>
    );
};

export default PaymentsTab;

import { TrendingUp, Banknote, DollarSign, Calendar } from 'lucide-react';
import { Button, Card, StatCard, Skeleton } from '@/shared/ui';

import { useTranslation } from 'react-i18next';

const SummaryTab = ({ startDate, setStartDate, endDate, setEndDate, comprehensiveStats, loading, getComprehensiveStats, setComprehensiveStats, setLoading }) => {
    const { t } = useTranslation();
    return (
        <div className="space-y-6">
            {/* Date Range Picker */}
            <Card className="flex items-center justify-between p-4">
                <h3 className="font-bold text-text-primary">{t('billing.summary.period')}</h3>
                <div className="flex items-center gap-3 bg-surface p-2 rounded-xl border border-border">
                    <div className="flex items-center gap-2">
                        <Calendar size={16} className="text-text-secondary" />
                        <span className="text-xs font-bold text-text-secondary">{t('billing.summary.from')}</span>
                        <input
                            type="date"
                            value={startDate}
                            onChange={(e) => setStartDate(e.target.value)}
                            className="bg-transparent border-none text-sm font-bold text-text-primary focus:ring-0 p-0 w-28"
                        />
                    </div>
                    <div className="w-px h-4 bg-border"></div>
                    <div className="flex items-center gap-2">
                        <span className="text-xs font-bold text-text-secondary">{t('billing.summary.to')}</span>
                        <input
                            type="date"
                            value={endDate}
                            onChange={(e) => setEndDate(e.target.value)}
                            className="bg-transparent border-none text-sm font-bold text-text-primary focus:ring-0 p-0 w-28"
                        />
                    </div>
                    <Button
                        onClick={async () => {
                            setLoading(true);
                            try {
                                const res = await getComprehensiveStats(startDate, endDate);
                                setComprehensiveStats(res.data);
                            } catch (err) { console.error(err); }
                            finally { setLoading(false); }
                        }}
                        variant="success"
                        size="sm"
                        isLoading={loading}
                    >
                        {t('billing.summary.calculate')}
                    </Button>
                </div>
            </Card>

            {/* Header Cards - Income */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <StatCard
                    title={t('billing.summary.total_revenue')}
                    value={`${(comprehensiveStats?.income?.total_revenue || 0).toLocaleString()}`}
                    icon={TrendingUp}
                    color="success"
                />
                <StatCard
                    title={t('billing.summary.total_collected')}
                    value={`${(comprehensiveStats?.income?.total_collected || 0).toLocaleString()}`}
                    icon={Banknote}
                    color="info"
                />
                <StatCard
                    title={t('billing.summary.outstanding')}
                    value={`${(comprehensiveStats?.income?.outstanding || 0).toLocaleString()}`}
                    icon={DollarSign}
                    color="warning"
                />
                <StatCard
                    title={t('billing.summary.patient_count')}
                    value={comprehensiveStats?.income?.unique_patients || 0}
                    icon={Calendar}
                    color="primary"
                />
            </div>

            {/* Deductions Breakdown */}
            <Card className="overflow-hidden">
                <div className="p-6 border-b border-border flex items-center gap-4 bg-surface">
                    <div className="w-1.5 h-8 bg-danger rounded-full"></div>
                    <h3 className="font-black text-xl text-text-primary">{t('billing.summary.deductions_title')}</h3>
                </div>
                <div className="p-6 space-y-4">
                    {/* Doctor Dues */}
                    <div className="p-4 bg-purple-50 dark:bg-purple-900/10 rounded-xl border border-purple-100 dark:border-purple-900/20">
                        <div className="flex items-center justify-between mb-3">
                            <h4 className="font-bold text-purple-700 dark:text-purple-400">{t('billing.summary.doctor_dues')}</h4>
                            <span className="font-black text-xl text-purple-600">-{(comprehensiveStats?.deductions?.doctor_dues?.total || 0).toLocaleString()}</span>
                        </div>
                        {comprehensiveStats?.deductions?.doctor_dues?.details?.map(doc => (
                            <div key={doc.id} className="flex items-center justify-between text-sm py-1 border-t border-purple-100 dark:border-purple-900/20">
                                <span className="text-text-secondary">{doc.name} - {t('billing.summary.commission')} {doc.commission_percent}% + {t('billing.summary.salary')} {doc.fixed_salary}</span>
                                <span className="font-bold text-purple-600">{doc.total_due.toLocaleString()}</span>
                            </div>
                        ))}
                    </div>

                    {/* Staff Dues */}
                    <div className="p-4 bg-blue-50 dark:bg-blue-900/10 rounded-xl border border-blue-100 dark:border-blue-900/20">
                        <div className="flex items-center justify-between mb-3">
                            <h4 className="font-bold text-blue-700 dark:text-blue-400">{t('billing.summary.staff_dues')}</h4>
                            <span className="font-black text-xl text-blue-600">-{(comprehensiveStats?.deductions?.staff_dues?.total || 0).toLocaleString()}</span>
                        </div>
                        {comprehensiveStats?.deductions?.staff_dues?.details?.map(s => (
                            <div key={s.id} className="flex items-center justify-between text-sm py-1 border-t border-blue-100 dark:border-blue-900/20">
                                <span className="text-text-secondary">{s.name} - {t('billing.summary.salary')} {s.fixed_salary} + ({s.per_appointment_fee} × {s.appointments_in_period} {t('billing.summary.appointment')})</span>
                                <span className="font-bold text-blue-600">{s.total_due.toLocaleString()}</span>
                            </div>
                        ))}
                        {(!comprehensiveStats?.deductions?.staff_dues?.details?.length) && (
                            <p className="text-sm text-text-muted">{t('billing.summary.no_employees')}</p>
                        )}
                    </div>


                    {/* Lab Costs */}
                    <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-xl border border-orange-100 dark:border-orange-900/20">
                        <div className="flex items-center justify-between">
                            <h4 className="font-bold text-orange-700 dark:text-orange-400">{t('billing.summary.lab_costs')}</h4>
                            <span className="font-black text-xl text-orange-600">-{(comprehensiveStats?.deductions?.lab_costs || 0).toLocaleString()}</span>
                        </div>
                    </div>

                    {/* Expenses */}
                    <div className="p-4 bg-red-50 dark:bg-red-900/10 rounded-xl border border-red-100 dark:border-red-900/20">
                        <div className="flex items-center justify-between">
                            <h4 className="font-bold text-red-700 dark:text-red-400">{t('billing.summary.other_expenses')}</h4>
                            <span className="font-black text-xl text-red-600">-{(comprehensiveStats?.deductions?.expenses || 0).toLocaleString()}</span>
                        </div>
                    </div>
                </div>
            </Card>

            {/* Net Profit */}
            <div className={`p-8 rounded-2xl text-center ${(comprehensiveStats?.net_profit || 0) >= 0 ? 'bg-gradient-to-br from-emerald-500 to-emerald-600' : 'bg-gradient-to-br from-red-500 to-red-600'} text-white shadow-xl`}>
                <p className="text-white/80 font-bold mb-2">{t('billing.summary.net_profit_after')}</p>
                <p className="text-5xl font-black">{(comprehensiveStats?.net_profit || 0).toLocaleString()}</p>
                <p className="text-sm text-white/60 mt-3">{t('billing.summary.net_profit_equation')}</p>
            </div>
        </div>
    );
};

export default SummaryTab;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { DollarSign, User, Calendar, Calculator, Save } from 'lucide-react';
import { getDoctorRevenue, getDoctorDetails, updateStaffCompensation } from '@/api';
import { Button, Input, Modal, Card, Skeleton, EmptyState, toast, Badge } from '@/shared/ui';
import DoctorRevenueDetails from './DoctorRevenueDetails';
import { useTranslation } from 'react-i18next';

export default function DoctorRevenue() {
    const { t } = useTranslation();
    const navigate = useNavigate();

    const today = new Date();
    const oneMonthAgo = new Date(today.getFullYear(), today.getMonth() - 1, today.getDate()).toISOString().split('T')[0];
    const currentDay = today.toISOString().split('T')[0];

    const [startDate, setStartDate] = useState(oneMonthAgo);
    const [endDate, setEndDate] = useState(currentDay);
    const [doctors, setDoctors] = useState([]);
    const [loading, setLoading] = useState(false);

    // Modal State
    const [detailsModalOpen, setDetailsModalOpen] = useState(false);
    const [activeModalTab, setActiveModalTab] = useState('treatments');
    const [doctorDetails, setDoctorDetails] = useState(null);
    const [detailsLoading, setDetailsLoading] = useState(false);
    const [selectedDoctorData, setSelectedDoctorData] = useState(null);

    // Editable compensation
    const [editCommission, setEditCommission] = useState(0);
    const [editSalary, setEditSalary] = useState(0);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        loadData();
    }, [startDate, endDate]);

    const loadData = async () => {
        setLoading(true);
        try {
            const res = await getDoctorRevenue(startDate, endDate);
            setDoctors((res.data.doctors || []).filter(d => d.doctor_name !== 'غير محدد'));
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.doctors_load_fail'));
        } finally {
            setLoading(false);
        }
    };

    const calculateTotal = (netRevenue, commissionPercent, fixedSalary) => {
        const commissionVal = netRevenue * (commissionPercent / 100);
        return commissionVal + fixedSalary;
    };

    const openDetails = async (doc) => {
        setSelectedDoctorData(doc);
        setEditCommission(doc.commission_percent || 0);
        setEditSalary(doc.fixed_salary || 0);
        setActiveModalTab('treatments');
        setDetailsModalOpen(true);
        setDetailsLoading(true);
        try {
            const res = await getDoctorDetails(doc.doctor_id, startDate, endDate);
            setDoctorDetails(res.data);
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.doctor_details_load_fail'));
        } finally {
            setDetailsLoading(false);
        }
    };

    const saveCompensation = async () => {
        if (!selectedDoctorData) return;
        setSaving(true);
        const toastId = toast.loading(t('billing.alerts.saving'));
        try {
            await updateStaffCompensation(selectedDoctorData.doctor_id, editCommission, editSalary);
            setDoctors(prev => prev.map(d =>
                d.doctor_id === selectedDoctorData.doctor_id
                    ? { ...d, commission_percent: editCommission, fixed_salary: editSalary }
                    : d
            ));
            setDetailsModalOpen(false);
            toast.success(t('billing.alerts.save_success'), { id: toastId });
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.save_fail'), { id: toastId });
        } finally {
            setSaving(false);
        }
    };

    return (
        <Card className="overflow-hidden">
            <div className="p-6 border-b border-border flex flex-col md:flex-row md:items-center justify-between gap-4 bg-surface">
                <div className="flex items-center gap-4">
                    <div className="w-1.5 h-8 bg-primary rounded-full"></div>
                    <div>
                        <h3 className="font-black text-xl text-text-primary">{t('billing.doctor_revenue.title')}</h3>
                        <p className="text-text-secondary text-sm">{t('billing.doctor_revenue.subtitle')}</p>
                    </div>
                </div>

                <div className="flex items-center gap-3 bg-background p-2 rounded-xl border border-border">
                    <div className="flex items-center gap-2 px-2">
                        <Calendar size={14} className="text-text-secondary" />
                        <span className="text-xs font-bold text-text-secondary">{t('common.date_range')}:</span>
                        <input
                            type="date"
                            value={startDate}
                            onChange={(e) => setStartDate(e.target.value)}
                            className="bg-transparent border-none text-xs font-bold text-text-primary focus:ring-0 p-0 w-24"
                        />
                        <span className="text-text-secondary">-</span>
                        <input
                            type="date"
                            value={endDate}
                            onChange={(e) => setEndDate(e.target.value)}
                            className="bg-transparent border-none text-xs font-bold text-text-primary focus:ring-0 p-0 w-24"
                        />
                    </div>
                    <Button size="sm" onClick={loadData} disabled={loading}>
                        <Calculator size={14} />
                    </Button>
                </div>
            </div>

            <div className="overflow-x-auto">
                {loading ? (
                    <div className="p-6 space-y-4">
                        {[1, 2, 3].map(i => <Skeleton.Box key={i} className="h-16 w-full rounded-xl" />)}
                    </div>
                ) : (
                    <table className="w-full text-right text-sm">
                        <thead className="bg-surface-hover text-text-secondary font-bold text-xs uppercase border-b border-border">
                            <tr>
                                <th className="p-4">{t('billing.doctor_revenue.table.doctor')}</th>
                                <th className="p-4">{t('billing.doctor_revenue.table.gross_total')}</th>
                                <th className="p-4 text-blue-600">{t('billing.doctor_revenue.table.collected')}</th>
                                <th className="p-4 text-orange-500">{t('billing.doctor_revenue.table.patient_discount')}</th>
                                <th className="p-4 text-rose-500">{t('billing.doctor_revenue.table.lab_cost')}</th>
                                <th className="p-4 text-emerald-600">{t('billing.doctor_revenue.table.net_profit')}</th>
                                <th className="p-4 text-purple-600">{t('billing.doctor_revenue.table.doctor_dues')}</th>
                                <th className="p-4 w-10"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {doctors.length > 0 ? (
                                doctors.map(doc => {
                                    const netRevenue = doc.net_revenue || (doc.revenue - (doc.lab_cost || 0));
                                    const labCost = doc.lab_cost || 0;
                                    // Use COLLECTED amount for commission base, not total revenue
                                    const commissionBase = (doc.collected || 0) - labCost;
                                    const totalDue = calculateTotal(commissionBase, doc.commission_percent || 0, doc.fixed_salary || 0);

                                    return (
                                        <tr key={doc.doctor_id} className="hover:bg-surface-hover transition-colors group">
                                            <td className="p-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold">
                                                        {doc.doctor_name.charAt(0).toUpperCase()}
                                                    </div>
                                                    <div>
                                                        <div className="font-bold text-text-primary">{doc.doctor_name}</div>
                                                        <div className="text-xs text-text-secondary">{doc.treatments} {t('common.cases')} • {t('billing.doctor_revenue.table.commission')} {doc.commission_percent || 0}%</div>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="p-4 font-bold text-text-secondary">{(doc.gross_cost || doc.revenue).toLocaleString()}</td>
                                            <td className="p-4 font-bold text-blue-600">{(doc.collected || 0).toLocaleString()}</td>
                                            <td className="p-4 font-bold text-orange-500">
                                                {(doc.patient_discount || 0) > 0 ? `-${doc.patient_discount.toLocaleString()}` : '-'}
                                            </td>
                                            <td className="p-4 font-bold text-rose-500">
                                                {labCost > 0 ? `-${labCost.toLocaleString()}` : '-'}
                                            </td>
                                            <td className="p-4 font-black text-emerald-600 bg-emerald-50 dark:bg-emerald-900/10 rounded-lg">{netRevenue.toLocaleString()}</td>
                                            <td className="p-4">
                                                <div className="font-black text-lg text-primary">
                                                    {totalDue.toLocaleString()}
                                                </div>
                                            </td>
                                            <td className="p-4">
                                                <Button variant="ghost" size="sm" onClick={() => openDetails(doc)}>
                                                    <User size={16} />
                                                </Button>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan="8">
                                        <EmptyState
                                            icon={Calculator}
                                            title={t('common.no_data')}
                                            description={t('billing.doctor_revenue.no_revenue')}
                                        />
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                )}
            </div>

            {detailsModalOpen && selectedDoctorData && (
                <DoctorRevenueDetails
                    doctor={selectedDoctorData}
                    startDate={startDate}
                    endDate={endDate}
                    onClose={() => setDetailsModalOpen(false)}
                    onUpdate={(doctorId, commission, salary) => {
                        setDoctors(prev => prev.map(d =>
                            d.doctor_id === doctorId
                                ? { ...d, commission_percent: commission, fixed_salary: salary }
                                : d
                        ));
                    }}
                />
            )}
        </Card>
    );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, DollarSign, Calendar, Save } from 'lucide-react';
import { Button, Input, Skeleton, Badge } from '@/shared/ui';
import { getDoctorDetails, updateStaffCompensation } from '@/api';
import toast from 'react-hot-toast';
import { useTranslation } from 'react-i18next';

export default function DoctorRevenueDetails({ doctor, startDate, endDate, onClose, onUpdate }) {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('treatments');
    const [details, setDetails] = useState(null);
    const [loading, setLoading] = useState(true);

    // Edit Form State
    const [commission, setCommission] = useState(0);
    const [salary, setSalary] = useState(0);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (doctor) {
            setCommission(doctor.commission_percent || 0);
            setSalary(doctor.fixed_salary || 0);
            loadDetails();
        }
    }, [doctor]);

    useEffect(() => {
        // Prevent background scrolling when open
        document.body.style.overflow = 'hidden';
        return () => { document.body.style.overflow = ''; }
    }, []);

    const loadDetails = async () => {
        setLoading(true);
        try {
            const res = await getDoctorDetails(doctor.doctor_id, startDate, endDate);
            setDetails(res.data);
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.load_fail'));
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            await updateStaffCompensation(doctor.doctor_id, commission, salary);
            toast.success(t('billing.alerts.save_success'));
            if (onUpdate) onUpdate(doctor.doctor_id, commission, salary);
            onClose();
        } catch (err) {
            toast.error(t('billing.alerts.save_fail'));
        } finally {
            setSaving(false);
        }
    };

    const calculateTotal = (netRevenue) => {
        const commValue = netRevenue * (commission / 100);
        return commValue + salary;
    };

    const netRevenue = details ? (
        (details.treatments?.reduce((sum, t) => sum + t.net, 0) || 0) -
        (details.lab_orders?.reduce((sum, l) => sum + l.cost, 0) || 0)
    ) : 0;

    return createPortal(
        <div className="fixed inset-0 z-[99999] flex items-center justify-center p-0 md:p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            {/* Main Card Container - Fixed Dimensions */}
            <div className="bg-white dark:bg-slate-900 w-full md:w-[95vw] md:max-w-6xl h-[100vh] md:h-[90vh] md:rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-slate-200 dark:border-slate-800 relative">

                {/* 1. Header (Fixed) */}
                <div className="flex justify-between items-center p-4 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 shrink-0">
                    <div>
                        <h2 className="text-xl font-black text-slate-800 dark:text-white flex items-center gap-2">
                            <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-lg">
                                {doctor.doctor_name.charAt(0)}
                            </div>
                            {doctor.doctor_name}
                            <Badge variant="outline" className="text-xs font-normal">
                                {new Date(startDate).toLocaleDateString()} - {new Date(endDate).toLocaleDateString()}
                            </Badge>
                        </h2>
                    </div>
                    <button onClick={onClose} className="p-2 bg-slate-100 hover:bg-slate-200 dark:bg-slate-800 dark:hover:bg-slate-700 rounded-full transition-colors">
                        <X size={24} className="text-slate-500" />
                    </button>
                </div>

                {/* 2. Tabs (Fixed) */}
                <div className="flex border-b border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 px-4 pt-4 gap-4 shrink-0">
                    <button
                        onClick={() => setActiveTab('treatments')}
                        className={`pb-3 px-4 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'treatments'
                            ? 'border-indigo-600 text-indigo-600'
                            : 'border-transparent text-slate-500 hover:text-slate-700'
                            }`}
                    >
                        <Calendar size={18} />
                        {t('billing.doctor_revenue.tabs.treatments')}
                    </button>
                    <button
                        onClick={() => setActiveTab('settings')}
                        className={`pb-3 px-4 text-sm font-bold flex items-center gap-2 border-b-2 transition-colors ${activeTab === 'settings'
                            ? 'border-indigo-600 text-indigo-600'
                            : 'border-transparent text-slate-500 hover:text-slate-700'
                            }`}
                    >
                        <DollarSign size={18} />
                        {t('billing.doctor_revenue.tabs.settings')}
                    </button>
                </div>

                {/* 3. Content Area (Scrollable) */}
                <div className="flex-1 overflow-y-auto bg-slate-50/30 dark:bg-black/20 p-6 relative">
                    {loading ? (
