export default function DentalChartV2() {
    const [activeTooth, setActiveTooth] = useState(null);
    const [selectedSegments, setSelectedSegments] = useState({});
    const [activeTool, setActiveTool] = useState('cursor');

    // Procedure History
    const [procedures, setProcedures] = useState([
        { tooth: 3, type: 'filling', label: 'حشو كمبوزيت', segments: ['Occlusal'], date: '2023-10-10', price: 450 },
        { tooth: 14, type: 'rct', label: 'علاج عصب', segments: [], date: '2023-09-01', isWholeTooth: true },
    ]);

    // Derived Status
    const getToothStatus = (toothId) => {
        const procs = procedures.filter(p => p.tooth === toothId);
        if (procs.some(p => p.type === 'extract')) return 'Missing';
        if (procs.some(p => p.type === 'crown')) return 'Crown';
        if (procs.some(p => p.type === 'rct')) return 'RCT';
        return 'Sound';
    };

    // --- INTERACTION LOGIC ---

    const handleToothClick = (toothId) => {
        if (activeTool === 'cursor') {
            setActiveTooth(toothId);
            return;
        }

        // TOOL ACTION: Whole Tooth (RCT, Crown, Extract)
        const tool = TOOLS.find(t => t.id === activeTool);
        if (tool.isWholeTooth) {
            applyProcedure(toothId, tool, []);
        } else if (tool.id === 'clear') {
            // Remove procedures for this tooth
            setProcedures(prev => prev.filter(p => p.tooth !== toothId));
        } else {
            // If tool is segment-based (Exam/Filling) but clicked on root/body, 
            // maybe just select the tooth? Or apply to all? 
            // Let's open panel for detail if ambiguous, or select tooth.
            setActiveTooth(toothId);
        }
    };

    const handleSegmentClick = (toothId, segment) => {
        if (activeTool === 'cursor') {
            setActiveTooth(toothId);
            setSelectedSegments(prev => {
                const current = prev[toothId] || [];
                const updated = current.includes(segment) ? current.filter(s => s !== segment) : [...current, segment];
                return { ...prev, [toothId]: updated };
            });
            return;
        }

        // TOOL ACTION: Segment Based (Filling)
        const tool = TOOLS.find(t => t.id === activeTool);
        if (!tool.isWholeTooth && tool.id !== 'clear') {
            applyProcedure(toothId, tool, [segment]);
        }
    };

    const applyProcedure = (toothId, tool, segments) => {
        const newProc = {
            tooth: toothId,
            type: tool.id,
            label: tool.label, // Simplified label
            code: tool.code,
            segments: segments,
            price: 0, // Should come from a pricelist lookup in real app
            isWholeTooth: tool.isWholeTooth,
            date: new Date().toISOString().split('T')[0]
        };

        // If whole tooth, maybe remove existing conflicting whole tooth procs?
        // e.g. cant be missing AND crown.
        setProcedures(prev => {
            let filtered = prev;
            if (tool.isWholeTooth) {
                // If adding Extract, remove Crowns/RCTs? Or keep history?
                // Usually keep history. But for visual "Current State", latest wins.
            }
            return [...filtered, newProc];
        });
    };

    const handleAddFromPanel = (data) => {
        setProcedures(prev => [...prev, data]);
        setSelectedSegments(prev => ({ ...prev, [data.tooth]: [] }));
    };

    return (
        <div className="flex h-screen bg-slate-50 overflow-hidden font-sans" dir="rtl">

            <div className="flex-1 flex flex-col relative">

                {/* 1. SMART TOOLBAR */}
                <div className="h-20 bg-white border-b border-slate-200 flex items-center px-4 justify-between shadow-[0_4px_12px_rgba(0,0,0,0.02)] z-30 shrink-0">
                    <div className="flex items-center gap-2 overflow-x-auto py-2 no-scrollbar">
                        {TOOLS.map(tool => (
                            <button
                                key={tool.id}
                                onClick={() => setActiveTool(tool.id)}
                                className={`
                                    flex flex-col items-center justify-center min-w-[4rem] h-14 rounded-xl transition-all duration-200 border
                                    ${activeTool === tool.id
                                        ? `${tool.color.includes('white') ? 'bg-slate-100' : tool.color} text-white border-transparent shadow-md scale-105`
                                        : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50 hover:border-slate-200'}
                                `}
                            >
                                <span className="text-xl mb-0.5">{tool.icon}</span>
                                <span className={`text-[10px] font-bold ${activeTool === tool.id ? 'text-white' : 'text-slate-500'}`}>{tool.label}</span>
                            </button>
                        ))}
                    </div>

                    {/* Mode Indicator */}
                    <div className="bg-slate-100 px-4 py-2 rounded-lg text-xs font-bold text-slate-500 border border-slate-200">
                        {activeTool === 'cursor' ? 'وضع التحديد (Selection Mode)' : `أداة نشطة: ${TOOLS.find(t => t.id === activeTool).label}`}
                    </div>
                </div>

                {/* 2. CHART AREA */}
                <div className={`flex-1 overflow-auto bg-slate-100/50 p-8 flex items-center justify-center relative cursor-${activeTool === 'cursor' ? 'default' : 'crosshair'}`}>

                    {/* Grid Background */}
                    <div className="absolute inset-0 opacity-[0.03]" style={{ backgroundImage: 'radial-gradient(#000 1px, transparent 1px)', backgroundSize: '20px 20px' }} />

                    <div className="bg-white/80 backdrop-blur-sm p-12 rounded-[2.5rem] shadow-xl border border-white min-w-[1000px] flex flex-col gap-10 relative z-10 transition-all">

                        {/* Upper Arch */}
                        <div className="flex justify-center gap-2">
                            {Array.from({ length: 16 }, (_, i) => i + 1).map(num => (
                                <SegmentedTooth
                                    key={num}
                                    number={num}
                                    activeTool={activeTool}
                                    isActive={activeTooth === num}
                                    status={getToothStatus(num)}
                                    procedures={procedures.filter(p => p.tooth === num)}
                                    selectedSegments={selectedSegments[num] || []}
                                    onToothClick={handleToothClick}
                                    onSegmentClick={handleSegmentClick}
                                />
                            ))}
                        </div>

                        {/* Lower Arch */}
                        <div className="flex justify-center gap-2 border-t-2 border-dashed border-slate-100 pt-10 relative">
                            <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-slate-100 text-slate-400 text-[10px] px-2 rounded-full font-bold">LOWER ARCH</span>
                            {Array.from({ length: 16 }, (_, i) => 32 - i).map(num => (
                                <SegmentedTooth
                                    key={num}
                                    number={num}
                                    activeTool={activeTool}
                                    isActive={activeTooth === num}
                                    status={getToothStatus(num)}
                                    procedures={procedures.filter(p => p.tooth === num)}
                                    selectedSegments={selectedSegments[num] || []}
                                    onToothClick={handleToothClick}
                                    onSegmentClick={handleSegmentClick}
                                />
                            ))}
                        </div>

                    </div>
                </div>
            </div>

            {/* 3. SIDE PANEL */}
            <div className={`transition-all duration-300 ${activeTooth ? 'w-96 translate-x-0 opacity-100' : 'w-0 translate-x-full opacity-0'} overflow-hidden shadow-2xl z-40 bg-white`}>
                {activeTooth && (
                    <DentalSidePanelV2
                        activeTooth={activeTooth}
                        procedures={procedures}
                        onAddProcedure={handleAddFromPanel}
                        chartSelectedSegments={selectedSegments[activeTooth] || []}
                    />
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import ToothSegmentMap from './ToothSegmentMap';
import { PROCEDURE_CATEGORIES, TOOTH_STATUS_OPTIONS } from './dentalData';

export default function DentalSidePanelV2({ activeTooth, procedures, onAddProcedure, chartSelectedSegments = [] }) {
    const [selectedSegments, setSelectedSegments] = useState([]);

    // UI State
    const [view, setView] = useState('ADD'); // ADD | HISTORY
    const [selectedCategory, setSelectedCategory] = useState('restorative');
    const [selectedProcedure, setSelectedProcedure] = useState(null);
    const [quickStatus, setQuickStatus] = useState(null); // For fast status updates

    // Form inputs
    const [price, setPrice] = useState(0);
    const [notes, setNotes] = useState('');

    // Sync Chart Selection
    useEffect(() => {
        if (chartSelectedSegments && chartSelectedSegments.length > 0) {
            setSelectedSegments(chartSelectedSegments);
        } else if (chartSelectedSegments.length === 0) {
            // Keep user selection if they are working on it, unless they clicked a different tooth
            setSelectedSegments([]);
        }
    }, [chartSelectedSegments, activeTooth]);

    if (!activeTooth) return <div className="p-6 text-center text-slate-400 font-medium">Select a tooth to begin</div>;

    const handleCategoryClick = (catId) => {
        setSelectedCategory(catId);
        setSelectedProcedure(null); // Reset procedure when category changes
    };

    const handleProcedureSelect = (proc) => {
        setSelectedProcedure(proc);
        setPrice(proc.price);
        // Auto-select segments if needed or whole tooth logic
        if (proc.isWholeTooth) {
            setSelectedSegments([]); // Clear segments for whole tooth
        }
    };

    const toggleSegment = (seg) => {
        if (selectedProcedure?.isWholeTooth) return; // Block segment picking for whole tooth procs
        setSelectedSegments(prev => prev.includes(seg) ? prev.filter(s => s !== seg) : [...prev, seg]);
    };

    const handleSubmit = () => {
        if (selectedProcedure) {
            onAddProcedure({
                tooth: activeTooth,
                type: selectedProcedure.id, // ID maps to internal logic (color etc)
                label: selectedProcedure.label,
                segments: selectedProcedure.isWholeTooth ? [] : selectedSegments,
                price,
                date: new Date().toISOString().split('T')[0],
                isWholeTooth: selectedProcedure.isWholeTooth
            });
            // Reset
            setNotes('');
            setView('HISTORY');
        }
    };

    const handleQuickStatus = (status) => {
        // Defines general status (missing, sound, etc.)
        // In a real app this might be a separate API call "updateToothStatus"
        // Here we add it as a "Status Change" procedure event or similar
        onAddProcedure({
            tooth: activeTooth,
            type: status.code.toLowerCase(), // e.g., missing
            label: `Marked as ${status.label}`,
            segments: [],
            price: 0,
            date: new Date().toISOString().split('T')[0],
            isStatusChange: true
        });
        setQuickStatus(status.id);
    };

    return (
        <div className="w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20 font-sans">
            {/* Header */}
            <div className="p-4 bg-slate-900 text-white shrink-0">
                <div className="flex justify-between items-center mb-2">
                    <h2 className="text-2xl font-bold">Tooth #{activeTooth}</h2>
                    <span className="text-xs bg-slate-700 px-2 py-1 rounded">Universal</span>
                </div>

                {/* Tabs */}
                <div className="flex gap-1 p-1 bg-slate-800 rounded-lg">
                    <button
                        onClick={() => setView('ADD')}
                        className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${view === 'ADD' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-400 hover:text-white'}`}
                    >
                        Treatment
                    </button>
                    <button
                        onClick={() => setView('HISTORY')}
                        className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${view === 'HISTORY' ? 'bg-blue-500 text-white shadow-sm' : 'text-slate-400 hover:text-white'}`}
                    >
                        History ({procedures.filter(p => p.tooth === activeTooth).length})
                    </button>
                </div>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto bg-slate-50">
                {view === 'ADD' && (
                    <div className="p-4 space-y-6">

                        {/* 1. Quick Status (Always visible on top) */}
                        <div className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
                            <h4 className="text-xs font-bold text-slate-400 uppercase mb-2 text-right">الحالة العامة</h4>
                            <div className="flex flex-wrap gap-2 justify-end">
                                {TOOTH_STATUS_OPTIONS.map(s => (
                                    <button
                                        key={s.id}
                                        onClick={() => handleQuickStatus(s)}
                                        className={`px-3 py-1 rounded-full text-[10px] font-bold transition-all border ${quickStatus === s.id ? 'bg-slate-800 text-white border-slate-800' : 'bg-slate-50 text-slate-600 border-slate-200 hover:border-slate-300'}`}
                                    >
                                        {s.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* 2. Categories */}
                        <div>
                            <h4 className="text-xs font-bold text-slate-400 uppercase mb-2 text-right">التصنيف</h4>
                            <div className="grid grid-cols-4 gap-1">
                                {PROCEDURE_CATEGORIES.map(cat => (
                                    <button
                                        key={cat.id}
                                        onClick={() => handleCategoryClick(cat.id)}
                                        className={`flex flex-col items-center justify-center p-2 rounded-xl transition-all border ${selectedCategory === cat.id ? 'bg-blue-50 border-blue-500 text-blue-700' : 'bg-white border-slate-200 text-slate-500 hover:bg-slate-100'}`}
                                    >
                                        <span className="text-xl mb-1">{cat.icon}</span>
                                        <span className="text-[9px] font-bold text-center leading-tight">{cat.label.split(' ')[0]}</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* 3. Procedures List */}
                        <div>
                            <h4 className="text-xs font-bold text-slate-400 uppercase mb-2 text-right">الإجراءات المتاحة</h4>
                            <div className="space-y-1">
                                {PROCEDURE_CATEGORIES.find(c => c.id === selectedCategory)?.items.map(proc => (
                                    <button
                                        key={proc.id}
                                        onClick={() => handleProcedureSelect(proc)}
                                        className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all text-right ${selectedProcedure?.id === proc.id ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-700 hover:border-blue-300'}`}
                                    >
                                        <span className="font-bold text-sm">{proc.label}</span>
                                        <span className={`text-xs ${selectedProcedure?.id === proc.id ? 'text-blue-200' : 'text-slate-400'}`}>{proc.price} LE</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* 4. Details Panel (Shows when procedure selected) */}
                        {selectedProcedure && (
                            <div className="animate-in slide-in-from-bottom-5 fade-in duration-300 bg-white border border-blue-100 rounded-xl p-4 shadow-lg ring-1 ring-blue-50">

                                {/* Segments (If required) */}
                                {selectedProcedure.requiresSegments && !selectedProcedure.isWholeTooth && (
                                    <div className="mb-4 text-center">
                                        <h5 className="text-xs font-bold text-slate-400 mb-2">تحديد الأسطح</h5>
                                        <ToothSegmentMap selectedSegments={selectedSegments} onToggleSegment={toggleSegment} />
                                    </div>
                                )}

                                <div className="flex gap-2">
                                    <div className="flex-1">
                                        <label className="text-[10px] font-bold text-slate-400 block mb-1">السعر النهائي</label>
                                        <input
                                            type="number"
                                            value={price}
                                            onChange={(e) => setPrice(e.target.value)}
                                            className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm font-bold"
                                        />
                                    </div>
                                    <button
                                        onClick={handleSubmit}
                                        className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-lg shadow-md transition-all active:scale-95"
                                    >
                                        Confirm
                                    </button>
                                </div>
                            </div>
                        )}

                    </div>
                )}

                {view === 'HISTORY' && (
                    <div className="p-4 space-y-2">
                        {procedures.filter(p => p.tooth === activeTooth).length === 0 && <div className="text-center text-slate-400 text-sm py-10">No history</div>}

                        {procedures.filter(p => p.tooth === activeTooth).map((proc, idx) => (
                            <div key={idx} className="bg-white p-3 rounded-xl border border-slate-200 shadow-sm flex justify-between items-center group">
                                <div dir="rtl">
                                    <div className="font-bold text-slate-800 text-sm">{proc.label}</div>
                                    <div className="text-[10px] text-slate-400">{proc.date} • {proc.segments?.join(', ')}</div>
                                </div>
                                <div className="text-right">
                                    <div className="font-mono text-xs font-bold text-blue-600">{proc.price}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

import React, { memo } from 'react';
import { ORGANIC_PATHS, getOrganicToothType } from './dentalPaths';

// LAYERED TOOTH COMPONENT (High Fidelity)
// 1. Root Layer: Handles RCT, Implants, Abscess
// 2. Crown Body Layer: Handles Crowns, Veneers, Missing
// 3. Surface Layer: Handles Fillings, Decay (On top of crown)

const SegmentedTooth = memo(({ 
    number, 
    procedures = [], 
    status = 'Sound',
    onSegmentClick,
    onToothClick,
    isActive,
    selectedSegments = [],
    activeTool = 'cursor' 
}) => {
    
    // Get specific paths for this tooth number
    const pathData = getOrganicToothType(number);
    if (!pathData) return null;

    const { isMirror } = pathData;
    const paths = pathData; // Structure is { Root: "...", CrownBox: {...} }

    // --- LOGIC: EXTRACT LAYERS FROM HISTORY ---
    
    // 1. Root Condition
    const rootProc = procedures.find(p => ['rct', 'implant', 'apicoectomy'].includes(p.type));
    const isRCT = rootProc?.type === 'rct';
    const isImplant = rootProc?.type === 'implant';

    // 2. Crown Condition (Whole Tooth Coverage)
    const crownProc = procedures.find(p => ['crown', 'bridge', 'veneer', 'extraction'].includes(p.type));
    const isCrown = crownProc?.type === 'crown';
    const isMissing = status === 'Missing' || crownProc?.type === 'extraction';

    // 3. Surfaces (Fillings/Decay)
    const getSurfaceColor = (segName) => {
        // A. Tool Interaction
        if (selectedSegments.includes(segName)) return 'fill-blue-400 animate-pulse'; 

        // B. Existing Procedures
        if (isMissing) return 'fill-transparent';

        const relevant = procedures.filter(p => !p.isWholeTooth && p.segments?.includes(segName));
        if (relevant.length === 0) return 'fill-transparent'; 
        
        const last = relevant[relevant.length - 1];
        if (last.type === 'filling') return 'fill-blue-500';
        if (last.type === 'decay') return 'fill-red-500';
        if (last.type === 'sealant') return 'fill-pink-300';
        
        return 'fill-transparent';
    };

    // --- STYLES ---

    // Root Fill
    const rootFill = isImplant ? 'fill-slate-200' : isRCT ? 'fill-red-100' : 'fill-white';
    
    // Crown Body Fill
    const crownFill = isMissing ? 'fill-slate-100 opacity-20' : isCrown ? 'fill-yellow-100' : 'fill-white';

    const containerClasses = `
        relative flex flex-col items-center justify-center p-1 rounded-xl transition-all duration-200
        ${isActive ? 'bg-blue-100/50 ring-2 ring-blue-500 shadow-lg scale-110 z-20' : 'hover:bg-slate-100/50'}
        ${activeTool !== 'cursor' ? 'cursor-crosshair' : 'cursor-pointer'}
        ${isMissing ? 'opacity-60' : ''}
    `;

    return (
        <div className={containerClasses} onClick={() => onToothClick(number)}>
            {/* Tooth Number */}
            <span className={`text-[10px] font-bold mb-1 leading-none ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>
                {number}
            </span>

            <svg 
                width="40" 
                height="70" 
                viewBox="0 0 100 150" 
                className={`overflow-visible drop-shadow-sm transition-transform ${isMirror ? '-scale-x-100' : ''}`} // MIRROR FLIP
            >
                {/* LAYER 1: ROOTS */}
                <g id="layer-roots">
                    <path 
                        d={paths.Root} 
                        className={`stroke-slate-400 stroke-[1.5] ${rootFill}`}
                    />
                    {isRCT && (
                        // Gutta Percha Lines
                        <path d={number <= 16 ? "M50,30 L50,85 M35,45 L35,80 M65,45 L65,80" : "M50,80 L50,140 M35,90 L35,135 M65,90 L65,135"} 
                              stroke="#ef4444" strokeWidth="2" fill="none" opacity="0.8" />
                    )}
                    {isImplant && (
                        // Implant Screw
                        <path d={number <= 16 ? "M50,10 L50,90" : "M50,60 L50,140"} 
                              stroke="#6366f1" strokeWidth="6" strokeDasharray="4 2" strokeLinecap="round" />
                    )}
                </g>

                {/* LAYER 2: CROWN BODY */}
                <g id="layer-crown-body">
                    {Object.values(paths.CrownBox).map((d, i) => (
                         <path key={i} d={d} className={`stroke-none ${crownFill}`} />
                    ))}
                    
                    {/* Visual Cues */}
                    {isCrown && (
                        <circle cx="70" cy={number <= 16 ? "110" : "30"} r="5" fill="white" opacity="0.6" />
                    )}
                </g>

                {/* LAYER 3: SURFACES */}
                <g id="layer-surfaces">
                    {Object.entries(paths.CrownBox).map(([seg, path]) => (
                        <path
                            key={seg}
                            d={path}
                            className={`
                                stroke-slate-300 stroke-[1] stroke-linejoin-round 
                                transition-colors duration-200 
                                ${getSurfaceColor(seg)} 
                                ${!isMissing ? 'hover:fill-blue-100 hover:opacity-70' : ''}
                            `}
                            onClick={(e) => {
                                e.stopPropagation();
                                if (!isMissing) onSegmentClick(number, seg);
                            }}
                        />
                    ))}
                </g>

                {/* LAYER 4: OVERLAYS */}
                {isMissing && (
                     <path d="M20,40 L80,120 M80,40 L20,120" stroke="#ef4444" strokeWidth="3" opacity="0.5" strokeLinecap="round" />
                )}

            </svg>
            
            {/* Status Dot */}
             {!isMissing && status !== 'Sound' && (
                <div className={`w-1.5 h-1.5 rounded-full mt-1 ${
                    status.includes('Decay') ? 'bg-red-500' :
                    status === 'Impacted' ? 'bg-purple-500' : 
                    'bg-slate-300'
                }`} />
             )}
        </div>
    );
});

export default SegmentedTooth;

// A generic molar map used for segment selection
// Segments: Occlusal (Center), Mesial, Distal, Buccal, Lingual
const SEGMENT_PATHS = {
    Occlusal: "M35,35 L65,35 L65,65 L35,65 Z", // Center square
    Buccal: "M35,35 L65,35 L80,10 L20,10 Z",   // Top trapezoid
    Lingual: "M35,65 L65,65 L80,90 L20,90 Z",  // Bottom trapezoid
    Mesial: "M35,35 L35,65 L10,80 L10,20 Z",   // Left trapezoid
    Distal: "M65,35 L65,65 L90,80 L90,20 Z"    // Right trapezoid
};

// Colors for conditions
const CONDITION_COLORS = {
    Healthy: 'fill-white',
    Decayed: 'fill-red-400',
    Filled: 'fill-blue-400',
    Crown: 'fill-green-400',
    Missing: 'fill-slate-800'
};

export default function ToothSegmentMap({ selectedSegments = [], onToggleSegment }) {
    // selectedSegments is an array of strings: ['Mesial', 'Occlusal']

    const renderSegment = (name, path) => {
        const isSelected = selectedSegments.includes(name);
        return (
            <path
                key={name}
                d={path}
                onClick={() => onToggleSegment(name)}
                className={`
                    cursor-pointer transition-colors duration-200 stroke-slate-300 stroke-1
                    ${isSelected ? 'fill-blue-600 hover:fill-blue-700' : 'fill-white hover:fill-slate-100'}
                `}
            />
        );
    };

    return (
        <div className="flex flex-col items-center">
            <svg width="100" height="100" viewBox="0 0 100 100" className="drop-shadow-md">
                {Object.entries(SEGMENT_PATHS).map(([name, path]) => renderSegment(name, path))}

                {/* Text Labels */}
                <text x="50" y="52" textAnchor="middle" className="text-[10px] fill-slate-400 pointer-events-none">O</text>
                <text x="50" y="25" textAnchor="middle" className="text-[10px] fill-slate-400 pointer-events-none">B</text>
