import React, { memo, useMemo } from 'react';
import { getOrganicToothType } from '../assets/dentalPaths';
import { PROCEDURE_TYPES, PROCEDURE_STATUS } from '../assets/dentalConstants';

/**
 * Advanced Tooth Component
 * Renders anatomical layers: Root -> Crown -> Procedures -> Status Overlay
 */
const AdvancedTooth = memo(({
    number,
    procedures = [],
    status = 'Healthy',
    onToothClick,
    isActive
}) => {

    // 1. Resolve Geometry
    const pathData = useMemo(() => getOrganicToothType(number), [number]);
    if (!pathData) return null;
    const { Root, CrownBox, isMirror } = pathData;

    // 2. Resolve Active Procedures derived from History
    // We categorize procedures to determine rendering layers

    const activeProcedures = useMemo(() =>
        procedures.filter(p => !p.removedAt && p.status !== PROCEDURE_STATUS.FAILED),
        [procedures]);

    const rootProcs = activeProcedures.filter(p => PROCEDURE_TYPES[p.type.toUpperCase()]?.isRoot);
    const crownProcs = activeProcedures.filter(p => PROCEDURE_TYPES[p.type.toUpperCase()]?.id === 'crown' || PROCEDURE_TYPES[p.type.toUpperCase()]?.id === 'veneer');
    const surfaceProcs = activeProcedures.filter(p => PROCEDURE_TYPES[p.type.toUpperCase()]?.isSurface);
    const extraction = activeProcedures.find(p => p.type === 'extraction');

    // 3. Determine Visual State
    const isMissing = status === 'Missing' || status === 'Extracted' || extraction;
    const isImplant = rootProcs.some(p => p.type === 'implant');
    const isRCT = rootProcs.some(p => p.type === 'rct');
    const hasCrown = crownProcs.length > 0;

    // --- RENDER HELPERS ---

    const getSurfaceColor = (segmentKey) => {
        // Find latest procedure on this segment
        const proc = surfaceProcs
            .filter(p => p.segments?.includes(segmentKey))
            .sort((a, b) => new Date(b.date) - new Date(a.date))[0]; // Latest wins

        if (proc) {
            const typeDef = PROCEDURE_TYPES[proc.type.toUpperCase()];
            return typeDef?.color || '#3b82f6';
        }
        return 'transparent'; // Show crown/enamel underneath
    };

    const rootFill = isImplant ? '#e0e7ff' : isRCT ? '#fee2e2' : '#ffffff';
    const crownFill = hasCrown ? '#dcfce7' : '#ffffff';

    return (
        <div
            onClick={() => onToothClick(number)}
            className={`
                relative flex flex-col items-center justify-center p-1 rounded-xl transition-all duration-200
                ${isActive ? 'bg-blue-50 ring-2 ring-blue-500 shadow-lg scale-110 z-30' : 'hover:bg-slate-50 cursor-pointer'}
                ${isMissing ? 'opacity-40 grayscale' : ''}
            `}
        >
            <span className={`text-[10px] font-bold mb-1 leading-none ${isActive ? 'text-blue-600' : 'text-slate-400'}`}>
                {number}
            </span>

            <svg
                width="40"
                height="70"
                viewBox="0 0 100 150"
                className={`overflow-visible drop-shadow-sm transition-transform ${isMirror ? '-scale-x-100' : ''}`}
            >
                {/* LAYER 1: ROOTS */}
                <g id="layer-roots">
                    <path
                        d={Root}
                        fill={rootFill}
                        stroke="#94a3b8"
                        strokeWidth="1.5"
                    />
                    {isRCT && (
                        // Gutta Percha visualization
                        <path
                            d={number <= 16 ? "M50,30 L50,85 M35,45 L35,80 M65,45 L65,80" : "M50,80 L50,140 M35,90 L35,135 M65,90 L65,135"}
                            stroke="#ef4444"
                            strokeWidth="2"
                            fill="none"
                            opacity="0.8"
                        />
                    )}
                    {isImplant && (
                        // Fixture visualization
                        <path
                            d={number <= 16 ? "M50,10 L50,90" : "M50,60 L50,140"}
                            stroke="#6366f1"
                            strokeWidth="6"
                            strokeDasharray="4 2"
                            strokeLinecap="round"
                        />
                    )}
                </g>

                {/* LAYER 2: CROWN BODY */}
                <g id="layer-crown">
                    {Object.values(CrownBox).map((d, i) => (
                        <path key={i} d={d} fill={crownFill} stroke="none" />
                    ))}

                    {hasCrown && (
                        <circle cx="70" cy={number <= 16 ? "110" : "30"} r="5" fill="#166534" opacity="0.2" />
                    )}
                </g>

                {/* LAYER 3: SURFACES (Interactive & Colored) */}
                <g id="layer-surfaces">
                    {Object.entries(CrownBox).map(([seg, path]) => {
                        const fill = getSurfaceColor(seg);
                        return (
                            <path
                                key={seg}
                                d={path}
                                fill={fill}
                                stroke={fill !== 'transparent' ? 'none' : '#cbd5e1'}
                                strokeWidth="1"
                                className="transition-colors duration-150"
                            />
                        );
                    })}
                </g>

                {/* LAYER 4: STATUS OVERLAYS */}
                {(isMissing || extraction) && (
                    <path d="M20,40 L80,120 M80,40 L20,120" stroke="#ef4444" strokeWidth="3" opacity="0.8" strokeLinecap="round" />
                )}

            </svg>

            {/* Status Dot for generic states */}
            {status === 'Impacted' && <div className="w-2 h-2 rounded-full bg-purple-500 mt-1" />}
        </div>
    );
});

export default AdvancedTooth;

import React, { useState } from 'react';
import { PROCEDURE_TYPES, PROCEDURE_STATUS, SEGMENTS } from '../assets/dentalConstants';

export default function SidePanel({ activeTooth, procedures, onAddProcedure }) {
    // Mode: VIEW | WIZARD
    const [mode, setMode] = useState('VIEW');

    // Wizard State
    const [wizStep, setWizStep] = useState(1);
    const [newProc, setNewProc] = useState({ type: null, segments: [], price: 0, notes: '' });

    if (!activeTooth) return <div className="w-full h-full flex items-center justify-center text-slate-400">Select a tooth</div>;

    const toothProcs = procedures.filter(p => p.tooth === activeTooth).sort((a, b) => new Date(b.date) - new Date(a.date));

    // --- WIZARD HANDLERS ---
    const startWizard = () => {
        setMode('WIZARD');
        setWizStep(1);
        setNewProc({ type: null, segments: [], price: 0, notes: '' });
    };

    const handleTypeSelect = (typeKey) => {
        const typeDef = PROCEDURE_TYPES[typeKey];
        setNewProc(prev => ({ ...prev, type: typeKey.toLowerCase(), price: 0 })); // Reset price or set default
        if (typeDef.isWholeTooth || typeDef.isRoot) {
            // Skip segment selection
            setWizStep(3);
        } else {
            setWizStep(2);
        }
    };

    const toggleSegment = (seg) => {
        setNewProc(prev => ({
            ...prev,
            segments: prev.segments.includes(seg)
                ? prev.segments.filter(s => s !== seg)
                : [...prev.segments, seg]
        }));
    };

    const commitProcedure = () => {
        onAddProcedure({
            ...newProc,
            tooth: activeTooth,
            status: PROCEDURE_STATUS.COMPLETED,
            date: new Date().toISOString()
        });
        setMode('VIEW');
    };

    return (
        <div className="w-96 bg-white flex flex-col h-full shadow-2xl border-l border-slate-100 font-sans">
            {/* HEADER */}
            <div className="p-6 bg-slate-900 text-white">
                <div className="flex justify-between items-baseline mb-2">
                    <h2 className="text-3xl font-bold">#{activeTooth}</h2>
                    <span className="opacity-50 text-sm">Universal System</span>
                </div>
                {/* Tooth Status Summary */}
                <div className="flex gap-2">
                    <span className="px-2 py-1 bg-slate-800 rounded text-xs">Status: Healthy</span>
                </div>
            </div>

            {/* CONTENT AREA */}
            <div className="flex-1 overflow-y-auto bg-slate-50 p-4">

                {/* MODE: VIEW TIMELINE */}
                {mode === 'VIEW' && (
                    <div className="space-y-6">
                        <div className="flex justify-between items-center">
                            <h3 className="font-bold text-slate-700">Timeline</h3>
                            <button
                                onClick={startWizard}
                                className="bg-blue-600 text-white px-3 py-1.5 rounded-lg text-sm font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition"
                            >
                                + Add Procedure
                            </button>
                        </div>

                        <div className="space-y-4 relative before:absolute before:inset-y-0 before:left-4 before:w-0.5 before:bg-slate-200">
                            {toothProcs.length === 0 && (
                                <p className="text-center text-slate-400 text-sm py-4 ml-8">No medical history</p>
                            )}

                            {toothProcs.map(proc => (
                                <div key={proc.id} className="relative pl-8">
                                    {/* Dot */}
                                    <div className={`absolute left-[13px] top-3 w-2 h-2 rounded-full ring-4 ring-slate-50 ${proc.status === 'completed' ? 'bg-green-500' : 'bg-slate-400'
                                        }`} />

                                    {/* Card */}
                                    <div className="bg-white p-3 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition">
                                        <div className="flex justify-between mb-1">
                                            <span className="font-bold text-slate-800">
                                                {PROCEDURE_TYPES[proc.type.toUpperCase()]?.label || proc.type}
                                            </span>
                                            <span className="text-xs text-slate-400 font-mono">
                                                {new Date(proc.date).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <div className="text-xs text-slate-500 mb-2">
                                            {proc.segments?.join(', ')}
                                        </div>
                                        {proc.notes && (
                                            <div className="bg-slate-50 p-2 rounded text-xs text-slate-600 mb-2">
                                                {proc.notes}
                                            </div>
                                        )}
                                        <div className="flex justify-end gap-2">
                                            <button className="text-[10px] text-red-400 hover:text-red-600 font-bold">Remove</button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* MODE: WIZARD STEP 1 (TYPE) */}
                {mode === 'WIZARD' && wizStep === 1 && (
                    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                        <button onClick={() => setMode('VIEW')} className="text-slate-400 text-xs mb-4">← Cancel</button>
                        <h3 className="font-bold text-lg mb-4">Select Procedure</h3>
                        <div className="grid grid-cols-2 gap-2">
                            {Object.entries(PROCEDURE_TYPES).map(([key, def]) => (
                                <button
                                    key={key}
                                    onClick={() => handleTypeSelect(key)}
                                    className="p-3 text-left bg-white border border-slate-200 rounded-xl hover:border-blue-500 hover:ring-1 hover:ring-blue-500 transition group"
                                >
                                    <div className="font-bold text-slate-700 group-hover:text-blue-600">{def.label}</div>
                                    <div className="text-[10px] text-slate-400 capitalize">{def.category}</div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}

                {/* MODE: WIZARD STEP 2 (SEGMENTS) */}
                {mode === 'WIZARD' && wizStep === 2 && (
                    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                        <button onClick={() => setWizStep(1)} className="text-slate-400 text-xs mb-4">← Back</button>
                        <h3 className="font-bold text-lg mb-4">Select Segments</h3>
                        <div className="flex flex-wrap gap-2 justify-center py-8">
                            {/* Mock Segment Selector Visual */}
                            <div className="relative w-32 h-32 bg-slate-100 rounded-full flex items-center justify-center">
                                {Object.values(SEGMENTS).map(seg => (
                                    <button
                                        key={seg}
                                        onClick={() => toggleSegment(seg)}
                                        className={`absolute w-10 h-10 rounded-full text-[10px] font-bold transition-all
                                            ${newProc.segments.includes(seg) ? 'bg-blue-600 text-white scale-110' : 'bg-white text-slate-500 shadow-sm hover:scale-105'}
                                            ${seg === 'Occlusal' ? 'inset-0 m-auto z-10' : ''}
                                            ${seg === 'Mesial' ? 'left-0 top-1/2 -translate-y-1/2' : ''}
                                            ${seg === 'Distal' ? 'right-0 top-1/2 -translate-y-1/2' : ''}
                                            ${seg === 'Buccal' ? 'top-0 left-1/2 -translate-x-1/2' : ''}
                                            ${seg === 'Lingual' ? 'bottom-0 left-1/2 -translate-x-1/2' : ''}
                                        `}
                                    >
                                        {seg[0]}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <button
                            onClick={() => setWizStep(3)}
                            disabled={newProc.segments.length === 0}
                            className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                        >
                            Next Step →
                        </button>
                    </div>
                )}

                {/* MODE: WIZARD STEP 3 (DETAILS) */}
                {mode === 'WIZARD' && wizStep === 3 && (
                    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
                        <button onClick={() => setWizStep(newProc.segments.length ? 2 : 1)} className="text-slate-400 text-xs mb-4">← Back</button>
                        <h3 className="font-bold text-lg mb-4">Procedure Details</h3>

                        <div className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 block mb-1">Notes</label>
                                <textarea
                                    className="w-full p-3 bg-white border border-slate-200 rounded-xl text-sm"
                                    rows={3}
                                    placeholder="Clinical notes..."
                                    value={newProc.notes}
                                    onChange={(e) => setNewProc(prev => ({ ...prev, notes: e.target.value }))}
                                />
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 block mb-1">Price</label>
                                <input
                                    type="number"
                                    className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold"
                                    value={newProc.price}
                                    onChange={(e) => setNewProc(prev => ({ ...prev, price: Number(e.target.value) }))}
                                />
                            </div>
                        </div>

                        <button
                            onClick={commitProcedure}
                            className="w-full mt-8 bg-green-500 hover:bg-green-600 text-white py-3 rounded-xl font-bold shadow-lg shadow-green-200 transition"
                        >
                            Confirm Procedure ✓
                        </button>
                    </div>
                )}

            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { X, Save, AlertCircle } from 'lucide-react';
import { createMaterial, updateMaterial } from '@/api/inventory';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { showToast } from '@/shared/ui/Toast';
import { useTranslation } from 'react-i18next';

const AddMaterialModal = ({ isOpen, onClose, initialData = null }) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const [formData, setFormData] = useState({
        name: '',
        type: 'NON_DIVISIBLE', // DIVISIBLE, NON_DIVISIBLE
        base_unit: 'Tablet',
        alert_threshold: 10,
        packaging_ratio: 1.0
    });

    useEffect(() => {
        if (isOpen && initialData) {
            setFormData({
                name: initialData.material_name || initialData.name,
                type: initialData.material_type || initialData.type || 'NON_DIVISIBLE',
                base_unit: initialData.unit || initialData.base_unit || 'Tablet',
                alert_threshold: initialData.alert_status === 'LOW' ? 10 : (initialData.alert_threshold || 5),
                packaging_ratio: initialData.packaging_ratio || 1.0,
                // standard_price removed
            });
        } else if (isOpen) {
            setFormData({
                name: '',
                type: 'NON_DIVISIBLE',
                base_unit: 'Tablet',
                alert_threshold: 10,
                packaging_ratio: 1.0
            });
        }
    }, [isOpen, initialData]);

    const mutation = useMutation({
        mutationFn: (data) => initialData ? updateMaterial(initialData.material_id, data) : createMaterial(data),
        onSuccess: () => {
            queryClient.invalidateQueries(['inventory-stock']);
            showToast('success', initialData ? t('inventory.materials.success_edit') : t('inventory.materials.success_add'));
            onClose();
        },
        onError: (error) => {
            showToast('error', (initialData ? t('inventory.materials.fail_edit') : t('inventory.materials.fail_add')) + (error.response?.data?.detail || error.message));
        }
    });

    if (!isOpen) return null;

    const handleSubmit = (e) => {
        e.preventDefault();
        mutation.mutate(formData);
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-surface w-full max-w-md rounded-2xl shadow-2xl border border-border overflow-hidden animate-in fade-in zoom-in duration-200">

                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-border bg-background">
                    <h2 className="text-lg font-bold">{initialData ? t('inventory.materials.modal_edit') : t('inventory.materials.modal_add')}</h2>
                    <button onClick={onClose} className="p-2 hover:bg-surface-hover rounded-full transition-colors">
                        <X size={20} />
                    </button>
                </div>

                {/* Form */}
