                                <option value="DIVISIBLE">{t('inventory.types.divisible')} (Liquids/Gels)</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.materials.unit_label')}</label>
                            <input
                                type="text"
