                        {/* Packaging Ratio */}
                        <div>
                            <label className="block text-sm font-medium text-text-secondary mb-1">
                                {formData.type === 'DIVISIBLE' ? t('inventory.materials.packaging_ratio_divisible') : t('inventory.materials.packaging_ratio_indivisible')}
                            </label>
                            <input
                                type="number"
                                step="0.1"
                                min="0.1"
                                value={formData.packaging_ratio}
                                onChange={e => setFormData({ ...formData, packaging_ratio: parseFloat(e.target.value) })}
                                className="w-full px-4 py-2 rounded-lg border border-border bg-background"
                                placeholder={formData.type === 'DIVISIBLE' ? t('inventory.materials.ratio_placeholder_divisible') : t('inventory.materials.ratio_placeholder_indivisible')}
                            />
                        </div>
                    </div>

                    {/* Info Alert */}
                    <div className="bg-blue-50 text-blue-700 p-3 rounded-lg text-xs flex items-start gap-2">
                        <AlertCircle size={16} className="shrink-0 mt-0.5" />
                        <p>
                            <strong>{formData.type === 'DIVISIBLE' ? t('inventory.materials.info_divisible_label') : t('inventory.materials.info_indivisible_label')}</strong>
                            {formData.type === 'DIVISIBLE'
                                ? t('inventory.materials.info_divisible_desc')
                                : t('inventory.materials.info_indivisible_desc')}
                        </p>
                    </div>

                    {/* Actions */}
                    <div className="pt-4 flex justify-end gap-3 border-t border-border">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 rounded-lg font-medium text-text-secondary hover:bg-surface-hover"
                        >
                            {t('common.cancel')}
                        </button>
                        <button
                            type="submit"
                            disabled={mutation.isPending}
                            className="flex items-center gap-2 px-6 py-2 bg-primary text-white rounded-lg font-bold hover:bg-primary-600 disabled:opacity-50 transition-all shadow-lg shadow-primary/20"
                        >
                            {mutation.isPending ? t('inventory.materials.saving') : (
                                <>
                                    <Save size={18} />
                                    <span>{initialData ? t('inventory.materials.save_changes') : t('inventory.materials.save_new')}</span>
                                </>
                            )}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AddMaterialModal;

import React, { useState } from 'react';
import { X, ArrowDownLeft, Calendar, Plus } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getMaterials, getWarehouses, receiveStock } from '@/api/inventory';
import { showToast } from '@/shared/ui/Toast';
import AddWarehouseModal from './components/AddWarehouseModal';
import { useTranslation } from 'react-i18next';

const ReceiveStockModal = ({ isOpen, onClose }) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const [isAddWarehouseOpen, setIsAddWarehouseOpen] = useState(false);

    // Data Fetching
    const { data: materials } = useQuery({ queryKey: ['inventory-materials'], queryFn: async () => (await getMaterials()).data });
    const { data: warehouses } = useQuery({ queryKey: ['inventory-warehouses'], queryFn: async () => (await getWarehouses()).data });

    // Helper to get today's date in YYYY-MM-DD format
    const getToday = () => new Date().toISOString().split('T')[0];

    const [formData, setFormData] = useState({
        material_id: '',
        warehouse_id: '',
        quantity: 1,
        batch_number: '',
        expiry_date: '',
        supplier: '',
        package_price: 0
    });

    const mutation = useMutation({
        mutationFn: (data) => {
            // Logic: Convert YYYY-MM to YYYY-MM-{LastDay}
            let finalExpiry = data.expiry_date;
            if (data.expiry_date && data.expiry_date.length === 7) {
                // It's YYYY-MM
                const [y, m] = data.expiry_date.split('-').map(Number);
                const lastDay = new Date(y, m, 0).getDate(); // Day 0 of next month is last day of this month
                finalExpiry = `${y}-${String(m).padStart(2, '0')}-${lastDay}`;
            }

            return receiveStock({
                material_id: parseInt(data.material_id),
                warehouse_id: parseInt(data.warehouse_id),
                quantity: parseFloat(data.quantity),
                batch: {
                    // Auto-generate hidden batch number based on Expiry Date
                    // Format: EXP-YYMMDD-{Random4Digit}
                    batch_number: `EXP-${finalExpiry.replace(/-/g, '')}-${Math.floor(1000 + Math.random() * 9000)}`,
                    expiry_date: finalExpiry,
                    supplier: data.supplier,
                    cost_per_unit: parseFloat(data.cost_per_unit)
                }
            });
        },
        onSuccess: () => {
            queryClient.invalidateQueries(['inventory-stock']);
            showToast('success', t('inventory.receive.success'));
            onClose();
            // Reset crucial fields
            setFormData(prev => ({
                ...prev,
                batch_number: '',
                quantity: 1
            }));
        },
        onError: (error) => {
            showToast('error', t('inventory.receive.fail') + (error.response?.data?.detail || error.message));
        }
    });

    if (!isOpen) return null;

    const handleSubmit = (e) => {
        e.preventDefault();
        if (!formData.material_id || !formData.warehouse_id) {
            showToast('error', t('inventory.receive.validation_error'));
            return;
        }

        // Calculate Cost Per Unit derived from Package Price
        const selectedMat = materials?.find(m => m.id === parseInt(formData.material_id));
        const ratio = selectedMat?.packaging_ratio || 1.0;
        const finalCostPerUnit = (parseFloat(formData.package_price) || 0) / ratio;

        mutation.mutate({
            ...formData,
            cost_per_unit: finalCostPerUnit
        });
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-surface w-full max-w-2xl rounded-2xl shadow-2xl border border-border overflow-hidden animate-in fade-in zoom-in duration-200">

                {/* Header */}
                <div className="flex items-center justify-between p-4 border-b border-border bg-background">
                    <h2 className="text-lg font-bold flex items-center gap-2">
                        <ArrowDownLeft className="text-secondary" />
                        {t('inventory.receive.title')}
                    </h2>
                    <button onClick={onClose} className="p-2 hover:bg-surface-hover rounded-full transition-colors">
                        <X size={20} />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">

                    {/* Material Selection */}
                    <div className="col-span-2">
                        <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.receive.select_material')}</label>
                        <select
                            required
                            value={formData.material_id}
                            onChange={e => {
                                const val = e.target.value;
                                const selectedMat = materials?.find(m => m.id === parseInt(val));
                                setFormData({
                                    ...formData,
                                    material_id: val,
                                    package_price: selectedMat?.standard_price || 0
                                });
                            }}
                            className="w-full px-4 py-2 rounded-lg border border-border bg-background focus:ring-2 focus:ring-secondary/20"
                        >
                            <option value="">{t('inventory.receive.select_placeholder_material')}</option>
                            {materials?.map(m => (
                                <option key={m.id} value={m.id}>{m.name} ({m.base_unit})</option>
                            ))}
                        </select>
                    </div>

                    {/* Warehouse Selection */}
                    <div>
                        <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.receive.select_warehouse')}</label>
                        <div className="flex gap-2">
                            <select
                                required
                                value={formData.warehouse_id}
                                onChange={e => setFormData({ ...formData, warehouse_id: e.target.value })}
                                className="w-full px-4 py-2 rounded-lg border border-border bg-background focus:ring-2 focus:ring-secondary/20"
                            >
                                <option value="">{t('inventory.receive.select_placeholder_warehouse')}</option>
                                {warehouses?.map(w => (
                                    <option key={w.id} value={w.id}>{w.name} ({w.type})</option>
                                ))}
                            </select>
                            <button
                                type="button"
                                onClick={() => setIsAddWarehouseOpen(true)}
                                className="p-2 bg-primary/10 text-primary rounded-lg hover:bg-primary/20 transition-colors"
                                title="إضافة مخزن جديد"
                            >
                                <Plus size={20} />
                            </button>
                        </div>
                    </div>

                    {/* Quantity */}
                    <div>
                        <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.receive.quantity')}</label>
                        <input
                            type="number"
                            min="1"
                            step="any"
                            required
                            value={formData.quantity}
                            onChange={e => setFormData({ ...formData, quantity: e.target.value })}
                            className="w-full px-4 py-2 rounded-lg border border-border bg-background font-mono"
                        />
                    </div>

                    <div className="col-span-2 border-t border-border my-2"></div>

                    {/* Batch Details Group */}
                    <div>
                        <label className="block text-sm font-medium text-text-secondary mb-1">
                            {t('inventory.receive.expiry_date')}
                        </label>
                        <div className="relative">
                            <input
                                type="month"
                                required
                                min={new Date().toISOString().slice(0, 7)}
                                value={formData.expiry_date ? formData.expiry_date.slice(0, 7) : ''}
                                onChange={e => {
                                    setFormData({ ...formData, expiry_date: e.target.value });
                                }}
                                className="w-full px-4 py-2 rounded-lg border border-border bg-background ltr-text"
                                style={{ direction: 'ltr' }}
                            />
                            <Calendar className="absolute right-3 top-1/2 -translate-y-1/2 text-text-secondary pointer-events-none" size={16} />
                        </div>
                        <p className="text-xs text-slate-400 mt-1">{t('inventory.receive.expiry_note')}</p>
                    </div>

                    {/* PACKAGE PRICE INPUT */}
                    <div>
                        <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.receive.package_price')}</label>
                        <input
                            type="number"
                            min="0"
                            step="0.01"
                            value={formData.package_price}
                            onChange={e => setFormData({ ...formData, package_price: e.target.value })}
                            className="w-full px-4 py-2 rounded-lg border border-border bg-background"
                            placeholder="0.00"
                        />
                        <p className="text-[10px] text-text-secondary mt-1">
                            {t('inventory.receive.price_note')}
                        </p>
                    </div>

                    {/* Supplier - Full Width */}
                    <div className="col-span-2">
                        <label className="block text-sm font-medium text-text-secondary mb-1">{t('inventory.receive.supplier')}</label>
                        <input
                            type="text"
                            value={formData.supplier}
                            onChange={e => setFormData({ ...formData, supplier: e.target.value })}
                            className="w-full px-4 py-2 rounded-lg border border-border bg-background"
                            placeholder={t('inventory.receive.supplier_placeholder')}
                        />
                    </div>

                    {/* Actions */}
                    <div className="col-span-2 pt-4 flex justify-end gap-3 mt-4 border-t border-border">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 rounded-lg font-medium text-text-secondary hover:bg-surface-hover"
                        >
                            {t('common.cancel')}
                        </button>
                        <button
                            type="submit"
                            disabled={mutation.isPending}
                            className="flex items-center gap-2 px-8 py-2 bg-secondary text-white rounded-lg font-bold hover:bg-secondary-600 disabled:opacity-50 transition-all shadow-lg shadow-secondary/20"
                        >
                            {mutation.isPending ? t('inventory.receive.receiving') : (
                                <>
                                    <ArrowDownLeft size={18} />
                                    <span>{t('inventory.receive.confirm')}</span>
                                </>
                            )}
                        </button>
                    </div>
                </form>

                {/* Nested Modals */}
                <AddWarehouseModal
                    isOpen={isAddWarehouseOpen}
                    onClose={() => setIsAddWarehouseOpen(false)}
                    onSuccess={(newWh) => setFormData(prev => ({ ...prev, warehouse_id: newWh.id }))}
                />
            </div>
        </div>
    );
};

export default ReceiveStockModal;

import React, { useState, useMemo } from 'react';
import {
    Search, Plus, Package, ArrowDownLeft, Brain, Play, Square, AlertCircle, Trash2, Edit
} from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getStockSummary, getActiveSessions, deleteMaterial } from '@/api/inventory';
import LoadingSpinner from '@/shared/ui/LoadingSpinner';
import { useTranslation } from 'react-i18next';

import SmartLearningModal from './components/SmartLearningModal';
import TrackSessionModal from './components/TrackSessionModal';
import MaterialDetailsModal from './components/MaterialDetailsModal';

const StockList = ({ onAddMaterial, onReceiveStock, onEditMaterial }) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const [searchQuery, setSearchQuery] = useState('');
    const [filter, setFilter] = useState('ALL');
    const [smartMaterial, setSmartMaterial] = useState(null);
    const [selectedMaterial, setSelectedMaterial] = useState(null); // For Details Modal
    const [sessionModal, setSessionModal] = useState({ open: false, mode: 'OPEN', material: null, session: null });

    const { data: stockItems, isLoading, error } = useQuery({
        queryKey: ['inventory-stock'],
        queryFn: async () => {
            const res = await getStockSummary();
            return Array.isArray(res.data) ? res.data : [];
        }
    });

    const { data: activeSessions } = useQuery({
        queryKey: ['active-sessions'],
        queryFn: async () => {
            const res = await getActiveSessions();
            return Array.isArray(res.data) ? res.data : [];
        },
        refetchInterval: 30000 // Refresh every 30s
    });

    const deleteMutation = useMutation({
        mutationFn: deleteMaterial,
        onSuccess: () => {
            queryClient.invalidateQueries(['inventory-stock']);
            alert(t('inventory.messages.delete_success'));
        },
        onError: (err) => {
            console.error(err);
            const msg = err.response?.data?.detail
                || err.response?.data?.error?.message
                || t('inventory.messages.delete_fail');
            alert(msg);
        }
    });

    // Map material_id -> Active Session (just take first one for MVP, or indicate count)
    const activeSessionsMap = useMemo(() => {
        const map = {};
        if (activeSessions) {
            const safeSessions = Array.isArray(activeSessions) ? activeSessions : [];
            safeSessions.forEach(sess => {
                // Fix: stock_item is nested with batch
                const matId = sess.stock_item?.batch?.material_id;
                if (matId) {
                    if (!map[matId]) map[matId] = [];
                    map[matId].push(sess);
                }
            });
        }
        return map;
    }, [activeSessions]);

    const filteredItems = (stockItems || [])?.filter(item => {
        const matchesSearch = item.material_name.toLowerCase().includes(searchQuery.toLowerCase());
        if (filter === 'ALL') return matchesSearch;
        return matchesSearch && item.alert_status === filter;
    });

    const handleOpenSession = (item) => {
        setSessionModal({
            open: true,
            mode: 'OPEN',
            material: { id: item.material_id, name: item.material_name, unit: item.unit },
            session: null
        });
    };

    const handleCloseSession = (session) => {
        setSessionModal({
            open: true,
            mode: 'CLOSE',
            material: null,
            session: session
        });
    };

    const handleDelete = (id, name) => {
        if (window.confirm(t('inventory.messages.delete_confirm', { name }))) {
            deleteMutation.mutate(id);
        }
    };

    if (isLoading) return <LoadingSpinner />;
    if (error) return <div className="text-red-500 text-center p-4">حدث خطأ في تحميل البيانات</div>;

    return (
        <div className="space-y-4">
            {/* Header Actions */}
            <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-surface p-4 rounded-xl shadow-sm border border-border">
                <div className="relative w-full md:w-96">
                    <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-text-secondary" size={20} />
                    <input
                        type="text"
                        placeholder={t('inventory.actions.search_placeholder')}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pr-10 pl-4 py-2 rounded-lg border border-border bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all"
                    />
                </div>

                <div className="flex gap-2 w-full md:w-auto">
                    <select
                        value={filter}
                        onChange={(e) => setFilter(e.target.value)}
                        className="px-4 py-2 rounded-lg border border-border bg-background focus:ring-2 focus:ring-primary/20"
                    >
                        <option value="ALL">{t('inventory.filters.all')}</option>
                        <option value="LOW">{t('inventory.filters.low')}</option>
                        <option value="CRITICAL">{t('inventory.filters.critical')}</option>
                    </select>

                    <button
                        onClick={onReceiveStock}
                        className="flex items-center gap-2 px-4 py-2 bg-secondary/10 text-secondary hover:bg-secondary/20 rounded-lg font-bold transition-colors"
                    >
                        <ArrowDownLeft size={18} />
                        <span>{t('inventory.actions.receive_stock')}</span>
                    </button>

                    <button
                        onClick={onAddMaterial}
                        className="flex items-center gap-2 px-4 py-2 bg-primary text-white hover:bg-primary-600 rounded-lg font-bold transition-colors shadow-lg shadow-primary/20"
                    >
                        <Plus size={18} />
                        <span>{t('inventory.actions.new_material')}</span>
                    </button>
                </div>
            </div>

            {/* Table */}
            <div className="bg-surface rounded-xl shadow-sm border border-border overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-right">
                        <thead className="bg-background border-b border-border">
                            <tr>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.material')}</th>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.type')}</th>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.standard_price')}</th>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.current_stock')}</th>
                                {/* Batches column removed */}
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.status')}</th>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.sessions')}</th>
                                <th className="px-6 py-4 text-sm font-bold text-text-secondary">{t('inventory.table.actions')}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {filteredItems?.length === 0 ? (
                                <tr>
                                    <td colSpan="8" className="px-6 py-12 text-center text-text-secondary">
                                        <Package size={48} className="mx-auto mb-2 opacity-20" />
                                        <p>{t('inventory.table.empty')}</p>
                                    </td>
                                </tr>
                            ) : (
                                filteredItems?.map((item) => {
                                    const sessions = activeSessionsMap[item.material_id] || [];
                                    const hasActiveSession = sessions.length > 0;

                                    return (
                                        <tr key={item.material_id} className="hover:bg-surface-hover transition-colors group">
                                            <td
                                                onClick={() => setSelectedMaterial(item)}
                                                className="px-6 py-4 font-bold text-text-primary cursor-pointer hover:text-primary transition-colors underline decoration-dotted decoration-text-secondary/30 hover:decoration-primary"
                                                title={t('inventory.table.details_tooltip')}
                                            >
                                                {item.material_name}
                                            </td>
                                            <td className="px-6 py-4 text-sm text-text-secondary">
                                                {item.material_type === 'DIVISIBLE' ? t('inventory.types.divisible') : t('inventory.types.indivisible')}
                                            </td>
                                            <td className="px-6 py-4 text-sm font-mono text-text-primary dir-ltr text-right">
                                                {item.standard_price?.toFixed(2) || '0.00'}
                                            </td>
                                            <td className="px-6 py-4 font-mono font-medium dir-ltr text-right">
                                                {item.packaging_ratio > 1 ? (
                                                    <div>
                                                        <span className="text-lg font-bold text-primary">
                                                            {Math.floor(item.total_quantity / item.packaging_ratio)}
                                                        </span>
                                                        <span className="text-xs text-text-secondary mx-1">{t('inventory.types.package')}</span>
                                                        <span className="block text-[10px] text-text-secondary opacity-70">
                                                            ({item.total_quantity} {item.unit})
                                                        </span>
                                                    </div>
                                                ) : (
                                                    <span>
                                                        {item.total_quantity} <span className="text-xs text-text-secondary">{item.unit}</span>
                                                    </span>
                                                )}
                                            </td>
                                            {/* Batches cell removed */}

                                            {/* Status */}
                                            <td className="px-6 py-4">
                                                {/* Existing alert logic can be simplified or kept */}
                                                {item.alert_status === 'OK' ? (
                                                    <span className="text-green-600 text-xs font-bold px-2 py-1 bg-green-100 rounded-full">{t('inventory.status.available')}</span>
                                                ) : (
                                                    <span className="text-amber-600 text-xs font-bold px-2 py-1 bg-amber-100 rounded-full">{t('inventory.status.low')}</span>
                                                )}
                                            </td>

                                            {/* Active Sessions Control */}
                                            <td className="px-6 py-4">
                                                <div className="flex gap-2">
                                                    {hasActiveSession ? (
                                                        // Case: Session Active -> Show Stop Button (Red)
                                                        <button
                                                            onClick={() => handleCloseSession(sessions[0])}
                                                            className="relative p-2 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg animate-pulse transition-colors"
                                                            title={sessions.length > 1 ? t('inventory.messages.open_packages_tooltip', { count: sessions.length }) : t('inventory.actions.close_package')}
                                                        >
                                                            <Square size={18} />
                                                            {sessions.length > 1 && (
                                                                <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] text-white">
                                                                    {sessions.length}
                                                                </span>
                                                            )}
                                                        </button>
                                                    ) : (
                                                        // Case: No Session -> Show Start Button (Green)
                                                        <button
                                                            onClick={() => handleOpenSession(item)}
                                                            className="p-2 bg-green-50 text-green-600 hover:bg-green-100 rounded-lg transition-colors"
                                                            title={t('inventory.actions.open_package')}
                                                        >
                                                            <Play size={18} />
                                                        </button>
                                                    )}
                                                </div>
                                            </td>

                                            {/* Smart Config & Actions */}
                                            <td className="px-6 py-4">
                                                <div className="flex gap-2">
                                                    {item.material_type === 'DIVISIBLE' && (
                                                        <button
                                                            onClick={() => setSmartMaterial({ id: item.material_id, name: item.material_name, unit: item.unit })}
                                                            title={t('inventory.actions.smart_settings')}
                                                            className="p-2 text-primary bg-primary/5 hover:bg-primary/20 rounded-lg transition-colors"
                                                        >
                                                            <Brain size={18} />
                                                        </button>
                                                    )}

                                                    <button
                                                        onClick={() => onEditMaterial && onEditMaterial(item)}
                                                        className="p-2 text-indigo-400 hover:bg-indigo-50 hover:text-indigo-600 rounded-lg transition-colors"
                                                        title={t('inventory.actions.edit')}
                                                    >
                                                        <Edit size={18} />
                                                    </button>

                                                    <button
                                                        onClick={() => handleDelete(item.material_id, item.material_name)}
                                                        className="p-2 text-red-400 hover:bg-red-50 hover:text-red-600 rounded-lg transition-colors"
                                                        title={t('inventory.actions.delete')}
                                                    >
                                                        <Trash2 size={18} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    )
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <SmartLearningModal
                isOpen={!!smartMaterial}
                onClose={() => setSmartMaterial(null)}
                material={smartMaterial}
            />

            <MaterialDetailsModal
                isOpen={!!selectedMaterial}
                onClose={() => setSelectedMaterial(null)}
                material={selectedMaterial}
                activeSessions={activeSessions || []}
            />

            <TrackSessionModal
                isOpen={sessionModal.open}
                onClose={() => setSessionModal(prev => ({ ...prev, open: false }))}
                mode={sessionModal.mode}
                material={sessionModal.material}
                session={sessionModal.session}
            />
        </div>
    );
};

export default StockList;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getWarehouses, deleteWarehouse } from '@/api/inventory';
import { Warehouse, Trash2, MapPin, Plus } from 'lucide-react';
import LoadingSpinner from '@/shared/ui/LoadingSpinner';
import { showToast } from '@/shared/ui/Toast';
import AddWarehouseModal from './components/AddWarehouseModal';
import WarehouseDetailsModal from './components/WarehouseDetailsModal';
import { useTranslation } from 'react-i18next';

const WarehouseList = () => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [selectedWarehouse, setSelectedWarehouse] = useState(null);

    const { data: warehouses, isLoading } = useQuery({
        queryKey: ['warehouses'],
        queryFn: async () => {
            const res = await getWarehouses();
            return Array.isArray(res.data) ? res.data : [];
        }
    });

    const deleteMutation = useMutation({
        mutationFn: deleteWarehouse,
        onSuccess: () => {
            queryClient.invalidateQueries(['warehouses']);
            showToast('success', t('inventory.warehouses.delete_success'));
        },
        onError: (err) => {
            showToast('error', err.response?.data?.detail || t('inventory.warehouses.delete_fail'));
        }
    });

    const handleDelete = (e, id, name) => {
        e.stopPropagation(); // Prevent opening modal
        if (window.confirm(t('inventory.warehouses.delete_confirm', { name }))) {
            deleteMutation.mutate(id);
        }
    };

    if (isLoading) return <LoadingSpinner />;

    return (
        <div className="space-y-6 animate-in fade-in duration-300">
            {/* Header Actions */}
            <div className="flex justify-end">
                <button
                    onClick={() => setIsAddOpen(true)}
                    className="flex items-center gap-2 bg-primary text-white px-4 py-2 rounded-lg hover:bg-primary-hover transition-colors shadow-sm font-medium"
                >
                    <Plus size={20} />
                    {t('inventory.warehouses.add_button')}
                </button>
            </div>

            {/* Grid */}
            {!warehouses || warehouses.length === 0 ? (
                <div className="text-center py-12 text-gray-500 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                    <Warehouse size={48} className="mx-auto mb-3 opacity-20" />
                    <p>{t('inventory.warehouses.empty_desc')}</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {warehouses.map((wh) => (
                        <div
                            key={wh.id}
                            onClick={() => setSelectedWarehouse(wh)}
                            className="bg-white p-5 rounded-xl border border-slate-200 hover:border-primary/50 hover:shadow-md transition-all group relative cursor-pointer"
                        >
                            <div className="flex items-start justify-between">
                                <div className="flex items-center gap-3">
                                    <div className="p-3 bg-blue-50 text-blue-600 rounded-lg group-hover:bg-blue-100 transition-colors">
                                        <Warehouse size={24} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-lg text-slate-800">{wh.name}</h3>
                                        {wh.location && (
                                            <div className="flex items-center gap-1 text-sm text-slate-500 mt-1">
                                                <MapPin size={14} />
                                                {wh.location}
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <button
                                    onClick={(e) => handleDelete(e, wh.id, wh.name)}
                                    className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors opacity-0 group-hover:opacity-100"
                                    title="حذف المخزن"
                                >
                                    <Trash2 size={18} />
                                </button>
                            </div>

                            {wh.description && (
                                <p className="text-sm text-slate-500 mt-4 line-clamp-2">
                                    {wh.description}
                                </p>
                            )}

                            <div className="mt-4 pt-4 border-t border-slate-100 flex justify-end">
                                <span className="text-xs font-semibold text-primary">{t('inventory.warehouses.click_to_view')}</span>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            <AddWarehouseModal
                isOpen={isAddOpen}
                onClose={() => setIsAddOpen(false)}
            />

            <WarehouseDetailsModal
                isOpen={!!selectedWarehouse}
                warehouse={selectedWarehouse}
                onClose={() => setSelectedWarehouse(null)}
            />
        </div>
    );
};

