import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Modal, Button, LoadingSpinner, Alert } from '@/shared/ui';
import { SmartMaterialRow } from './SmartMaterialRow';
import api from '@/api';
import { toast } from 'react-hot-toast';
import { Plus, CheckCircle, AlertTriangle } from 'lucide-react';
import { cn } from '@/utils/cn';

export function EnhancedMaterialConsumption({
    procedure,
    patientAge,
    availableMaterials = [],
    initialMaterials = [], // [{ material_id, quantity, unit }]
    mode = 'smart', // 'smart' | 'manual'
    onSave,
    onClose,
    isOpen
}) {
    const queryClient = useQueryClient();

    // Track if we've initialized for this modal session
    const hasInitializedRef = useRef(false);
    const prevIsOpenRef = useRef(false);

    // Initialize with empty - will be populated by useEffect
    const [materials, setMaterials] = useState([]);

    const [pickerOpen, setPickerOpen] = useState(false);

    // Auto-open picker for manual mode
    useEffect(() => {
        if (isOpen && mode === 'manual') {
            setPickerOpen(true);
        } else {
            setPickerOpen(false);
        }
    }, [isOpen, mode]);

    // CRITICAL FIX: Only sync from props when modal OPENS (transition from closed to open)
    // Never overwrite while modal is already open
    useEffect(() => {
        const wasOpen = prevIsOpenRef.current;
        prevIsOpenRef.current = isOpen;

        // Case 1: Modal just opened (transition from closed to open)
        if (isOpen && !wasOpen) {
            hasInitializedRef.current = false; // Reset for new session
        }

        // Case 2: Modal closed - reset for next time
        if (!isOpen && wasOpen) {
            hasInitializedRef.current = false;
            setMaterials([]);
            return;
        }

        // Case 3: Modal is open and we have data to initialize with
        if (isOpen && !hasInitializedRef.current && availableMaterials.length > 0) {
            const mapped = initialMaterials.map(m => {
                const matInfo = availableMaterials.find(am => am.id === parseInt(m.material_id)) || {};
                return {
                    materialId: parseInt(m.material_id),
                    materialName: matInfo.name || 'Unknown',
                    quantity: parseFloat(m.quantity),
                    unit: m.unit || matInfo.base_unit,
                    suggested: false
                };
            });
            setMaterials(mapped);
            hasInitializedRef.current = true; // Mark as initialized - NO MORE OVERWRITES
            console.log('[EnhancedMaterialConsumption] Initialized materials:', mapped);
        }
    }, [isOpen, availableMaterials, initialMaterials]);

    // Pre-flight Stock Check
    const { data: stockCheckData } = useQuery({
        queryKey: ['stock-check', materials],
        queryFn: async () => {
            if (materials.length === 0) return [];
            const payload = materials.map(m => ({ material_id: m.materialId, quantity: m.quantity }));
            const res = await api.post('/api/v1/inventory/smart/check-availability', payload);
            return res.data?.data || [];
        },
        enabled: materials.length > 0
    });

    const addManualMaterial = (materialId) => {
        const mat = availableMaterials.find(m => m.id === parseInt(materialId));
        if (!mat) return;

        // Prevent duplicates
        if (materials.some(m => m.materialId === mat.id)) {
            toast.error("هذه المادة مضافة بالفعل");
            setPickerOpen(false);
            return;
        }

        // Check for smart suggestion (Relative Weight)
        let initialQuantity = 1;

        // Check if material is divisible (by type or unit)
        const isDivisible = mat.material_type === 'DIVISIBLE' || mat.type === 'DIVISIBLE' || ['ml', 'g', 'cm'].includes(mat.base_unit?.toLowerCase());

        if (isDivisible) {
            // FIX: For manual addition of divisible items (g/ml), always start with small relative weight (0.1)
            // The user prefers "Relative" increment logic over the static BOM definition (which might be large, e.g. 1.5g)
            initialQuantity = 0.1;
        }

        setMaterials(prev => [
            ...prev,
            {
                materialId: mat.id,
                materialName: mat.name,
                quantity: initialQuantity,
                unit: mat.base_unit,
                suggested: false
            }
        ]);
        setPickerOpen(false);
    };

    // Analyze Warnings
    const warnings = useMemo(() => {
        if (!stockCheckData) return [];

        return stockCheckData.filter(check => check.status !== 'OK').map(check => ({
            type: check.status === 'CRITICAL' ? 'critical' : 'warning',
            message: `${check.material_name}: ${check.message}`,
            materialId: check.material_id
        }));
    }, [stockCheckData]);

    const hasCritical = warnings.some(w => w.type === 'critical');

    const handleSave = async () => {
        // 1. Check for materials needing Open Confirmation
        // We need to know which ones are "New/Closed" but `stockCheckData` only returns qty.
        // The backend consumes_stock throws error `CONFIRM_OPEN_REQUIRED`. 
        // So we can try to save, catch that error, show confirm dialog.

        try {
            onSave(materials);
            onClose();
        } catch (error) {
            console.error("Save failed", error);
        }
    };

    // Actually `onSave` just passes data to parent (TreatmentModal). 
    // The parent calls the API. The parent needs to handle the confirmation workflow.
    // BUT we are in `EnhancedMaterialConsumption`.
    // Let's modify the parent logic OR we can do a "Pre-Check" here if we want.
    // The user requirement says "System must ask for approval".
    // Best place: The backend throws specific error. The UI catches it and shows "Confirm Open?".
    // Then re-tries with `auto_open=true`.
    // Since `onSave` is just passing data, we should update `TreatmentModal` or whoever calls API.
    // Let's create an `SmartStockHandler` component or hook in the parent.

    // WAIT: `EnhancedMaterialConsumption` is just a picker.
    // The API call happens in `TreatmentModal.jsx` -> `createTreatment`.

    // We should look at `TreatmentModal.jsx`.

    // Placeholder to avoid breaking current file logic.
    const handleSavePlaceholder = () => {
        onSave(materials);
        onClose();
    };

    const updateMaterial = (index, updated) => {
        const newMats = [...materials];
        newMats[index] = updated;
        setMaterials(newMats);
    };

    const removeMaterial = (index) => {
        const newMats = [...materials];
        newMats.splice(index, 1);
        setMaterials(newMats);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} size="lg" title={`المواد المستخدمة: ${procedure?.name || ''}`}>
            <div className="space-y-6">

                {/* Warnings */}
                {warnings.length > 0 && (
                    <div className="space-y-2">
                        {warnings.map((w, i) => (
                            <div key={i} className={`p-3 rounded-lg flex items-center gap-2 text-sm font-bold border ${w.type === 'critical' ? 'bg-red-50 text-red-700 border-red-200' : 'bg-yellow-50 text-yellow-800 border-yellow-200'
                                }`}>
                                <AlertTriangle size={18} />
                                {w.message}
                            </div>
                        ))}
                    </div>
                )}

                {materials.length === 0 && !pickerOpen ? (
                    <div className="text-center py-12 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                        <p className="text-gray-500 mb-4">لا توجد مواد مقترحة لهذا الإجراء</p>
                        <Button variant="outline" onClick={() => setPickerOpen(true)}>
                            + إضافة يدوية
                        </Button>
                    </div>
                ) : (
                    <div className="space-y-3 max-h-[60vh] overflow-y-auto pr-1">
                        {materials.map((mat, idx) => (
                            <SmartMaterialRow
                                key={mat.materialId || idx}
                                material={mat}
                                stockInfo={stockCheckData?.find(s => s.material_id === mat.materialId)}
                                onChange={(updated) => updateMaterial(idx, updated)}
                                onRemove={() => removeMaterial(idx)}
                            />
                        ))}

                        {/* Inline Picker */}
                        {pickerOpen && (
                            <div className="p-4 bg-blue-50/50 rounded-xl border border-blue-100 animate-in slide-in-from-top-2">
                                <label className="block text-sm font-bold text-blue-900 mb-2">اختر مادة من المخزون:</label>
                                <div className="flex gap-2">
                                    <select
                                        className="flex-1 p-2 rounded-lg border border-blue-200 outline-none"
                                        onChange={(e) => addManualMaterial(e.target.value)}
                                        value=""
                                    >
                                        <option value="">-- اختر مادة --</option>
                                        {availableMaterials.map(m => (
                                            <option key={m.id} value={m.id}>{m.name} ({m.quantity} {m.base_unit})</option>
                                        ))}
                                    </select>
                                    <Button size="sm" variant="ghost" onClick={() => setPickerOpen(false)}>إلغاء</Button>
                                </div>
                            </div>
                        )}
                    </div>
                )}

                <div className="pt-4 border-t border-gray-100 flex justify-between items-center">
                    <Button variant="ghost" className="text-gray-500" onClick={onClose}>
                        إلغاء
                    </Button>

                    <div className="flex gap-3">
                        {!pickerOpen && (
                            <Button variant="outline" onClick={() => setPickerOpen(true)}>
                                <Plus size={18} className="ml-2" />
                                مادة أخرى
                            </Button>
                        )}
                        <Button
                            onClick={handleSave}
                            disabled={hasCritical || materials.length === 0}
                            className={cn(hasCritical && "opacity-50 cursor-not-allowed")}
                            variant="primary"
                        >
                            <CheckCircle size={18} className="ml-2" />
                            تأكيد الصرف
                        </Button>
                    </div>
                </div>
            </div>
        </Modal>
    );
}

import React, { useMemo } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { getMaterialStock, updateMaterial } from '@/api/inventory';
import { X, Package, Calendar, Truck, AlertCircle, Play, Square, Settings } from 'lucide-react';
import LoadingSpinner from '@/shared/ui/LoadingSpinner';
import { showToast } from '@/shared/ui/Toast';
import { useTranslation } from 'react-i18next';

const MaterialDetailsModal = ({ isOpen, onClose, material, activeSessions = [] }) => {
    const { t } = useTranslation();
    // Handle both 'id' (Active Session) and 'material_id' (Stock Summary) formats
    const materialId = material?.material_id || material?.id;

    const [isEditing, setIsEditing] = React.useState(false);
    const [formData, setFormData] = React.useState({
        type: 'NON_DIVISIBLE',
        base_unit: '',
        packaging_ratio: 1.0,
        standard_price: 0.0
    });

    const queryClient = useQueryClient();

    const { data: stockItems, isLoading } = useQuery({
        queryKey: ['material-stock', materialId],
        queryFn: async () => {
            const res = await getMaterialStock(materialId);
            return res.data;
        },
        enabled: !!materialId && isOpen
    });

    // Initialize form data when material changes
    React.useEffect(() => {
        if (material) {
            setFormData({
                // Fix: Handle both 'type' (API) and 'material_type' (StockSummary)
                type: material.type || material.material_type || 'NON_DIVISIBLE',
                // Fix: Handle both 'base_unit' (API) and 'unit' (StockSummary)
                base_unit: material.base_unit || material.unit || '',
                packaging_ratio: material.packaging_ratio || 1.0,
                standard_price: material.standard_price || 0.0
            });
        }
    }, [material]);

    const activeSessionMap = useMemo(() => {
        const map = {};
        const sessions = Array.isArray(activeSessions) ? activeSessions : [];
        sessions.forEach(s => {
            map[s.stock_item_id] = s;
        });
        return map;
    }, [activeSessions]);

    const handleSaveSettings = async () => {
        try {
            await updateMaterial(materialId, formData);
            setIsEditing(false);
            await updateMaterial(materialId, formData);
            setIsEditing(false);
            queryClient.invalidateQueries(['inventory-stock']);
            showToast('success', t('inventory.material_details.messages.update_success'));
        } catch (error) {
            console.error("Failed to update material", error);
            showToast('error', t('inventory.material_details.messages.update_fail'));
        }
    };

    if (!isOpen || !material) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-surface w-full max-w-4xl rounded-xl shadow-2xl border border-border flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="flex items-center justify-between p-6 border-b border-border">
                    <div>
                        <h2 className="text-xl font-bold text-text-primary flex items-center gap-2">
                            <Package className="text-primary" />
                            {material.material_name || material.name}
                        </h2>
                        <p className="text-sm text-text-secondary mt-1">
                            {t('inventory.material_details.title')}
                        </p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-surface-hover rounded-full transition-colors">
                        <X size={20} className="text-text-secondary" />
                    </button>
                </div>

                {/* Material Settings Section */}
                <div className="p-4 bg-secondary/5 border-b border-border">
                    <div className="flex items-center justify-between mb-2">
                        <h3 className="text-sm font-semibold text-text-primary flex items-center gap-2">
                            <Settings size={16} /> {t('inventory.material_details.settings.title')}
                        </h3>
                        {!isEditing ? (
                            <button
                                onClick={() => setIsEditing(true)}
                                className="text-xs text-primary hover:underline"
                            >
                                {t('inventory.material_details.settings.edit')}
                            </button>
                        ) : (
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setIsEditing(false)}
                                    className="text-xs text-text-secondary hover:text-text-primary"
                                >
                                    {t('inventory.material_details.settings.cancel')}
                                </button>
                                <button
                                    onClick={handleSaveSettings}
                                    className="text-xs bg-primary text-white px-3 py-1 rounded hover:bg-primary-hover"
                                >
                                    {t('inventory.material_details.settings.save')}
                                </button>
                            </div>
                        )}
                    </div>

                    <div className="grid grid-cols-3 gap-4">
                        <div>
                            <label className="block text-xs text-text-secondary mb-1">{t('inventory.material_details.settings.type')}</label>
                            {isEditing ? (
                                <select
                                    value={formData.type}
                                    onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                                    className="w-full text-sm p-1 border rounded bg-surface"
                                >
                                    <option value="NON_DIVISIBLE">{t('inventory.material_details.settings.type_indivisible')}</option>
                                    <option value="DIVISIBLE">{t('inventory.material_details.settings.type_divisible')}</option>
                                </select>
                            ) : (
                                <span className={`text-sm font-medium ${formData.type === 'DIVISIBLE' ? 'text-blue-600' : 'text-gray-700'}`}>
                                    {formData.type === 'DIVISIBLE' ? t('inventory.material_details.settings.type_divisible') : t('inventory.material_details.settings.type_indivisible')}
                                </span>
                            )}
                        </div>
                        <div>
                            <label className="block text-xs text-text-secondary mb-1">{t('inventory.material_details.settings.unit')}</label>
                            {isEditing ? (
                                <input
                                    type="text"
                                    value={formData.base_unit}
                                    onChange={(e) => setFormData({ ...formData, base_unit: e.target.value })}
                                    placeholder="e.g., ml, g, pcs"
                                    className="w-full text-sm p-1 border rounded bg-surface"
                                />
                            ) : (
                                <span className="text-sm font-medium">{formData.base_unit || '-'}</span>
                            )}
                        </div>
                        <div>
                            <label className="block text-xs text-text-secondary mb-1">{t('inventory.material_details.settings.ratio')}</label>
                            {isEditing ? (
                                <input
                                    type="number"
                                    value={formData.packaging_ratio}
                                    onChange={(e) => setFormData({ ...formData, packaging_ratio: parseFloat(e.target.value) })}
                                    step="0.01"
                                    className="w-full text-sm p-1 border rounded bg-surface"
                                />
                            ) : (
                                <span className="text-sm font-medium">{formData.packaging_ratio}</span>
                            )}
                        </div>
                        <div>
                            <label className="block text-xs text-text-secondary mb-1">{t('inventory.material_details.settings.price')}</label>
                            {isEditing ? (
                                <input
                                    type="number"
                                    value={formData.standard_price}
                                    onChange={(e) => setFormData({ ...formData, standard_price: parseFloat(e.target.value) })}
                                    className="w-full text-sm p-1 border rounded bg-surface"
                                />
                            ) : (
                                <span className="text-sm font-medium">{formData.standard_price || 0} ج.م</span>
                            )}
                        </div>
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 scrollbar-thin">
                    {isLoading ? (
                        <div className="flex justify-center py-12">
                            <LoadingSpinner />
                        </div>
                    ) : !stockItems || stockItems.length === 0 ? (
                        <div className="text-center py-12 text-text-secondary">
                            <Package size={48} className="mx-auto mb-4 opacity-20" />
                            <p>{t('inventory.material_details.empty')}</p>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 gap-4">
                            {stockItems.map((item) => {
                                const activeSession = activeSessionMap[item.id];
                                const isExpired = new Date(item.batch?.expiry_date) < new Date();
                                const isNearExpiry = new Date(item.batch?.expiry_date) < new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

                                return (
                                    <div
                                        key={item.id}
                                        className={`
                                            relative p-4 rounded-xl border transition-all
                                            ${activeSession
                                                ? 'bg-red-50/50 border-red-200 ring-1 ring-red-100'
                                                : 'bg-background border-border hover:border-primary/30'}
                                        `}
                                    >
                                        <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center">

                                            {/* Batch Info */}
                                            <div className="flex items-center gap-4">
                                                <div className={`
                                                    p-3 rounded-lg 
                                                    ${activeSession ? 'bg-red-100 text-red-600' : 'bg-secondary/10 text-secondary'}
                                                `}>
                                                    {activeSession ? <Square size={24} className="animate-pulse" /> : <Package size={24} />}
                                                </div>

                                                <div>
                                                    <div className="flex items-center gap-2">
                                                        <span className="font-mono font-bold text-lg dir-ltr">
                                                            {item.batch?.batch_number}
                                                        </span>
                                                        {activeSession && (
                                                            <span className="px-2 py-0.5 bg-red-100 text-red-600 text-[10px] font-bold rounded-full border border-red-200">
                                                                {t('inventory.material_details.active_badge')}
                                                            </span>
                                                        )}
                                                    </div>

                                                    <div className="flex items-center gap-4 text-sm text-text-secondary mt-1">
                                                        <span className="flex items-center gap-1" title="تاريخ الصلاحية">
                                                            <Calendar size={14} />
                                                            <span className={`dir-ltr ${isExpired ? 'text-red-500 font-bold' : isNearExpiry ? 'text-amber-500 font-bold' : ''}`}>
                                                                {item.batch?.expiry_date}
                                                            </span>
                                                        </span>
                                                        {item.batch?.supplier && (
                                                            <span className="flex items-center gap-1" title="المورد">
                                                                <Truck size={14} />
                                                                {item.batch.supplier}
                                                            </span>
                                                        )}
                                                    </div>
                                                </div>
                                            </div>

                                            {/* Quantity & Warehouse */}
                                            <div className="text-right">
                                                <div className="font-bold text-xl text-text-primary">
                                                    {item.quantity} <span className="text-sm font-normal text-text-secondary">{(material.unit || material.base_unit)}</span>
                                                </div>
                                                <div className="text-xs text-text-secondary mt-0.5">
                                                    المستودع: {item.warehouse?.name || 'Main'}
                                                </div>
                                            </div>
                                        </div>

                                        {/* Usage Bar (Visual only for now) */}
                                        {activeSession && (
                                            <div className="mt-4 pt-4 border-t border-red-100 flex items-center justify-between text-xs text-red-700">
                                                <span className="flex items-center gap-1">
                                                    <AlertCircle size={14} />
                                                    {t('inventory.material_details.usage_bar')}
                                                </span>
                                                <span className="font-mono dir-ltr">
                                                    {t('inventory.material_details.started_at')} {new Date(activeSession.opened_at).toLocaleDateString()}
                                                </span>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="p-4 border-t border-border bg-surface-hover/30 flex justify-end">
                    <button
                        onClick={onClose}
                        className="px-6 py-2 bg-surface border border-border hover:bg-surface-hover rounded-lg transition-colors font-medium text-text-secondary"
                    >
                        {t('inventory.material_details.close')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default MaterialDetailsModal;

import React, { useState, useEffect } from 'react';
import { X, Save, Plus, Scale, Brain } from 'lucide-react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getProcedureWeights, setProcedureWeight } from '@/api/inventory';
import { useProcedures } from '@/shared/context/ProceduresContext';
import LoadingSpinner from '@/shared/ui/LoadingSpinner';
import { useTranslation } from 'react-i18next';

const SmartLearningModal = ({ isOpen, onClose, material }) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const { procedures: allProcedures } = useProcedures();
    const [weights, setWeights] = useState([]);
    const [newProcName, setNewProcName] = useState('');
    const [newProcWeight, setNewProcWeight] = useState(1.0);
    const [isAdding, setIsAdding] = useState(false);
    const [editingId, setEditingId] = useState(null);

    // Fetch existing weights
    const { data: existingWeights, isLoading: isLoadingWeights } = useQuery({
        queryKey: ['procedure-weights', material?.id],
        queryFn: () => getProcedureWeights(material?.id),
        enabled: !!material?.id,
    });

    useEffect(() => {
        if (existingWeights?.data) {
            setWeights(existingWeights.data);
        } else if (existingWeights) {
            setWeights(existingWeights);
        }
    }, [existingWeights]);

    const mutation = useMutation({
        mutationFn: setProcedureWeight,
        onSuccess: () => {
            queryClient.invalidateQueries(['procedure-weights', material?.id]);
            setIsAdding(false);
            setEditingId(null);
            setNewProcName('');
            setNewProcWeight(1.0);
        }
    });

    const handleAdd = async (procName, weight) => {
        await mutation.mutateAsync({
            procedure_name: procName,
            material_id: material.id,
            weight: parseFloat(weight)
        });
    };

    const handleUpdate = async (item, newWeight) => {
        if (!newWeight || isNaN(newWeight)) return;
        await mutation.mutateAsync({
            procedure_name: item.procedure?.name || item.procedure_name, // Backend needs name to find ID
            material_id: material.id,
            weight: parseFloat(newWeight)
        });
    };

    if (!isOpen || !material) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-surface w-full max-w-2xl rounded-2xl shadow-2xl border border-border flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="p-6 border-b border-border flex justify-between items-center bg-primary/5">
                    <div className="flex items-center gap-3">
                        <div className="p-3 bg-primary/10 rounded-xl">
                            <Brain className="text-primary" size={24} />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-text-primary">{t('inventory.smart_learning.title')}</h2>
                            <p className="text-sm text-text-secondary">{t('inventory.smart_learning.subtitle', { name: material.name })}</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-black/5 rounded-full text-text-secondary transition-colors">
                        <X size={24} />
                    </button>
                </div>

                {/* Body */}
                <div className="p-6 overflow-y-auto flex-1 space-y-6">

                    <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-xl text-sm text-blue-800 dark:text-blue-200 flex gap-3 items-start">
                        <Scale size={20} className="mt-0.5 shrink-0" />
                        <div>
                            <p className="font-bold mb-1">{t('inventory.smart_learning.help_title')}</p>
                            <p>{t('inventory.smart_learning.help_desc')}</p>
                            <p className="mt-1 opacity-80">{t('inventory.smart_learning.help_note')}</p>
                        </div>
                    </div>

                    {isLoadingWeights ? <LoadingSpinner /> : (
                        <div className="border border-border rounded-xl overflow-hidden">
                            <table className="w-full text-right">
                                <thead className="bg-background-secondary border-b border-border">
                                    <tr>
                                        <th className="px-4 py-3 text-sm font-bold text-text-secondary">{t('inventory.smart_learning.table.procedure')}</th>
                                        <th className="px-4 py-3 text-sm font-bold text-text-secondary">{t('inventory.smart_learning.table.weight')}</th>
                                        <th className="px-4 py-3 text-sm font-bold text-text-secondary">{t('inventory.smart_learning.table.average')}</th>
                                        <th className="px-4 py-3 text-sm font-bold text-text-secondary">{t('inventory.smart_learning.table.edit')}</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-border bg-surface">
                                    {weights.length === 0 && !isAdding && (
                                        <tr>
                                            <td colSpan="4" className="px-4 py-8 text-center text-text-secondary">
                                                {t('inventory.smart_learning.empty')}
                                            </td>
                                        </tr>
                                    )}
                                    {weights.map((w) => {
                                        const isEditing = editingId === w.id;
                                        return (
                                            <tr key={w.id} className="group hover:bg-surface-hover transition-colors">
                                                <td className="px-4 py-3 font-medium">
                                                    {w.procedure?.name || w.procedure_name || `ID: ${w.procedure_id}`}
                                                </td>
                                                <td className="px-4 py-3">
                                                    {isEditing ? (
                                                        <input
                                                            type="number"
                                                            step="0.01"
                                                            min="0.01"
                                                            className="w-20 p-1 rounded border border-primary outline-none text-center"
                                                            defaultValue={w.weight}
                                                            onKeyDown={(e) => {
                                                                if (e.key === 'Enter') handleUpdate(w, e.currentTarget.value);
                                                            }}
                                                            onBlur={(e) => handleUpdate(w, e.currentTarget.value)}
                                                            autoFocus
                                                        />
                                                    ) : (
                                                        <span className="inline-block px-2 py-1 bg-primary/10 text-primary rounded-lg font-bold">
                                                            {w.weight}x
                                                        </span>
                                                    )}
                                                </td>
                                                <td className="px-4 py-3 font-mono text-sm text-text-secondary dir-ltr">
                                                    {w.current_average_usage > 0 ? `${w.current_average_usage.toFixed(3)} ${material.unit || 'units'}` : '-'}
                                                </td>
                                                <td className="px-4 py-3">
                                                    {isEditing ? (
                                                        <button onClick={() => setEditingId(null)} className="text-xs text-slate-500 hover:text-slate-700">{t('inventory.smart_learning.actions.cancel')}</button>
                                                    ) : (
                                                        <div className="flex gap-2">
                                                            <button
                                                                onClick={() => setEditingId(w.id)}
                                                                className="text-xs text-primary hover:underline"
                                                            >
                                                                {t('inventory.smart_learning.actions.edit')}
                                                            </button>
                                                            <button
                                                                onClick={() => {
                                                                    if (confirm(t('inventory.smart_learning.delete_confirm'))) mutation.mutate({ procedure_name: w.procedure?.name || w.procedure_name, material_id: material.id, weight: 0 }); // 0/Delete logic needed
                                                                    // For now, setting to 0 might be equivalent to delete in backend or we need Delete API
                                                                    // Current backend `setProcedureWeight` updates or creates. 
                                                                    // To delete, we probably need a dedicated delete or handle 0/null.
                                                                    // Assuming update for now.
                                                                }}
                                                                className="text-xs text-red-500 hover:underline"
                                                            >
                                                                {t('inventory.smart_learning.actions.delete')}
                                                            </button>
                                                        </div>
                                                    )}
                                                </td>
                                            </tr>
                                        );
                                    })}

                                    {/* Add Row */}
                                    {isAdding && (
                                        <tr className="bg-primary/5">
                                            <td className="px-4 py-3">
                                                <select
                                                    className="w-full p-2 rounded-lg border border-border bg-surface"
                                                    value={newProcName}
                                                    onChange={e => setNewProcName(e.target.value)}
                                                >
                                                    <option value="">{t('inventory.smart_learning.select_placeholder')}</option>
                                                    {allProcedures
                                                        ?.filter(p => !weights.some(w => w.procedure_id === p.id || w.procedure?.id === p.id))
                                                        .map(p => (
                                                            <option key={p.id} value={p.name}>{p.name}</option>
                                                        ))}
                                                </select>
                                            </td>
                                            <td className="px-4 py-3">
                                                <input
                                                    type="number" step="0.01" min="0.01"
                                                    className="w-20 p-2 rounded-lg border border-border bg-surface text-center"
                                                    value={newProcWeight}
                                                    onChange={e => setNewProcWeight(e.target.value)}
                                                />
                                            </td>
                                            <td className="px-4 py-3 text-center">-</td>
                                            <td className="px-4 py-3">
                                                <button
                                                    onClick={() => handleAdd(newProcName, newProcWeight)} // Renamed handleSave to handleAdd for clarity
                                                    disabled={!newProcName}
                                                    className="p-2 bg-primary text-white rounded-lg hover:bg-primary-600 disabled:opacity-50"
                                                >
                                                    <Save size={16} />
                                                </button>
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}

                    {!isAdding && (
                        <button
                            onClick={() => setIsAdding(true)}
                            className="w-full py-3 border-2 border-dashed border-border rounded-xl flex items-center justify-center gap-2 text-text-secondary hover:text-primary hover:border-primary hover:bg-primary/5 transition-all"
                        >
                            <Plus size={20} />
                            <span>{t('inventory.smart_learning.add_button')}</span>
                        </button>
                    )}

                </div>

                {/* Footer */}
                <div className="p-6 border-t border-border bg-surface-secondary/30 flex justify-end">
                    <button
                        onClick={onClose}
                        className="px-6 py-2 bg-white border border-border text-text-primary rounded-lg font-bold hover:bg-gray-50 transition-colors"
                    >
                        {t('inventory.smart_learning.actions.close')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default SmartLearningModal;

import React, { useMemo, useState } from 'react';
import { Badge, IconButton, Input } from '@/shared/ui';
import { X, Check, AlertTriangle } from 'lucide-react';
import { cn } from '@/utils/cn';

export function SmartMaterialRow({
    material,
    stockInfo,
    onChange,
    onRemove
}) {
    // Check if this is a divisible material based on unit
    const isDivisible = ['ml', 'g', 'cm'].includes(material.unit?.toLowerCase());
    // Generate quick amounts based on unit
    const quickAmounts = useMemo(() => {
        // For divisible materials, these are RELATIVE WEIGHTS (not actual grams)
        if (isDivisible) {
            return [
                { value: 0.1, label: '0.1' },
                { value: 0.25, label: '¼' },
                { value: 0.5, label: '½' },
                { value: 1, label: '1' }
            ];
        } else {
            return [
                { value: 1, label: '1' },
                { value: 2, label: '2' },
                { value: 3, label: '3' },
                { value: 5, label: '5' }
            ];
        }
    }, [isDivisible]);

    const [mode, setMode] = useState(() => {
        // Auto-detect mode: If quantity matches a quick amount, use 'quick', else 'custom'
        const isQuick = quickAmounts.some(q => q.value === material.quantity);
        return isQuick ? 'quick' : 'custom';
    });

    // Stock status - now uses has_active_session from backend
    const stockStatus = useMemo(() => {
        if (!stockInfo) return 'unknown';
        // Material has active session = virtual consumption, always OK
        if (stockInfo.has_active_session) return 'session_active';
        if (stockInfo.available === 0) return 'out';
        if (stockInfo.available < material.quantity) return 'insufficient';
        if (stockInfo.available < material.quantity * 2) return 'low';
        return 'ok';
    }, [stockInfo, material.quantity]);

    const StockStatusBadge = ({ status, stockInfo }) => {
        switch (status) {
            case 'session_active':
                return <Badge variant="success" className="bg-green-100 text-green-700">✓ جلسة مفتوحة</Badge>;
            case 'out':
                return (
                    <div className="flex flex-col gap-1">
                        <Badge variant="destructive">⚠️ غير متاح</Badge>
                        <span className="text-xs text-red-600 font-medium">
                            💡 يجب فتح جلسة من صفحة المخزون
                        </span>
                    </div>
                );
            case 'insufficient': return <Badge variant="warning">غير كافي</Badge>;
            case 'low': return <Badge variant="warning" className="bg-yellow-100 text-yellow-800">منخفض</Badge>;
            case 'ok': return <Badge variant="success">متوفر</Badge>;
            default: return <Badge variant="secondary">تحقق...</Badge>;
        }
    };

    return (
        <div className={cn(
            "bg-white border-2 rounded-xl p-4 transition-all",
            stockStatus === 'out' ? 'border-red-200 bg-red-50' :
                stockStatus === 'session_active' ? 'border-green-200 bg-green-50/30' :
                    'border-gray-200 hover:border-primary/30'
        )}>
            <div className="flex items-start gap-4">
                {/* Material Info */}
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                        <h4 className="font-bold text-lg truncate text-slate-800">{material.materialName}</h4>

                        {material.suggested && (
                            <Badge variant="primary" size="sm" className="bg-blue-100 text-blue-700 hover:bg-blue-200">
                                ✨ مقترح
                            </Badge>
                        )}
                    </div>

                    {/* Suggestion Reason */}
                    {material.reason && material.suggested && (
                        <p className="text-sm text-gray-500 mb-2 flex items-center gap-1">
                            💡 {material.reason}
                            {material.confidence && (
                                <span className="text-xs opacity-70">
                                    ({Math.round(material.confidence * 100)}%)
                                </span>
                            )}
                        </p>
                    )}

                    {/* Stock Status */}
                    <div className="flex items-center gap-3 flex-wrap mt-2">
                        <StockStatusBadge status={stockStatus} stockInfo={stockInfo} />

                        {stockInfo && stockStatus !== 'session_active' && (
                            <span className="text-sm text-gray-600">
                                المتوفر: <strong className="font-mono">{stockInfo.available} {isDivisible ? material.unit : 'وحدة'}</strong>
                            </span>
                        )}

                        {stockInfo && stockStatus === 'session_active' && (
                            <span className="text-sm text-green-700 font-medium">
                                استهلاك افتراضي (لا حاجة للتحقق من الكمية)
                            </span>
                        )}
                    </div>
                </div>

                {/* Quantity Selector */}
                <div className="flex-shrink-0">
                    {mode === 'quick' ? (
                        <div className="space-y-2">
                            <div className="grid grid-cols-4 gap-1 min-w-[200px]">
                                {quickAmounts.map(({ value, label }) => (
                                    <button
                                        key={value}
                                        type="button"
                                        onClick={() => onChange({ ...material, quantity: value })}
                                        className={cn(
                                            'px-2 py-2 rounded-lg border font-bold transition-all text-sm',
                                            material.quantity === value
                                                ? 'border-primary bg-primary text-white shadow-md'
                                                : 'border-gray-200 hover:border-primary/50 hover:bg-primary/5 bg-white'
                                        )}
                                    >
                                        {label}
                                    </button>
                                ))}
                            </div>

                            <button
                                type="button"
                                onClick={() => setMode('custom')}
                                className="w-full text-xs text-primary hover:underline text-center mt-1"
                            >
                                ✏️ كمية مخصصة
                            </button>
                        </div>
                    ) : (
                        <div className="flex items-center gap-2 bg-gray-50 p-2 rounded-lg border border-gray-200">
                            <Input
                                type="number"
                                step="0.01"
                                min="0"
                                value={material.quantity}
                                onChange={(e) => onChange({
                                    ...material,
                                    quantity: parseFloat(e.target.value) || 0
                                })}
                                className="w-20 text-center h-9"
                                autoFocus
                            />
                            <span className="text-sm text-gray-600 font-medium">
                                {isDivisible ? 'وزن نسبي' : material.unit}
                            </span>
                            <IconButton
                                icon={<Check size={16} />}
                                variant="ghost"
                                size="sm"
                                onClick={() => setMode('quick')}
                                className="hover:bg-green-100 hover:text-green-700"
                            />
                        </div>
                    )}
                </div>

                {/* Remove Button */}
                <button
                    onClick={onRemove}
                    className="text-gray-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-full transition-colors"
                >
                    <X size={20} />
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { X, Play, Square, AlertCircle, Clock, Package } from 'lucide-react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { openSession, closeSession, getMaterialStock } from '@/api/inventory';
import LoadingSpinner from '@/shared/ui/LoadingSpinner';
import { useTranslation } from 'react-i18next';

const TrackSessionModal = ({ isOpen, onClose, session, material, stockItem, mode = 'OPEN', onSuccess }) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const [selectedStockId, setSelectedStockId] = useState(stockItem?.id || '');
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Fetch batches if we don't have a specific stock item but have material
    const { data: batches, isLoading: isLoadingBatches } = useQuery({
        queryKey: ['material-stock', material?.id],
        queryFn: () => getMaterialStock(material?.id),
        enabled: isOpen && mode === 'OPEN' && !stockItem && !!material?.id,
    });

    useEffect(() => {
        if (stockItem) setSelectedStockId(stockItem.id);
    }, [stockItem]);

    const openMutation = useMutation({
        mutationFn: openSession,
        onSuccess: () => {
            queryClient.invalidateQueries(['active-sessions']);
            if (onSuccess) onSuccess();
            onClose();
        }
    });

    const closeMutation = useMutation({
        mutationFn: (data) => closeSession(session.id, data),
        onSuccess: () => {
            queryClient.invalidateQueries(['active-sessions']);
            queryClient.invalidateQueries(['procedure-weights']);
            if (onSuccess) onSuccess();
            onClose();
        }
    });

    const handleConfirm = async () => {
        setIsSubmitting(true);
        console.log("Starting Confirm...", { mode, selectedStockId });
        try {
            if (mode === 'OPEN') {
                if (!selectedStockId) {
                    alert(t('inventory.track_session.messages.select_error'));
                    return;
                }
                const payload = {
                    stock_item_id: parseInt(selectedStockId),
                    status: 'ACTIVE'
                };
                console.log("Sending Open Payload:", payload);
                await openMutation.mutateAsync(payload);
                alert(t('inventory.track_session.messages.success_open'));
            } else {
                // Close session - no quantity needed, auto-calculates
                await closeMutation.mutateAsync({});
                alert(t('inventory.track_session.messages.success_close'));
            }
        } catch (e) {
            console.error("Operation Failed:", e);
            const res = e.response?.data;
            const msg = res?.error?.message || res?.detail || e.message;
            alert(t('inventory.track_session.messages.error_prefix') + msg);
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!isOpen) return null;

    const isOpenMode = mode === 'OPEN';
    const displayMaterialName = material?.name || material?.material_name || stockItem?.name || stockItem?.material_name || session?.stock_item?.batch?.material?.name || session?.stock_item?.material?.name;
    const unit = material?.unit || session?.stock_item?.batch?.material?.base_unit || session?.stock_item?.material?.base_unit || 'Units';

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-surface w-full max-w-md rounded-2xl shadow-xl border border-border overflow-hidden">
                <div className={`p-6 border-b border-border flex justify-between items-center ${isOpenMode ? 'bg-green-500/10' : 'bg-red-500/10'}`}>
                    <div className="flex items-center gap-3">
                        <div className={`p-2 rounded-lg ${isOpenMode ? 'bg-green-500/20 text-green-600' : 'bg-red-500/20 text-red-600'}`}>
                            {isOpenMode ? <Play size={24} /> : <Square size={24} />}
                        </div>
                        <div>
                            <h3 className="text-lg font-bold">{isOpenMode ? t('inventory.track_session.title_open') : t('inventory.track_session.title_close')}</h3>
                            <p className="text-sm opacity-70">
                                {isOpenMode ? t('inventory.track_session.subtitle_open') : t('inventory.track_session.subtitle_close')}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-1 hover:bg-black/5 rounded-full"><X size={20} /></button>
                </div>

                <div className="p-6 space-y-6">
                    <div className="text-sm font-medium border-b border-border pb-4">
                        <span className="text-text-secondary">{t('inventory.track_session.material_label')} </span>
                        <span className="font-bold text-lg text-text-primary mr-2">{displayMaterialName}</span>
                    </div>

                    {isOpenMode ? (
                        <div className="space-y-4">
                            <div className="flex items-start gap-3 p-3 bg-background-secondary rounded-lg">
                                <AlertCircle className="text-primary shrink-0 mt-0.5" size={18} />
                                <p className="text-sm text-text-secondary leading-relaxed">
                                    {t('inventory.track_session.info_open')}
                                </p>
                            </div>

                            {!stockItem && (
                                <div>
                                    <label className="block text-sm font-bold mb-2">{t('inventory.track_session.select_batch_label')}</label>
                                    {isLoadingBatches ? <LoadingSpinner size="sm" /> : (
                                        <select
                                            className="w-full p-3 rounded-lg border border-border bg-background"
                                            value={selectedStockId}
                                            onChange={e => setSelectedStockId(e.target.value)}
                                        >
                                            <option value="">{t('inventory.track_session.select_placeholder')}</option>
                                            {batches?.data?.map(b => (
                                                <option key={b.id} value={b.id}>
                                                    {b.warehouse?.name || 'مخزن'} - Batch: {b.batch?.batch_number} (Exp: {b.batch?.expiry_date}) - Qty: {b.quantity}
                                                </option>
                                            ))}
                                        </select>
                                    )}
                                    {batches?.data?.length === 0 && (
                                        <p className="text-red-500 text-sm mt-1">{t('inventory.track_session.empty_stock')}</p>
                                    )}
                                </div>
                            )}

                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="flex items-center gap-2 text-sm text-text-secondary mb-4 p-3 bg-red-50 rounded-lg dark:bg-red-900/10">
                                <Clock size={16} />
                                <span>{t('inventory.track_session.opened_since')} </span>
                                <span className="font-mono dir-ltr font-bold">
                                    {session?.opened_at ? new Date(session.opened_at).toLocaleDateString() + ' ' + new Date(session.opened_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '-'}
                                </span>
                            </div>

                            <div className="flex items-start gap-3 p-3 bg-amber-50 rounded-lg dark:bg-amber-900/10">
                                <AlertCircle className="text-amber-600 shrink-0 mt-0.5" size={18} />
                                <p className="text-sm text-text-secondary leading-relaxed">
                                    {t('inventory.track_session.info_close_auto', 'عند إنهاء الجلسة، سيتم حساب الاستهلاك تلقائياً بناءً على الأوزان النسبية للإجراءات.')}
                                </p>
                            </div>
                        </div>
                    )}
                </div>

                <div className="p-4 border-t border-border bg-surface-secondary/30 flex justify-end gap-3">
                    <button onClick={onClose} className="px-4 py-2 rounded-lg font-bold hover:bg-black/5">{t('inventory.track_session.actions.cancel')}</button>
                    <button
                        onClick={handleConfirm}
                        disabled={isSubmitting || (isOpenMode && !selectedStockId)}
                        className={`px-6 py-2 rounded-lg font-bold text-white shadow-lg transition-transform active:scale-95 flex items-center gap-2 ${isOpenMode ? 'bg-green-600 hover:bg-green-700 disabled:bg-green-400' : 'bg-red-600 hover:bg-red-700 disabled:bg-red-400'}`}
                    >
                        {isSubmitting && <LoadingSpinner size="sm" color="white" />}
                        {isOpenMode ? t('inventory.track_session.actions.start') : t('inventory.track_session.actions.end')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default TrackSessionModal;

import React, { useState, useEffect } from 'react';
import { FlaskConical, CheckCircle, Clock, AlertCircle, Plus, Edit2, Trash2, X } from 'lucide-react';
import { getPatientLabOrders, getLaboratories, createLabOrder, updateLabOrder, deleteLabOrder } from '@/api';
import { useTranslation } from 'react-i18next';

const LabOrdersTab = ({ patientId }) => {
    const { t } = useTranslation();
    const [labOrders, setLabOrders] = useState([]);
    const [laboratories, setLaboratories] = useState([]);
    const [loading, setLoading] = useState(false);

    // Modal State
    const [isLabOrderModalOpen, setIsLabOrderModalOpen] = useState(false);
    const [editingLabOrder, setEditingLabOrder] = useState(null);
    const initialLabOrder = { laboratory_id: '', work_type: '', tooth_number: '', shade: '', material: '', cost: '', price_to_patient: '', notes: '' };
    const [newLabOrder, setNewLabOrder] = useState(initialLabOrder);

    useEffect(() => {
        if (patientId) {
            loadData();
        }
    }, [patientId]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [ordersRes, labsRes] = await Promise.all([
                getPatientLabOrders(patientId),
                getLaboratories()
            ]);
            setLabOrders(ordersRes.data);
            setLaboratories(labsRes.data);
        } catch (err) {
            console.error("Failed to load lab data", err);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteLabOrder = async (orderId) => {
        if (!window.confirm(t('patientDetails.lab_orders.confirm_delete'))) return;
        try {
            await deleteLabOrder(orderId);
            loadData();
        } catch (err) {
            alert(t('patientDetails.lab_orders.delete_failed'));
        }
    };

    const handleSaveLabOrder = async () => {
        if (!newLabOrder.laboratory_id || !newLabOrder.work_type) {
            alert(t('patientDetails.lab_orders.validation_error'));
            return;
        }
        try {
            const orderData = {
                patient_id: parseInt(patientId),
                laboratory_id: parseInt(newLabOrder.laboratory_id),
                work_type: newLabOrder.work_type,
                tooth_number: newLabOrder.tooth_number,
                shade: newLabOrder.shade,
                material: newLabOrder.material,
                cost: parseFloat(newLabOrder.cost) || 0,
                price_to_patient: parseFloat(newLabOrder.price_to_patient) || 0,
                notes: newLabOrder.notes
            };

            if (editingLabOrder) {
                orderData.status = newLabOrder.status;
                await updateLabOrder(editingLabOrder.id, orderData);
            } else {
                await createLabOrder(orderData);
            }

            setIsLabOrderModalOpen(false);
            setNewLabOrder(initialLabOrder);
            setEditingLabOrder(null);
            loadData();
        } catch (err) {
            alert(t('patientDetails.lab_orders.save_error'));
            console.error(err);
        }
    };

    if (loading && labOrders.length === 0) return <div className="p-10 text-center">Loading...</div>;

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
            {/* Lab Stats */}
            <div className="grid grid-cols-3 gap-4">
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.lab_orders.stats.total_orders')}</p>
                    <p className="text-2xl font-bold text-slate-800">{labOrders.length}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.lab_orders.stats.prosthetics_cost')}</p>
                    <p className="text-2xl font-bold text-purple-600">
                        {labOrders.reduce((acc, curr) => acc + (curr.price_to_patient || 0), 0)}
                    </p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.lab_orders.stats.pending')}</p>
                    <p className="text-2xl font-bold text-amber-600">
                        {labOrders.filter(o => o.status === 'pending' || o.status === 'in_progress').length}
                    </p>
                </div>
            </div>

            {/* Lab Orders List */}
            <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden">
