import React, { useState, useRef, useEffect } from 'react';
import { Camera, X, RefreshCw, Check, Loader2, Info, Scan } from 'lucide-react';
import { performOCR } from '@/api';

export default function PatientScanner({ onScanComplete, onClose }) {
    const [isReady, setIsReady] = useState(false);
    const [isProcessing, setIsProcessing] = useState(false);
    const [stream, setStream] = useState(null);
    const [capturedImage, setCapturedImage] = useState(null);
    const [ocrStatus, setOcrStatus] = useState('');
    const [isReviewing, setIsReviewing] = useState(false);
    const [rawOcrText, setRawOcrText] = useState('');
    const [showRaw, setShowRaw] = useState(false);
    const [extractedData, setExtractedData] = useState({ name: '', age: '', address: '', phone: '' });
    const [errorHeader, setErrorHeader] = useState('');
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const fileInputRef = useRef(null);

    useEffect(() => {
        startCamera();
        return () => stopCamera();
    }, []);

    const startCamera = async () => {
        if (!window.isSecureContext && window.location.hostname !== 'localhost') {
            setErrorHeader('الكاميرا تتطلب رابط آمن (HTTPS).');
            return;
        }

        if (!navigator.mediaDevices?.getUserMedia) {
            setErrorHeader('متصفحك لا يدعم فتح الكاميرا.');
            return;
        }

        try {
            const constraints = {
                video: {
                    facingMode: 'environment',
                    width: { ideal: 1920 },
                    height: { ideal: 1080 }
                }
            };
            const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
            setStream(mediaStream);
            if (videoRef.current) {
                videoRef.current.srcObject = mediaStream;
                setIsReady(true);
            }
        } catch (err) {
            console.error("Camera error:", err);
            setErrorHeader('حدث خطأ في الكاميرا. يمكنك رفع الصورة بدلاً من ذلك.');
        }
    };

    const stopCamera = () => {
        if (stream) stream.getTracks().forEach(t => t.stop());
        setIsReady(false);
    };

    const retake = () => {
        setCapturedImage(null);
        setIsReviewing(false);
        setErrorHeader('');
        startCamera();
    };

    const handleFileUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = (event) => {
                setCapturedImage(event.target.result);
                setErrorHeader('');
                stopCamera();
            };
            reader.readAsDataURL(file);
        }
    };

    const processOCR = async (useOriginal = false) => {
        setIsProcessing(true);
        setOcrStatus('جاري تحليل الكارت...');
        try {
            let imageToProcess = capturedImage;
            if (!useOriginal && canvasRef.current && videoRef.current) {
                const canvas = canvasRef.current;
                const video = videoRef.current;

                const MAX_SIZE = 1600;
                let width = video.videoWidth;
                let height = video.videoHeight;
                if (width > MAX_SIZE || height > MAX_SIZE) {
                    const ratio = Math.min(MAX_SIZE / width, MAX_SIZE / height);
                    width *= ratio;
                    height *= ratio;
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(video, 0, 0, width, height);

                // Grayscale + Contrast Adjustment (Softer than hard threshold)
                const imageData = ctx.getImageData(0, 0, width, height);
                const data = imageData.data;
                for (let i = 0; i < data.length; i += 4) {
                    const gray = 0.299 * data[i] + 0.587 * data[i + 1] + 0.114 * data[i + 2];
                    // Boost contrast: push darks darker and lights lighter without hard clipping
                    let pixel = gray;
                    if (pixel < 128) pixel = pixel * 0.8; // Darker
                    else pixel = Math.min(255, pixel * 1.2); // Brighter
                    data[i] = data[i + 1] = data[i + 2] = pixel;
                }
                ctx.putImageData(imageData, 0, 0);
                imageToProcess = canvas.toDataURL('image/jpeg', 0.80);
            }

            const response = await performOCR(imageToProcess);
            if (response.data.IsErroredOnProcessing) throw new Error(response.data.ErrorMessage[0]);

            const rawText = response.data.ParsedResults?.[0]?.ParsedText || "";
            const text = sanitizeText(rawText);
            setRawOcrText(text);
            const parsed = parseText(text);
            setExtractedData(parsed);
            setIsReviewing(true);
        } catch (err) {
            console.error("OCR Error:", err);
            let msg = "فشل الاتصال بمحرك القراءة.";
            if (err.code === 'ECONNABORTED') {
                msg = "انتهى وقت المحاولة (Timeout)";
            } else if (err.message) {
                msg = `خطأ: ${err.message}`;
            }
            alert(`${msg}\n\nيرجى المحاولة مرة أخرى أو اختيار صورة أوضح.`);
        } finally {
            setIsProcessing(false);
            setOcrStatus('');
        }
    };

    const sanitizeText = (text) => {
        if (!text) return '';
        return text.trim().replace(/\r\n/g, '\n');
    };

    const parseText = (text) => {
        const hindiToEn = (s) => s.replace(/[٠١٢٣٤٥٦٧٨٩]/g, d => "٠١٢٣٤٥٦٧٨٩".indexOf(d));
        const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);

        // Filter out clinic headers to reduce noise
        const cleanLines = lines.filter(l =>
            !l.includes('إسلام عمارة') &&
            !l.includes('Eslam Emara') &&
            !l.includes('عيادة') &&
            !l.includes('دكتور') &&
            !l.includes('مركز')
        );

        const data = { name: '', age: '', phone: '', address: '' };

        const phoneRegex = /(01[0125]\d{8})/;
        const ageRegex = /\b([1-9][0-9]?)\b/;

        // Keyword lists for fuzzy matching
        const nameKeywords = ['المريض', 'الاسم', 'اسم', 'مريض'];
        const ageKeywords = ['السن', 'السم', 'سنة', 'سنه', 'عمر', 'عام'];
        const phoneKeywords = ['تليفون', 'موبايل', 'هاتف', 'محمول', 'جوال', 'ت:', 'م:'];
        const addressKeywords = ['العنوان', 'عنوان', 'شارع', 'بجوار', 'حي', 'قرية', 'مركز'];

        cleanLines.forEach((line, index) => {
            const normalizedLine = hindiToEn(line);

            // Helper: Get value after label or from next line
            const extractValue = (lineContent, keywords) => {
                let val = '';
                const matchedKeyword = keywords.find(k => lineContent.includes(k));
                if (matchedKeyword) {
                    const parts = lineContent.split(matchedKeyword);
                    // Take what's after the keyword on the same line
                    val = parts[1] ? parts[1].replace(/[:\-]/g, '').trim() : '';

                    // If same line empty, check next line
                    if (!val && cleanLines[index + 1]) {
                        const nextLine = cleanLines[index + 1];
                        // Ensure next line isn't another label
                        const isNextLabel = [...nameKeywords, ...ageKeywords, ...phoneKeywords, ...addressKeywords]
                            .some(k => nextLine.includes(k));
                        if (!isNextLabel) val = nextLine;
                    }
                }
                return val;
            };

            // 1. Phone (Priority: High Regex Match)
            const phoneMatch = normalizedLine.match(phoneRegex);
            if (phoneMatch && !data.phone) data.phone = phoneMatch[0];

            // 2. Name
            if (!data.name) {
                const nameVal = extractValue(line, nameKeywords);
                if (nameVal && nameVal.length > 3) data.name = nameVal;
            }

            // 3. Age
            if (!data.age) {
                const ageMatch = normalizedLine.match(ageRegex);
                const hasAgeKeyword = ageKeywords.some(k => line.includes(k));
                if (hasAgeKeyword && ageMatch) {
                    data.age = ageMatch[0];
                }
            }

            // 4. Address
            if (!data.address) {
                const addrVal = extractValue(line, addressKeywords);
                if (addrVal && addrVal.length > 4) data.address = addrVal;
            }
        });

        // --- Final Fallbacks (If still empty) ---

        // Name Fallback: Usually the first line after doctor info
        if (!data.name && cleanLines.length > 0) {
            data.name = cleanLines.find(l => l.length > 5 && !l.match(/\d/) && !l.includes('شارع')) || '';
        }

        // Phone Fallback: Any 11-digit number starting with 01
        if (!data.phone) {
            const anyPhone = hindiToEn(text).match(phoneRegex);
            if (anyPhone) data.phone = anyPhone[0];
        }

        // Age Fallback: Any 2-digit number 5-95
        if (!data.age) {
            const possibleAges = hindiToEn(text).match(/\b\d{1,2}\b/g);
            if (possibleAges) {
                const age = possibleAges.find(n => parseInt(n) > 4 && parseInt(n) < 100);
                if (age) data.age = age;
            }
        }

        return data;
    };

    return (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[200] flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-800 w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden relative">

                <div className="p-6 flex justify-between items-center border-b dark:border-white/5">
                    <h3 className="font-bold text-xl flex items-center gap-2 dark:text-white">
                        <Scan className="text-primary" /> اسكان كارت المريض
                    </h3>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/5 rounded-xl transition-colors">
                        <X className="dark:text-white" />
                    </button>
                </div>

                <div className="aspect-video bg-black relative overflow-hidden">
                    {errorHeader ? (
                        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center bg-slate-900">
                            <Info size={48} className="text-red-500 mb-4" />
                            <p className="text-white font-bold mb-6 text-lg">{errorHeader}</p>
                            <button onClick={() => fileInputRef.current?.click()} className="w-full bg-primary py-4 rounded-2xl text-white font-black">اختيار صورة من الجهاز</button>
                        </div>
                    ) : capturedImage && !isReviewing ? (
                        <div className="absolute inset-0 bg-slate-900 flex items-center justify-center p-4">
                            <img src={capturedImage} className="max-w-full max-h-full object-contain rounded-xl" alt="Preview" />
                        </div>
                    ) : !isReviewing ? (
                        <>
                            <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
                            <div className="absolute inset-0 border-[40px] border-black/40 pointer-events-none">
                                <div className="w-full h-full border-2 border-dashed border-white/30 rounded-2xl flex items-center justify-center">
                                    <p className="text-white/50 text-xs font-bold bg-black/50 px-4 py-2 rounded-full">ضع بيانات الكارت داخل هذا الإطار</p>
                                </div>
                            </div>
                        </>
                    ) : (
                        <div className="absolute inset-0 bg-white dark:bg-slate-900 p-8 overflow-y-auto">
                            <div className="flex items-center justify-between mb-6">
                                <h4 className="text-xl font-black dark:text-white flex items-center gap-2">
                                    <Check className="text-green-500" /> مراجعة البيانات
                                </h4>
                                <button
                                    onClick={() => setShowRaw(!showRaw)}
                                    className="text-[10px] font-black uppercase tracking-wider text-primary hover:bg-primary/5 px-3 py-1.5 rounded-lg border border-primary/20 transition-colors"
                                >
                                    {showRaw ? 'إخفاء النص الأصلي' : 'عرض النص المستخرج'}
                                </button>
                            </div>

                            {showRaw && (
                                <div className="mb-6 p-4 bg-slate-50 dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-white/5 animate-in fade-in slide-in-from-top-2 duration-300">
                                    <label className="text-[10px] font-black text-slate-400 block mb-2">النص كما قرأه البرنامج (OCR):</label>
                                    <p className="text-xs text-slate-600 dark:text-slate-300 whitespace-pre-wrap leading-relaxed font-medium bg-white dark:bg-slate-900 p-3 rounded-xl border border-slate-100 dark:border-white/5 max-h-40 overflow-y-auto">
                                        {rawOcrText || 'لم يتم العثور على نص'}
                                    </p>
                                </div>
                            )}

                            <div className="space-y-4">
                                <div><label className="text-xs font-bold text-slate-400 block mb-1">الاسم</label>
                                    <input type="text" value={extractedData.name} onChange={e => setExtractedData({ ...extractedData, name: e.target.value })} className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl font-bold dark:text-white focus:ring-2 focus:ring-primary/20 transition-all" /></div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div><label className="text-xs font-bold text-slate-400 block mb-1">السن</label>
                                        <input type="text" value={extractedData.age} onChange={e => setExtractedData({ ...extractedData, age: e.target.value })} className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl font-bold dark:text-white focus:ring-2 focus:ring-primary/20 transition-all" /></div>
                                    <div><label className="text-xs font-bold text-slate-400 block mb-1">رقم الهاتف</label>
                                        <input type="text" value={extractedData.phone} onChange={e => setExtractedData({ ...extractedData, phone: e.target.value })} className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl font-bold dark:text-white text-left focus:ring-2 focus:ring-primary/20 transition-all" dir="ltr" /></div>
                                </div>
                                <div><label className="text-xs font-bold text-slate-400 block mb-1">العنوان</label>
                                    <input type="text" value={extractedData.address} onChange={e => setExtractedData({ ...extractedData, address: e.target.value })} className="w-full p-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl font-bold dark:text-white focus:ring-2 focus:ring-primary/20 transition-all" /></div>
                            </div>
                        </div>
                    )}

                    {isProcessing && (
                        <div className="absolute inset-0 bg-black/80 backdrop-blur-sm flex flex-col items-center justify-center text-white z-50">
                            <Loader2 className="animate-spin text-primary mb-4" size={48} />
                            <p className="font-black text-xl">{ocrStatus}</p>
                        </div>
                    )}
                </div>

                <div className="p-8 flex gap-4 bg-slate-50 dark:bg-slate-900/50">
                    {isReviewing ? (
                        <>
                            <button onClick={retake} className="flex-1 py-4 font-bold text-slate-500 hover:bg-slate-100 rounded-2xl transition-colors">إعادة تصوير</button>
                            <button onClick={() => { onScanComplete(extractedData); onClose(); }} className="flex-[2] py-4 bg-primary text-white font-black rounded-2xl shadow-xl shadow-primary/20 hover:scale-[1.02] transition-all">تأكيد وحفظ</button>
                        </>
                    ) : (
                        <div className="flex gap-4 w-full">
                            {capturedImage ? (
                                <>
                                    <button onClick={retake} className="flex-1 py-4 font-bold text-slate-500 bg-slate-200 rounded-2xl">إلغاء</button>
                                    <button onClick={() => processOCR(true)} className="flex-[2] py-4 bg-primary text-white font-black rounded-2xl shadow-lg">تحليل الصورة المرفوعة</button>
                                </>
                            ) : (
                                <button
                                    disabled={!isReady || isProcessing}
                                    onClick={() => {
                                        const canvas = canvasRef.current;
                                        const video = videoRef.current;
                                        if (video && canvas) {
                                            canvas.width = video.videoWidth;
                                            canvas.height = video.videoHeight;
                                            canvas.getContext('2d').drawImage(video, 0, 0);
                                            setCapturedImage(canvas.toDataURL('image/jpeg'));
                                            processOCR();
                                        }
                                    }}
                                    className="w-full py-5 bg-primary text-white font-black rounded-3xl flex items-center justify-center gap-3 shadow-2xl shadow-primary/30 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50"
                                >
                                    <Camera size={24} />
                                    <span>التقاط صورة الكارت</span>
                                </button>
                            )}
                        </div>
                    )}
                </div>

                <canvas ref={canvasRef} className="hidden" />
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { Printer, Trash2 } from 'lucide-react';
import { fdiToPalmer } from '@/utils/toothUtils';
import { useTranslation } from 'react-i18next';

const PatientBilling = ({
    patientId,
    history,
    payments,
    onAddPayment,
    onDeletePayment,
    onPrintInvoice
}) => {
    const { t } = useTranslation();
    const [billingTab, setBillingTab] = useState('invoices');

    const totalTreatments = history.reduce((acc, curr) => acc + (curr.cost - (curr.discount || 0)), 0);
    const totalPayments = payments.reduce((acc, curr) => acc + curr.amount, 0);
    const totalRemaining = totalTreatments - totalPayments;

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
            {/* Sub Tabs and Print Button */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-200 pb-4">
                <div className="flex bg-slate-100 p-1.5 rounded-xl">
                    <button
                        onClick={() => setBillingTab('invoices')}
                        className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${billingTab === 'invoices' ? 'bg-white text-primary shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        {t('patientDetails.billing.tabs.invoices')}
                    </button>
                    <button
                        onClick={() => setBillingTab('payments')}
                        className={`px-6 py-2 rounded-lg text-sm font-bold transition-all ${billingTab === 'payments' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        {t('patientDetails.billing.tabs.payments')}
                    </button>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={onAddPayment} className="text-white bg-emerald-500 hover:bg-emerald-600 px-4 py-2 rounded-xl text-sm font-bold transition-colors shadow-lg shadow-emerald-500/20">
                        {t('patientDetails.billing.add_payment')}
                    </button>
                    <button onClick={onPrintInvoice} className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-900 shadow-lg shadow-slate-800/20 text-sm">
                        <Printer size={16} /> {t('patientDetails.billing.print_invoice')}
                    </button>
                </div>
            </div>

            {/* Summary Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.billing.stats.total_treatments')}</p>
                    <p className="text-2xl font-bold text-slate-800">
                        {totalTreatments}
                    </p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.billing.stats.paid')}</p>
                    <p className="text-2xl font-bold text-emerald-600">{totalPayments}</p>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">{t('patientDetails.billing.stats.remaining')}</p>
                    <p className="text-2xl font-bold text-slate-400">
                        {totalRemaining}
                    </p>
                </div>
            </div>

            {/* Invoices Tab Content */}
            {billingTab === 'invoices' && (
                <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                    <div className="p-4 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
                        <h3 className="font-bold text-slate-700">{t('patientDetails.billing.invoices_title')}</h3>
                        <span className="text-xs bg-slate-200 text-slate-600 px-2 py-1 rounded-md">{t('patientDetails.billing.procedure_count', { count: history.length })}</span>
                    </div>
                    <div className="overflow-x-auto">
                        <table className="w-full text-right">
                            <thead className="bg-slate-50 text-slate-600 text-sm font-bold">
                                <tr>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.date')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.treatment')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.cost')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.discount')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.net')}</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {history.map(item => (
                                    <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="p-4 whitespace-nowrap text-sm text-slate-600">{new Date(item.date).toLocaleDateString()}</td>
                                        <td className="p-4 font-bold text-slate-700">{item.procedure} <span className="text-xs font-normal text-slate-400">({fdiToPalmer(item.tooth_number) || ''})</span></td>
                                        <td className="p-4 font-bold text-slate-800">{item.cost}</td>
                                        <td className="p-4 text-red-500">{item.discount > 0 ? item.discount : '-'}</td>
                                        <td className="p-4 font-bold text-emerald-600">{item.cost - (item.discount || 0)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    {history.length === 0 && <div className="p-8 text-center text-slate-400">{t('patientDetails.billing.empty_treatments')}</div>}
                </div>
            )}

            {/* Payments Tab Content */}
            {billingTab === 'payments' && (
                <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                    <div className="p-4 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
                        <h3 className="font-bold text-slate-700">{t('patientDetails.billing.payments_title')}</h3>
                    </div>
                    <div className="overflow-x-auto">
                        <table className="w-full text-right">
                            <thead className="bg-slate-50 text-slate-600 text-sm font-bold">
                                <tr>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.date')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.amount')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.notes')}</th>
                                    <th className="p-4 whitespace-nowrap">{t('patientDetails.billing.table.actions')}</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {payments.map(item => (
                                    <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="p-4 whitespace-nowrap">{new Date(item.date).toLocaleDateString()}</td>
                                        <td className="p-4 font-bold text-emerald-600 text-lg">{item.amount}</td>
                                        <td className="p-4 text-slate-500">{item.notes || '-'}</td>
                                        <td className="p-4">
                                            <button onClick={() => onDeletePayment(item.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={16} /></button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    {payments.length === 0 && <div className="p-8 text-center text-slate-400">{t('patientDetails.billing.empty_payments')}</div>}
                </div>
            )}
        </div>
    );
};

export default PatientBilling;

import React, { useState, useEffect } from 'react';
import { api } from '@/api';
import { Shield, Smartphone, Key, Monitor, Smartphone as PhoneIcon, X } from 'lucide-react';

export default function SecuritySettings() {
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [user, setUser] = useState(null);

    // 2FA Flow
    const [show2FAModal, setShow2FAModal] = useState(false);
    const [secret, setSecret] = useState('');
    const [otpUrl, setOtpUrl] = useState('');
    const [verificationCode, setVerificationCode] = useState('');

    useEffect(() => {
        fetchSecurityData();
    }, []);

    const fetchSecurityData = async () => {
        try {
            setLoading(true);
            const [userRes, sessionRes] = await Promise.all([
                api.get('/users/me'),
                api.get('/api/v1/auth/sessions')
            ]);
            setUser(userRes.data);
            setSessions(sessionRes.data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const handleRevokeSession = async (sessionId) => {
        if (!window.confirm("هل أنت متأكد من تسجيل خروج هذا الجهاز؟")) return;
        try {
            await api.delete(`/api/v1/auth/sessions/${sessionId}`);
            fetchSecurityData();
        } catch (error) {
            alert("فشل قطع الاتصال");
        }
    };

    const start2FASetup = async () => {
        try {
            const res = await api.post('/api/v1/auth/2fa/setup');
            setSecret(res.data.secret);
            setOtpUrl(res.data.otpauth_url);
            setShow2FAModal(true);
        } catch (error) {
            alert("فشل بدء إعداد المصادقة الثنائية");
        }
    };

    const handleVerify2FA = async () => {
        try {
            await api.post('/api/v1/auth/2fa/verify', null, {
                params: { code: verificationCode, secret: secret }
            });
            alert("تم تفعيل المصادقة الثنائية بنجاح!");
            setShow2FAModal(false);
            setSecret('');
            setVerificationCode('');
            fetchSecurityData();
        } catch (error) {
            alert("رمز التحقق غير صحيح");
        }
    };

    if (loading) return <div>جاري التحميل...</div>;

    return (
        <div className="space-y-8 animate-fade-in-up">
            {/* 2FA Status Card */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex justify-between items-center">
                    <div className="flex items-center gap-4">
                        <div className={`p-4 rounded-2xl ${user.is_2fa_enabled ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                            <Shield size={32} />
                        </div>
                        <div>
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white">المصادقة الثنائية (2FA)</h3>
                            <p className="text-slate-500 mt-1">
                                {user.is_2fa_enabled
                                    ? "حسابك محمي بواسطة المصادقة الثنائية."
                                    : "تأمين حسابك يتطلب خطوة إضافية عند تسجيل الدخول."}
                            </p>
                        </div>
                    </div>

                    {!user.is_2fa_enabled ? (
                        <button
                            onClick={start2FASetup}
                            className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-500/20"
                        >
                            تفعيل الحماية
                        </button>
                    ) : (
                        <span className="px-4 py-2 bg-emerald-100 text-emerald-700 rounded-lg font-bold">
                            الخدمة مفعلة
                        </span>
                    )}
                </div>
            </div>

            {/* Active Sessions List */}
            <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 overflow-hidden">
                <div className="p-6 border-b border-slate-100 dark:border-slate-800">
                    <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                        <Monitor className="text-indigo-500" />
                        الجلسات النشطة (Active Sessions)
                    </h3>
                </div>
                <div className="divide-y divide-slate-100 dark:divide-slate-800">
                    {sessions.map(session => (
                        <div key={session.id} className="p-6 flex justify-between items-center hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                            <div className="flex items-center gap-4">
                                <div className="p-3 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500">
                                    {session.device_info?.toLowerCase().includes('mobile') ? <PhoneIcon /> : <Monitor />}
                                </div>
                                <div>
                                    <p className="font-bold text-slate-800 dark:text-white dir-ltr text-left">
                                        {session.ip_address}
                                        {session.token_hash /* Ideally don't show hash, show 'Current Session' if matches */}
                                    </p>
                                    <p className="text-sm text-slate-500 mt-1" dir-ltr>
                                        Last active: {new Date(session.last_active_at).toLocaleString()}
                                    </p>
                                    <p className="text-xs text-slate-400 mt-0.5 truncate max-w-md" dir="ltr">
                                        {session.user_agent}
                                    </p>
                                </div>
                            </div>

                            <button
                                onClick={() => handleRevokeSession(session.id)}
                                className="text-red-500 hover:bg-red-50 px-4 py-2 rounded-lg font-bold text-sm transition-colors"
                            >
                                تسجيل خروج
                            </button>
                        </div>
                    ))}
                    {sessions.length === 0 && (
                        <div className="p-8 text-center text-slate-400">لا توجد جلسات نشطة أخرى.</div>
                    )}
                </div>
            </div>

            {/* 2FA Setup Modal */}
            {show2FAModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-6">
                        <div className="flex justify-between items-center">
                            <h3 className="text-xl font-bold text-slate-800 dark:text-white">إعداد المصادقة الثنائية</h3>
                            <button onClick={() => setShow2FAModal(false)}><X className="text-slate-400" /></button>
                        </div>

                        <div className="space-y-4 text-center">
                            <div className="bg-slate-100 p-4 rounded-xl mx-auto inline-block">
                                {/* In real app: <QRCode value={otpUrl} /> */}
                                <Smartphone size={64} className="text-slate-400 mx-auto" />
                                <p className="text-xs text-slate-500 mt-2 font-mono break-all">{secret}</p>
                            </div>

                            <p className="text-slate-600 dark:text-slate-300 text-sm">
                                امسح الكود باستخدام تطبيق Google Authenticator أو أدخل الرمز السري يدوياً (محاكاة: أدخل 123456).
                            </p>

                            <input
                                type="text"
                                placeholder="أدخل الرمز (مثال: 123456)"
                                className="w-full text-center text-2xl tracking-widest px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 outline-none font-mono"
                                value={verificationCode}
                                onChange={(e) => setVerificationCode(e.target.value)}
                            />

                            <button
                                onClick={handleVerify2FA}
                                className="w-full py-3 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold shadow-lg"
                            >
                                تفعيل وتأكيد
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Database, Upload, Download, AlertTriangle } from 'lucide-react';
import * as api from '@/api';

const BackupSettings = ({ backupStatus, currentUser, setMessage, loadUserInfo }) => {
    const { t } = useTranslation();
    const [restoring, setRestoring] = useState(false);

    const handleDownload = async () => {
        try {
            const response = await api.exportTenantBackup();
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            const timestamp = new Date().toISOString().split('T')[0];
            link.setAttribute('download', `clinic_backup_${timestamp}.json`);
            document.body.appendChild(link);
            link.click();
            link.remove();
        } catch (err) {
            let msg = 'فشل تحميل النسخة الاحتياطية';
            if (err.response?.data?.detail) msg = err.response.data.detail;
            setMessage({ type: 'error', text: msg });
        }
    };

    const handleUpload = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        if (!window.confirm(t('backup.restore_warning'))) return;

        const formData = new FormData();
        formData.append('file', file);
        try {
            setRestoring(true);
            await api.uploadBackup(formData);
            setMessage({ type: 'success', text: t('backup.restore_success') });
            setTimeout(() => window.location.reload(), 2000);
        } catch (err) {
            setMessage({ type: 'error', text: 'فشل استعادة البيانات' });
            setRestoring(false);
        }
    };

    const handlePurge = async () => {
        if (!window.confirm(t('backup.danger_zone.purge_confirm'))) return;

        try {
            await api.purgeDeletedPatients(currentUser.tenant_id);
            setMessage({ type: 'success', text: t('backup.danger_zone.purge_success') });
        } catch (err) {
            setMessage({ type: 'error', text: 'فشل تنفيذ العملية' });
        }
    };

    return (
        <div className="space-y-8">
            {/* Google Drive */}
            <div className="space-y-4">
                <h3 className="font-bold text-lg flex items-center gap-2 text-slate-700 dark:text-slate-200">
                    <div className="p-2 bg-blue-100 text-blue-600 rounded-lg"><Database size={20} /></div>
                    {t('backup.cloud_title')}
                </h3>

                <div className={`p-6 rounded-2xl border ${backupStatus.connected ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-200'}`}>
                    <div className="flex justify-between items-center mb-4">
                        <div>
                            <p className="font-bold text-slate-800">{t('backup.status_label')}</p>
                            <p className={`text-sm ${backupStatus.connected ? 'text-emerald-600' : 'text-slate-500'}`}>
                                {backupStatus.loading ? t('backup.checking') : (backupStatus.connected ? t('backup.connected') : t('backup.disconnected'))}
                            </p>
                        </div>
                        {!backupStatus.connected && !backupStatus.loading && (
                            <button
                                onClick={async () => {
                                    try {
                                        const res = await api.getGoogleAuthUrl();
                                        window.location.href = res.data.url;
                                    } catch (err) { setMessage({ type: 'error', text: 'فشل الاتصال' }) }
                                }}
                                className="px-6 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700"
                            >
                                {t('backup.connect_btn')}
                            </button>
                        )}
                    </div>

                    {backupStatus.connected && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-slate-200/50">
                            <div>
                                <label className="text-sm font-bold text-slate-600">{t('backup.auto_backup_label')}</label>
                                <select
                                    defaultValue={currentUser?.tenant?.backup_frequency || 'off'}
                                    onChange={async (e) => {
                                        await api.updateBackupSchedule(e.target.value);
                                        setMessage({ type: 'success', text: 'تم تحديث الجدول' });
                                    }}
                                    className="w-full mt-2 p-3 bg-white border border-slate-200 rounded-xl"
                                >
                                    <option value="off">{t('backup.off')}</option>
                                    <option value="daily">{t('backup.daily')}</option>
                                    <option value="weekly">{t('backup.weekly')}</option>
                                    <option value="monthly">{t('backup.monthly')}</option>
                                </select>
                            </div>
                            <div className="flex items-end">
                                <button
                                    onClick={async () => {
                                        setMessage({ type: 'success', text: 'جاري النسخ...' });
                                        await api.triggerManualBackup();
                                        setMessage({ type: 'success', text: t('backup.backup_success') });
                                        loadUserInfo();
                                    }}
                                    className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 text-center"
                                >
                                    {t('backup.backup_now')}
                                </button>
                            </div>
                            {currentUser?.tenant?.last_backup_at && (
                                <p className="md:col-span-2 text-xs text-slate-500 text-center">
                                    {t('backup.curr_backup')} {new Date(currentUser.tenant.last_backup_at + "Z").toLocaleString('ar-EG')}
                                </p>
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Local Backup */}
            <div className="space-y-4 pt-6 border-t dark:border-white/10">
                <h3 className="font-bold text-lg flex items-center gap-2 text-slate-700 dark:text-slate-200">
                    <div className="p-2 bg-amber-100 text-amber-600 rounded-lg"><Upload size={20} /></div>
                    {t('backup.local_title')}
                </h3>
                <div className="grid grid-cols-2 gap-4">
                    <button onClick={handleDownload} className="p-6 border-2 border-slate-200 border-dashed rounded-2xl hover:bg-slate-50 transition flex flex-col items-center gap-3">
                        <Download className="text-slate-400" size={32} />
                        <span className="font-bold text-slate-600">{t('backup.download_btn')}</span>
                    </button>

                    <div className="relative">
                        <input type="file" accept=".json,.db,.sql" onChange={handleUpload} disabled={restoring} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-10" />
                        <div className="h-full p-6 border-2 border-amber-200 border-dashed rounded-2xl bg-amber-50/50 flex flex-col items-center justify-center gap-3">
                            {restoring ? <div className="animate-spin h-8 w-8 border-4 border-amber-500 border-t-transparent rounded-full" /> : <Upload className="text-amber-500" size={32} />}
                            <span className="font-bold text-amber-700">{t('backup.restore_btn')}</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Danger Zone */}
            <div className="space-y-4 pt-6 border-t border-red-100 dark:border-red-900/30">
                <h3 className="font-bold text-lg flex items-center gap-2 text-red-600">
                    <div className="p-2 bg-red-100 text-red-600 rounded-lg"><AlertTriangle size={20} /></div>
                    {t('backup.danger_zone.title')}
                </h3>
                <div className="p-6 bg-red-50 border border-red-100 rounded-2xl flex flex-col md:flex-row justify-between items-center gap-4">
                    <div>
                        <h4 className="font-bold text-red-700">{t('backup.danger_zone.purge_patients')}</h4>
                        <p className="text-sm text-red-600/80 mt-1">{t('backup.danger_zone.purge_desc')}</p>
                    </div>
                    <button
                        onClick={handlePurge}
                        className="px-6 py-2 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 whitespace-nowrap"
                    >
                        {t('common.delete')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default BackupSettings;

import React, { useState, useEffect } from 'react';
import { getMaterials, getProcedureWeights, setProcedureWeight, deleteProcedureWeight } from '@/api/inventory';
import * as api from '@/api';
import { Package, X, Search, Plus, Edit2, Trash2 } from 'lucide-react';

const ProceduresMaterialsModal = ({ isOpen, onClose, procedure }) => {
    const [materials, setMaterials] = useState([]);
    const [weights, setWeights] = useState([]);
    const [loading, setLoading] = useState(false);

    // Form state
    const [selectedMaterial, setSelectedMaterial] = useState('');
    const [amount, setAmount] = useState(1);

    useEffect(() => {
        if (isOpen && procedure) {
            loadData();
        }
    }, [isOpen, procedure]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [matRes, weightRes] = await Promise.all([
                getMaterials(),
                getProcedureWeights({ procedure_id: procedure.id })
            ]);
            setMaterials(matRes.data);
            setWeights(weightRes.data);
        } catch (err) {
            console.error("Failed to load inventory data", err);
        } finally {
            setLoading(false);
        }
    };

    const handleAdd = async () => {
        if (!selectedMaterial || amount <= 0) return;
        try {
            await setProcedureWeight({
                procedure_name: procedure.name, // API uses name currently
                material_id: parseInt(selectedMaterial),
                weight: parseFloat(amount)
            });
            loadData();
            setSelectedMaterial('');
            setAmount(1);
        } catch (err) {
            alert('فشل إضافة المادة');
        }
    };

    const handleDelete = async (weightId) => {
        if (!window.confirm('هل أنت متأكد من إزالة هذه المادة من الإجراء؟')) return;
        try {
            await deleteProcedureWeight(weightId);
            loadData();
        } catch (err) {
            alert('فشل حذف المادة');
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in">
            <div className="bg-white dark:bg-slate-800 w-full max-w-2xl rounded-3xl p-6 shadow-2xl scale-100 animate-in zoom-in-95 duration-200 flex flex-col">
                <div className="flex justify-between items-center mb-6">
                    <div>
                        <h3 className="text-xl font-bold text-slate-800 dark:text-white">إدارة مواد: {procedure?.name}</h3>
                        <p className="text-sm text-slate-500">تكوين المواد المستهلكة لهذا الإجراء</p>
                    </div>
                    <button onClick={onClose}><X /></button>
                </div>

                <div className="space-y-4 animate-in fade-in slide-in-from-left-4">
                    <div className="flex gap-2 items-end bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-100 dark:border-slate-700">
                        <div className="flex-1">
                            <label className="text-xs font-bold mb-1 block text-slate-600 dark:text-slate-400">المادة</label>
                            <select
                                value={selectedMaterial}
                                onChange={e => setSelectedMaterial(e.target.value)}
                                className="w-full p-2 rounded-lg border bg-white dark:bg-slate-800 dark:border-slate-600"
                            >
                                <option value="">اختر مادة...</option>
                                {materials.map(m => (
                                    <option key={m.id} value={m.id}>{m.name} ({m.base_unit})</option>
                                ))}
                            </select>
                        </div>
                        <div className="w-24">
                            <label className="text-xs font-bold mb-1 block text-slate-600 dark:text-slate-400">الكمية</label>
                            <input
                                type="number" step="0.1"
                                value={amount}
                                onChange={e => setAmount(e.target.value)}
                                className="w-full p-2 rounded-lg border text-center bg-white dark:bg-slate-800 dark:border-slate-600"
                            />
                        </div>
                        <button
                            onClick={handleAdd}
                            disabled={!selectedMaterial}
                            className="bg-indigo-600 text-white p-2.5 rounded-lg hover:bg-indigo-700 disabled:opacity-50"
                        >
                            <Plus size={20} />
                        </button>
                    </div>

                    {/* List */}
                    <div className="space-y-2">
                        {weights.length === 0 ? (
                            <div className="text-center py-8 text-slate-400">لا توجد مواد مرتبطة بهذا الإجراء</div>
                        ) : weights.map(w => {
                            const mat = materials.find(m => m.id === w.material_id);
                            return (
                                <div key={w.id} className="flex justify-between items-center p-3 bg-white dark:bg-slate-800 border dark:border-slate-700 rounded-xl shadow-sm">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 rounded-lg"><Package size={18} /></div>
                                        <div>
                                            <div className="font-bold dark:text-slate-200">{mat?.name || 'مادة غير معروفة'}</div>
                                            <div className="text-xs text-slate-500">يخصم: {w.weight} {mat?.base_unit}</div>
                                        </div>
                                    </div>
                                    <button onClick={() => handleDelete(w.id)} className="text-xs text-red-500 hover:align-baseline hover:text-red-700">حذف</button>
                                </div>
                            );
                        })}
                    </div>

                    <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg text-xs text-blue-700 dark:text-blue-300 mt-4">
                        💡 لتحليل التكلفة واستهلاك المواد (Coverage)، انتقل إلى قسم <b>التحليلات الذكية</b>.
                    </div>
                </div>

                <div className="pt-4 border-t dark:border-slate-700 mt-6">
                    <button onClick={onClose} className="w-full py-3 bg-slate-100 dark:bg-slate-700 text-slate-700 dark:text-slate-300 font-bold rounded-xl hover:bg-slate-200 dark:hover:bg-slate-600">إغلاق</button>
                </div>
            </div>
        </div>
    );
};

const ProceduresSettings = ({ setMessage }) => {
    const [procedures, setProcedures] = useState([]);
    const [isProcLoading, setIsProcLoading] = useState(false);
    const [isProcModalOpen, setIsProcModalOpen] = useState(false);
    const [editingProc, setEditingProc] = useState(null);
    const [newProc, setNewProc] = useState({ name: '', price: '' });
    const [procSearch, setProcSearch] = useState('');

    // Material Modal State
    const [materialModal, setMaterialModal] = useState({ open: false, procedure: null });

    useEffect(() => {
        loadProcedures();
    }, []);

    const loadProcedures = async () => {
        setIsProcLoading(true);
        try {
            const res = await api.getProcedures();
            setProcedures(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setIsProcLoading(false);
        }
    };

    const handleSaveProcedure = async (e) => {
        e.preventDefault();
        try {
            const payload = {
                name: newProc.name,
                price: parseFloat(newProc.price) || 0
            };
            if (editingProc) {
                await api.updateProcedure(editingProc.id, payload);
            } else {
                await api.createProcedure(payload);
            }
            setIsProcModalOpen(false);
            setNewProc({ name: '', price: '' });
            setEditingProc(null);
            loadProcedures();
            setMessage({ type: 'success', text: editingProc ? 'تم تعديل الإجراء بنجاح' : 'تم إضافة الإجراء بنجاح' });
            setTimeout(() => setMessage(null), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'حدث خطأ أثناء الحفظ' });
        }
    };

    const handleDeleteProcedure = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذا الإجراء؟')) return;
        try {
            await api.deleteProcedure(id);
            loadProcedures();
            setMessage({ type: 'success', text: 'تم حذف الإجراء بنجاح' });
            setTimeout(() => setMessage(null), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'فشل الحذف' });
        }
    };

    const openEditProc = (proc) => {
        setEditingProc(proc);
        setNewProc({ name: proc.name, price: proc.price });
        setIsProcModalOpen(true);
    };

    const filteredProcedures = procedures.filter(p => p.name.toLowerCase().includes(procSearch.toLowerCase()));

    return (
        <div className="space-y-6">
            <div className="flex justify-between gap-4">
                <div className="relative flex-1">
                    <Search className="absolute right-4 top-3.5 text-slate-400" size={20} />
                    <input
                        type="text"
                        placeholder="بحث عن إجراء..."
                        className="w-full p-3 pr-12 bg-slate-50 dark:bg-slate-900/50 rounded-xl border border-slate-200 outline-none focus:border-indigo-500 font-bold"
                        value={procSearch}
                        onChange={(e) => setProcSearch(e.target.value)}
                    />
                </div>
                <button
                    onClick={() => {
                        setEditingProc(null);
                        setNewProc({ name: '', price: '' });
                        setIsProcModalOpen(true);
                    }}
                    className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition flex items-center gap-2"
                >
                    <Plus size={20} />
                    إضافة
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {isProcLoading ? (
                    <div className="col-span-2 text-center py-10 text-slate-500">جاري التحميل...</div>
                ) : filteredProcedures.map(proc => (
                    <div key={proc.id} className="group p-4 bg-slate-50 dark:bg-slate-900/30 rounded-xl border border-slate-100 dark:border-white/5 flex justify-between items-center hover:bg-white dark:hover:bg-slate-800 transition-colors shadow-sm hover:shadow-md">
                        <div>
                            <h4 className="font-bold text-slate-800 dark:text-white">{proc.name}</h4>
                            <p className="text-indigo-600 font-bold mt-1">{proc.price} ج.م</p>
                        </div>
                        <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button
                                onClick={() => setMaterialModal({ open: true, procedure: proc })}
                                className="p-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg"
                                title="المواد المستهلكة"
                            >
                                <Package size={18} />
                            </button>
                            <button onClick={() => openEditProc(proc)} className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg"><Edit2 size={18} /></button>
                            <button onClick={() => handleDeleteProcedure(proc.id)} className="p-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg"><Trash2 size={18} /></button>
                        </div>
                    </div>
                ))}
            </div>

            {/* Proc Modal */}
            {isProcModalOpen && (
                <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in">
                    <div className="bg-white dark:bg-slate-800 w-full max-w-md rounded-3xl p-8 shadow-2xl scale-100 animate-in zoom-in-95 duration-200">
                        <h3 className="text-2xl font-bold mb-6 text-slate-800 dark:text-white">{editingProc ? 'تعديل الخدمة' : 'إضافة خدمة جديدة'}</h3>
                        <form onSubmit={handleSaveProcedure} className="space-y-5">
                            <div>
                                <label className="text-sm font-bold text-slate-600 dark:text-slate-400 mb-2 block">اسم الخدمة</label>
                                <input
                                    value={newProc.name}
                                    onChange={e => setNewProc({ ...newProc, name: e.target.value })}
                                    className="w-full p-4 bg-slate-50 dark:bg-slate-900 rounded-xl outline-none border focus:border-indigo-500 font-bold"
                                    required
                                />
                            </div>
                            <div>
                                <label className="text-sm font-bold text-slate-600 dark:text-slate-400 mb-2 block">السعر (ج.م)</label>
                                <input
                                    value={newProc.price}
                                    onChange={e => setNewProc({ ...newProc, price: e.target.value })}
                                    type="number"
                                    className="w-full p-4 bg-slate-50 dark:bg-slate-900 rounded-xl outline-none border focus:border-indigo-500 font-bold"
                                    required
                                />
                            </div>
                            <div className="flex gap-3 mt-8">
                                <button type="button" onClick={() => setIsProcModalOpen(false)} className="flex-1 py-3 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl font-bold text-slate-600 transition">إلغاء</button>
                                <button type="submit" className="flex-1 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 font-bold shadow-lg shadow-indigo-500/20 transition">حفظ</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Materials Modal */}
            <ProceduresMaterialsModal
                isOpen={materialModal.open}
                onClose={() => setMaterialModal({ ...materialModal, open: false })}
                procedure={materialModal.procedure}
            />
        </div>
    );
};

export default ProceduresSettings;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Save, Plus, Trash2, Printer, Edit3 } from 'lucide-react';
import { getSavedMedications, saveMedication, deleteSavedMedication, updateTenantSettings, getTenantSettings } from '@/api';

export default function RxSettings({ setMessage }) {
    const { t } = useTranslation();
    const [headerInfo, setHeaderInfo] = useState({
        doctor_name: '',
        doctor_title: '',
        clinic_address: '',
        clinic_phone: ''
    });
    const [medications, setMedications] = useState([]);
    const [newMed, setNewMed] = useState({ name: '', default_dose: '', notes: '' });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            const [settingsRes, medsRes] = await Promise.all([
                getTenantSettings(),
                getSavedMedications()
            ]);

            // Populate header info if exists
            setHeaderInfo({
                doctor_name: settingsRes.data.doctor_name || '',
                doctor_title: settingsRes.data.doctor_title || '',
                clinic_address: settingsRes.data.clinic_address || '',
                clinic_phone: settingsRes.data.clinic_phone || ''
            });

            setMedications(medsRes.data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleSaveHeader = async () => {
        setLoading(true);
        try {
            await updateTenantSettings(headerInfo);
            setMessage({ type: 'success', text: 'تم حفظ إعدادات الروشتة' });
        } catch (err) {
            setMessage({ type: 'error', text: 'فشل الحفظ' });
        } finally {
            setLoading(false);
        }
    };

    const handleAddMedication = async (e) => {
        e.preventDefault();
        if (!newMed.name) return;

        try {
            const res = await saveMedication(newMed);
            setMedications([...medications, res.data]);
            setNewMed({ name: '', default_dose: '', notes: '' });
            setMessage({ type: 'success', text: 'تم إضافة الدواء' });
        } catch (err) {
            setMessage({ type: 'error', text: err.response?.data?.detail || 'فشل الإضافة' });
        }
    };

    const handleDeleteMed = async (id) => {
        if (!window.confirm('هل أنت متأكد من الحذف؟')) return;
        try {
            await deleteSavedMedication(id);
            setMedications(medications.filter(m => m.id !== id));
            setMessage({ type: 'success', text: 'تم الحذف' });
        } catch (err) {
            setMessage({ type: 'error', text: 'فشل الحذف' });
        }
    };

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

            {/* Header Settings Section */}
            <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-white/5 p-6 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-indigo-100 dark:bg-indigo-500/10 flex items-center justify-center text-indigo-600">
                        <Printer size={20} />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">{t('rx_settings.title')}</h3>
                        <p className="text-sm text-slate-500">{t('rx_settings.subtitle')}</p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('rx_settings.doctor_name')}</label>
                        <input
                            type="text"
                            value={headerInfo.doctor_name}
                            onChange={(e) => setHeaderInfo({ ...headerInfo, doctor_name: e.target.value })}
                            placeholder={t('rx_settings.doctor_name')}
                            className="w-full p-3 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 outline-none focus:border-indigo-500 transition-colors"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('rx_settings.doctor_title')}</label>
                        <input
                            type="text"
                            value={headerInfo.doctor_title}
                            onChange={(e) => setHeaderInfo({ ...headerInfo, doctor_title: e.target.value })}
                            placeholder={t('rx_settings.doctor_title')}
                            className="w-full p-3 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 outline-none focus:border-indigo-500 transition-colors"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('rx_settings.address')}</label>
                        <input
                            type="text"
                            value={headerInfo.clinic_address}
                            onChange={(e) => setHeaderInfo({ ...headerInfo, clinic_address: e.target.value })}
                            placeholder={t('rx_settings.address')}
                            className="w-full p-3 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 outline-none focus:border-indigo-500 transition-colors"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('rx_settings.phone')}</label>
                        <input
                            type="text"
                            dir="ltr"
                            value={headerInfo.clinic_phone}
                            onChange={(e) => setHeaderInfo({ ...headerInfo, clinic_phone: e.target.value })}
                            placeholder="010xxxxxxx"
                            className="w-full p-3 bg-slate-50 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-700 outline-none focus:border-indigo-500 transition-colors text-right"
                        />
                    </div>
                </div>

                <div className="mt-6 flex justify-end">
                    <button
                        onClick={handleSaveHeader}
                        disabled={loading}
                        className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-indigo-500/20"
                    >
                        <Save size={18} />
                        {t('rx_settings.save')}
                    </button>
                </div>
            </div>

            {/* Saved Medications Section */}
            <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-100 dark:border-white/5 p-6 shadow-sm">
                <div className="flex items-center gap-3 mb-6">
                    <div className="w-10 h-10 rounded-xl bg-emerald-100 dark:bg-emerald-500/10 flex items-center justify-center text-emerald-600">
                        <Plus size={20} />
                    </div>
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">{t('rx_settings.saved_meds')}</h3>
                        <p className="text-sm text-slate-500">{t('rx_settings.saved_meds_subtitle')}</p>
                    </div>
                </div>

                {/* Add Form */}
                <form onSubmit={handleAddMedication} className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl mb-6 grid grid-cols-1 md:grid-cols-4 gap-4 items-end border border-slate-200 dark:border-slate-700">
                    <div className="md:col-span-1">
                        <label className="block text-xs font-bold text-slate-500 mb-1">{t('rx_settings.med_name')}</label>
                        <input
                            type="text"
                            required
                            dir="ltr"
                            value={newMed.name}
                            onChange={(e) => setNewMed({ ...newMed, name: e.target.value })}
                            className="w-full p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-600 outline-none focus:border-emerald-500 text-left"
                            placeholder={t('rx_settings.plac_name')}
                        />
                    </div>
                    <div className="md:col-span-1">
                        <label className="block text-xs font-bold text-slate-500 mb-1">{t('rx_settings.dose')}</label>
                        <input
                            type="text"
                            value={newMed.default_dose}
                            onChange={(e) => setNewMed({ ...newMed, default_dose: e.target.value })}
                            className="w-full p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-600 outline-none focus:border-emerald-500"
                            placeholder={t('rx_settings.plac_dose')}
                        />
                    </div>
                    <div className="md:col-span-1">
                        <label className="block text-xs font-bold text-slate-500 mb-1">{t('rx_settings.notes')}</label>
                        <input
                            type="text"
                            value={newMed.notes}
                            onChange={(e) => setNewMed({ ...newMed, notes: e.target.value })}
                            className="w-full p-2 bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-600 outline-none focus:border-emerald-500"
                            placeholder={t('rx_settings.plac_notes')}
                        />
                    </div>
                    <button
                        type="submit"
                        className="bg-emerald-500 hover:bg-emerald-600 text-white p-2 rounded-lg font-bold flex items-center justify-center gap-2 transition-colors h-[42px]"
                    >
                        <Plus size={18} />
                        {t('rx_settings.add_btn')}
                    </button>
                </form>

                {/* List */}
                <div className="overflow-x-auto">
                    <table className="w-full text-right">
                        <thead>
                            <tr className="border-b border-slate-100 dark:border-slate-700 text-slate-500 text-sm">
                                <th className="pb-3 pr-2 text-left">{t('rx_settings.table.name')}</th>
                                <th className="pb-3 px-2">{t('rx_settings.table.dose')}</th>
                                <th className="pb-3 px-2">{t('rx_settings.table.notes')}</th>
                                <th className="pb-3 pl-2 w-20"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                            {medications.length === 0 ? (
                                <tr>
                                    <td colSpan="4" className="py-8 text-center text-slate-400">{t('rx_settings.table.empty')}</td>
                                </tr>
                            ) : (
                                medications.map(med => (
                                    <tr key={med.id} className="group hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                                        <td className="py-3 pr-2 font-bold text-slate-800 dark:text-slate-200 text-left" dir="ltr">{med.name}</td>
                                        <td className="py-3 px-2 text-slate-600 dark:text-slate-400">{med.default_dose}</td>
                                        <td className="py-3 px-2 text-slate-500 text-sm">{med.notes}</td>
                                        <td className="py-3 pl-2 text-left">
                                            <button
                                                onClick={() => handleDeleteMed(med.id)}
                                                className="text-red-400 hover:text-red-500 p-1 rounded-lg hover:bg-red-50 dark:hover:bg-red-500/10 transition-colors opacity-0 group-hover:opacity-100"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { List, Banknote, Shield } from 'lucide-react';
import ProceduresSettings from './ProceduresSettings';
import PriceLists from '@/pages/admin/PriceLists';
import InsuranceProviders from '@/pages/admin/InsuranceProviders';
import { useTranslation } from 'react-i18next';

export default function ServicesSettings({ setMessage }) {
    const { t } = useTranslation();
    const [activeSubTab, setActiveSubTab] = useState('procedures');

    const subTabs = [
        { id: 'procedures', label: t('settings.services.tabs.procedures'), icon: List },
        { id: 'price-lists', label: t('settings.services.tabs.price_lists'), icon: Banknote },
        { id: 'insurance', label: t('settings.services.tabs.insurance'), icon: Shield },
    ];

    return (
        <div className="space-y-6">
            {/* Sub-Tab Navigation */}
            <div className="flex flex-wrap items-center gap-2 bg-slate-50 dark:bg-slate-800/50 p-1.5 rounded-xl border border-slate-100 dark:border-white/5 w-fit">
                {subTabs.map(tab => {
                    const Icon = tab.icon;
                    const isActive = activeSubTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setActiveSubTab(tab.id)}
                            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all duration-200 ${isActive
                                ? 'bg-white dark:bg-slate-800 text-indigo-600 shadow-sm border border-slate-200 dark:border-slate-700'
                                : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                                }`}
                        >
                            <Icon size={16} />
                            {tab.label}
                        </button>
                    );
                })}
            </div>

            {/* Content Area */}
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                {activeSubTab === 'procedures' && (
                    <ProceduresSettings setMessage={setMessage} />
                )}

                {activeSubTab === 'price-lists' && (
                    <PriceLists />
                )}

                {activeSubTab === 'insurance' && (
                    <InsuranceProviders />
                )}
            </div>
        </div>
    );
}

import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
    getDashboardStats,
    getAppointments,
    getTodayPayments,
    getTodayDebtors
} from '@/api';
import { queryKeys } from '@/lib/queryClient';

/**
 * Prefetch hook for dashboard (used by sidebar hover)
 */
export function usePrefetchDashboard() {
    const queryClient = useQueryClient();

    return () => {
        queryClient.prefetchQuery({
            queryKey: queryKeys.dashboardStats,
            queryFn: async () => {
                const res = await getDashboardStats();
                return res.data;
            },
            staleTime: 30 * 1000,
        });
    };
}

/**
 * Hook for dashboard statistics
 */
export function useDashboardStats() {
    return useQuery({
        queryKey: queryKeys.dashboardStats,
        queryFn: async () => {
            const res = await getDashboardStats();
            return res.data;
