import axios from 'axios';
import { API_URL } from '@/api';

const LOG_ENDPOINT = '/api/v1/system/logs';

export const logger = {
    error: async (message, stack = null, componentStack = null) => {
        try {
            // Prevent recursive logging if the logger itself fails
            const payload = {
                level: 'ERROR',
                source: 'FRONTEND',
                message: message?.toString() || 'Unknown Error',
                stack_trace: stack ? `Stack: ${stack} \nComponent: ${componentStack} ` : null,
                path: window.location.pathname,
                user_agent: navigator.userAgent
            };

            // Use fetch to avoid axios interceptor loops if axios is broken
            await fetch(`${API_URL}${LOG_ENDPOINT} `, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(payload)
            });

            console.error('[SystemLogger] Error reported:', message);

        } catch (err) {
            console.error('[SystemLogger] Failed to report error:', err);
        }
    },

    info: (message) => {
        console.log('[SystemLogger]', message);
        // Optional: Send info logs to backend if needed
    }
};

import React, { useEffect, useState } from 'react';
import { Search, Filter, CheckCircle, XCircle, Clock } from 'lucide-react';
import { getAILogs } from '@/api';

export default function AILogs() {
    const [logs, setLogs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(0);

    const fetchLogs = async (pageNum = 0) => {
        try {
            setLoading(true);
            const res = await getAILogs(pageNum * 20, 20);
            setLogs(res.data);
            setPage(pageNum);
        } catch (err) {
            console.error("Failed to load logs", err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchLogs();
    }, []);

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700" dir="rtl">

            {/* Header */}
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white">سجل العمليات 📜</h1>
                    <p className="text-slate-500 mt-2">تتبع جميع تفاعلات المساعد الذكي بالتفصيل.</p>
                </div>
                <div className="flex gap-2">
                    <button
                        disabled={page === 0}
                        onClick={() => fetchLogs(page - 1)}
                        className="px-4 py-2 rounded-xl bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 disabled:opacity-50"
                    >
                        السابق
                    </button>
                    <button
                        onClick={() => fetchLogs(page + 1)}
                        className="px-4 py-2 rounded-xl bg-primary text-white font-bold"
                    >
                        التالي
                    </button>
                </div>
            </div>

            {/* Logs Table */}
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-sm border border-slate-100 dark:border-slate-700 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-slate-50 dark:bg-slate-900/50">
                            <tr>
                                <th className="px-6 py-4 text-right text-sm font-bold text-slate-500">الوقت</th>
                                <th className="px-6 py-4 text-right text-sm font-bold text-slate-500">المستخدم</th>
                                <th className="px-6 py-4 text-right text-sm font-bold text-slate-500">السؤال</th>
                                <th className="px-6 py-4 text-right text-sm font-bold text-slate-500">الأداة</th>
                                <th className="px-6 py-4 text-right text-sm font-bold text-slate-500">الحالة</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                            {loading ? (
                                <tr><td colSpan="5" className="px-6 py-8 text-center text-slate-400">تحميل...</td></tr>
                            ) : logs.length === 0 ? (
                                <tr><td colSpan="5" className="px-6 py-8 text-center text-slate-400">لا توجد سجلات</td></tr>
                            ) : logs.map((log) => (
                                <tr key={log.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                                    <td className="px-6 py-4 text-sm text-slate-600 dark:text-slate-300">
                                        <div className="flex items-center gap-2">
                                            <Clock size={14} className="text-slate-400" />
                                            {new Date(log.created_at).toLocaleString('ar-EG')}
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200">
                                            {log.username}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-sm text-slate-800 dark:text-white max-w-xs truncate" title={log.query}>
                                        {log.query}
                                    </td>
                                    <td className="px-6 py-4 text-sm font-mono text-slate-500">
                                        {log.response_tool || '-'}
                                    </td>
                                    <td className="px-6 py-4">
                                        {log.success ? (
                                            <span className="inline-flex items-center gap-1 text-emerald-600 text-xs font-bold">
                                                <CheckCircle size={14} /> نجاح
                                            </span>
                                        ) : (
                                            <span className="inline-flex items-center gap-1 text-red-500 text-xs font-bold">
                                                <XCircle size={14} /> فشل
                                            </span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Brain, DollarSign, Activity, Zap, TrendingUp } from 'lucide-react';
import { getAIStats } from '@/api';

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

export default function AIStats() {
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const res = await getAIStats();
                setStats(res.data);
            } catch (err) {
                console.error("Failed to load AI stats", err);
            } finally {
                setLoading(false);
            }
        };
        fetchStats();
    }, []);

    if (loading) return (
        <div className="flex h-[50vh] items-center justify-center">
            <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin"></div>
                <p className="text-slate-400 font-medium">جاري تحليل البيانات...</p>
            </div>
        </div>
    );

    if (!stats) return <div className="p-8 text-center text-red-500">فشل تحميل الإحصائيات</div>;

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 pb-20" dir="rtl">

            {/* Header Section */}
            <div className="relative overflow-hidden bg-gradient-to-r from-indigo-600 to-violet-600 rounded-3xl p-8 text-white shadow-xl shadow-indigo-500/20">
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/10 rounded-full -ml-8 -mb-8 blur-2xl"></div>

                <div className="relative z-10">
                    <h1 className="text-3xl font-black mb-2 flex items-center gap-3">
                        <Brain className="w-8 h-8 text-indigo-100" />
                        مركز قيادة الذكاء الاصطناعي
                    </h1>
                    <p className="text-indigo-100/90 text-lg max-w-2xl">
                        متابعة حية لأداء المساعد الذكي، تحليل التكلفة، ونشاط المستخدمين.
                    </p>
                </div>
            </div>

            {/* Key Metrics Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <MetricCard
                    title="إجمالي الطلبات"
                    value={stats.total_requests}
                    icon={Activity}
                    color="indigo"
                    trend="+12%"
                />
                <MetricCard
                    title="التكلفة التقديرية"
                    value={`$${stats.estimated_cost}`}
                    icon={DollarSign}
                    color="emerald"
                    subtext="Llama 3 70B (Free Tier)"
                />
                <MetricCard
                    title="الأدوات النشطة"
                    value={stats.tool_usage.length}
                    icon={Zap}
                    color="amber"
                />
                <MetricCard
                    title="المستخدمين المتفاعلين"
                    value={stats.top_users.length}
                    icon={TrendingUp}
                    color="rose"
                />
            </div>

            {/* Charts Section */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

                {/* Tool Usage Chart */}
                <div className="bg-white dark:bg-slate-800 p-8 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col">
                    <div className="mb-8">
                        <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                            <span className="w-2 h-8 bg-indigo-500 rounded-full"></span>
                            أكثر الأدوات استخداماً
                        </h3>
                        <p className="text-slate-400 text-sm mt-1 mr-4">توزيع استخدام أدوات النظام المختلفة</p>
                    </div>

                    <div className="h-[400px] w-full" dir="ltr">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={stats.tool_usage} layout="vertical" margin={{ left: 20, right: 30, top: 10, bottom: 10 }}>
                                <XAxis type="number" hide />
                                <YAxis
                                    dataKey="name"
                                    type="category"
                                    width={180}
                                    tick={{ fontSize: 13, fill: '#64748b', fontWeight: 500 }}
                                    axisLine={false}
                                    tickLine={false}
                                />
                                <Tooltip
                                    cursor={{ fill: '#f1f5f9', opacity: 0.4 }}
                                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}
                                />
                                <Bar
                                    dataKey="value"
                                    fill="#6366f1"
                                    radius={[0, 6, 6, 0]}
                                    barSize={24}
                                    background={{ fill: '#f8fafc', radius: [0, 6, 6, 0] }}
                                />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Users Activity Chart */}
                <div className="bg-white dark:bg-slate-800 p-8 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-700 flex flex-col">
                    <div className="mb-8">
                        <h3 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                            <span className="w-2 h-8 bg-emerald-500 rounded-full"></span>
                            نشاط المستخدمين
                        </h3>
                        <p className="text-slate-400 text-sm mt-1 mr-4">نسبة تفاعل كل مستخدم مع النظام</p>
                    </div>

                    <div className="h-[400px] w-full relative">
                        <ResponsiveContainer width="100%" height="100%">
                            <PieChart margin={{ top: 0, right: 0, bottom: 0, left: 0 }}>
                                <Pie
                                    data={stats.top_users}
                                    cx="50%"
                                    cy="45%"
                                    innerRadius={80}
                                    outerRadius={120}
                                    paddingAngle={5}
                                    dataKey="count"
                                    stroke="none"
                                >
                                    {stats.top_users.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                    ))}
                                </Pie>
                                <Tooltip
                                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 20px rgba(0,0,0,0.1)' }}
                                />
                                <Legend
                                    verticalAlign="bottom"
                                    height={36}
                                    iconType="circle"
                                    formatter={(value) => <span className="text-slate-600 dark:text-slate-300 font-medium ml-2">{value}</span>}
                                />
                            </PieChart>
                        </ResponsiveContainer>

                        {/* Center Text */}
                        <div className="absolute top-[45%] left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                            <p className="text-3xl font-black text-slate-800 dark:text-white">{stats.total_requests}</p>
                            <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">Total</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function MetricCard({ title, value, icon: Icon, color, subtext, trend }) {
    // Map color names to tailwind classes for dynamic usage
    const colorMap = {
        indigo: 'bg-indigo-50 text-indigo-600 ring-indigo-100',
        emerald: 'bg-emerald-50 text-emerald-600 ring-emerald-100',
        amber: 'bg-amber-50 text-amber-600 ring-amber-100',
        rose: 'bg-rose-50 text-rose-600 ring-rose-100',
        blue: 'bg-blue-50 text-blue-600 ring-blue-100',
    };

    const styleClass = colorMap[color] || colorMap.indigo;

    return (
        <div className="bg-white dark:bg-slate-800 p-6 rounded-3xl shadow-[0_2px_20px_-4px_rgba(0,0,0,0.05)] border border-slate-100 dark:border-slate-700 hover:translate-y-[-4px] transition-all duration-300">
            <div className="flex justify-between items-start mb-4">
                <div className={`p-3.5 rounded-2xl ${styleClass} ring-4 ring-opacity-50`}>
                    <Icon size={24} strokeWidth={2.5} />
                </div>
                {trend && (
                    <span className="bg-emerald-100 text-emerald-700 text-xs font-bold px-2 py-1 rounded-full flex items-center">
                        {trend} ↗
                    </span>
                )}
            </div>

            <h3 className="text-3xl font-black text-slate-800 dark:text-white tracking-tight mb-1">{value}</h3>
            <p className="text-slate-500 font-medium text-sm">{title}</p>
            {subtext && <p className="text-xs text-slate-400 mt-3 pt-3 border-t border-slate-50 dark:border-slate-700 border-dashed">{subtext}</p>}
        </div>
    );
}

import React, { useState, useMemo, useCallback, memo, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useSearchParams } from 'react-router-dom';
import { Calendar, Clock, Plus, User, CheckCircle, XCircle, Trash2, LayoutGrid, List as ListIcon, Edit2, Filter } from 'lucide-react';
import { createAppointment, updateAppointmentStatus, deleteAppointment } from '@/api';
import { useAppointments } from '@/hooks/useAppointments';
import { usePatients } from '@/hooks/usePatients';
import { getTodayDateTimeStr } from '@/utils/toothUtils';
import { Button, Input, Modal, Badge, Skeleton, EmptyState, toast } from '@/shared/ui';

export default function Appointments() {
    const [searchParams, setSearchParams] = useSearchParams();
    const { t } = useTranslation();
    const preselectPatientId = searchParams.get('patient_id');
    const [viewMode, setViewMode] = useState('board'); // 'list' | 'board'
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newAppt, setNewAppt] = useState({ patient_id: '', date_time: getTodayDateTimeStr(), notes: '' });

    useEffect(() => {
        if (preselectPatientId) {
            setNewAppt(prev => ({ ...prev, patient_id: preselectPatientId }));
            setIsModalOpen(true);
            setSearchParams({}, { replace: true });
        }
    }, [preselectPatientId, setSearchParams]);

    // Use cached hooks instead of direct API calls
    const { data: appointments = [], isLoading: apptsLoading, refetch: refetchAppointments } = useAppointments();
    const { data: patients = [], isLoading: patientsLoading } = usePatients();

    const loading = apptsLoading || patientsLoading;

    const handleCreate = useCallback(async () => {
        if (!newAppt.patient_id || !newAppt.date_time) {
            toast.error(t('appointments.messages.fill_all'));
            return;
        }
        const toastId = toast.loading(t('appointments.messages.booking'));
        try {
            await createAppointment({
                ...newAppt,
                patient_id: parseInt(newAppt.patient_id)
            });
            setIsModalOpen(false);
            setNewAppt({ patient_id: '', date_time: getTodayDateTimeStr(), notes: '' });
            refetchAppointments(); // Use cached refetch
            toast.success(t('appointments.messages.booking_success'), { id: toastId });
        } catch (err) {
            toast.error(t('appointments.messages.booking_error'), { id: toastId });
        }
    }, [newAppt, refetchAppointments, t]);

    const handleStatus = useCallback(async (id, status) => {
        const toastId = toast.loading(t('appointments.messages.updating'));
        try {
            await updateAppointmentStatus(id, status);
            refetchAppointments(); // Use cached refetch
            toast.success(t('appointments.messages.update_success'), { id: toastId });
        } catch (err) {
            toast.error(t('appointments.messages.update_error'), { id: toastId });
        }
    }, [refetchAppointments, t]);

    const handleDelete = useCallback(async (id) => {
        if (!window.confirm(t('appointments.confirm_delete'))) return;
        const toastId = toast.loading(t('appointments.messages.deleting'));
        try {
            await deleteAppointment(id);
            refetchAppointments(); // Use cached refetch
            toast.success(t('appointments.messages.delete_success'), { id: toastId });
        } catch (err) {
            toast.error(t('appointments.messages.delete_error'), { id: toastId });
        }
    }, [refetchAppointments, t]);

    // Kanban Columns
    const columns = useMemo(() => [
        { id: 'Scheduled', title: t('appointments.status.scheduled'), icon: Calendar, color: 'text-blue-600', bg: 'bg-blue-50 dark:bg-blue-900/20', border: 'border-blue-200 dark:border-blue-800' },
        { id: 'Waiting', title: t('appointments.status.waiting'), icon: Clock, color: 'text-amber-600', bg: 'bg-amber-50 dark:bg-amber-900/20', border: 'border-amber-200 dark:border-amber-800' },
        { id: 'In-Chair', title: t('appointments.status.in_chair'), icon: User, color: 'text-purple-600', bg: 'bg-purple-50 dark:bg-purple-900/20', border: 'border-purple-200 dark:border-purple-800' },
        { id: 'Completed', title: t('appointments.status.completed'), icon: CheckCircle, color: 'text-emerald-600', bg: 'bg-emerald-50 dark:bg-emerald-900/20', border: 'border-emerald-200 dark:border-emerald-800' },
        { id: 'Cancelled', title: t('appointments.status.cancelled_noshow'), icon: XCircle, color: 'text-slate-600', bg: 'bg-slate-50 dark:bg-slate-800', border: 'border-slate-200 dark:border-slate-700' },
    ], [t]);

    const getColumnAppointments = (status) => {
        if (status === 'Cancelled') {
            return appointments.filter(a => ['Cancelled', 'No Show'].includes(a.status));
        }
        return appointments.filter(a => a.status === status);
    };

    const getStatusVariant = (status) => {
        switch (status) {
            case 'Scheduled': return 'info';
            case 'Completed': return 'success';
            case 'Cancelled': case 'No Show': return 'danger';
            case 'Waiting': return 'warning';
            case 'In-Chair': return 'primary';
            default: return 'default';
        }
    };

    const getStatusLabel = (status) => {
        const labels = {
            'Scheduled': t('appointments.status.scheduled'),
            'Completed': t('appointments.status.completed'),
            'Cancelled': t('appointments.status.cancelled'),
            'Waiting': t('appointments.status.waiting'),
            'In-Chair': t('appointments.status.in_chair'),
            'Postponed': t('appointments.status.postponed'),
            'No Show': t('appointments.status.no_show')
        };
        return labels[status] || status;
    };

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 min-h-screen pb-20">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-black text-text-primary tracking-tight">{t('appointments.title')}</h2>
                    <p className="text-text-secondary mt-1 font-medium">{t('appointments.subtitle')}</p>
                </div>
                <div className="flex items-center gap-3 w-full md:w-auto">
                    {/* View Toggle */}
                    <div className="bg-surface p-1 rounded-xl flex border border-border">
                        <button
                            onClick={() => setViewMode('list')}
                            className={`p-2 rounded-lg transition-all ${viewMode === 'list' ? 'bg-primary text-white shadow' : 'text-text-secondary hover:bg-surface-hover'}`}
                        >
                            <ListIcon size={18} />
                        </button>
                        <button
                            onClick={() => setViewMode('board')}
                            className={`p-2 rounded-lg transition-all ${viewMode === 'board' ? 'bg-primary text-white shadow' : 'text-text-secondary hover:bg-surface-hover'}`}
                        >
                            <LayoutGrid size={18} />
                        </button>
                    </div>

                    <Button onClick={() => setIsModalOpen(true)}>
                        <Plus size={20} className="mr-2" />
                        {t('appointments.new_booking')}
                    </Button>
                </div>
            </div>

            {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <Skeleton.Box className="h-96 w-full rounded-3xl" />
                    <Skeleton.Box className="h-96 w-full rounded-3xl" />
                    <Skeleton.Box className="h-96 w-full rounded-3xl" />
                </div>
            ) : appointments.length === 0 ? (
                <EmptyState
                    title={t('appointments.no_appointments')}
                    description={t('appointments.no_appointments_desc')}
                    icon={Calendar}
                    action={<Button onClick={() => setIsModalOpen(true)}>{t('appointments.add_appointment')}</Button>}
                />
            ) : viewMode === 'list' ? (
                // List View
                <div className="bg-surface rounded-3xl shadow-sm border border-border overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full text-start">
                            <thead className="bg-surface-hover text-text-secondary text-xs font-bold uppercase tracking-wider border-b border-border">
                                <tr>
                                    <th className="p-4 text-start">{t('appointments.table.patient')}</th>
                                    <th className="p-4 text-start">{t('appointments.table.datetime')}</th>
                                    <th className="p-4 text-start">{t('appointments.table.notes')}</th>
                                    <th className="p-4 text-start">{t('appointments.table.status')}</th>
                                    <th className="p-4 text-start">{t('appointments.table.change_status')}</th>
                                    <th className="p-4 text-center">{t('appointments.table.actions')}</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-border">
                                {appointments.map(appt => {
                                    const patient = patients.find(p => p.id === appt.patient_id);
                                    return (
                                        <tr key={appt.id} className="hover:bg-surface-hover transition-colors">
                                            <td className="p-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-xl bg-primary/10 text-primary flex items-center justify-center font-bold">
                                                        {patient?.name?.charAt(0) || '?'}
                                                    </div>
                                                    <span className="font-bold text-text-primary">{patient?.name || 'Unknown'}</span>
                                                </div>
                                            </td>
                                            <td className="p-4">
                                                <div className="flex items-center gap-2 text-text-secondary text-sm font-medium">
                                                    <Calendar size={14} />
                                                    <span dir="ltr">
                                                        {new Date(appt.date_time).toLocaleString(t('language.switch_to_en') === 'English' ? 'ar-EG' : 'en-US', {
                                                            month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
                                                        })}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="p-4 text-sm text-text-secondary max-w-xs truncate">
                                                {appt.notes || '-'}
                                            </td>
                                            <td className="p-4">
                                                <Badge variant={getStatusVariant(appt.status)} size="sm">
                                                    {getStatusLabel(appt.status)}
                                                </Badge>
                                            </td>
                                            <td className="p-4">
                                                <select
                                                    className="px-3 py-1.5 bg-background rounded-lg border border-border text-xs font-bold focus:ring-2 focus:ring-primary/20 outline-none"
                                                    value={appt.status}
                                                    onChange={(e) => handleStatus(appt.id, e.target.value)}
                                                >
                                                    <option value="Scheduled">{t('appointments.status.scheduled')}</option>
                                                    <option value="Waiting">{t('appointments.status.waiting')}</option>
                                                    <option value="In-Chair">{t('appointments.status.in_chair')}</option>
                                                    <option value="Completed">{t('appointments.status.completed')}</option>
                                                    <option value="Postponed">{t('appointments.status.postponed')}</option>
                                                    <option value="No Show">{t('appointments.status.no_show')}</option>
                                                    <option value="Cancelled">{t('appointments.status.cancelled')}</option>
                                                </select>
                                            </td>
                                            <td className="p-4">
                                                <div className="flex justify-center">
                                                    <button
                                                        onClick={() => handleDelete(appt.id)}
                                                        className="p-2 text-text-secondary hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                                                    >
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </div>
            ) : (
                // Kanban Board View
                <div className="flex gap-6 overflow-x-auto pb-6 items-start min-h-[500px]">
                    {columns.map(col => (
                        <div key={col.id} className={`min-w-[300px] w-[300px] flex-shrink-0 bg-surface rounded-[2rem] p-4 flex flex-col gap-4 border border-border shadow-sm`}>
                            {/* Column Header */}
                            <div className={`p-3 rounded-2xl border ${col.border} ${col.bg} flex justify-between items-center`}>
                                <div className="flex items-center gap-3">
                                    <div className={`p-1.5 rounded-lg bg-background/50 ${col.color}`}>
                                        <col.icon size={18} />
                                    </div>
                                    <span className={`font-black text-sm ${col.color}`}>{col.title}</span>
                                </div>
                                <span className={`bg-background/80 px-2 py-0.5 rounded-lg text-xs font-black ${col.color}`}>
                                    {getColumnAppointments(col.id).length}
                                </span>
                            </div>

                            {/* Cards */}
                            <div className="flex flex-col gap-3 min-h-[100px]">
                                {getColumnAppointments(col.id).map(appt => {
                                    const patient = patients.find(p => p.id === appt.patient_id);
                                    return (
                                        <div key={appt.id} className="bg-background hover:bg-surface-hover p-4 rounded-2xl shadow-sm border border-border transition-all group relative">
                                            <div className="flex justify-between items-start mb-3">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-8 h-8 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold">
                                                        {patient?.name?.charAt(0)}
                                                    </div>
                                                    <h4 className="font-bold text-text-primary text-sm line-clamp-1">
                                                        {patient?.name || 'Unknown'}
                                                    </h4>
                                                </div>
                                                <button
                                                    onClick={() => handleDelete(appt.id)}
                                                    className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-400 hover:text-red-500 rounded-lg transition-opacity"
                                                >
                                                    <Trash2 size={14} />
                                                </button>
                                            </div>

                                            <div className="flex items-center gap-2 text-text-secondary text-xs font-bold mb-3 bg-surface p-2 rounded-lg border border-border/50">
                                                <Clock size={14} className="text-primary" />
                                                <span dir="ltr">
                                                    {new Date(appt.date_time).toLocaleString(t('language.switch_to_en') === 'English' ? 'ar-EG' : 'en-US', {
                                                        month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
                                                    })}
                                                </span>
                                            </div>

                                            {appt.notes && (
                                                <p className="text-text-secondary text-xs p-2 bg-surface rounded-lg mb-3 border border-border/50">
                                                    {appt.notes}
                                                </p>
                                            )}

                                            <select
                                                className="w-full text-xs p-2 bg-surface rounded-lg border border-border font-bold outline-none focus:border-primary"
                                                value={appt.status}
                                                onChange={(e) => handleStatus(appt.id, e.target.value)}
                                            >
                                                <option value="Scheduled">{t('appointments.status.scheduled')}</option>
                                                <option value="Waiting">{t('appointments.status.waiting')}</option>
                                                <option value="In-Chair">{t('appointments.status.in_chair')}</option>
                                                <option value="Completed">{t('appointments.status.completed')}</option>
                                                <option value="Cancelled">{t('appointments.status.cancelled')}</option>
                                            </select>
                                        </div>
                                    );
                                })}
                                {getColumnAppointments(col.id).length === 0 && (
                                    <div className="h-24 flex flex-col items-center justify-center border-2 border-dashed border-border rounded-xl text-text-secondary/50 text-xs font-medium">
                                        <span>{t('appointments.no_appointments')}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}

            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={t('appointments.form.title')}
                size="md"
            >
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-bold text-text-primary mb-2">{t('appointments.form.select_patient')}</label>
                        <select
                            className="w-full p-3 bg-surface rounded-xl border border-border outline-none focus:ring-2 focus:ring-primary/20 text-sm font-bold"
                            value={newAppt.patient_id}
                            onChange={e => setNewAppt({ ...newAppt, patient_id: e.target.value })}
                        >
                            <option value="">{t('appointments.form.select_patient_placeholder')}</option>
                            {patients.map(p => (
                                <option key={p.id} value={p.id}>{p.name}</option>
                            ))}
                        </select>
                    </div>

                    <Input
                        type="datetime-local"
                        label={t('appointments.form.datetime')}
                        value={newAppt.date_time}
                        onChange={e => setNewAppt({ ...newAppt, date_time: e.target.value })}
                    />

                    <div>
                        <label className="block text-sm font-bold text-text-primary mb-2">{t('appointments.form.notes')}</label>
                        <textarea
                            className="w-full p-3 bg-surface rounded-xl border border-border outline-none focus:ring-2 focus:ring-primary/20 text-sm font-bold resize-none"
                            rows={3}
                            placeholder={t('appointments.form.notes_placeholder')}
                            value={newAppt.notes}
                            onChange={e => setNewAppt({ ...newAppt, notes: e.target.value })}
                        />
                    </div>

                    <div className="flex gap-3 pt-4">
                        <Button variant="ghost" onClick={() => setIsModalOpen(false)} className="flex-1">{t('appointments.form.cancel_btn')}</Button>
                        <Button onClick={handleCreate} className="flex-[2]">{t('appointments.form.confirm_btn')}</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Users, LayoutDashboard, Receipt, Briefcase, TrendingDown } from 'lucide-react';
import toast from 'react-hot-toast';
import DoctorRevenue from '@/features/billing/DoctorRevenue';
import { getFinancialStats, getAllPayments, getExpenses, createExpense, deleteExpense, getStaffRevenue, updateStaffCompensation, getComprehensiveStats, getSalariesStatus, recordSalaryPayment, deleteSalaryPayment, updateHireDate, getLabOrders } from '@/api';
import { getTodayStr } from '@/utils/toothUtils';
import { Skeleton, Button } from '@/shared/ui';

// Import extracted components
import ExpensesTab from '@/features/billing/BillingTabs/ExpensesTab';
import ExpenseModal from '@/features/billing/BillingTabs/ExpenseModal';
import StaffTab from '@/features/billing/BillingTabs/StaffTab';
import StaffModal from '@/features/billing/BillingTabs/StaffModal';
import SalariesTab from '@/features/billing/BillingTabs/SalariesTab';
import PaymentsTab from '@/features/billing/BillingTabs/PaymentsTab';
import SummaryTab from '@/features/billing/BillingTabs/SummaryTab';

import { useTranslation } from 'react-i18next';
export default function Billing() {
    const { t } = useTranslation();
    const navigate = useNavigate();
    const [stats, setStats] = useState(null);
    const [payments, setPayments] = useState([]);
    const [expenses, setExpenses] = useState([]);
    const [staff, setStaff] = useState([]);
    const [comprehensiveStats, setComprehensiveStats] = useState(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('doctors');
    const [expensesSubTab, setExpensesSubTab] = useState('expenses'); // 'expenses' or 'salaries'

    // Expense Modal
    const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
    const [newExpense, setNewExpense] = useState({ item_name: '', cost: '', category: 'General', date: getTodayStr(), notes: '' });

    // Staff Profile Modal
    const [staffModalOpen, setStaffModalOpen] = useState(false);
    const [selectedStaff, setSelectedStaff] = useState(null);
    const [editStaffSalary, setEditStaffSalary] = useState(0);
    const [editStaffPerAppointment, setEditStaffPerAppointment] = useState(0);
    const [savingStaff, setSavingStaff] = useState(false);

    // Date range: 1 month from today by default
    const today = new Date();
    const oneMonthAgo = new Date(today.getFullYear(), today.getMonth() - 1, today.getDate()).toISOString().split('T')[0];
    const [startDate, setStartDate] = useState(oneMonthAgo);
    const [endDate, setEndDate] = useState(today.toISOString().split('T')[0]);

    // Salaries state
    const [salaryMonth, setSalaryMonth] = useState(today.toISOString().slice(0, 7));
    const [salariesData, setSalariesData] = useState([]);
    const [salariesLoading, setSalariesLoading] = useState(false);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            const [sRes, pRes, eRes, labRes, staffRes, compRes] = await Promise.all([
                getFinancialStats(),
                getAllPayments(),
                getExpenses(),
                getLabOrders(),
                getStaffRevenue(startDate, endDate),
                getComprehensiveStats(startDate, endDate)
            ]);
            setStats(sRes.data);
            setPayments(pRes.data);

            // Merge Expenses and Lab Orders
            const manualExpenses = eRes.data.map(e => ({ ...e, type: 'manual' }));
            const labExpenses = (labRes.data || []).map(order => ({
                id: `lab-${order.id}`,
                original_id: order.id,
                item_name: `معمل: ${order.work_type} (${order.patient_name}) - ${order.laboratory_name}`,
                category: 'Laboratory',
                date: order.order_date,
                cost: order.cost,
                type: 'lab_order'
            }));

            setExpenses([...manualExpenses, ...labExpenses].sort((a, b) => new Date(b.date) - new Date(a.date)));

            setStaff(staffRes.data.staff || []);
            setComprehensiveStats(compRes.data);
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.load_fail'));
        } finally {
            setLoading(false);
        }
    };

    const handleCreateExpense = async () => {
        if (!newExpense.item_name || !newExpense.cost) return toast.error(t('billing.alerts.enter_item_cost'));
        try {
            await createExpense({ ...newExpense, cost: parseFloat(newExpense.cost) });
            setIsExpenseModalOpen(false);
            setNewExpense({ item_name: '', cost: '', category: 'General', date: getTodayStr(), notes: '' });
            toast.success(t('billing.alerts.expense_add_success'));
            loadData();
        } catch (err) {
            toast.error(t('billing.alerts.expense_add_fail'));
        }
    };

    const handleDeleteExpense = async (id) => {
        if (String(id).startsWith('lab-')) {
            return toast.error(t('billing.alerts.lab_delete_error'));
        }
        if (!confirm(t('billing.alerts.delete_expense_confirm'))) return;
        try {
            await deleteExpense(id);
            toast.success(t('billing.alerts.expense_delete_success'));
            loadData();
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.delete_error'));
        }
    };

    const openStaffProfile = (staffMember) => {
        setSelectedStaff(staffMember);
        setEditStaffSalary(staffMember.fixed_salary || 0);
        setEditStaffPerAppointment(staffMember.per_appointment_fee || 0);
        setStaffModalOpen(true);
    };

    const saveStaffCompensation = async () => {
        if (!selectedStaff) return;
        setSavingStaff(true);
        try {
            await updateStaffCompensation(selectedStaff.id, 0, editStaffSalary, editStaffPerAppointment);
            // Update local state
            setStaff(prev => prev.map(s =>
                s.id === selectedStaff.id
                    ? { ...s, fixed_salary: editStaffSalary, per_appointment_fee: editStaffPerAppointment }
                    : s
            ));
            setStaffModalOpen(false);
            toast.success(t('billing.alerts.save_success'));
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.save_fail'));
        } finally {
            setSavingStaff(false);
        }
    };

    const loadSalaries = async () => {
        setSalariesLoading(true);
        try {
            const res = await getSalariesStatus(salaryMonth);
            setSalariesData(res.data.employees || []);
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.salaries_load_fail'));
        } finally {
            setSalariesLoading(false);
        }
    };

    const handlePaySalary = async (employee, isPartial = false) => {
        const amount = isPartial ? employee.prorated_salary : employee.base_salary;
        if (!confirm(`${t('billing.alerts.pay_confirm_prefix')} ${amount} ${t('billing.alerts.pay_confirm_suffix')} ${employee.username}?`)) return;

        try {
            await recordSalaryPayment(employee.id, salaryMonth, amount, isPartial, isPartial ? employee.days_worked : null, null);
            toast.success(t('billing.alerts.pay_success'));
            loadSalaries();
        } catch (err) {
            console.error(err);
            toast.error(err.response?.data?.error || t('billing.alerts.pay_fail'));
        }
    };


    const updateEmployeeHireDate = async (userId, date) => {
        try {
            await updateHireDate(userId, date); // Use the imported function directly
            toast.success(t('billing.alerts.hire_date_success'));
            loadSalaries();
        } catch (err) {
            console.error(err);
            toast.error(t('billing.alerts.hire_date_fail'));
        }
    };

    // UseEffect for salary month change
    useEffect(() => {
        if (activeTab === 'expenses' && expensesSubTab === 'salaries') {
            loadSalaries();
        }
    }, [activeTab, expensesSubTab, salaryMonth]);

    if (loading) return (
        <div className="space-y-6">
            <div className="flex gap-4">
                <Skeleton.Box className="h-10 w-32" />
                <Skeleton.Box className="h-10 w-32" />
            </div>
            <Skeleton.Box className="h-[400px] w-full rounded-2xl" />
        </div>
    );

    const tabs = [
        { id: 'doctors', label: t('billing.tabs.doctors'), icon: Users },
        { id: 'staff', label: t('billing.tabs.staff'), icon: Briefcase },
        //{ id: 'salaries', label: 'المرتبات', icon: CreditCard }, // Merged into expenses
        { id: 'expenses', label: t('billing.tabs.expenses'), icon: TrendingDown },
        { id: 'summary', label: t('billing.tabs.summary'), icon: LayoutDashboard },
        { id: 'payments', label: t('billing.tabs.payments'), icon: Receipt },
    ];

    const roleLabels = {
        assistant: t('billing.roles.assistant'),
        receptionist: t('billing.roles.receptionist'),
        accountant: t('billing.roles.accountant'),
        nurse: t('billing.roles.nurse')
    };

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
                <div>
                    <h2 className="text-3xl font-black text-text-primary tracking-tight">{t('billing.title')}</h2>
                    <p className="text-text-secondary mt-1 text-lg font-medium">{t('billing.subtitle')}</p>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex flex-wrap gap-2 p-1.5 bg-surface rounded-2xl w-fit border border-border">
                {tabs.map(tab => (
                    <button
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id)}
                        className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-bold text-sm transition-all ${activeTab === tab.id
                            ? 'bg-background text-primary shadow-sm'
                            : 'text-text-secondary hover:text-text-primary'
                            }`}
                    >
                        <tab.icon size={16} />
                        {tab.label}
                    </button>
                ))}
            </div>

            {/* Tab Content */}
            {activeTab === 'doctors' && <DoctorRevenue />}

            {activeTab === 'staff' && (
                <StaffTab
                    staff={staff}
                    roleLabels={roleLabels}
                    openStaffProfile={openStaffProfile}
                />
            )}

            {activeTab === 'expenses' && (
                <div className="space-y-4">
                    {/* Sub Tabs */}
                    <div className="flex gap-2 p-1 bg-surface rounded-lg w-fit border border-border">
                        <Button
                            variant={expensesSubTab === 'expenses' ? 'default' : 'ghost'}
                            size="sm"
                            onClick={() => setExpensesSubTab('expenses')}
                        >
                            {t('billing.subtabs.general_expenses')}
                        </Button>
                        <Button
                            variant={expensesSubTab === 'salaries' ? 'default' : 'ghost'}
                            size="sm"
                            onClick={() => setExpensesSubTab('salaries')}
                        >
                            {t('billing.subtabs.salaries')}
                        </Button>
                    </div>

                    {expensesSubTab === 'expenses' ? (
                        <ExpensesTab
                            expenses={expenses}
                            stats={stats}
                            setIsExpenseModalOpen={setIsExpenseModalOpen}
                            handleDeleteExpense={handleDeleteExpense}
                        />
                    ) : (
                        <SalariesTab
                            salaryMonth={salaryMonth}
                            setSalaryMonth={setSalaryMonth}
                            salariesData={salariesData}
                            salariesLoading={salariesLoading}
                            updateEmployeeHireDate={updateEmployeeHireDate}
                            roleLabels={roleLabels}
                            handlePaySalary={handlePaySalary}
                            deleteSalaryPayment={deleteSalaryPayment}
                            loadSalaries={loadSalaries}
                        />
                    )}
                </div>
            )}

            {activeTab === 'summary' && (
                <SummaryTab
                    startDate={startDate}
                    setStartDate={setStartDate}
                    endDate={endDate}
                    setEndDate={setEndDate}
                    comprehensiveStats={comprehensiveStats}
                    loading={loading}
                    getComprehensiveStats={getComprehensiveStats}
                    setComprehensiveStats={setComprehensiveStats}
                    setLoading={setLoading}
                />
            )}

            {activeTab === 'payments' && (
                <PaymentsTab
                    payments={payments}
                    navigate={navigate}
                />
            )}

            {/* Modals */}
            <ExpenseModal
                isOpen={isExpenseModalOpen}
                onClose={() => setIsExpenseModalOpen(false)}
                newExpense={newExpense}
                setNewExpense={setNewExpense}
                handleCreateExpense={handleCreateExpense}
            />

            <StaffModal
                isOpen={staffModalOpen}
                onClose={() => setStaffModalOpen(false)}
                selectedStaff={selectedStaff}
                roleLabels={roleLabels}
                editStaffSalary={editStaffSalary}
                setEditStaffSalary={setEditStaffSalary}
                editStaffPerAppointment={editStaffPerAppointment}
                setEditStaffPerAppointment={setEditStaffPerAppointment}
                saveStaffCompensation={saveStaffCompensation}
                savingStaff={savingStaff}
            />
        </div>
    );
}

import React, { useState, useMemo, memo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Users, Calendar, Activity, Clock,
    TrendingUp, Wallet, Stethoscope, ChevronLeft, Banknote
} from 'lucide-react';
import { useTranslation } from 'react-i18next';
import {
    AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, BarChart
} from 'recharts';
import { getTodayPayments, getTodayDebtors } from '@/api';
import { useDashboardStats, useTodayPayments, useTodayDebtors } from '@/hooks/useDashboard';
import { useAppointments } from '@/hooks/useAppointments';
import { useAuth } from '@/auth/useAuth';
import { Skeleton, Card, Button, Modal, DataTable } from '@/shared/ui';

// Memoized Gradient Card - prevents re-renders when parent state changes
const GradientCard = memo(({ title, value, subtext, icon: Icon, gradient, onClick }) => (
    <div
        onClick={onClick}
        className={`relative overflow-hidden rounded-[2.5rem] p-6 text-white shadow-xl hover:shadow-2xl transition-all duration-300 hover:scale-[1.02] cursor-pointer group ${gradient}`}
    >
        <div className="relative z-10 flex flex-col h-full justify-between">
            <div className="flex justify-between items-start">
                <div className="p-3 bg-white/20 backdrop-blur-md rounded-2xl">
                    <Icon size={24} className="text-white" />
                </div>
            </div>
            <div className="mt-4">
                <p className="text-white/80 text-sm font-medium mb-1">{title}</p>
                <h3 className="text-3xl font-black tracking-tight">{value}</h3>
                <p className="text-white/60 text-xs mt-2 font-medium bg-black/10 inline-block px-2 py-1 rounded-lg">
                    {subtext}
                </p>
            </div>
        </div>
        <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-white/10 rounded-full blur-3xl group-hover:scale-150 transition-transform duration-700"></div>
    </div>
));

GradientCard.displayName = 'GradientCard';

export default function Dashboard() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const { t } = useTranslation();

    // Use cached hooks instead of direct API calls
    const { data: statsData, isLoading: statsLoading } = useDashboardStats();
    const { data: appointments = [], isLoading: apptsLoading } = useAppointments();

    const loading = statsLoading || apptsLoading;

    // Derive stats from cached data
    const stats = useMemo(() => ({
        new_patients_today: statsData?.new_patients_today || 0,
        appointments: statsData?.total_appointments_today || 0,
        revenue: statsData?.today_received || 0,
        outstanding: statsData?.outstanding || 0,
        chartData: statsData?.revenue_chart || []
    }), [statsData]);

    // Filter today's appointments from cached data
    const todaysAppointments = useMemo(() => {
        if (!Array.isArray(appointments)) return [];
        const today = new Date().toISOString().split('T')[0];
        return appointments
            .filter(app => app.date_time?.startsWith(today) && app.status !== 'Cancelled')
            .sort((a, b) => new Date(a.date_time) - new Date(b.date_time));
    }, [appointments]);

    // Modal State
    const [modalOpen, setModalOpen] = useState(false);
    const [modalTitle, setModalTitle] = useState('');
    const [modalData, setModalData] = useState([]);
    const [modalLoading, setModalLoading] = useState(false);
    const [modalType, setModalType] = useState(null);

    const formatCurrency = useCallback((amount) => {
        return new Intl.NumberFormat('en-EG', { style: 'currency', currency: 'EGP', maximumFractionDigits: 0 }).format(amount);
    }, []);

    const handleRevenueClick = useCallback(async () => {
        setModalTitle(t('dashboard.daily_income_details'));
        setModalOpen(true);
        setModalLoading(true);
        setModalType('payments');
        try {
            const res = await getTodayPayments();
            setModalData(res.data);
        } catch (err) { /* Silent */ }
        finally { setModalLoading(false); }
    }, [t]);

    const handleOutstandingClick = useCallback(async () => {
        setModalTitle(t('dashboard.outstanding_today'));
        setModalOpen(true);
        setModalLoading(true);
        setModalType('debtors');
        try {
            const res = await getTodayDebtors();
            setModalData(res.data);
        } catch (err) { /* Silent */ }
        finally { setModalLoading(false); }
    }, [t]);

    return (
        <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500 pb-10">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-surface/50 backdrop-blur-sm p-6 rounded-[2rem] border border-border">
                <div className="flex items-center gap-4 w-full md:w-auto">
                    <div className="w-14 h-14 bg-gradient-to-tr from-indigo-500 to-purple-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-500/20">
                        <Stethoscope size={28} />
                    </div>
                    <div>
                        {loading ? (
                            <Skeleton.Text lines={2} className="w-48" />
                        ) : (
                            <>
                                <h1 className="text-2xl font-black text-text-primary tracking-tight">
                                    {t('dashboard.welcome', { name: user?.username })}
                                </h1>
                                <p className="text-text-secondary text-sm font-medium">
                                    {t('dashboard.clinic_overview_today')}
                                </p>
                            </>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <div className="px-5 py-3 bg-surface-hover rounded-2xl font-bold text-text-secondary text-sm flex items-center gap-2 border border-border">
                        <Clock size={18} className="text-primary" />
                        {new Date().toLocaleDateString(t('language.switch_to_en') === 'English' ? 'ar-EG' : 'en-US', { weekday: 'long', day: 'numeric', month: 'long' })}
                    </div>
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {loading ? (
                    Array.from({ length: 4 }).map((_, i) => <Skeleton.StatCard key={i} />)
                ) : (
                    <>
                        <GradientCard
                            title={t('dashboard.new_patients_today')}
                            value={stats.new_patients_today}
                            subtext={t('dashboard.registered_today')}
                            icon={Users}
                            gradient="bg-gradient-to-br from-blue-500 to-blue-600"
                            onClick={() => navigate('/patients')}
                        />
                        <GradientCard
                            title={t('dashboard.appointments_today')}
                            value={stats.appointments}
                            subtext={t('dashboard.confirmed_booking')}
                            icon={Calendar}
                            gradient="bg-gradient-to-br from-purple-500 to-purple-600"
                            onClick={() => navigate('/appointments')}
                        />
                        <GradientCard
                            title={t('dashboard.daily_income')}
                            value={formatCurrency(stats.revenue)}
                            subtext={t('dashboard.cash_collection')}
                            icon={Wallet}
                            gradient="bg-gradient-to-br from-emerald-500 to-emerald-600"
                            onClick={handleRevenueClick}
                        />
                        <GradientCard
                            title={t('dashboard.outstanding_dues')}
                            value={formatCurrency(stats.outstanding)}
                            subtext={t('dashboard.to_collect')}
                            icon={Activity}
                            gradient="bg-gradient-to-br from-amber-500 to-amber-600"
                            onClick={handleOutstandingClick}
                        />
                    </>
                )}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main Chart Section */}
                <div className="lg:col-span-2 space-y-8">
                    <Card className="min-h-[400px]">
                        <div className="flex justify-between items-center mb-8">
                            <div>
                                <h3 className="text-xl font-bold text-text-primary flex items-center gap-2">
                                    <TrendingUp className="text-primary" />
                                    {t('dashboard.revenue_analysis')}
                                </h3>
                                <p className="text-sm text-text-secondary mt-1">{t('dashboard.revenue_growth')}</p>
                            </div>
                        </div>

                        <div className="h-[300px] w-full" style={{ direction: 'ltr' }}>
                            {loading ? (
                                <Skeleton.Box height="100%" width="100%" />
                            ) : stats.chartData.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={stats.chartData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                                        <defs>
                                            <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="5%" stopColor="#6366f1" stopOpacity={0.4} />
                                                <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
                                            </linearGradient>
                                        </defs>
                                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 600 }} dy={10} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 12, fontWeight: 600 }} />
                                        <Tooltip
                                            contentStyle={{ backgroundColor: 'rgba(255, 255, 255, 0.9)', borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)' }}
                                            itemStyle={{ color: '#1e293b', fontWeight: 'bold' }}
                                            formatter={(value) => formatCurrency(value)}
                                            cursor={{ stroke: '#6366f1', strokeWidth: 2, strokeDasharray: '4 4' }}
                                        />
                                        <Area
                                            type="monotone"
                                            dataKey="revenue"
                                            stroke="#6366f1"
                                            strokeWidth={4}
                                            fillOpacity={1}
                                            fill="url(#colorRevenue)"
                                            activeDot={{ r: 8, strokeWidth: 0, fill: '#4f46e5' }}
                                        />
                                    </AreaChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex flex-col items-center justify-center text-text-secondary gap-4">
                                    <div className="w-16 h-16 bg-surface-hover rounded-full flex items-center justify-center">
                                        <BarChart size={32} className="text-slate-400" />
                                    </div>
                                    <p>{t('dashboard.no_financial_data')}</p>
                                </div>
                            )}
                        </div>
                    </Card>
                </div>

                {/* Left Sidebar: Timeline */}
                <div className="space-y-6">
                    <Card className="h-full relative overflow-hidden transition-all duration-300 hover:shadow-lg">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="font-bold text-lg text-text-primary flex items-center gap-2">
                                <Calendar className="text-primary" size={20} />
                                {t('dashboard.appointments_today')}
                            </h3>
                            <span className="bg-primary/10 text-primary px-3 py-1 rounded-lg text-xs font-bold">
                                {t('dashboard.appointments_count', { count: loading ? '...' : todaysAppointments.length })}
                            </span>
                        </div>

                        <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                            {loading ? (
                                <Skeleton.Text lines={5} />
                            ) : todaysAppointments.length > 0 ? todaysAppointments.map((appt) => (
                                <div
                                    key={appt.id}
                                    className="relative pl-4 border-r-2 border-border pr-4 py-1 group cursor-pointer"
                                    onClick={() => navigate('/appointments')}
                                >
                                    {/* Timeline Dot */}
                                    <div className={`absolute -right-[9px] top-3 w-4 h-4 rounded-full border-2 border-background ${appt.status === 'Completed' ? 'bg-emerald-500' :
                                        appt.status === 'Cancelled' ? 'bg-red-500' : 'bg-primary'
                                        }`}></div>

                                    <div className="bg-surface-hover p-4 rounded-xl group-hover:bg-primary/5 transition-colors">
                                        <div className="flex justify-between items-start mb-1">
                                            <h4 className="font-bold text-text-primary">{appt.patient_name}</h4>
                                            <span className="text-xs font-bold font-mono text-text-secondary bg-background px-2 py-1 rounded-md border border-border">
                                                {new Date(appt.date_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </span>
                                        </div>
                                        <p className="text-xs text-text-secondary line-clamp-1">
                                            {appt.notes || 'زيارة عادية - كشف'}
                                        </p>
                                    </div>
                                </div>
                            )) : (
                                <div className="flex flex-col items-center justify-center py-12 text-center">
                                    <div className="bg-surface-hover p-4 rounded-full mb-4">
                                        <Calendar size={32} className="text-text-secondary" />
                                    </div>
                                    <p className="text-text-secondary font-medium">{t('dashboard.no_appointments_today')}</p>
                                    <Button variant="ghost" size="sm" onClick={() => navigate('/appointments')} className="mt-2">
                                        + {t('dashboard.add_new_appointment')}
                                    </Button>
                                </div>
                            )}
                        </div>

                        {!loading && todaysAppointments.length > 0 && (
                            <Button
                                variant="secondary"
                                className="w-full mt-6"
                                onClick={() => navigate('/appointments')}
                            >
                                {t('dashboard.view_full_schedule')}
                                <ChevronLeft size={16} className="mr-2" />
                            </Button>
                        )}
                    </Card>
                </div>
            </div>

            {/* Reusable Modal for Revenue/Debtors */}
            <Modal
                isOpen={modalOpen}
                onClose={() => setModalOpen(false)}
                title={modalTitle}
                size="md"
            >
                <div className="space-y-3">
                    {modalLoading ? (
                        <div className="flex flex-col gap-3">
                            <Skeleton.Box height="4rem" />
                            <Skeleton.Box height="4rem" />
                            <Skeleton.Box height="4rem" />
                        </div>
                    ) : modalData.length > 0 ? modalData.map((item, idx) => (
                        <div key={idx} className="flex justify-between items-center p-4 bg-surface-hover rounded-2xl border border-border">
                            <div className="flex items-center gap-3">
                                <div className={`p-2 rounded-xl ${modalType === 'payments' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                                    {modalType === 'payments' ? <Banknote size={20} /> : <Activity size={20} />}
                                </div>
                                <div>
                                    <p className="font-bold text-text-primary">{item.patient_name || item.name}</p>
                                    <p className="text-xs text-text-secondary">{new Date(item.date || new Date()).toLocaleTimeString()}</p>
                                </div>
                            </div>
                            <span className="font-black text-lg dir-ltr text-text-primary">{formatCurrency(item.amount)}</span>
                        </div>
                    )) : (
                        <div className="text-center py-8">
                            <p className="text-text-secondary">{t('dashboard.no_data')}</p>
                        </div>
                    )}
                </div>
            </Modal>
        </div>
    );
}

const ActionButton = ({ icon: Icon, label, color, onClick }) => (
    <button
        onClick={onClick}
        className={`${color} text-white p-4 rounded-[1.5rem] shadow-lg shadow-indigo-500/20 hover:scale-105 transition-all flex flex-col items-center justify-center gap-2 group`}
    >
        <div className="bg-white/20 p-2 rounded-full group-hover:rotate-12 transition-transform">
            <Icon size={24} />
        </div>
        <span className="font-bold text-sm whitespace-nowrap">{label}</span>
    </button>
);

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, DollarSign, TrendingUp, TrendingDown, Calendar } from 'lucide-react';
import { getExpenses, createExpense, deleteExpense, getFinancialStats } from '../api';
import { getTodayStr } from '../utils/toothUtils';

import { useTranslation } from 'react-i18next';

export default function Expenses() {
    const { t } = useTranslation();
    const [expenses, setExpenses] = useState([]);
    const [stats, setStats] = useState({ total_received: 0, total_expenses: 0, net_profit: 0 });
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    // Form
    const [newItem, setNewItem] = useState({ item_name: '', cost: '', category: 'General', date: getTodayStr(), notes: '' });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const [eRes, sRes] = await Promise.all([
                getExpenses(),
                getFinancialStats()
            ]);
            setExpenses(eRes.data);
            setStats(sRes.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleCreate = async () => {
        if (!newItem.item_name || !newItem.cost) return alert(t('billing.alerts.enter_item_cost'));
        try {
            await createExpense({ ...newItem, cost: parseFloat(newItem.cost) });
            setIsModalOpen(false);
            setNewItem({ item_name: '', cost: '', category: 'General', date: getTodayStr(), notes: '' });
            loadData();
        } catch (err) {
            alert(t('billing.expenses_page.create_fail'));
        }
    };

    const handleDelete = async (id) => {
        if (!confirm(t('billing.alerts.delete_expense_confirm'))) return;
        try {
            await deleteExpense(id);
            loadData();
        } catch (err) {
            console.error(err);
        }
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row justify-between items-end gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800">{t('billing.expenses_page.title')}</h2>
                    <p className="text-slate-500">{t('billing.expenses_page.subtitle')}</p>
                </div>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="flex items-center gap-2 px-6 py-3 bg-red-500 text-white font-bold rounded-xl hover:bg-red-600 shadow-lg shadow-red-500/30 transition-all"
                >
                    <Plus size={20} /> {t('billing.expenses_page.add_button')}
                </button>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
                    <div className="relative z-10">
                        <p className="text-slate-500 font-bold mb-1">{t('billing.stats.total_income')}</p>
                        <h3 className="text-3xl font-bold text-emerald-600">{stats.total_received.toLocaleString()}</h3>
                    </div>
                    <TrendingUp className="absolute left-4 bottom-4 text-emerald-100" size={60} />
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
                    <div className="relative z-10">
                        <p className="text-slate-500 font-bold mb-1">{t('billing.stats.total_expenses')}</p>
                        <h3 className="text-3xl font-bold text-red-500">{stats.total_expenses.toLocaleString()}</h3>
                    </div>
                    <TrendingDown className="absolute left-4 bottom-4 text-red-100" size={60} />
                </div>

                <div className={`p-6 rounded-2xl shadow-sm border relative overflow-hidden ${stats.net_profit >= 0 ? 'bg-gradient-to-br from-blue-500 to-blue-600 border-blue-400 text-white' : 'bg-red-50 border-red-200 text-red-600'}`}>
                    <div className="relative z-10">
                        <p className={`font-bold mb-1 ${stats.net_profit >= 0 ? 'text-blue-100' : 'text-red-400'}`}>{t('billing.stats.net_profit')}</p>
                        <h3 className="text-3xl font-bold">{stats.net_profit.toLocaleString()}</h3>
                    </div>
                    <DollarSign className={`absolute left-4 bottom-4 ${stats.net_profit >= 0 ? 'text-white/20' : 'text-red-200'}`} size={60} />
                </div>
            </div>

            {/* Expenses Table */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-right">
                        <thead className="bg-slate-50 text-slate-600 font-bold text-sm">
                            <tr>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses.item')}</th>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses.category')}</th>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses.date')}</th>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses.cost')}</th>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses_page.notes')}</th>
                                <th className="p-4 whitespace-nowrap">{t('billing.expenses.actions')}</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                            {expenses.map(exp => (
                                <tr key={exp.id} className="hover:bg-slate-50 transition-colors">
                                    <td className="p-4 font-bold text-slate-800">{exp.item_name}</td>
                                    <td className="p-4">
                                        <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-bold">{exp.category}</span>
                                    </td>
                                    <td className="p-4 text-slate-500 text-sm flex items-center gap-2">
                                        <Calendar size={14} />
                                        {new Date(exp.date).toLocaleDateString()}
                                    </td>
                                    <td className="p-4 font-bold text-red-500">{exp.cost.toLocaleString()}</td>
                                    <td className="p-4 text-slate-500 text-sm max-w-[200px] truncate">{exp.notes || '-'}</td>
                                    <td className="p-4">
                                        <button onClick={() => handleDelete(exp.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                {expenses.length === 0 && <div className="p-12 text-center text-slate-400">{t('billing.expenses_page.empty')}</div>}
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                    <div className="bg-white w-full max-w-md rounded-2xl p-6 shadow-2xl animate-in zoom-in duration-200">
                        <h3 className="text-xl font-bold mb-4 text-slate-800">{t('billing.expenses.modal_title')}</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('billing.expenses.item')}</label>
                                <input
                                    value={newItem.item_name}
                                    onChange={e => setNewItem({ ...newItem, item_name: e.target.value })}
                                    placeholder={t('billing.expenses.placeholder')}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-1">{t('billing.expenses.cost')}</label>
                                    <input
                                        type="number"
                                        value={newItem.cost}
                                        onChange={e => setNewItem({ ...newItem, cost: e.target.value })}
                                        className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-1">{t('billing.expenses.category')}</label>
                                    <select
                                        value={newItem.category}
                                        onChange={e => setNewItem({ ...newItem, category: e.target.value })}
                                        className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                    >
                                        <option value="General">{t('billing.expenses.categories.general')}</option>
                                        <option value="Materials">{t('billing.expenses.categories.materials')}</option>
                                        <option value="Salaries">{t('billing.expenses.categories.salaries')}</option>
                                        <option value="Rent">{t('billing.expenses.categories.rent')}</option>
                                        <option value="Utilities">{t('billing.expenses.categories.utilities')}</option>
                                        <option value="Maintenance">{t('billing.expenses.categories.maintenance')}</option>
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('billing.expenses.date')}</label>
                                <input
                                    type="date"
                                    value={newItem.date}
                                    onChange={e => setNewItem({ ...newItem, date: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('billing.expenses_page.notes')}</label>
                                <textarea
                                    value={newItem.notes}
                                    onChange={e => setNewItem({ ...newItem, notes: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors h-24 resize-none"
                                />
                            </div>
                            <div className="flex justify-end gap-3 mt-6">
                                <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 hover:bg-slate-100 rounded-lg font-bold text-slate-500">{t('common.cancel')}</button>
                                <button onClick={handleCreate} className="px-6 py-2 bg-primary text-white font-bold rounded-lg hover:bg-sky-600 shadow-lg shadow-primary/20">{t('common.save')}</button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Link } from 'react-router-dom';
import { Mail, ArrowLeft, Send, CheckCircle, AlertCircle } from 'lucide-react';
import { forgotPassword } from '../api';

export default function ForgotPassword() {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');
    const [devToken, setDevToken] = useState(null);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!email) return setError(t('auth.forgot_password.errors.email_required'));


        setLoading(true);
        setError('');

        try {
            const res = await forgotPassword(email);
            setSuccess(true);
            // For development - show token if SMTP not configured
            if (res.data.dev_token) {
                setDevToken(res.data.dev_token);
            }
        } catch (err) {
            setError(err.response?.data?.detail || t('auth.forgot_password.errors.generic'));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-100 to-sky-50 dark:from-slate-900 dark:to-slate-800 flex items-center justify-center p-4">
            <div className="w-full max-w-md">
                {/* Logo */}
                <div className="text-center mb-8">
                    <div className="text-5xl mb-2">🏥</div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white">DENTIX</h1>
                </div>

                <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl p-8">
                    {!success ? (
                        <>
                            <div className="text-center mb-6">
                                <div className="w-16 h-16 bg-sky-100 dark:bg-sky-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                    <Mail className="text-sky-500" size={32} />
                                </div>
                                <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">{t('auth.forgot_password.title')}</h2>
                                <p className="text-slate-500">{t('auth.forgot_password.subtitle')}</p>
                            </div>

                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('auth.forgot_password.email')}</label>
                                    <input
                                        type="email"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                        placeholder="example@email.com"
                                        className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-xl border border-slate-200 dark:border-slate-600 outline-none focus:border-sky-500 transition-colors text-left"
                                        dir="ltr"
                                    />
                                </div>

                                {error && (
                                    <div className="flex items-center gap-2 text-red-500 bg-red-50 dark:bg-red-500/10 p-3 rounded-xl">
                                        <AlertCircle size={18} />
                                        <span className="text-sm">{error}</span>
                                    </div>
                                )}

                                <button
                                    type="submit"
                                    disabled={loading}
                                    className="w-full py-4 bg-gradient-to-r from-sky-500 to-blue-600 text-white font-bold rounded-xl hover:from-sky-600 hover:to-blue-700 transition-all shadow-lg shadow-sky-500/30 flex items-center justify-center gap-2 disabled:opacity-50"
                                >
                                    {loading ? (
                                        <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                                    ) : (
                                        <>
                                            <Send size={18} />
                                            {t('auth.forgot_password.submit')}
                                        </>
                                    )}
                                </button>
                            </form>
                        </>
                    ) : (
                        <div className="text-center">
                            <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CheckCircle className="text-emerald-500" size={40} />
                            </div>
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">{t('auth.forgot_password.success_title')}</h2>
                            <p className="text-slate-500 mb-4">{t('auth.forgot_password.success_msg')}</p>

                            {devToken && (
                                <div className="bg-amber-50 dark:bg-amber-500/10 border border-amber-200 dark:border-amber-500/20 rounded-xl p-4 mb-4 text-left" dir="ltr">
                                    <p className="text-amber-600 text-xs font-bold mb-2">⚠️ Development Mode (SMTP not configured)</p>
                                    <p className="text-xs text-slate-600 mb-2">Reset Link:</p>
                                    <a
                                        href={`/reset-password?token=${devToken}`}
                                        className="text-sky-500 text-sm break-all hover:underline"
                                    >
                                        /reset-password?token={devToken}
                                    </a>
                                </div>
                            )}
                        </div>
                    )}

                    <div className="mt-6 text-center">
                        <Link to="/login" className="inline-flex items-center gap-2 text-sky-500 hover:text-sky-600 font-bold">
                            <ArrowLeft size={16} />
                            {t('auth.forgot_password.back_to_login')}
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { X, FlaskConical, Search, Filter } from 'lucide-react';
import { getLabOrders } from '../api';

const GlobalLabOrdersModal = ({ isOpen, onClose, initialStatus = '', title = '' }) => {
    const [orders, setOrders] = useState([]);
    const [loading, setLoading] = useState(false);
    const [statusFilter, setStatusFilter] = useState(initialStatus);
    const [searchQuery, setSearchQuery] = useState('');

    useEffect(() => {
        if (isOpen) {
            setStatusFilter(initialStatus);
            loadOrders(initialStatus);
        }
    }, [isOpen, initialStatus]);

    const loadOrders = async (status) => {
        setLoading(true);
        try {
            const res = await getLabOrders({ status: status || undefined });
            setOrders(res.data);
        } catch (error) {
            console.error("Failed to load global orders", error);
        } finally {
            setLoading(false);
        }
    };

    const handleFilterChange = (status) => {
        setStatusFilter(status);
        loadOrders(status);
    };

    const filteredOrders = orders.filter(order =>
        (order.patient_name?.toLowerCase() || '').includes(searchQuery.toLowerCase()) ||
        (order.laboratory_name?.toLowerCase() || '').includes(searchQuery.toLowerCase())
    );

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl max-h-[90vh] overflow-hidden flex flex-col">
                {/* Header */}
                <div className="p-6 bg-slate-50 border-b flex justify-between items-center">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-purple-100 rounded-xl text-purple-600">
                            <FlaskConical size={24} />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-800">{title || 'طلبات المعامل'}</h2>
                            <div className="text-sm text-slate-500">
                                {filteredOrders.length} طلب
                            </div>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                        <X size={20} className="text-slate-500" />
                    </button>
                </div>

                {/* Filters */}
                <div className="p-4 border-b flex gap-4 bg-white">
                    <div className="relative flex-1">
                        <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                        <input
                            type="text"
                            placeholder="بحث باسم المريض أو المعمل..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pr-10 pl-4 py-2 bg-slate-50 rounded-lg border outline-none focus:ring-2 focus:ring-purple-500/20"
                        />
                    </div>
                    <select
                        className="p-2 border rounded-lg text-sm bg-slate-50 outline-none focus:ring-2 focus:ring-purple-500/20"
                        value={statusFilter}
                        onChange={(e) => handleFilterChange(e.target.value)}
                    >
                        <option value="">كل الحالات</option>
                        <option value="pending">معلق (Pending)</option>
                        <option value="in_progress">جاري التنفيذ</option>
                        <option value="completed">مكتمل (Completed)</option>
                    </select>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
                    {loading ? (
                        <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600"></div></div>
                    ) : (
                        <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
                            <table className="w-full text-sm text-right">
                                <thead className="bg-slate-50 border-b text-slate-500">
                                    <tr>
                                        <th className="p-3 font-medium">الم عمل</th>
                                        <th className="p-3 font-medium">المريض</th>
                                        <th className="p-3 font-medium">العمل</th>
                                        <th className="p-3 font-medium">الحالة</th>
                                        <th className="p-3 font-medium">التكلفة</th>
                                        <th className="p-3 font-medium">تاريخ الطلب</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y">
                                    {filteredOrders.map(order => (
                                        <tr key={order.id} className="hover:bg-slate-50/50">
                                            <td className="p-3 font-bold text-indigo-600">{order.laboratory_name}</td>
                                            <td className="p-3 font-medium text-slate-700">{order.patient_name}</td>
                                            <td className="p-3">
                                                <div className="font-medium">{order.work_type}</div>
                                                <div className="text-xs text-slate-400">{order.material} {order.shade && `(${order.shade})`}</div>
                                            </td>
                                            <td className="p-3">
                                                <span className={`px-2 py-1 rounded text-xs font-bold 
                                                    ${order.status === 'completed' ? 'bg-emerald-100 text-emerald-700' :
                                                        order.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                                                            'bg-blue-100 text-blue-700'}`}>
                                                    {order.status}
                                                </span>
                                            </td>
                                            <td className="p-3 font-mono">{order.cost} ج.م</td>
                                            <td className="p-3 text-slate-500">{new Date(order.order_date).toLocaleDateString('ar-EG')}</td>
                                        </tr>
                                    ))}
                                    {filteredOrders.length === 0 && (
                                        <tr>
                                            <td colSpan="6" className="p-8 text-center text-slate-400">لا توجد طلبات</td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default GlobalLabOrdersModal;

import React, { useState } from 'react';
import StockList from '@/features/inventory/StockList';
import WarehouseList from '@/features/inventory/WarehouseList';
import AddMaterialModal from '@/features/inventory/AddMaterialModal';
import ReceiveStockModal from '@/features/inventory/ReceiveStockModal';
import { getExpiryAlerts } from '@/api/inventory';
import { Package, AlertTriangle, Layers, Warehouse } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { useTranslation } from 'react-i18next';

const Inventory = () => {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('stock'); // 'stock' | 'warehouses'
    const [editingMaterial, setEditingMaterial] = useState(null);
    const [isAddMaterialOpen, setIsAddMaterialOpen] = useState(false);
    const [isReceiveStockOpen, setIsReceiveStockOpen] = useState(false);

    const { data: alerts = [] } = useQuery({
        queryKey: ['inventory-alerts'],
        queryFn: async () => {
            if (!getExpiryAlerts) return [];
            try {
                const res = await getExpiryAlerts();
                return Array.isArray(res.data) ? res.data : [];
            } catch (e) {
                console.error("Alerts fetch error", e);
                return [];
            }
        },
        enabled: !!getExpiryAlerts
    });

    const handleOpenAdd = () => {
        setEditingMaterial(null);
        setIsAddMaterialOpen(true);
    };

    const handleOpenEdit = (material) => {
        setEditingMaterial(material);
        setIsAddMaterialOpen(true);
    };

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-6">

            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-black text-text-primary flex items-center gap-3">
                        <Package className="text-primary" size={32} />
                        {t('inventory.title')}
                    </h1>
                    <p className="text-text-secondary mt-1">{t('inventory.subtitle')}</p>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-border">
                <button
                    onClick={() => setActiveTab('stock')}
                    className={`pb-3 px-6 text-sm font-bold flex items-center gap-2 transition-colors relative
                        ${activeTab === 'stock' ? 'text-primary' : 'text-text-secondary hover:text-text-primary'}
                    `}
                >
                    <Layers size={18} />
                    {t('inventory.tabs.stock')}
                    {activeTab === 'stock' && (
                        <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary rounded-t-full" />
                    )}
                </button>
                <button
                    onClick={() => setActiveTab('warehouses')}
                    className={`pb-3 px-6 text-sm font-bold flex items-center gap-2 transition-colors relative
                        ${activeTab === 'warehouses' ? 'text-primary' : 'text-text-secondary hover:text-text-primary'}
                    `}
                >
                    <Warehouse size={18} />
                    {t('inventory.tabs.warehouses')}
                    {activeTab === 'warehouses' && (
                        <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-primary rounded-t-full" />
                    )}
                </button>
            </div>

            {/* Content based on Tab */}
            {activeTab === 'stock' ? (
                <>
                    {/* Alerts Section */}
                    {alerts && alerts.length > 0 && (
                        <div className="bg-red-50 border border-red-200 rounded-2xl p-4 animate-in slide-in-from-top-2">
                            <h3 className="flex items-center gap-2 text-red-800 font-bold mb-3">
                                <AlertTriangle size={20} />
                                {t('inventory.alerts.title')}
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                                {alerts.map((alert, idx) => (
                                    <div key={idx} className="bg-white p-3 rounded-xl border border-red-100 flex items-center justify-between shadow-sm">
                                        <div>
                                            <div className="font-bold text-slate-800">{alert.material_name}</div>
                                            <div className="text-xs text-slate-500 font-mono">{alert.batch_number}</div>
                                        </div>
                                        <div className="text-right">
                                            <div className="text-sm font-bold text-red-600">{alert.days_left} {t('inventory.alerts.days_left')}</div>
                                            <div className="text-xs text-slate-400">{new Date(alert.expiry_date).toLocaleDateString()}</div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {/* Main Content */}
                    <StockList
                        onAddMaterial={handleOpenAdd}
                        onEditMaterial={handleOpenEdit}
                        onReceiveStock={() => setIsReceiveStockOpen(true)}
                    />
                </>
            ) : (
                <WarehouseList />
            )}

            {/* Modals */}
            <AddMaterialModal
                isOpen={isAddMaterialOpen}
                onClose={() => setIsAddMaterialOpen(false)}
                initialData={editingMaterial}
            />

            <ReceiveStockModal
                isOpen={isReceiveStockOpen}
                onClose={() => setIsReceiveStockOpen(false)}
            />
        </div>
    );
};

export default Inventory;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { X, Building2, FlaskConical, DollarSign, Calendar, CheckCircle, Clock, TrendingUp, Plus, Search } from 'lucide-react';
import { getLabStats, getLabOrders, getLabPayments, createLabPayment } from '../api';

const LabDetailsModal = ({ lab, isOpen, onClose }) => {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('overview'); // overview, orders, payments
    const [stats, setStats] = useState(null);
    const [orders, setOrders] = useState([]);
    const [payments, setPayments] = useState([]);
    const [loading, setLoading] = useState(false);

    // Order filters
    const [orderStatus, setOrderStatus] = useState('');

    // Payment Form
    const [showPaymentForm, setShowPaymentForm] = useState(false);
    const [paymentData, setPaymentData] = useState({ amount: '', notes: '', method: 'Cash' });

    useEffect(() => {
        if (isOpen && lab) {
            loadData();
            setActiveTab('overview');
            setOrderStatus('');
            setShowPaymentForm(false);
        }
    }, [isOpen, lab]);

    // Reload orders when filter changes
    useEffect(() => {
        if (activeTab === 'orders' && lab) {
            loadOrders();
        }
    }, [orderStatus]);

    const loadData = async () => {
        setLoading(true);
        try {
            const [statsRes, ordersRes, paymentsRes] = await Promise.all([
                getLabStats(lab.id),
                getLabOrders({ laboratory_id: lab.id }),
                getLabPayments(lab.id)
            ]);
            setStats(statsRes.data);
            setOrders(ordersRes.data);
            setPayments(paymentsRes.data);
        } catch (error) {
            console.error("Failed to load lab details", error);
        } finally {
            setLoading(false);
        }
    };

    const loadOrders = async () => {
        try {
            const res = await getLabOrders({ laboratory_id: lab.id, status: orderStatus || undefined });
            setOrders(res.data);
        } catch (error) {
            console.error("Failed to filter orders", error);
        }
    };

    const handleAddPayment = async (e) => {
        e.preventDefault();
        if (!paymentData.amount) return;

        try {
            await createLabPayment(lab.id, paymentData);
            setPaymentData({ amount: '', notes: '', method: 'Cash' });
            setShowPaymentForm(false);
            loadData(); // Reload all to update balance
        } catch (error) {
            alert(t('labs.details.payments.messages.add_fail'));
        }
    };

    if (!isOpen || !lab) return null;

    return (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-white w-full max-w-4xl rounded-2xl shadow-2xl max-h-[90vh] overflow-hidden flex flex-col">
                {/* Header */}
                <div className="p-6 bg-slate-50 border-b flex justify-between items-center">
                    <div className="flex items-center gap-4">
                        <div className="p-3 bg-purple-100 rounded-xl text-purple-600">
                            <FlaskConical size={24} />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-800">{lab.name}</h2>
                            <div className="flex gap-3 text-sm text-slate-500">
                                {lab.phone && <span>{lab.phone}</span>}
                                {lab.contact_person && <span>• {lab.contact_person}</span>}
                            </div>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                        <X size={20} className="text-slate-500" />
                    </button>
                </div>

                {/* Tabs */}
                <div className="flex border-b px-6 bg-white shrink-0">
                    <button
                        onClick={() => setActiveTab('overview')}
                        className={`px-4 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === 'overview' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                    >
                        {t('labs.details.tabs.overview')}
                    </button>
                    <button
                        onClick={() => setActiveTab('orders')}
                        className={`px-4 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === 'orders' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                    >
                        {t('labs.details.tabs.orders')} ({stats?.total_orders || 0})
                    </button>
                    <button
                        onClick={() => setActiveTab('payments')}
                        className={`px-4 py-3 text-sm font-bold border-b-2 transition-colors ${activeTab === 'payments' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                    >
                        {t('labs.details.tabs.payments')}
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 bg-slate-50/50">
                    {loading && !stats ? (
                        <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-600"></div></div>
                    ) : (
                        <>
                            {/* OVERVIEW TAB */}
                            {activeTab === 'overview' && stats && (
                                <div className="space-y-6 animate-in slide-in-from-bottom-2 fade-in duration-300">
                                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                                        <div className="bg-white p-4 rounded-xl border shadow-sm">
                                            <div className="text-sm text-slate-500 mb-1">{t('labs.details.overview.total_cost')}</div>
                                            <div className="text-2xl font-black text-slate-800">{stats.total_cost}</div>
                                        </div>
                                        <div className="bg-white p-4 rounded-xl border shadow-sm">
                                            <div className="text-sm text-slate-500 mb-1">{t('labs.details.overview.paid')}</div>
                                            <div className="text-2xl font-black text-emerald-600">{stats.total_paid}</div>
                                        </div>
                                        <div className={`bg-white p-4 rounded-xl border shadow-sm ${stats.balance > 0 ? 'border-red-200 bg-red-50' : 'border-emerald-200 bg-emerald-50'}`}>
                                            <div className="text-sm text-slate-500 mb-1">{t('labs.details.overview.balance')}</div>
                                            <div className={`text-2xl font-black ${stats.balance > 0 ? 'text-red-600' : 'text-emerald-600'}`}>
                                                {stats.balance}
                                            </div>
                                        </div>
                                        <div className="bg-white p-4 rounded-xl border shadow-sm">
                                            <div className="text-sm text-slate-500 mb-1">{t('labs.details.overview.order_status')}</div>
                                            <div className="flex gap-2 text-sm mt-1">
                                                <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded text-xs font-bold">{stats.pending_orders} {t('labs.details.overview.status_pending')}</span>
                                                <span className="bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded text-xs font-bold">{stats.completed_orders} {t('labs.details.overview.status_completed')}</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Recent Activity placeholder could go here */}
                                </div>
                            )}

                            {/* ORDERS TAB */}
                            {activeTab === 'orders' && (
                                <div className="space-y-4 animate-in slide-in-from-bottom-2 fade-in duration-300">
                                    <div className="flex gap-2 mb-4">
                                        <select
                                            className="p-2 border rounded-lg text-sm bg-white"
                                            value={orderStatus}
                                            onChange={(e) => setOrderStatus(e.target.value)}
                                        >
                                            <option value="">{t('labs.details.orders.filter_all')}</option>
                                            <option value="pending">{t('labs.details.orders.filter_pending')}</option>
                                            <option value="in_progress">{t('labs.details.orders.filter_in_progress')}</option>
                                            <option value="completed">{t('labs.details.orders.filter_completed')}</option>
                                        </select>
                                    </div>

                                    <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
                                        <table className="w-full text-sm text-right">
                                            <thead className="bg-slate-50 border-b text-slate-500">
                                                <tr>
                                                    <th className="p-3 font-medium">{t('labs.details.orders.table.patient')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.orders.table.work')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.orders.table.status')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.orders.table.cost')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.orders.table.date')}</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y">
                                                {orders.map(order => (
                                                    <tr key={order.id} className="hover:bg-slate-50/50">
                                                        <td className="p-3 font-bold text-slate-700">{order.patient_name}</td>
                                                        <td className="p-3">
                                                            <div className="font-medium">{order.work_type}</div>
                                                            <div className="text-xs text-slate-400">{order.material} {order.shade && `(${order.shade})`}</div>
                                                        </td>
                                                        <td className="p-3">
                                                            <span className={`px-2 py-1 rounded text-xs font-bold 
                                                                ${order.status === 'completed' ? 'bg-emerald-100 text-emerald-700' :
                                                                    order.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                                                                        'bg-blue-100 text-blue-700'}`}>
                                                                {order.status}
                                                            </span>
                                                        </td>
                                                        <td className="p-3 font-mono">{order.cost}</td>
                                                        <td className="p-3 text-slate-500">{new Date(order.order_date).toLocaleDateString('ar-EG')}</td>
                                                    </tr>
                                                ))}
                                                {orders.length === 0 && (
                                                    <tr>
                                                        <td colSpan="5" className="p-8 text-center text-slate-400">{t('labs.details.orders.table.empty')}</td>
                                                    </tr>
                                                )}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}

                            {/* PAYMENTS TAB */}
                            {activeTab === 'payments' && (
                                <div className="space-y-4 animate-in slide-in-from-bottom-2 fade-in duration-300">
                                    <div className="flex justify-between items-center mb-4">
                                        <h3 className="font-bold text-slate-700">{t('labs.details.payments.title')}</h3>
                                        <button
                                            onClick={() => setShowPaymentForm(!showPaymentForm)}
                                            className="flex items-center gap-2 px-3 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-bold"
                                        >
                                            <Plus size={16} />
                                            {showPaymentForm ? t('labs.details.payments.cancel_button') : t('labs.details.payments.add_button')}
                                        </button>
                                    </div>

                                    {showPaymentForm && (
                                        <form onSubmit={handleAddPayment} className="bg-indigo-50 p-4 rounded-xl mb-4 border border-indigo-100 animate-in fade-in slide-in-from-top-2">
                                            <div className="grid grid-cols-1 md:grid-cols-3 gap-3 mb-3">
                                                <div>
                                                    <label className="block text-xs font-bold text-indigo-800 mb-1">{t('labs.details.payments.form.amount')}</label>
                                                    <input
                                                        type="number"
                                                        value={paymentData.amount}
                                                        onChange={(e) => setPaymentData({ ...paymentData, amount: e.target.value })}
                                                        className="w-full p-2 rounded border focus:ring-2 focus:ring-indigo-500 outline-none"
                                                        required
                                                    />
                                                </div>
                                                <div>
                                                    <label className="block text-xs font-bold text-indigo-800 mb-1">{t('labs.details.payments.form.method')}</label>
                                                    <select
                                                        value={paymentData.method}
                                                        onChange={(e) => setPaymentData({ ...paymentData, method: e.target.value })}
                                                        className="w-full p-2 rounded border focus:ring-2 focus:ring-indigo-500 outline-none"
                                                    >
                                                        <option>Cash</option>
                                                        <option>Bank Transfer</option>
                                                        <option>Cheque</option>
                                                        <option>Vodafone Cash</option>
                                                    </select>
                                                </div>
                                                <div>
                                                    <label className="block text-xs font-bold text-indigo-800 mb-1">{t('labs.details.payments.form.notes')}</label>
                                                    <input
                                                        type="text"
                                                        value={paymentData.notes}
                                                        onChange={(e) => setPaymentData({ ...paymentData, notes: e.target.value })}
                                                        className="w-full p-2 rounded border focus:ring-2 focus:ring-indigo-500 outline-none"
                                                    />
                                                </div>
                                            </div>
                                            <button type="submit" className="w-full py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700">
                                                {t('labs.details.payments.form.submit')}
                                            </button>
                                        </form>
                                    )}

                                    <div className="bg-white rounded-xl border shadow-sm overflow-hidden">
                                        <table className="w-full text-sm text-right">
                                            <thead className="bg-slate-50 border-b text-slate-500">
                                                <tr>
                                                    <th className="p-3 font-medium">{t('labs.details.payments.table.date')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.payments.table.amount')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.payments.table.method')}</th>
                                                    <th className="p-3 font-medium">{t('labs.details.payments.table.notes')}</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y">
                                                {payments.map(payment => (
                                                    <tr key={payment.id} className="hover:bg-slate-50/50">
                                                        <td className="p-3 text-slate-600">{new Date(payment.date).toLocaleDateString('ar-EG')}</td>
                                                        <td className="p-3 font-black text-emerald-600">{payment.amount}</td>
                                                        <td className="p-3 text-slate-500">{payment.method}</td>
                                                        <td className="p-3 text-slate-500 text-xs">{payment.notes || '-'}</td>
                                                    </tr>
                                                ))}
                                                {payments.length === 0 && (
                                                    <tr>
                                                        <td colSpan="4" className="p-8 text-center text-slate-400">{t('labs.details.payments.table.empty')}</td>
                                                    </tr>
                                                )}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

export default LabDetailsModal;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { FlaskConical, Plus, Edit2, Trash2, X, Phone, MapPin, Mail, User, Search, Building2, Crown } from 'lucide-react';
import { getLaboratories, createLaboratory, updateLaboratory, deleteLaboratory, getLabOrdersStats } from '../api';
import LabDetailsModal from './LabDetailsModal';
import GlobalLabOrdersModal from './GlobalLabOrdersModal';

export default function Labs() {
    const { t } = useTranslation();
    const [labs, setLabs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [stats, setStats] = useState(null);

    // Modal State
    const [selectedLab, setSelectedLab] = useState(null);
    const [isDetailsModalOpen, setIsDetailsModalOpen] = useState(false);

    const [isGlobalModalOpen, setIsGlobalModalOpen] = useState(false);
    const [globalModalTitle, setGlobalModalTitle] = useState('');
    const [globalModalStatus, setGlobalModalStatus] = useState('');

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingLab, setEditingLab] = useState(null);
    const [formData, setFormData] = useState({
        name: '',
        phone: '',
        address: '',
        contact_person: '',
        email: '',
        specialties: '',
        notes: ''
    });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const [labsRes, statsRes] = await Promise.all([
                getLaboratories(),
                getLabOrdersStats()
            ]);
            setLabs(labsRes.data);
            setStats(statsRes.data);
        } catch (err) {
            console.error('Failed to load labs:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (lab = null) => {
        if (lab) {
            setEditingLab(lab);
            setFormData({
                name: lab.name || '',
                phone: lab.phone || '',
                address: lab.address || '',
                contact_person: lab.contact_person || '',
                email: lab.email || '',
                specialties: lab.specialties || '',
                notes: lab.notes || ''
            });
        } else {
            setEditingLab(null);
            setFormData({
                name: '',
                phone: '',
                address: '',
                contact_person: '',
                email: '',
                specialties: '',
                notes: ''
            });
        }
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingLab(null);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingLab) {
                await updateLaboratory(editingLab.id, formData);
            } else {
                await createLaboratory(formData);
            }
            handleCloseModal();
            loadData();
        } catch (err) {
            alert(t('labs.messages.save_error'));
            console.error(err);
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm(t('labs.actions.confirm_delete'))) return;
        try {
            await deleteLaboratory(id);
            loadData();
        } catch (err) {
            alert(t('labs.messages.delete_error'));
            console.error(err);
        }
    };

    const filteredLabs = labs.filter(lab =>
        lab.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (lab.contact_person && lab.contact_person.toLowerCase().includes(searchQuery.toLowerCase()))
    );

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-primary border-t-transparent"></div>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
                        <div className="p-2 bg-purple-100 rounded-xl">
                            <FlaskConical className="text-purple-600" size={24} />
                        </div>
                        {t('labs.title')}
                    </h1>
                    <p className="text-slate-500 text-sm mt-1">{t('labs.subtitle')}</p>
                </div>
                <button
                    onClick={() => handleOpenModal()}
                    className="flex items-center gap-2 px-6 py-3 bg-purple-600 text-white font-bold rounded-xl hover:bg-purple-700 shadow-lg shadow-purple-500/20 transition-all"
                >
                    <Plus size={20} />
                    {t('labs.actions.add_lab')}
                </button>
            </div>

            {/* Stats Cards */}
            {stats && (
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-purple-100 rounded-lg">
                                <Building2 className="text-purple-600" size={20} />
                            </div>
                            <div>
                                <p className="text-xs text-slate-500 font-bold">{t('labs.stats.total_labs')}</p>
                                <p className="text-xl font-bold text-slate-800">{stats.total_labs}</p>
                            </div>
                        </div>
                    </div>
                    <div
                        onClick={() => {
                            setGlobalModalTitle(t('labs.stats.pending_orders'));
                            setGlobalModalStatus('pending');
                            setIsGlobalModalOpen(true);
                        }}
                        className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm cursor-pointer hover:shadow-md transition-all hover:border-amber-200"
                    >
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-amber-100 rounded-lg">
                                <Crown className="text-amber-600" size={20} />
                            </div>
                            <div>
                                <p className="text-xs text-slate-500 font-bold">{t('labs.stats.pending_orders')}</p>
                                <p className="text-xl font-bold text-amber-600">{stats.pending_orders}</p>
                            </div>
                        </div>
                    </div>
                    <div
                        onClick={() => {
                            setGlobalModalTitle(t('labs.stats.completed_orders'));
                            setGlobalModalStatus('completed');
                            setIsGlobalModalOpen(true);
                        }}
                        className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm cursor-pointer hover:shadow-md transition-all hover:border-emerald-200"
                    >
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-emerald-100 rounded-lg">
                                <Crown className="text-emerald-600" size={20} />
                            </div>
                            <div>
                                <p className="text-xs text-slate-500 font-bold">{t('labs.stats.completed_orders')}</p>
                                <p className="text-xl font-bold text-emerald-600">{stats.completed_orders}</p>
                            </div>
                        </div>
                    </div>
                    <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-blue-100 rounded-lg">
                                <FlaskConical className="text-blue-600" size={20} />
                            </div>
                            <div>
                                <p className="text-xs text-slate-500 font-bold">{t('labs.stats.profit')}</p>
                                <p className="text-xl font-bold text-blue-600">{stats.profit?.toFixed(0)}</p>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Search */}
            <div className="relative">
                <Search className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input
                    type="text"
                    placeholder={t('labs.search_placeholder')}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pr-12 pl-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:border-purple-500 focus:ring-2 focus:ring-purple-500/20 transition-all"
                />
            </div>

            {/* Labs Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredLabs.map(lab => (
                    <div
                        key={lab.id}
                        onClick={(e) => {
                            // Prevent opening details if clicking edit/delete buttons
                            if (e.target.closest('button')) return;
                            setSelectedLab(lab);
                            setIsDetailsModalOpen(true);
                        }}
                        className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all cursor-pointer hover:border-purple-300 group"
                    >
                        <div className="flex justify-between items-start mb-4">
                            <div className="flex items-center gap-3">
                                <div className="p-3 bg-gradient-to-br from-purple-500 to-indigo-600 rounded-xl text-white">
                                    <FlaskConical size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-slate-800">{lab.name}</h3>
                                    {lab.contact_person && (
                                        <p className="text-sm text-slate-500 flex items-center gap-1">
                                            <User size={12} />
                                            {lab.contact_person}
                                        </p>
                                    )}
                                </div>
                            </div>
                            <div className={`px-2 py-1 rounded-full text-xs font-bold ${lab.is_active ? 'bg-emerald-100 text-emerald-700' : 'bg-red-100 text-red-700'}`}>
                                {lab.is_active ? t('labs.active') : t('labs.inactive')}
                            </div>
                        </div>

                        <div className="space-y-2 text-sm text-slate-600 mb-4">
                            {lab.phone && (
                                <div className="flex items-center gap-2">
                                    <Phone size={14} className="text-slate-400" />
                                    <span dir="ltr">{lab.phone}</span>
                                </div>
                            )}
                            {lab.email && (
                                <div className="flex items-center gap-2">
                                    <Mail size={14} className="text-slate-400" />
                                    <span>{lab.email}</span>
                                </div>
                            )}
                            {lab.address && (
                                <div className="flex items-center gap-2">
                                    <MapPin size={14} className="text-slate-400" />
                                    <span className="truncate">{lab.address}</span>
                                </div>
                            )}
                        </div>

                        {lab.specialties && (
                            <div className="flex flex-wrap gap-1 mb-3">
                                {lab.specialties.split(',').map((s, i) => (
                                    <span key={i} className="px-2 py-0.5 bg-purple-50 text-purple-700 text-xs rounded-full font-medium">
                                        {s.trim()}
                                    </span>
                                ))}
                            </div>
                        )}

                        {lab.notes && (
                            <p className="text-xs text-slate-500 bg-slate-50 p-2 rounded-lg mb-4 line-clamp-2">
                                {lab.notes}
                            </p>
                        )}

                        <div className="flex gap-2 pt-3 border-t border-slate-100">
                            <button
                                onClick={() => handleOpenModal(lab)}
                                className="flex-1 flex items-center justify-center gap-2 px-3 py-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
                            >
                                <Edit2 size={16} />
                                {t('labs.actions.edit')}
                            </button>
                            <button
                                onClick={() => handleDelete(lab.id)}
                                className="flex-1 flex items-center justify-center gap-2 px-3 py-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                            >
                                <Trash2 size={16} />
                                {t('labs.actions.delete')}
                            </button>
                        </div>
                    </div>
                ))}

                {filteredLabs.length === 0 && (
                    <div className="col-span-full py-12 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                        <FlaskConical size={48} className="mx-auto mb-3 text-slate-300" />
                        <FlaskConical size={48} className="mx-auto mb-3 text-slate-300" />
                        <p className="text-slate-500">{t('labs.empty')}</p>
                        <button
                            onClick={() => handleOpenModal()}
                            className="mt-4 text-purple-600 font-bold hover:underline"
                        >
                            {t('labs.add_new_empty')}
                        </button>
                    </div>
                )}
            </div>

            {/* Add/Edit Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white w-full max-w-lg rounded-2xl p-6 shadow-2xl max-h-[90vh] overflow-y-auto">
                        <div className="flex justify-between items-center mb-6">
                            <h3 className="text-xl font-bold text-slate-800">
                                {editingLab ? t('labs.form.edit_title') : t('labs.form.add_title')}
                            </h3>
                            <button
                                onClick={handleCloseModal}
                                className="p-2 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-600 transition-colors"
                            >
                                <X size={20} />
                            </button>
                        </div>

                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-1">
                                    {t('labs.form.name')} <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="text"
                                    value={formData.name}
                                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                    placeholder={t('labs.form.placeholders.name')}
                                    required
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.phone')}</label>
                                    <input
                                        type="tel"
                                        value={formData.phone}
                                        onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                        className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                        placeholder={t('labs.form.placeholders.phone')}
                                        dir="ltr"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.email')}</label>
                                    <input
                                        type="email"
                                        value={formData.email}
                                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                        className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                        placeholder={t('labs.form.placeholders.email')}
                                        dir="ltr"
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.address')}</label>
                                <input
                                    type="text"
                                    value={formData.address}
                                    onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                    placeholder={t('labs.form.placeholders.address')}
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.contact_person')}</label>
                                <input
                                    type="text"
                                    value={formData.contact_person}
                                    onChange={(e) => setFormData({ ...formData, contact_person: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                    placeholder={t('labs.form.placeholders.contact_person')}
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.specialties')}</label>
                                <input
                                    type="text"
                                    value={formData.specialties}
                                    onChange={(e) => setFormData({ ...formData, specialties: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500"
                                    placeholder={t('labs.form.placeholders.specialties')}
                                />
                                <p className="text-xs text-slate-400 mt-1">{t('labs.form.specialties_hint')}</p>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-600 mb-1">{t('labs.form.notes')}</label>
                                <textarea
                                    value={formData.notes}
                                    onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl outline-none focus:ring-2 focus:ring-purple-500/20 border border-transparent focus:border-purple-500 h-24 resize-none"
                                    placeholder={t('labs.form.placeholders.notes')}
                                />
                            </div>

                            <div className="flex gap-3 pt-4">
                                <button
                                    type="button"
                                    onClick={handleCloseModal}
                                    className="flex-1 px-4 py-3 text-slate-600 hover:bg-slate-100 rounded-xl transition-colors font-bold"
                                >
                                    {t('labs.actions.cancel')}
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 px-4 py-3 bg-purple-600 text-white rounded-xl hover:bg-purple-700 transition-colors font-bold shadow-lg shadow-purple-500/20"
                                >
                                    {editingLab ? t('labs.actions.save') : t('labs.actions.add')}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            {/* Lab Details Modal */}
            <LabDetailsModal
                lab={selectedLab}
                isOpen={isDetailsModalOpen}
                onClose={() => setIsDetailsModalOpen(false)}
            />

            {/* Global Orders Modal */}
            <GlobalLabOrdersModal
                isOpen={isGlobalModalOpen}
                onClose={() => setIsGlobalModalOpen(false)}
                initialStatus={globalModalStatus}
                title={globalModalTitle}
            />
        </div>
    );
}

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, Link } from 'react-router-dom';
import { login } from '../api';
import { Sun, Moon, Globe } from 'lucide-react';
import { logoBase64 as logo } from '@/assets/logoBase64';

export default function Login({ isDarkMode, toggleDarkMode }) {
    const { t, i18n } = useTranslation();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const { data } = await login(username, password);
            // Save token based on rememberMe
            if (rememberMe) {
                localStorage.setItem('token', data.access_token);
            } else {
                sessionStorage.setItem('token', data.access_token);
            }
            if (data.role === 'super_admin') {
                window.location.href = '/admin';
            } else {
                window.location.href = '/';
            }
        } catch (err) {
            console.error("Login Error:", err);
            if (err.response) {
                // Server responded with a status code
                setError(err.response.data.detail || err.response.data.error?.message || t('auth.login.errors.server') + ': ' + err.response.status);
            } else if (err.request) {
                // Request made but no response received
                setError(t('auth.login.errors.connection'));
            } else {
                // Something else happened
                setError(t('auth.login.errors.unknown') + ': ' + err.message);
            }
        }
    };

    return (
        <div className={`min-h-screen flex items-center justify-center p-4 transition-colors duration-500 bg-background`}>
            <div className={`w-full max-w-md p-8 rounded-[2rem] shadow-2xl border transition-all duration-300 bg-surface border-white/10 text-center`}>
                <div className="flex justify-between items-start mb-6 w-full">
                    {/* Language Switcher */}
                    <button
                        onClick={() => {
                            const newLang = i18n.language === 'ar' ? 'en' : 'ar';
                            i18n.changeLanguage(newLang);
                        }}
                        className={`p-3 rounded-2xl transition-colors bg-surface-hover text-text-secondary hover:text-text-primary hover:bg-primary/5`}
                        title={i18n.language === 'ar' ? 'Switch to English' : 'تغيير للعربية'}
                    >
                        <Globe size={20} />
                    </button>

                    <div className="h-44 w-full overflow-hidden flex items-center justify-center">
                        <img src={logo} alt="DENTIX Logo" className="h-full w-full object-contain scale-[2.5] translate-x-4" />
                    </div>

                    <button
                        onClick={toggleDarkMode}
                        className={`p-3 rounded-2xl transition-colors bg-surface-hover text-text-secondary hover:text-text-primary hover:bg-primary/5`}
                    >
                        {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
                    </button>
                </div>

                {error && (
                    <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-2xl text-sm font-bold mb-6 animate-shake">
                        {error}
                    </div>
                )}

                <form onSubmit={handleLogin} className="space-y-5">
                    <div className="relative group">
                        <input
                            type="text"
                            placeholder={t('auth.login.username')}
                            className={`w-full p-4 rounded-2xl border outline-none transition-all text-right bg-input border-border text-text-primary focus:border-primary focus:ring-1 focus:ring-primary`}
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                        />
                    </div>
                    <div className="relative group">
                        <input
                            type="password"
                            placeholder={t('auth.login.password')}
                            className={`w-full p-4 rounded-2xl border outline-none transition-all text-right bg-input border-border text-text-primary focus:border-primary focus:ring-1 focus:ring-primary`}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                        />
                    </div>

                    <div className="flex items-center justify-between px-1">
                        <Link
                            to="/forgot-password"
                            className={`text-sm font-bold hover:underline text-primary`}
                        >
                            {t('auth.login.forgot_password')}
                        </Link>
                        <div className="flex items-center gap-3">
                            <label htmlFor="rememberMe" className={`text-sm cursor-pointer select-none font-medium text-text-secondary hover:text-text-primary`}>
                                {t('auth.login.remember_me')}
                            </label>
                            <input
                                id="rememberMe"
                                type="checkbox"
                                className="w-5 h-5 rounded-lg border-slate-300 text-primary focus:ring-primary cursor-pointer transition-transform active:scale-90"
                                checked={rememberMe}
                                onChange={(e) => setRememberMe(e.target.checked)}
                            />
                        </div>
                    </div>

                    <button
                        type="submit"
                        className="w-full py-4 bg-primary text-white font-black rounded-2xl hover:brightness-110 shadow-xl shadow-primary/25 transition-all active:scale-[0.98] transform"
                    >
                        {t('auth.login.submit')}
                    </button>

                    <div className="text-center mt-6">
                        <Link
                            to="/register"
                            className={`inline-block w-full py-3 rounded-2xl border-2 font-bold transition-all ${isDarkMode
                                ? 'border-primary/50 text-primary hover:bg-primary/10'
                                : 'border-primary text-primary hover:bg-primary/5'
                                }`}
                        >
                            {t('auth.login.register_new')}
                        </Link>
                    </div>
                </form>

                <div className="mt-8 pt-6 border-t border-slate-100/10 flex flex-col gap-2">
                    <div className="flex justify-center gap-4 text-xs font-medium text-text-secondary">
                        <Link to="/terms" className="hover:text-primary transition-colors">{t('auth.login.terms')}</Link>
                        <span>•</span>
                        <Link to="/privacy" className="hover:text-primary transition-colors">{t('auth.login.privacy')}</Link>
                    </div>
                    <p className={`text-xs ${isDarkMode ? 'text-slate-500' : 'text-slate-400'}`}>
                        {t('auth.login.copyright')}
                    </p>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useCallback, memo, useMemo, Suspense, lazy, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import DentalChartSVG from '@/features/dental/DentalChartSVG';
import PatientInfoCard from '@/features/patients/PatientInfoCard';
import { useProcedures } from '@/shared/context/ProceduresContext';
import TreatmentModal from '@/shared/ui/modals/TreatmentModal';
import PrescriptionModal from '@/shared/ui/modals/PrescriptionModal';
import PaymentModal from '@/shared/ui/modals/PaymentModal';
import { Skeleton } from '@/shared/ui';
import { useTranslation } from 'react-i18next';

// Hooks for lazy data loading
import {
    usePatient,
    usePatientTeeth,
    usePatientTreatments,
    usePatientPayments,
    usePatientAttachments,
    useInvalidatePatientData
} from '@/hooks/usePatientDetails';

import { Baby, User as UserIcon, X } from 'lucide-react';
import { toothToNumber, palmerToFdi, fdiToPalmer, getTodayStr, universalToPalmer } from '../utils/toothUtils';
import { getToken } from '../utils';
import {
    updatePatient, updateToothStatus,
    createTreatment, createPayment, deleteTreatment, deletePayment,
    uploadAttachment, deleteAttachment, updateTreatment,
    createPrescription, getUsers
} from '../api';
import { consumeStock } from '@/api/inventory';
import { showToast } from '@/shared/ui/Toast';

// Lazy load tab components - only loaded when tab is active
const TreatmentHistory = lazy(() => import('@/features/patients/PatientTabs/TreatmentHistory'));
const PatientFiles = lazy(() => import('@/features/patients/PatientTabs/PatientFiles'));
const PatientBilling = lazy(() => import('@/features/patients/PatientTabs/PatientBilling'));
const LabOrdersTab = lazy(() => import('@/features/lab/LabOrdersTab'));

// Tab skeleton component
const TabSkeleton = memo(() => (
    <div className="space-y-4 p-4">
        <Skeleton.Box height="4rem" className="rounded-xl" />
        <Skeleton.Box height="4rem" className="rounded-xl" />
        <Skeleton.Box height="4rem" className="rounded-xl" />
    </div>
));

// Patient info skeleton
const PatientInfoSkeleton = memo(() => (
    <div className="bg-surface rounded-3xl p-6 border border-border animate-pulse">
        <div className="flex items-center gap-4">
            <div className="w-16 h-16 bg-slate-200 dark:bg-slate-700 rounded-2xl" />
            <div className="flex-1 space-y-2">
                <div className="h-6 bg-slate-200 dark:bg-slate-700 rounded w-48" />
                <div className="h-4 bg-slate-200 dark:bg-slate-700 rounded w-32" />
            </div>
        </div>
    </div>
));

// Price List Selector Component
const PriceListSelector = ({ value, onChange }) => {
    const { t } = useTranslation();
    const [lists, setLists] = useState([]);
    const [loading, setLoading] = useState(true);

    React.useEffect(() => {
        if (!getToken()) {
            setLoading(false);
            return;
        }
        import('@/api').then(({ getPriceLists }) => {
            getPriceLists()
                .then(res => {
                    setLists(res.data || []);
                })
                .catch(() => {
                    // 401 or other error: keep lists empty, user can still use "Default"
                    setLists([]);
                })
                .finally(() => setLoading(false));
        });
    }, []);

    if (loading) return <div className="text-sm text-gray-400">{t('common.loading')}</div>;

    const valueStr = value === null || value === undefined ? '' : String(value);
    return (
        <select
            value={valueStr}
            onChange={e => {
                const v = e.target.value;
                onChange(v ? parseInt(v, 10) : null);
            }}
            className="w-full p-3 bg-white rounded-xl outline-none border border-gray-200 focus:border-blue-500"
        >
            <option value="">{t('patient_details.edit_modal.default_option')}</option>
            {Array.isArray(lists) && lists.map(l => (
                <option key={l.id} value={String(l.id)}>
                    {l.name} {l.type === 'insurance' ? t('patient_details.edit_modal.insurance_tag') : ''}
                </option>
            ))}
        </select>
    );
};

export default function PatientDetails() {
    const { t } = useTranslation();
    const { id } = useParams();
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('chart');

    // Cache procedures from context
    const { procedures } = useProcedures();

    // Invalidation helper
    const invalidateData = useInvalidatePatientData();

    // Feature Toggle
    const [isPediatric, setIsPediatric] = useState(false);

    // === LAZY DATA LOADING ===
    // Patient core data - loads immediately
    const { data: patient, isLoading: patientLoading, isError: patientIsError, error: patientError, refetch: refetchPatient } = usePatient(id);

    // Teeth data - loads for chart tab (default)
    const { data: teethStatus = {}, isLoading: teethLoading, refetch: refetchTeeth } = usePatientTeeth(id, true);

    // Tab-specific data - only loads when tab is active
    const { data: history = [], isLoading: historyLoading, refetch: refetchHistory } = usePatientTreatments(
        id,
        activeTab === 'history' || activeTab === 'billing' // Also needed for billing calculations
    );

    const { data: payments = [], isLoading: paymentsLoading, refetch: refetchPayments } = usePatientPayments(
        id,
        activeTab === 'billing'
    );

    const { data: attachments = [], isLoading: attachmentsLoading, refetch: refetchAttachments } = usePatientAttachments(
        id,
        activeTab === 'files'
    );

    // Local state for teeth (to allow optimistic updates)
    const [localTeethStatus, setLocalTeethStatus] = useState(null);
    const effectiveTeethStatus = localTeethStatus ?? teethStatus;

    // Modals
    const [isEditPatientOpen, setIsEditPatientOpen] = useState(false);
    const [isRxModalOpen, setIsRxModalOpen] = useState(false);
    const [isTreatmentModalOpen, setIsTreatmentModalOpen] = useState(false);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isToothSelectModalOpen, setIsToothSelectModalOpen] = useState(false);

    const getInitialTreatment = () => ({
        date: getTodayStr(), diagnosis: '', procedure: '', cost: '', discount: '',
        tooth_number: '', canal_count: '', canals: [{ name: '', length: '' }],
        sessions: '', complications: '', notes: ''
    });

    const [newTreatment, setNewTreatment] = useState(getInitialTreatment());
    const [editingTreatmentId, setEditingTreatmentId] = useState(null);
    const [selectedToothCondition, setSelectedToothCondition] = useState('Healthy');
    const [doctors, setDoctors] = useState([]);

    // Fetch doctors for the edit modal
    useEffect(() => {
        if (isEditPatientOpen) {
            getUsers({ role: 'doctor' })
                .then(res => setDoctors(res.data))
                .catch(err => console.error("Failed to fetch doctors", err));
        }
    }, [isEditPatientOpen]);

    // === HANDLERS ===
    const handleFileUpload = useCallback(async (e) => {
        const file = e.target.files[0];
        if (!file) return;

        try {
            await uploadAttachment(id, file);
            refetchAttachments();
        } catch (err) {
            showToast('error', t('patient_details.alerts.upload_fail'));
        }
    }, [id, refetchAttachments, t]);

    const handleDeleteAttachment = useCallback(async (attachmentId) => {
        if (!confirm('Delete this file?')) return;
        try {
            await deleteAttachment(attachmentId);
            refetchAttachments();
        } catch (err) {
            // Silent error
        }
    }, [refetchAttachments]);

    const handleToothClick = useCallback((number) => {
        const fdi = toothToNumber(number);
        const current = effectiveTeethStatus[fdi]?.condition || 'Healthy';
        setSelectedToothCondition(current);
        const palmerPrefix = universalToPalmer(number, isPediatric);
        setNewTreatment({
            ...getInitialTreatment(),
            tooth_number: palmerPrefix,
            default_price_list_id: patient?.default_price_list_id // Inject default price list
        });
        setIsTreatmentModalOpen(true);
    }, [effectiveTeethStatus, isPediatric, patient]);


    // Form Data State
    const [formData, setFormData] = useState({});

    useEffect(() => {
        if (isEditPatientOpen && patient) {
            setFormData({
                name: patient.name,
                age: patient.age,
                phone: patient.phone,
                address: patient.address,
                default_price_list_id: patient.default_price_list_id,
                assigned_doctor_id: patient.assigned_doctor_id
            });
        }
    }, [isEditPatientOpen, patient]);

    const handleSavePatient = useCallback(async (e) => {
        e.preventDefault();
        try {
            await updatePatient(id, formData);
            setIsEditPatientOpen(false);
            refetchPatient();
        } catch (err) {
            showToast('error', t('common.error') + ': ' + (err.response?.data?.detail || err.message));
        }
    }, [id, formData, refetchPatient, t]);
    const handleNewAppointment = useCallback(() => {
        navigate(`/appointments?patient_id=${id}`);
    }, [navigate, id]);

    const handleSaveTreatment = useCallback(async (data) => {
        try {
            // Prepare payload: convert Palmer tooth number (e.g. "UR5") to FDI integer (e.g. 15)
            // Backend expects integer or null
            let fdiToothNumber = data.tooth_number;
            if (typeof data.tooth_number === 'string') {
                fdiToothNumber = palmerToFdi(data.tooth_number);
            }

            // If conversion fails (e.g. generic input) but we have a string, set to null to avoid 422
            // unless backend handles string (it doesn't, schema is int)
            if (data.tooth_number && !fdiToothNumber) {
                // Warning: Invalid tooth number string, stripping it to prevent crash
                fdiToothNumber = null;
            }

            const payload = {
                ...data,
                tooth_number: fdiToothNumber,
                patient_id: parseInt(id, 10)
            };

            // 1. Save Treatment
            if (editingTreatmentId) {
                await updateTreatment(editingTreatmentId, payload);
            } else {
                await createTreatment(payload);
            }

            // 2. Update Tooth Status if applicable
            if (data.tooth_number && selectedToothCondition) {
                try {
                    console.log("[DEBUG] Updating Tooth Status:", {
                        patientId: id,
                        tooth: data.tooth_number,
                        condition: selectedToothCondition
                    });

                    // Start of Fix: Ensure we convert Palmer/Display string back to Internal FDI Integer
                    let fdiNumber = palmerToFdi(data.tooth_number);
                    console.log("[DEBUG] FDI Number:", fdiNumber);

                    if (fdiNumber) {
                        await updateToothStatus({
                            patient_id: parseInt(id, 10),
                            tooth_number: fdiNumber,
                            condition: selectedToothCondition
                        });
                        console.log("[DEBUG] Tooth status updated successfully");
                        await refetchTeeth(); // Await refetch
                    } else {
                        console.warn("[DEBUG] Failed to convert to FDI:", data.tooth_number);
                    }
                } catch (e) {
                    console.error("Failed to update tooth status", e);
                    showToast('error', t('patient_details.alerts.tooth_update_fail'));
                }
            }

            setIsTreatmentModalOpen(false);
            setEditingTreatmentId(null);
            refetchHistory();
            showToast('success', t('patient_details.alerts.treatment_save_success'));
        } catch (err) {
            console.error(err);
            const res = err.response?.data;
            const detail = res?.detail;
            const envelope = res?.error;
            const msg = envelope?.details?.message || envelope?.message || detail || res?.message;

            // SPECIAL HANDLING: If generic error, show alert. 
            // If "CONFIRM_OPEN_REQUIRED", rethrow so TreatmentModal can handle it.
            if (
                detail?.code === "CONFIRM_OPEN_REQUIRED" ||
                envelope?.details?.code === "CONFIRM_OPEN_REQUIRED" ||
                (typeof msg === 'string' && msg.includes('CONFIRM_OPEN_REQUIRED'))
            ) {
                throw err;
            }

            const finalMsg = typeof msg === 'object' ? JSON.stringify(msg) : (msg || t('patient_details.alerts.treatment_save_fail'));
            showToast('error', finalMsg);
        }
    }, [id, editingTreatmentId, refetchHistory, refetchTeeth, selectedToothCondition, t]);

    const handleSavePayment = useCallback(async (data) => {
        try {
            await createPayment({ ...data, patient_id: parseInt(id, 10) });
            setIsPaymentModalOpen(false);
            setIsPaymentModalOpen(false);
            refetchPayments();
        } catch (err) {
            showToast('error', err.response?.data?.detail || t('patient_details.alerts.payment_save_fail'));
        }
    }, [id, refetchPayments, t]);

    const openManualTreatment = useCallback(() => {
        setEditingTreatmentId(null);
        setNewTreatment({
            ...getInitialTreatment(),
            tooth_number: '',
            default_price_list_id: patient?.default_price_list_id
        });
        setIsTreatmentModalOpen(true);
    }, [patient]);

    const handleEditTreatment = useCallback((item) => {
        setEditingTreatmentId(item.id);
        let canals = [{ name: '', length: '' }];
        try {
            const parsed = item.canal_lengths ? JSON.parse(item.canal_lengths) : null;
            if (Array.isArray(parsed) && parsed.length) canals = parsed;
        } catch { /* ignore */ }

        setNewTreatment({
            date: item.date ? new Date(item.date).toLocaleDateString('en-CA') : getTodayStr(),
            diagnosis: item.diagnosis || '',
            procedure: item.procedure || '',
            cost: item.cost ?? '',
            discount: item.discount ?? '',
            tooth_number: item.tooth_number ? fdiToPalmer(item.tooth_number) : '',
            canal_count: item.canal_count ?? '',
            canals,
            sessions: item.sessions || '',
            complications: item.complications || '',
            notes: item.notes || '',
            default_price_list_id: patient?.default_price_list_id
        });
        setIsTreatmentModalOpen(true);
    }, [patient]);

    const handleDeleteTreatment = useCallback(async (treatmentId) => {
        if (!window.confirm(t('patient_details.alerts.delete_treatment_confirm'))) return;
        try {
            await deleteTreatment(treatmentId);
            refetchHistory();
        } catch (err) {
            showToast('error', err.response?.data?.detail || t('patient_details.alerts.delete_treatment_fail'));
        }
    }, [refetchHistory, t]);

    const handleDeletePayment = useCallback(async (paymentId) => {
        if (!window.confirm(t('patient_details.alerts.delete_payment_confirm'))) return;
        try {
            await deletePayment(paymentId);
            refetchPayments();
        } catch (err) {
            showToast('error', err.response?.data?.detail || t('patient_details.alerts.delete_payment_fail'));
        }
    }, [refetchPayments, t]);

    const handlePrintInvoice = useCallback(() => {
        navigate(`/print/invoice/${id}`);
    }, [navigate, id]);

    const handlePrintRx = useCallback(async ({ drugs, notes }) => {
        try {
            const payload = {
                patient_id: parseInt(id, 10),
                medications: JSON.stringify(drugs || []),
                notes: notes || ''
            };
            const res = await createPrescription(payload);
            sessionStorage.setItem('print_rx_data', JSON.stringify({
                patient,
                prescription: res.data
            }));
            setIsRxModalOpen(false);
            navigate(`/print/rx/${id}`);
            setIsRxModalOpen(false);
            navigate(`/print/rx/${id}`);
        } catch (err) {
            showToast('error', err.response?.data?.detail || t('patient_details.alerts.rx_fail'));
        }
    }, [id, patient, navigate, t]);

    return (
        <div className="space-y-6 p-4 md:p-6">
            {patientIsError ? (
                <div className="p-4 rounded-xl border border-red-200 bg-red-50 text-red-700">
                    <div className="font-bold mb-1">{t('patient_details.loading_error')}</div>
                    <div className="text-sm">
                        {patientError?.response?.data?.detail || patientError?.message || t('patient_details.unknown_error')}
                    </div>
                    <div className="mt-3 flex gap-2">
                        <button
                            onClick={() => refetchPatient()}
                            className="px-4 py-2 bg-white border border-red-200 rounded-lg text-sm font-bold hover:bg-red-50"
                        >
                            {t('patient_details.retry')}
                        </button>
                        <button
                            onClick={() => navigate('/')}
                            className="px-4 py-2 bg-red-600 text-white rounded-lg text-sm font-bold hover:bg-red-700"
                        >
                            {t('patient_details.login')}
                        </button>
                    </div>
                </div>
            ) : patientLoading ? (
                <PatientInfoSkeleton />
            ) : patient ? (
                <PatientInfoCard
                    patient={patient}
                    onEdit={() => setIsEditPatientOpen(true)}
                    onPrescription={() => setIsRxModalOpen(true)}
                    onNewAppointment={handleNewAppointment}
                />
            ) : (
                <div className="p-4 rounded-xl border border-slate-200 bg-slate-50 text-slate-700">
                    {t('patient_details.no_data')}
                </div>
            )}

            {/* Tabs */}
            <div className="bg-white rounded-2xl border border-slate-100 p-2 flex flex-wrap gap-2">
                {[
                    { id: 'chart', label: t('patient_details.tabs.chart') },
                    { id: 'history', label: t('patient_details.tabs.history') },
                    { id: 'files', label: t('patient_details.tabs.files') },
                    { id: 'billing', label: t('patient_details.tabs.billing') },
                    { id: 'labs', label: t('patient_details.tabs.labs') },
                ].map(t => (
                    <button
                        key={t.id}
                        onClick={() => setActiveTab(t.id)}
                        className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === t.id ? 'bg-primary text-white shadow' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
                    >
                        {t.label}
                    </button>
                ))}
            </div>

            {/* Tab Content */}
            {activeTab === 'chart' && (
                <div className="bg-white rounded-2xl border border-slate-100 p-4 space-y-4">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
                        <div>
                            <h3 className="font-bold text-slate-800">{t('patient_details.chart.title')}</h3>
                            <p className="text-xs text-slate-400">{t('patient_details.chart.subtitle')}</p>
                        </div>
                        <div className="flex items-center gap-2">
                            <button
                                onClick={() => setIsPediatric(v => !v)}
                                className={`px-4 py-2 rounded-xl text-sm font-bold border transition-colors ${isPediatric ? 'bg-amber-50 border-amber-200 text-amber-700' : 'bg-slate-50 border-slate-200 text-slate-600'}`}
                                title={t('patient_details.chart.pediatric_mode')}
                            >
                                <Baby size={16} className="inline-block scale-x-[-1] ml-2 rtl:ml-0 rtl:mr-2" />
                                {isPediatric ? t('patient_details.chart.child') : t('patient_details.chart.adult')}
                            </button>
                            <button
                                onClick={() => setIsToothSelectModalOpen(true)}
                                className="px-4 py-2 rounded-xl text-sm font-bold bg-emerald-500 text-white hover:bg-emerald-600"
                            >
                                {t('patient_details.chart.new_treatment')}
                            </button>
                        </div>
                    </div>

                    {teethLoading ? (
                        <TabSkeleton />
                    ) : (
                        <DentalChartSVG
                            teethStatus={effectiveTeethStatus}
                            onToothClick={handleToothClick}
                            isPediatric={isPediatric}
                        />
                    )}
                </div>
            )}

            {activeTab === 'history' && (
                <Suspense fallback={<TabSkeleton />}>
                    <TreatmentHistory
                        history={history}
                        onAdd={openManualTreatment}
                        onEdit={handleEditTreatment}
                        onDelete={handleDeleteTreatment}
                    />
                </Suspense>
            )}

            {activeTab === 'files' && (
                <Suspense fallback={<TabSkeleton />}>
                    <PatientFiles
                        attachments={attachments}
                        handleFileUpload={handleFileUpload}
                        handleDeleteAttachment={handleDeleteAttachment}
                        loading={attachmentsLoading}
                        reloadAttachments={refetchAttachments}
                    />
                </Suspense>
            )}

            {activeTab === 'billing' && (
                <Suspense fallback={<TabSkeleton />}>
                    <PatientBilling
                        patientId={id}
                        history={history}
                        payments={payments}
                        onAddPayment={() => setIsPaymentModalOpen(true)}
                        onDeletePayment={handleDeletePayment}
                        onPrintInvoice={handlePrintInvoice}
                    />
                </Suspense>
            )}

            {activeTab === 'labs' && (
                <Suspense fallback={<TabSkeleton />}>
                    <LabOrdersTab patientId={id} />
                </Suspense>
            )}

            {/* Edit Patient Modal */}
            {
                isEditPatientOpen && (
                    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
                        <div className="bg-white w-full max-w-lg rounded-2xl p-6 shadow-2xl max-h-[90vh] overflow-y-auto">
                            <h3 className="text-xl font-bold mb-4">{t('patient_details.edit_modal.title')}</h3>
                            <form onSubmit={handleSavePatient} className="space-y-4">
                                <input value={formData.name || ''} onChange={(e) => setFormData({ ...formData, name: e.target.value })} className="w-full p-3 bg-slate-50 rounded-xl outline-none border focus:border-primary" placeholder={t('patients.form.name_label')} />
                                <div className="grid grid-cols-2 gap-4">
                                    <input value={formData.age || ''} onChange={(e) => setFormData({ ...formData, age: e.target.value })} className="w-full p-3 bg-slate-50 rounded-xl outline-none border focus:border-primary" placeholder={t('patients.form.age_label')} />
                                    <input value={formData.phone || ''} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} className="w-full p-3 bg-slate-50 rounded-xl outline-none border focus:border-primary" placeholder={t('patients.form.phone_label')} />
                                </div>
                                <input value={formData.address || ''} onChange={(e) => setFormData({ ...formData, address: e.target.value })} className="w-full p-3 bg-slate-50 rounded-xl outline-none border focus:border-primary" placeholder={t('patients.form.address_label')} />

                                {/* Price List Selector */}
                                <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('patient_details.edit_modal.price_list_label')}</label>
                                    <PriceListSelector
                                        value={formData.default_price_list_id ?? ''}
                                        onChange={(val) => setFormData(prev => ({ ...prev, default_price_list_id: val }))}
                                    />
                                    <p className="text-xs text-slate-400 mt-1">{t('patient_details.edit_modal.price_list_hint')}</p>
                                </div>

                                {/* Doctor Assignment */}
                                <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('patient_details.edit_modal.doctor_label')}</label>
                                    <select
                                        value={formData.assigned_doctor_id || ''}
                                        onChange={(e) => setFormData({ ...formData, assigned_doctor_id: e.target.value })}
                                        className="w-full p-3 bg-white rounded-xl outline-none border border-gray-200 focus:border-blue-500"
                                    >
                                        <option value="">{t('patient_details.edit_modal.doctor_select')}</option>
                                        {doctors.map(doc => (
                                            <option key={doc.id} value={doc.id}>
                                                د. {doc.username}
                                            </option>
                                        ))}
                                    </select>
                                    <p className="text-xs text-slate-400 mt-1">{t('patient_details.edit_modal.doctor_hint')}</p>
                                </div>

                                <div className="flex justify-end gap-3"><button type="button" onClick={() => setIsEditPatientOpen(false)} className="px-4 py-2 hover:bg-slate-100 rounded-lg">{t('common.cancel')}</button><button type="submit" className="px-6 py-2 bg-primary text-white rounded-lg">{t('common.save')}</button></div>
                            </form>
                        </div>
                    </div >
                )
            }

            <TreatmentModal
                isOpen={isTreatmentModalOpen}
                onClose={() => setIsTreatmentModalOpen(false)}
                onSave={handleSaveTreatment}
                initialData={newTreatment}
                isEditing={!!editingTreatmentId}
                procedures={procedures}
                selectedToothCondition={selectedToothCondition}
                setSelectedToothCondition={setSelectedToothCondition}
            />

            <PrescriptionModal
                isOpen={isRxModalOpen}
                onClose={() => setIsRxModalOpen(false)}
                onPrint={handlePrintRx}
            />

            <PaymentModal
                isOpen={isPaymentModalOpen}
                onClose={() => setIsPaymentModalOpen(false)}
                onAdd={handleSavePayment}
            />

            {
                isToothSelectModalOpen && (
                    <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4 backdrop-blur-md">
                        <div className="bg-white w-full max-w-4xl rounded-3xl p-6 shadow-2xl overflow-y-auto max-h-[95vh]">
                            <div className="flex justify-between items-center mb-6">
                                <h3 className="text-2xl font-bold text-slate-800">{t('patient_details.chart.tooth_modal_title')}</h3>
                                <button onClick={() => setIsToothSelectModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full"><X /></button>
                            </div>
                            <div className="mb-8">
                                <DentalChartSVG
                                    teethStatus={effectiveTeethStatus}
                                    onToothClick={(num) => {
                                        handleToothClick(num);
                                        setIsToothSelectModalOpen(false);
                                    }}
                                    isPediatric={isPediatric}
                                />
                            </div>
                            <div className="flex justify-center gap-4">
                                <button
                                    onClick={() => {
                                        setNewTreatment({
                                            ...getInitialTreatment(),
                                            tooth_number: '',
                                            default_price_list_id: patient?.default_price_list_id
                                        });
                                        setIsTreatmentModalOpen(true);
                                        setIsToothSelectModalOpen(false);
                                    }}
                                    className="px-8 py-3 bg-slate-100 text-slate-600 font-bold rounded-xl hover:bg-slate-200 transition-all"
                                >
                                    {t('patient_details.chart.continue_no_tooth')}
                                </button>
                            </div>
                        </div>
                    </div>
                )
            }
        </div >
    );
}

import React, { useState, useMemo, memo, useCallback } from 'react';
import { Search, Plus, User, Trash2, Users, UserPlus, Activity, Phone, MapPin, Calendar, Clock } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { createPatient, deletePatient, searchPatients, getUsers } from '@/api';
import { usePatients } from '@/hooks/usePatients';
import { useAuth } from '@/auth/useAuth';
import PatientScanner from '@/features/patients/PatientScanner';
import { Skeleton, EmptyState, Modal, Button, Input, toast, Badge } from '@/shared/ui';

export default function Patients() {
    const navigate = useNavigate();
    const { t } = useTranslation();

    // Use cached patients data from React Query
    const { data: patients = [], isLoading: loading, refetch } = usePatients();

    const [search, setSearch] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isScannerOpen, setIsScannerOpen] = useState(false);

    const { user } = useAuth();
    const [doctors, setDoctors] = useState([]);

    // New Patient State
    const [newPatient, setNewPatient] = useState({
        name: '',
        age: '',
        phone: '',
        address: '',
        medical_history: '',
        assigned_doctor_id: ''
    });
    const [suggestions, setSuggestions] = useState([]);
    const [searchTimeoutState, setSearchTimeoutState] = useState(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Fetch Doctors if Admin or Staff
    React.useEffect(() => {
        const fetchDoctors = async () => {
            try {
                // If the user is a doctor, they can assign to themselves by default
                // But we still list other doctors in case they want to assign to a colleague
                const res = await getUsers({ role: 'doctor' });
                setDoctors(res.data);

                // Auto-set assigned_doctor_id if current user is a doctor
                if (user?.role === 'doctor') {
                    setNewPatient(prev => ({ ...prev, assigned_doctor_id: user.id }));
                }
            } catch (err) {
                console.error("Failed to fetch doctors", err);
            }
        };
        if (isModalOpen) fetchDoctors();
    }, [isModalOpen, user]);

    // Modern Vibrant Card Colors - keeping this logic as it adds nice variety
    const cardColors = [
        {
            bg: "bg-gradient-to-br from-blue-50 to-indigo-50 dark:from-slate-800/50 dark:to-slate-900/50",
            border: "border-blue-100 dark:border-blue-900/20",
            text: "text-blue-600 dark:text-blue-400",
            accent: "from-blue-500 to-indigo-600"
        },
        {
            bg: "bg-gradient-to-br from-purple-50 to-fuchsia-50 dark:from-slate-800/50 dark:to-slate-900/50",
            border: "border-purple-100 dark:border-purple-900/20",
            text: "text-purple-600 dark:text-purple-400",
            accent: "from-purple-500 to-fuchsia-600"
        },
        {
            bg: "bg-gradient-to-br from-emerald-50 to-teal-50 dark:from-slate-800/50 dark:to-slate-900/50",
            border: "border-emerald-100 dark:border-emerald-900/20",
            text: "text-emerald-600 dark:text-emerald-400",
            accent: "from-emerald-500 to-teal-600"
        },
        {
            bg: "bg-gradient-to-br from-amber-50 to-orange-50 dark:from-slate-800/50 dark:to-slate-900/50",
            border: "border-amber-100 dark:border-amber-900/20",
            text: "text-amber-600 dark:text-amber-400",
            accent: "from-amber-500 to-orange-600"
        },
        {
            bg: "bg-gradient-to-br from-rose-50 to-pink-50 dark:from-slate-800/50 dark:to-slate-900/50",
            border: "border-rose-100 dark:border-rose-900/20",
            text: "text-rose-600 dark:text-rose-400",
            accent: "from-rose-500 to-pink-600"
        }
    ];

    // cardColors array stays the same...

    // Derived Stats
    const stats = useMemo(() => {
        const total = patients.length;
        const newThisMonth = patients.filter(p => {
            if (!p.created_at) return false;
            const date = new Date(p.created_at);
            const now = new Date();
            return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
        }).length;
        const active = Math.floor(total * 0.7); // Mock logic kept
        return { total, newThisMonth, active };
    }, [patients]);

    const handleDeletePatient = useCallback(async (id, name) => {
        if (!window.confirm(t('patients.delete_confirm', { name }))) {
            return;
        }
        const toastId = toast.loading(t('common.loading'));
        try {
            await deletePatient(id);
            toast.success(t('patients.delete_success'), { id: toastId });
            refetch(); // Refetch from cache
        } catch (err) {
            toast.error(t('patients.delete_error'), { id: toastId });
        }
    }, [refetch, t]);

    const handleCreatePatient = async (e) => {
        e.preventDefault();
        if (!newPatient.name || !newPatient.phone) {
            toast.error(t('patients.form.name_placeholder') + ' ' + t('common.and') + ' ' + t('patients.form.phone_label')); // Fallback simplistic validation message
            return;
        }

        setIsSubmitting(true);
        const toastId = toast.loading(t('common.loading'));

        try {
            // Check duplicates
            const res = await searchPatients(newPatient.phone);
            const duplicates = res.data;
            const exactMatch = duplicates.find(p => p.phone === newPatient.phone && p.name === newPatient.name);
            if (exactMatch) {
                toast.error(t('patients.form.duplicate_error'), { id: toastId });
                setIsSubmitting(false);
                return;
            }
            // Logic for phone match warning could be a confirm dialog or toast action, keeping simple for now
        } catch (err) {
            console.error("Error checking duplicates", err);
        }

        try {
            await createPatient({
                name: newPatient.name,
                age: parseInt(newPatient.age) || 0,
                phone: newPatient.phone,
                address: newPatient.address || '',
                medical_history: newPatient.medical_history || '',
                assigned_doctor_id: newPatient.assigned_doctor_id || null,
                notes: ''
            });
            toast.success(t('patients.form.submit_btn'), { id: toastId });
            setIsModalOpen(false);
            setNewPatient({
                name: '',
                age: '',
                phone: '',
                address: '',
                medical_history: '',
                assigned_doctor_id: user?.role === 'doctor' ? user.id : ''
            });
            setSuggestions([]);
            setSearch('');
            refetch(); // Refetch from cache
        } catch (err) {
            console.error(err);
            const msg = err.response?.data?.detail || t('patients.delete_error'); // Reusing generic error
            toast.error(msg, { id: toastId });
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleInputChange = (field, value) => {
        setNewPatient(prev => ({ ...prev, [field]: value }));

        if (['name', 'phone'].includes(field)) {
            if (searchTimeoutState) clearTimeout(searchTimeoutState);

            if (!value || value.length < 2) {
                setSuggestions([]);
                return;
            }

            const timeoutId = setTimeout(async () => {
                try {
                    const res = await searchPatients(value);
                    setSuggestions(res.data);
                } catch (err) {
                    console.error(err);
                }
            }, 300);
            setSearchTimeoutState(timeoutId);
        }
    };

    const handleScanComplete = (data) => {
        setNewPatient(prev => ({
            ...prev,
            name: data.name || prev.name,
            age: data.age || prev.age,
            phone: data.phone || prev.phone,
            address: data.address || prev.address
        }));
        toast.success(t('patients.form.scan_success'));
    };

    const filteredPatients = patients.filter(p =>
        p.name.includes(search) || p.phone.includes(search)
    );

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700 min-h-screen pb-20">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                    <h2 className="text-4xl font-black text-text-primary tracking-tight flex items-center gap-3">
                        <Users className="text-primary" size={40} />
                        {t('patients.title')}
                    </h2>
                    <p className="text-text-secondary mt-2 text-lg font-medium">{t('patients.subtitle')}</p>
                </div>
                <Button
                    size="lg"
                    onClick={() => setIsModalOpen(true)}
                    className="shadow-xl shadow-primary/25"
                >
                    <Plus size={20} className="mr-2" />
                    {t('patients.add_new')}
                </Button>
            </div>

            {/* Stats Bar */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <StatCard
                    label={t('patients.stats_total')}
                    value={stats.total}
                    icon={Users}
                    color="text-blue-600"
                    bg="bg-blue-50 dark:bg-blue-900/20"
                    loading={loading}
                />
                <StatCard
                    label={t('patients.stats_new_month')}
                    value={stats.newThisMonth}
                    icon={UserPlus}
                    color="text-emerald-600"
                    bg="bg-emerald-50 dark:bg-emerald-900/20"
                    loading={loading}
                />
                <StatCard
                    label={t('patients.stats_active')}
                    value={stats.active}
                    icon={Activity}
                    color="text-violet-600"
                    bg="bg-violet-50 dark:bg-violet-900/20"
                    loading={loading}
                />
            </div>

            {/* Search Bar */}
            <div className="sticky top-20 z-30 bg-surface/80 backdrop-blur-xl p-4 rounded-3xl border border-border shadow-lg shadow-slate-200/50 dark:shadow-black/20 transitiion-all">
                <Input
                    placeholder={t('patients.search_placeholder')}
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    icon={Search}
                    className="border-none bg-background focus:ring-0 text-lg py-3"
                    containerClassName="w-full"
                />
            </div>

            {/* Patients Grid Virtualized */}
            <div className="flex-1 min-h-[500px]">
                {loading ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {Array.from({ length: 6 }).map((_, i) => <Skeleton.Card key={i} />)}
                    </div>
                ) : filteredPatients.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-20">
                        {filteredPatients.map((patient, index) => {
                            const theme = cardColors[index % cardColors.length];
                            return (
                                <div
                                    key={patient.id}
                                    onClick={() => navigate(`/patients/${patient.id}`)}
                                    className={`group ${theme.bg} rounded-[2rem] p-6 border ${theme.border} shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 relative overflow-hidden cursor-pointer h-[180px]`}
                                >
                                    {/* Card Background Decoration */}
                                    <div className={`absolute top-0 right-0 w-32 h-32 bg-gradient-to-br ${theme.accent} opacity-10 rounded-bl-[4rem] group-hover:opacity-20 transition-all`} />

                                    <div className="relative z-10 flex flex-col h-full justify-between">
                                        <div className="flex justify-between items-start">
                                            <div className="flex items-center gap-3">
                                                <div className={`w-12 h-12 flex-shrink-0 rounded-2xl bg-gradient-to-br ${theme.accent} flex items-center justify-center text-white text-lg font-black shadow-lg shadow-black/5`}>
                                                    {patient.name.charAt(0)}
                                                </div>
                                                <div className="min-w-0">
                                                    <h3 className={`text-base font-black ${theme.text} group-hover:brightness-110 transition-all truncate`} title={patient.name}>{patient.name}</h3>
                                                    <div className="flex items-center gap-2 text-text-secondary text-xs mt-1">
                                                        <Calendar size={12} />
                                                        <span className="font-bold">{patient.age} سنة</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <button
                                                onClick={(e) => { e.stopPropagation(); handleDeletePatient(patient.id, patient.name); }}
                                                className="p-1.5 text-text-secondary hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>

                                        <div className="space-y-1.5">
                                            <div className="flex items-center gap-2 p-2 bg-surface/50 rounded-xl backdrop-blur-sm">
                                                <Phone size={14} className={theme.text} />
                                                <span className="font-bold text-text-primary text-xs" dir="ltr">{patient.phone}</span>
                                            </div>
                                            {patient.address && (
                                                <div className="flex items-center gap-2 p-2 bg-surface/50 rounded-xl backdrop-blur-sm">
                                                    <MapPin size={14} className={theme.text} />
                                                    <span className="font-bold text-text-primary text-[10px] truncate">{patient.address}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <EmptyState
                        icon={Users}
                        title={t('patients.empty_state.title')}
                        description={t('patients.empty_state.desc')}
                        action={
                            <Button onClick={() => setIsModalOpen(true)}>
                                <Plus size={18} className="mr-2" /> {t('patients.add_new')}
                            </Button>
                        }
                    />
                )}
            </div>

            {/* Add Patient Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title={t('patients.add_new')}
                size="lg"
            >
                <form onSubmit={handleCreatePatient} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <Input
                            label={t('patients.form.name_label')}
                            placeholder={t('patients.form.name_placeholder')}
                            value={newPatient.name}
                            onChange={(e) => handleInputChange('name', e.target.value)}
                            containerClassName="md:col-span-2"
                        />
                        <Input
                            label={t('patients.form.age_label')}
                            type="number"
                            placeholder="مثال: 25"
                            value={newPatient.age}
                            onChange={(e) => handleInputChange('age', e.target.value)}
                        />
                        <Input
                            label={t('patients.form.phone_label')}
                            type="tel"
                            placeholder="01xxxxxxxxx"
                            value={newPatient.phone}
                            onChange={(e) => handleInputChange('phone', e.target.value)}
                            dir="ltr"
                            className="text-right"
                        />
                        <Input
                            label={t('patients.form.address_label')}
                            placeholder={t('patients.form.address_placeholder')}
                            value={newPatient.address}
                            onChange={(e) => handleInputChange('address', e.target.value)}
                            containerClassName="md:col-span-2"
                        />

                        {/* Doctor Assignment Dropdown */}
                        <div className="md:col-span-2 space-y-1.5">
                            <label className="block text-sm font-bold text-text-secondary">
                                {t('patients.form.doctor_label')}
                            </label>
                            <select
                                value={newPatient.assigned_doctor_id || ''}
                                onChange={(e) => handleInputChange('assigned_doctor_id', e.target.value)}
                                className="w-full rounded-xl border border-border bg-input text-text-primary p-2.5 outline-none focus:border-primary focus:ring-1 focus:ring-primary transition-all"
                            >
                                <option value="">{t('patients.form.doctor_select')}</option>
                                {doctors.map(doc => (
                                    <option key={doc.id} value={doc.id}>
                                        د. {doc.username}
                                    </option>
                                ))}
                            </select>
                        </div>

                        <div className="md:col-span-2 space-y-3 pt-2 border-t border-border">
                            <label className="text-sm font-black text-text-secondary flex items-center gap-2">
                                <Activity size={16} />
                                {t('patients.form.medical_history')}
                            </label>
                            <div className="flex flex-wrap gap-2">
                                {['لا يوجد', 'سكري', 'ضغط دم', 'أزمة قلبية', 'حساسية', 'سيولة دم', 'فيروس سي', 'غدة درقية', 'حمل/رضاعة', 'تدخين'].map(condition => (
                                    <button
                                        key={condition}
                                        type="button"
                                        onClick={() => {
                                            let current = newPatient.medical_history ? newPatient.medical_history.split('، ') : [];
                                            current = current.map(c => c.trim()).filter(c => c && c !== 'لا يوجد');

                                            if (condition === 'لا يوجد') {
                                                setNewPatient(prev => ({ ...prev, medical_history: 'لا يوجد' }));
                                                return;
                                            }
                                            if (current.includes(condition)) {
                                                current = current.filter(c => c !== condition);
                                            } else {
                                                current.push(condition);
                                            }
                                            setNewPatient(prev => ({ ...prev, medical_history: current.length ? current.join('، ') : '' }));
                                        }}
                                        className={`px-3 py-1.5 rounded-xl text-xs font-bold transition-all border ${(newPatient.medical_history || '').includes(condition)
                                            ? 'bg-rose-500 text-white border-rose-500'
                                            : 'bg-surface text-text-secondary border-border hover:border-rose-300'
                                            }`}
                                    >
                                        {condition}
                                    </button>
                                ))}
                            </div>
                            <Input
                                placeholder={t('patients.form.other_notes')}
                                value={newPatient.medical_history}
                                onChange={(e) => handleInputChange('medical_history', e.target.value)}
                            />
                        </div>

                        {suggestions.length > 0 && (
                            <div className="md:col-span-2 bg-amber-50 dark:bg-amber-900/20 p-4 rounded-2xl border border-amber-200 dark:border-amber-700/50">
                                <h4 className="text-amber-800 dark:text-amber-400 font-bold mb-3 text-sm">
                                    {t('patients.form.duplicate_warning')}
                                </h4>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-2 max-h-32 overflow-y-auto custom-scrollbar">
                                    {suggestions.map(s => (
                                        <div key={s.id} className="flex justify-between text-sm bg-surface p-2 rounded-lg border border-border">
                                            <span className="font-bold text-text-primary">{s.name}</span>
                                            <span className="text-text-secondary" dir="ltr">{s.phone}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex gap-4 pt-4">
                        <Button
                            variant="ghost"
                            type="button"
                            onClick={() => setIsModalOpen(false)}
                            className="flex-1"
                        >
                            {t('patients.form.cancel_btn')}
                        </Button>
                        <Button
                            type="submit"
                            isLoading={isSubmitting}
                            className="flex-[2]"
                        >
                            {t('patients.form.submit_btn')}
                        </Button>
                    </div>
                </form>
            </Modal>

            {isScannerOpen && (
                <PatientScanner
                    onScanComplete={handleScanComplete}
                    onClose={() => setIsScannerOpen(false)}
                />
            )}
        </div>
    );
}

// Memoized StatCard to prevent re-renders
const StatCard = memo(({ label, value, icon: Icon, color, bg, loading }) => (
    <div className="bg-surface p-6 rounded-3xl border border-border shadow-sm flex items-center gap-4">
        {loading ? (
            <Skeleton.Box width="3.5rem" height="3.5rem" rounded="2xl" />
        ) : (
            <div className={`w-14 h-14 rounded-2xl ${bg} ${color} flex items-center justify-center`}>
                <Icon size={28} />
            </div>
        )}
        <div>
            {loading ? (
                <>
                    <Skeleton.Box width="80px" height="12px" className="mb-2" />
                    <Skeleton.Box width="40px" height="24px" />
                </>
            ) : (
                <>
                    <p className="text-text-secondary font-bold text-sm">{label}</p>
                    <p className="text-3xl font-black text-text-primary">{value}</p>
                </>
            )}
        </div>
    </div>
));

StatCard.displayName = 'StatCard';

import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getPatient, getPatientTreatments, getPatientPayments } from '../api';

export default function PrintInvoice() {
    const { id } = useParams();
    const [patient, setPatient] = useState(null);
    const [items, setItems] = useState([]);
    const [payments, setPayments] = useState([]);

    useEffect(() => {
        async function fetchData() {
            const [p, t, pay] = await Promise.all([
                getPatient(id),
                getPatientTreatments(id),
                getPatientPayments(id)
            ]);
            setPatient(p.data);
            setItems(t.data);
            setPayments(pay.data);
            // Auto print after small delay
            setTimeout(() => window.print(), 500);
        }
        fetchData();
    }, [id]);

    if (!patient) return <div>Loading...</div>;

    const total = items.reduce((acc, curr) => acc + curr.cost, 0);
    const paid = payments.reduce((acc, curr) => acc + curr.amount, 0);
    const remaining = total - paid;

    return (
        <div className="bg-white p-8 min-h-screen font-cairo" dir="rtl">
            {/* Header */}
            <div className="flex justify-between items-end border-b-2 border-slate-800 pb-4 mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900">عيادة د. إسلام عمارة</h1>
                    <p className="text-slate-600 mt-1">لطب وجراحة الأسنان</p>
                </div>
                <div className="text-left text-sm text-slate-500">
                    <p>Date: {new Date().toLocaleDateString()}</p>
                    <p>Invoice #: {id}-{Date.now().toString().slice(-4)}</p>
                </div>
            </div>

            {/* Patient Info */}
            <div className="mb-8 p-4 bg-slate-50 rounded-lg border border-slate-200">
                <h2 className="text-lg font-bold mb-2">بيانات المريض</h2>
                <div className="grid grid-cols-2 gap-4">
                    <p><span className="text-slate-500">الاسم:</span> <span className="font-bold">{patient.name}</span></p>
                    <p><span className="text-slate-500">رقم الهاتف:</span> <span dir="ltr" className="font-mono">{patient.phone}</span></p>
                </div>
            </div>

            {/* Treatments Table */}
            <div className="mb-8">
                <table className="w-full text-right border-collapse">
                    <thead>
                        <tr className="border-b border-slate-300">
                            <th className="py-2 text-slate-600">الإجراء العلاجي</th>
                            <th className="py-2 text-slate-600 w-32">التاريخ</th>
                            <th className="py-2 text-slate-600 w-32">التكلفة</th>
                        </tr>
                    </thead>
                    <tbody>
                        {items.map((item, index) => (
                            <tr key={index} className="border-b border-slate-100">
                                <td className="py-3 font-bold text-slate-800">{item.diagnosis} - {item.procedure} <span className="text-xs text-slate-400">({item.tooth_number || 'عام'})</span></td>
                                <td className="py-3 text-slate-600">{new Date(item.date).toLocaleDateString()}</td>
                                <td className="py-3 font-mono">{item.cost}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Totals */}
            <div className="flex justify-end">
                <div className="w-64 space-y-2">
                    <div className="flex justify-between py-2 border-b border-slate-100">
                        <span className="text-slate-600">الإجمالي</span>
                        <span className="font-bold text-lg">{total} ج.م</span>
                    </div>
                    <div className="flex justify-between py-2 border-b border-slate-100 text-green-600">
                        <span>المدفوع</span>
                        <span className="font-bold">{paid} ج.م</span>
                    </div>
                    <div className="flex justify-between py-2 text-xl font-bold text-slate-800">
                        <span>المتبقي</span>
                        <span>{remaining} ج.م</span>
                    </div>
                </div>
            </div>

            {/* Footer */}
            <div className="fixed bottom-0 left-0 right-0 p-8 text-center text-slate-400 text-sm border-t border-slate-100">
                <p>عنوان العيادة: شارع التحرير - أمام محطة المترو</p>
                <p>تليفون: 01000000000</p>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { getPatient, getTenantSettings } from '../api';
import { Stethoscope, MapPin, Phone } from 'lucide-react';

export default function PrintRx() {
    const { id } = useParams();
    const [patient, setPatient] = useState(null);
    const [prescription, setPrescription] = useState(null);
    const [headerInfo, setHeaderInfo] = useState({
        doctor_name: 'اسم الطبيب',
        doctor_title: 'التخصص',
        clinic_address: 'العنوان',
        clinic_phone: '0000000000'
    });

    useEffect(() => {
        // Fetch Tenant Settings (Rx Header)
        getTenantSettings().then((res) => {
            if (res.data) {
                setHeaderInfo({
                    doctor_name: res.data.doctor_name || 'اسم الطبيب',
                    doctor_title: res.data.doctor_title || 'التخصص',
                    clinic_address: res.data.clinic_address || 'العنوان',
                    clinic_phone: res.data.clinic_phone || '0000000000',
                });
            }
        }).catch(err => console.error("Failed to fetch rx header info", err));

        // In a real app, you'd fetch the specific prescription by an ID
        // For now, let's look for state passed via router or fetch last one
        const data = sessionStorage.getItem('print_rx_data');
        if (data) {
            const parsed = JSON.parse(data);
            setPrescription(parsed.prescription);
            setPatient(parsed.patient);

            // Auto print and close tab/go back
            setTimeout(() => {
                window.print();
            }, 1000); // Increased delay slightly to ensure font loading
        }
    }, [id]);

    if (!patient || !prescription) return <div className="p-10 text-center text-slate-400">Loading Prescription Data...</div>;

    const medications = JSON.parse(prescription.medications);

    return (
        <div className="min-h-screen bg-white p-4 sm:p-10 font-['Cairo']" dir="rtl">
            <div className="max-w-2xl mx-auto border-2 border-slate-900 min-h-[90vh] flex flex-col p-8 relative overflow-hidden">

                {/* Header Decoration */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 -mr-16 -mt-16 rounded-full"></div>

                {/* Header */}
                <div className="flex justify-between items-start border-b-2 border-slate-900 pb-6 mb-8 relative z-10">
                    <div>
                        <h1 className="text-3xl font-extrabold text-slate-900 mb-1">{headerInfo.doctor_name}</h1>
                        <p className="text-lg font-bold text-primary">{headerInfo.doctor_title}</p>
                    </div>
                    <div className="w-16 h-16 bg-primary/10 rounded-2xl flex items-center justify-center text-primary">
                        <Stethoscope size={40} />
                    </div>
                </div>

                {/* Patient Info Bar */}
                <div className="bg-slate-50 p-4 rounded-xl flex justify-between items-center mb-10 border border-slate-200">
                    <div className="flex gap-4">
                        <span className="font-bold text-slate-500">اسم المريض:</span>
                        <span className="font-bold text-slate-900">{patient.name}</span>
                    </div>
                    <div className="flex gap-4">
                        <span className="font-bold text-slate-500">التاريخ:</span>
                        <span className="font-bold text-slate-900">{new Date(prescription.date).toLocaleDateString('ar-EG')}</span>
                    </div>
                </div>

                {/* RX Symbol Area */}
                <div className="mb-6">
                    <span className="text-6xl font-serif text-slate-900 opacity-20">℞</span>
                </div>

                {/* Medications List */}
                <div className="flex-1 space-y-8 px-6">
                    {medications.map((med, index) => (
                        <div key={index} className="border-b border-slate-100 pb-4 last:border-0">
                            <h3 className="text-xl font-bold text-slate-900 mb-2 text-left" dir="auto">{med.name}</h3>
                            <p className="text-slate-600 mr-4 flex items-center gap-2 italic">
                                <span>-</span>
                                <span>{med.dose}</span>
                            </p>
                        </div>
                    ))}
                </div>

                {/* Doctor's Notes */}
                {prescription.notes && (
                    <div className="mt-10 p-4 bg-yellow-50/50 rounded-lg border-r-4 border-yellow-400">
                        <h4 className="font-bold text-slate-700 mb-1 text-sm">ملاحظات إضافية:</h4>
                        <p className="text-slate-600">{prescription.notes}</p>
                    </div>
                )}

                {/* Footer Signature */}
                <div className="mt-auto pt-10 flex justify-end">
                    <div className="text-center w-48">
                        <div className="h-px bg-slate-300 mb-2"></div>
                        <p className="text-sm font-bold text-slate-400">توقيع الطبيب</p>
                    </div>
                </div>

                {/* Contact Info Footer */}
                <div className="mt-10 pt-6 border-t border-slate-200 flex flex-wrap justify-center gap-x-10 gap-y-2 text-sm text-slate-500">
                    <div className="flex items-center gap-2">
                        <Phone size={14} className="text-primary" />
                        <span dir="ltr">{headerInfo.clinic_phone}</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <MapPin size={14} className="text-primary" />
                        <span>{headerInfo.clinic_address}</span>
                    </div>
                </div>
            </div>

            {/* Print Instructions Hide on Print */}
            <div className="mt-8 text-center print:hidden flex flex-col items-center gap-4">
                <p className="text-slate-500">انتهت المعاينة، سيتم فتح نافذة الطباعة تلقائياً.</p>
                <div className="flex gap-4">
                    <button
                        onClick={() => window.print()}
                        className="bg-primary text-white px-8 py-3 rounded-xl font-bold hover:shadow-lg transition-all"
                    >
                        إعادة طباعة
                    </button>
                    <button
                        onClick={() => window.close()}
                        className="bg-slate-100 text-slate-600 px-8 py-3 rounded-xl font-bold hover:bg-slate-200 transition-all"
                    >
                        إغلاق النافذة
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useNavigate, Link } from 'react-router-dom';
import { registerClinic } from '../api';
import { logoBase64 as logo } from '@/assets/logoBase64';
import { Building2, User, Lock, AlertCircle, CheckCircle } from 'lucide-react';

const RegisterClinic = ({ isDarkMode }) => {
    const { t } = useTranslation();
    const [formData, setFormData] = useState({
        clinic_name: '',
        admin_username: '',
        admin_email: '',
        admin_password: '',
        confirm_password: ''
    });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        // Frontend validations
        if (!formData.clinic_name.trim() || formData.clinic_name.trim().length < 2) {
            setError(t('auth.register.errors.clinic_name_short'));
            return;
        }

        if (!formData.admin_email.includes('@') || !formData.admin_email.includes('.')) {
            setError(t('auth.register.errors.invalid_email'));
            return;
        }

        if (!formData.admin_username.trim() || formData.admin_username.trim().length < 3) {
            setError(t('auth.register.errors.username_short'));
            return;
        }

        if (formData.admin_password.length < 6) {
            setError(t('auth.register.errors.password_min_length'));
            return;
        }

        const hasLetter = /[a-zA-Z]/.test(formData.admin_password);
        const hasNumber = /[0-9]/.test(formData.admin_password);
        if (!hasLetter || !hasNumber) {
            setError(t('auth.register.errors.password_weak'));
            return;
        }

        if (formData.admin_password !== formData.confirm_password) {
            setError(t('auth.register.errors.password_mismatch'));
            return;
        }

        setLoading(true);
        try {
            const data = new FormData();
            data.append('clinic_name', formData.clinic_name.trim());
            data.append('admin_username', formData.admin_username.trim());
            data.append('admin_email', formData.admin_email.trim().toLowerCase());
            data.append('admin_password', formData.admin_password);

            await registerClinic(data);
            navigate('/', { state: { message: t('auth.register.success') } });
        } catch (err) {
            console.error(err);
            const serverDetail = err.response?.data?.detail;
            if (serverDetail) {
                // Backend returns specific Arabic messages now
                setError(serverDetail);
            } else if (err.code === 'ERR_NETWORK' || !err.response) {
                setError(t('auth.register.errors.connection'));
            } else {
                setError(t('auth.register.errors.generic'));
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className={`min-h-screen flex items-center justify-center p-4 dir-rtl bg-background`}>
            <div className={`w-full max-w-md p-8 rounded-2xl shadow-xl bg-surface`}>
                <div className="text-center mb-8">
                    <div className="h-32 w-full overflow-hidden flex items-center justify-center mb-4">
                        <img src={logo} alt="Logo" className="h-full w-full object-contain scale-[2.5] translate-x-4" />
                    </div>
                    <h1 className={`text-2xl font-bold mb-2 text-text-primary`}>{t('auth.register.title')}</h1>
                    <p className={`text-sm text-text-secondary`}>{t('auth.register.subtitle')}</p>
                </div>

                {error && (
                    <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl flex items-center gap-3 text-red-500">
                        <AlertCircle size={20} />
                        <span className="text-sm font-medium">{error}</span>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="space-y-2">
                        <label className={`text-sm font-medium text-text-secondary`}>{t('auth.register.clinic_name')}</label>
                        <div className="relative">
                            <Building2 className={`absolute right-3 top-1/2 -translate-y-1/2 h-5 w-5 text-text-secondary`} />
                            <input
                                type="text"
                                name="clinic_name"
                                required
                                value={formData.clinic_name}
                                onChange={handleChange}
                                className={`w-full pr-10 pl-4 py-3 rounded-xl outline-none focus:ring-2 transition-all bg-input border-border text-text-primary focus:ring-primary/20 focus:border-primary border`}
                                placeholder={t('auth.register.clinic_name_placeholder')}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className={`text-sm font-medium text-text-secondary`}>{t('auth.register.email')}</label>
                        <div className="relative">
                            <input
                                type="email"
                                name="admin_email"
                                required
                                value={formData.admin_email}
                                onChange={handleChange}
                                className={`w-full pr-4 pl-4 py-3 rounded-xl outline-none focus:ring-2 transition-all bg-input border-border text-text-primary focus:ring-primary/20 focus:border-primary border`}
                                placeholder="example@email.com"
                                dir="ltr"
                            />
                        </div>
                        <p className={`text-xs text-text-secondary`}>{t('auth.register.email_hint')}</p>
                    </div>

                    <div className="space-y-2">
                        <label className={`text-sm font-medium text-text-secondary`}>{t('auth.register.username')}</label>
                        <div className="relative">
                            <User className={`absolute right-3 top-1/2 -translate-y-1/2 h-5 w-5 text-text-secondary`} />
                            <input
                                type="text"
                                name="admin_username"
                                required
                                value={formData.admin_username}
                                onChange={handleChange}
                                className={`w-full pr-10 pl-4 py-3 rounded-xl outline-none focus:ring-2 transition-all bg-input border-border text-text-primary focus:ring-primary/20 focus:border-primary border`}
                                placeholder={t('auth.register.username_placeholder')}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className={`text-sm font-medium text-text-secondary`}>{t('auth.register.password')}</label>
                        <div className="relative">
                            <Lock className={`absolute right-3 top-1/2 -translate-y-1/2 h-5 w-5 text-text-secondary`} />
                            <input
                                type="password"
                                name="admin_password"
                                required
                                value={formData.admin_password}
                                onChange={handleChange}
                                className={`w-full pr-10 pl-4 py-3 rounded-xl outline-none focus:ring-2 transition-all bg-input border-border text-text-primary focus:ring-primary/20 focus:border-primary border`}
                                placeholder="••••••••"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className={`text-sm font-medium text-text-secondary`}>{t('auth.register.confirm_password')}</label>
                        <div className="relative">
                            <Lock className={`absolute right-3 top-1/2 -translate-y-1/2 h-5 w-5 text-text-secondary`} />
                            <input
                                type="password"
                                name="confirm_password"
                                required
                                value={formData.confirm_password}
                                onChange={handleChange}
                                className={`w-full pr-10 pl-4 py-3 rounded-xl outline-none focus:ring-2 transition-all bg-input border-border text-text-primary focus:ring-primary/20 focus:border-primary border`}
                                placeholder="••••••••"
                            />
                        </div>
                    </div>

                    <div className="flex items-start gap-3 mt-4">
                        <div className="relative flex items-center">
                            <input
                                type="checkbox"
                                required
                                id="terms"
                                className="peer h-5 w-5 cursor-pointer appearance-none rounded-md border border-slate-300 transition-all checked:border-primary checked:bg-primary hover:border-primary/50 focus:outline-none focus:ring-2 focus:ring-primary/20"
                            />
                            <div className="pointer-events-none absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 text-white opacity-0 transition-opacity peer-checked:opacity-100">
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" viewBox="0 0 20 20" fill="currentColor" stroke="currentColor" strokeWidth="1">
                                    <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd"></path>
                                </svg>
                            </div>
                        </div>
                        <label htmlFor="terms" className="text-xs text-text-secondary cursor-pointer select-none leading-relaxed">
                            {t('auth.register.agree_pre')} <Link to="/terms" className="text-primary hover:underline font-bold" target="_blank">{t('auth.register.agree_terms')}</Link> {t('auth.register.agree_and')} <Link to="/privacy" className="text-primary hover:underline font-bold" target="_blank">{t('auth.register.agree_privacy')}</Link> {t('auth.register.agree_post')}
                        </label>
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full bg-primary hover:bg-primary-600 text-white py-3 rounded-xl font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed mt-4 shadow-lg shadow-primary/25"
                    >
                        {loading ? t('auth.register.submitting') : t('auth.register.submit')}
                    </button>

                    <div className="text-center mt-4">
                        <Link to="/" className={`text-sm hover:underline text-primary`}>
                            {t('auth.register.login_link')}
                        </Link>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default RegisterClinic;

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { Lock, Eye, EyeOff, CheckCircle, AlertCircle, ArrowLeft } from 'lucide-react';
import { verifyResetToken, resetPassword } from '../api';

export default function ResetPassword() {
    const { t } = useTranslation();
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const token = searchParams.get('token');

    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [tokenValid, setTokenValid] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (!token) {
            setError(t('auth.reset_password.errors.invalid_link'));
            setLoading(false);
            return;
        }

        // Verify token on mount
        verifyResetToken(token)
            .then(res => {
                setTokenValid(res.data.valid);
                if (!res.data.valid) {
                    setError(res.data.message || t('auth.reset_password.errors.invalid_link'));
                }
            })
            .catch(() => {
                setError(t('auth.reset_password.errors.verification_error'));
            })
            .finally(() => {
                setLoading(false);
            });
    }, [token]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!password) return setError(t('auth.reset_password.errors.password_required'));
        if (password.length < 6) return setError(t('auth.reset_password.errors.password_min_length'));
        if (password !== confirmPassword) return setError(t('auth.reset_password.errors.password_mismatch'));


        setSubmitting(true);
        setError('');

        try {
            await resetPassword(token, password);
            setSuccess(true);
            setTimeout(() => navigate('/login'), 3000);
        } catch (err) {
            setError(err.response?.data?.detail || t('auth.forgot_password.errors.generic'));
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen bg-gradient-to-br from-slate-100 to-sky-50 dark:from-slate-900 dark:to-slate-800 flex items-center justify-center">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-sky-500 border-t-transparent"></div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-gradient-to-br from-slate-100 to-sky-50 dark:from-slate-900 dark:to-slate-800 flex items-center justify-center p-4">
            <div className="w-full max-w-md">
                {/* Logo */}
                <div className="text-center mb-8">
                    <div className="text-5xl mb-2">🏥</div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white">DENTIX</h1>
                </div>

                <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-2xl p-8">
                    {success ? (
                        <div className="text-center">
                            <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                <CheckCircle className="text-emerald-500" size={40} />
                            </div>
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">{t('auth.reset_password.success_title')}</h2>
                            <p className="text-slate-500 mb-4">{t('auth.reset_password.success_msg')}</p>
                        </div>
                    ) : !tokenValid ? (
                        <div className="text-center">
                            <div className="w-20 h-20 bg-red-100 dark:bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                <AlertCircle className="text-red-500" size={40} />
                            </div>
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">{t('auth.reset_password.invalid_link_title')}</h2>
                            <p className="text-slate-500 mb-4">{error}</p>
                            <Link to="/forgot-password" className="text-sky-500 hover:underline font-bold">
                                {t('auth.reset_password.request_new')}
                            </Link>
                        </div>
                    ) : (
                        <>
                            <div className="text-center mb-6">
                                <div className="w-16 h-16 bg-sky-100 dark:bg-sky-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                                    <Lock className="text-sky-500" size={32} />
                                </div>
                                <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2">{t('auth.reset_password.title')}</h2>
                                <p className="text-slate-500">{t('auth.reset_password.subtitle')}</p>
                            </div>

                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('auth.reset_password.new_password')}</label>
                                    <div className="relative">
                                        <input
                                            type={showPassword ? "text" : "password"}
                                            value={password}
                                            onChange={(e) => setPassword(e.target.value)}
                                            className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-xl border border-slate-200 dark:border-slate-600 outline-none focus:border-sky-500 transition-colors"
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setShowPassword(!showPassword)}
                                            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                                        >
                                            {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                                        </button>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">{t('auth.reset_password.confirm_password')}</label>
                                    <input
                                        type={showPassword ? "text" : "password"}
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        className="w-full p-4 bg-slate-50 dark:bg-slate-700 rounded-xl border border-slate-200 dark:border-slate-600 outline-none focus:border-sky-500 transition-colors"
                                    />
                                </div>

                                {error && (
                                    <div className="flex items-center gap-2 text-red-500 bg-red-50 dark:bg-red-500/10 p-3 rounded-xl">
                                        <AlertCircle size={18} />
                                        <span className="text-sm">{error}</span>
                                    </div>
                                )}

                                <button
                                    type="submit"
                                    disabled={submitting}
                                    className="w-full py-4 bg-gradient-to-r from-sky-500 to-blue-600 text-white font-bold rounded-xl hover:from-sky-600 hover:to-blue-700 transition-all shadow-lg shadow-sky-500/30 flex items-center justify-center gap-2 disabled:opacity-50"
                                >
                                    {submitting ? (
                                        <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                                    ) : (
                                        t('auth.reset_password.submit')
                                    )}
                                </button>
                            </form>
                        </>
                    )}

                    <div className="mt-6 text-center">
                        <Link to="/login" className="inline-flex items-center gap-2 text-sky-500 hover:text-sky-600 font-bold">
                            <ArrowLeft size={16} />
                            {t('auth.forgot_password.back_to_login')}
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Database, List, User, Settings as SettingsIcon, CreditCard, CheckCircle, AlertTriangle, Printer, Banknote, Shield } from 'lucide-react';
import { getMe, getBackupStatus } from '../api';

// Import newly created components
// Import newly created components
import GeneralSettings from '@/features/settings/SettingsTabs/GeneralSettings';
import SubscriptionSettings from '@/features/settings/SettingsTabs/SubscriptionSettings';
import ProceduresSettings from '@/features/settings/SettingsTabs/ProceduresSettings';
import ServicesSettings from '@/features/settings/SettingsTabs/ServicesSettings';
import BackupSettings from '@/features/settings/SettingsTabs/BackupSettings';
import RxSettings from '@/features/settings/SettingsTabs/RxSettings';
// Legacy imports removed (PriceLists, InsuranceProviders now inside ServicesSettings)

export default function Settings() {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('general');
    const [message, setMessage] = useState(null);
    const [currentUser, setCurrentUser] = useState(null);

    // Backup State
    const [backupStatus, setBackupStatus] = useState({ connected: false, loading: true });

    useEffect(() => {
        // Parse URL params for status (redirected from Google)
        const query = new URLSearchParams(window.location.search);
        const status = query.get('status');
        const detail = query.get('detail');
        const tabParam = query.get('tab');

        if (status === 'success') {
            setMessage({ type: 'success', text: 'Google Account Linked Successfully' }); // Could keep backend msg or translate
            window.history.replaceState({}, document.title, window.location.pathname);
            setActiveTab('backup'); // Switch to backup tab
            checkBackupConnection();
        } else if (status === 'error') {
            setMessage({ type: 'error', text: detail || 'Failed to link Google Account' });
            window.history.replaceState({}, document.title, window.location.pathname);
            setActiveTab('backup');
        } else if (tabParam) {
            setActiveTab(tabParam);
            checkBackupConnection();
        } else {
            checkBackupConnection();
        }

        loadUserInfo();
    }, []);

    const checkBackupConnection = async () => {
        try {
            const res = await getBackupStatus();
            setBackupStatus({
                connected: res.data.connected === true,
                loading: false,
                lastBackup: res.data.last_backup
            });
        } catch (err) {
            setBackupStatus({ connected: false, loading: false });
        }
    };

    const loadUserInfo = async () => {
        try {
            const res = await getMe();
            setCurrentUser(res.data);
        } catch (err) {
            console.error('Failed to load user info', err);
        }
    };

    const tabs = useMemo(() => [
        { id: 'general', label: t('settings.tabs.general'), icon: User },
        { id: 'subscription', label: t('settings.tabs.subscription'), icon: CreditCard },
        { id: 'services', label: t('settings.tabs.services'), icon: List }, // Combined Tab
        { id: 'rx', label: t('settings.tabs.rx'), icon: Printer },
        { id: 'backup', label: t('settings.tabs.backup'), icon: Database },
    ], [t]);

    return (
        <div className="min-h-screen bg-slate-50/50 dark:bg-slate-900/50 p-6 flex flex-col md:flex-row gap-6 animate-in fade-in active">

            {/* Sidebar Navigation */}
            <div className="w-full md:w-64 flex-shrink-0">
                <div className="bg-white dark:bg-slate-800 rounded-2xl p-4 shadow-sm border border-slate-100 dark:border-white/5 sticky top-6">
                    <h2 className="text-xl font-bold text-slate-800 dark:text-white px-4 mb-6 flex items-center gap-2">
                        <SettingsIcon className="text-indigo-600" />
                        {t('settings.title')}
                    </h2>

                    <nav className="space-y-1">
                        {tabs.map(tab => {
                            const Icon = tab.icon;
                            const isActive = activeTab === tab.id;
                            return (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id)}
                                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 font-bold ${isActive
                                        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/30'
                                        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50'
                                        }`}
                                >
                                    <Icon size={20} />
                                    {tab.label}
                                </button>
                            );
                        })}
                    </nav>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1">
                <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-white/5 min-h-[600px] relative overflow-hidden">

                    {/* Header Banner */}
                    <div className="h-32 bg-gradient-to-r from-indigo-500 to-violet-600 relative overflow-hidden">
                        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                        <div className="absolute -bottom-6 right-8">
                            <div className="p-4 bg-white dark:bg-slate-800 rounded-2xl shadow-lg border-4 border-white dark:border-slate-800">
                                {activeTab === 'general' && <User size={32} className="text-indigo-600" />}
                                {activeTab === 'subscription' && <CreditCard size={32} className="text-indigo-600" />}
                                {activeTab === 'services' && <List size={32} className="text-indigo-600" />}
                                {activeTab === 'backup' && <Database size={32} className="text-indigo-600" />}
                                {activeTab === 'rx' && <Printer size={32} className="text-indigo-600" />}
                            </div>
                        </div>
                    </div>

                    <div className="p-8 pt-12">

                        {/* Tab Title */}
                        <div className="mb-8">
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white">
                                {tabs.find(t => t.id === activeTab)?.label}
                            </h2>
                            <p className="text-slate-500 dark:text-slate-400">
                                {activeTab === 'general' && t('settings.headers.general')}
                                {activeTab === 'subscription' && t('settings.headers.subscription')}
                                {activeTab === 'services' && t('settings.headers.services')}
                                {activeTab === 'rx' && t('settings.headers.rx')}
                                {activeTab === 'backup' && t('settings.headers.backup')}
                            </p>
                        </div>

                        {/* TAB CONTENT */}
                        {activeTab === 'general' && (
                            <GeneralSettings
                                currentUser={currentUser}
                                loadUserInfo={loadUserInfo}
                                setMessage={setMessage}
                            />
                        )}

                        {activeTab === 'subscription' && (
                            <SubscriptionSettings
                                currentUser={currentUser}
                            />
                        )}


                        {activeTab === 'services' && (
                            <ServicesSettings
                                setMessage={setMessage}
                            />
                        )}

                        {activeTab === 'rx' && (
                            <RxSettings
                                setMessage={setMessage}
                            />
                        )}

                        {activeTab === 'backup' && (
                            <BackupSettings
                                backupStatus={backupStatus}
                                currentUser={currentUser}
                                setMessage={setMessage}
                                loadUserInfo={loadUserInfo}
                            />
                        )}

                    </div>
                </div>
            </div>

            {/* Toast Message */}
            {message && (
                <div className={`fixed bottom-8 left-8 p-4 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-bottom-10 z-[100] ${message.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-red-500 text-white'}`}>
                    {message.type === 'success' ? <CheckCircle size={24} /> : <AlertTriangle size={24} />}
                    <span className="font-bold text-lg">{message.text}</span>
                </div>
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { api, broadcastNotification, deleteNotification, deleteSupportMessage } from '../api';
import {
    LayoutDashboard, Building2, CreditCard, CalendarRange,
    MessageSquare, Bell, ShieldCheck, X, Banknote, Landmark,
    PlusCircle, Activity, Users, Settings, Puzzle, Key
} from 'lucide-react';

// Imported Sub-Components
// Imported Sub-Components
import DashboardStats from '@/features/admin/SuperAdmin/DashboardStats';
import TenantsManager from '@/features/admin/SuperAdmin/TenantsManager';
import PlansManager from '@/features/admin/SuperAdmin/PlansManager';
import PaymentsManager from '@/features/admin/SuperAdmin/PaymentsManager';
import UsersManager from '@/features/admin/SuperAdmin/UsersManager'; // Phase 2
import SettingsManager from '@/features/admin/SuperAdmin/SettingsManager'; // Phase 3
import SupportInbox from '@/features/admin/SuperAdmin/SupportInbox';
import NotificationsManager from '@/features/admin/SuperAdmin/NotificationsManager';
import AuditLogViewer from '@/features/admin/SuperAdmin/AuditLogViewer';
import AIAnalyticsDashboard from '@/features/admin/SuperAdmin/AIAnalyticsDashboard';
import SecurityPanel from '@/features/admin/SuperAdmin/SecurityPanel'; // Phase 3
import FeatureManager from '@/features/admin/SuperAdmin/FeatureManager'; // Phase 3
import SystemHealth from '@/features/admin/SuperAdmin/SystemHealth'; // Phase 5

import Modal from '@/shared/ui/Modal'; // Assuming generic Modal exists, or keeping locally if needed for logic reuse

export default function SuperAdmin() {
    const [activeTab, setActiveTab] = useState('dashboard');
    const [tenants, setTenants] = useState([]);
    const [plans, setPlans] = useState([]);
    const [payments, setPayments] = useState([]);
    const [stats, setStats] = useState(null);
    const [messages, setMessages] = useState([]);
    const [notifications, setNotifications] = useState([]);
    const [auditLogs, setAuditLogs] = useState([]);
    const [systemSettings, setSystemSettings] = useState([]);
    const [loading, setLoading] = useState(true);

    // Editing Plan State
    const [editingPlan, setEditingPlan] = useState(null);
    const [editedPlanData, setEditedPlanData] = useState({});

    // Payment Modal State
    const [showPaymentModal, setShowPaymentModal] = useState(null);
    const [paymentForm, setPaymentForm] = useState({ plan_id: '', amount: '', payment_method: 'cash', notes: '' });

    // Notification Form State
    const [notifForm, setNotifForm] = useState({ title: '', content: '', type: 'info', is_global: true, tenant_id: null });

    // Password Reset State
    const [showPasswordResetModal, setShowPasswordResetModal] = useState(null); // {tenantId, tenantName}
    const [tenantUsers, setTenantUsers] = useState([]);
    const [passwordResetForm, setPasswordResetForm] = useState({ user_id: '', new_password: '' });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            setLoading(true);
            // Cache busting
            const timestamp = new Date().getTime();
            const results = await Promise.allSettled([
                api.get(`/api/v1/admin/tenants?_t=${timestamp}`),
                api.get(`/api/v1/admin/plans?_t=${timestamp}`),
                api.get(`/api/v1/admin/stats?_t=${timestamp}`),
                api.get(`/api/v1/admin/payments?_t=${timestamp}`),
                api.get(`/support/messages?_t=${timestamp}`),
                api.get(`/api/v1/notifications/?_t=${timestamp}`),
                api.get(`/api/v1/admin/audit-logs?_t=${timestamp}`),
                api.get(`/api/v1/admin/settings?_t=${timestamp}`)
            ]);

            const [tenantsRes, plansRes, statsRes, paymentsRes, messagesRes, notificationsRes, auditsRes, settingsRes] = results;

            if (tenantsRes.status === 'fulfilled') setTenants(Array.isArray(tenantsRes.value.data) ? tenantsRes.value.data : []);
            if (plansRes.status === 'fulfilled') setPlans(Array.isArray(plansRes.value.data) ? plansRes.value.data : []);
            if (statsRes.status === 'fulfilled') setStats(statsRes.value.data);
            if (paymentsRes.status === 'fulfilled') setPayments(Array.isArray(paymentsRes.value.data) ? paymentsRes.value.data : []);
            if (messagesRes.status === 'fulfilled') setMessages(messagesRes.value.data);
            if (notificationsRes.status === 'fulfilled') setNotifications(notificationsRes.value.data);
            if (auditsRes.status === 'fulfilled') setAuditLogs(auditsRes.value.data);
            if (settingsRes.status === 'fulfilled') setSystemSettings(settingsRes.value.data);

        } finally {
            setLoading(false);
        }
    };

    const handleSavePlan = async (planId) => {
        try {
            await api.put(`/admin/plans/${planId}`, editedPlanData);
            setEditingPlan(null);
            setEditedPlanData({});
            fetchData();
        } catch (err) {
            alert('فشل التعديل');
        }
    };

    const handleRecordPayment = async () => {
        try {
            await api.post('/api/v1/admin/payments', {
                ...paymentForm,
                tenant_id: showPaymentModal.id
            });
            setShowPaymentModal(null);
            setPaymentForm({ plan_id: '', amount: '', payment_method: 'cash', notes: '' });
            fetchData();
        } catch (err) {
            alert('فشل تسجيل الدفعة');
        }
    };

    const handleSendNotification = async () => {
        if (!notifForm.title || !notifForm.content) return alert('الرجاء تعبئة العنوان والمحتوى');
        try {
            await broadcastNotification(notifForm);
            setNotifForm({ title: '', content: '', type: 'info', is_global: true, tenant_id: null });
            fetchData();
            alert('تم إرسال الإشعار بنجاح');
        } catch (err) {
            alert('فشل إرسال الإشعار');
        }
    };

    const handleDeleteNotification = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذا الإشعار؟')) return;
        try {
            await deleteNotification(id);
            fetchData();
        } catch (err) {
            alert('فشل حذف الإشعار');
        }
    };

    const handleDeleteMessage = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذه الرسالة؟')) return;
        try {
            await deleteSupportMessage(id);
            setMessages(prev => prev.filter(m => m.id !== id));
            alert('تم حذف الرسالة بنجاح');
        } catch (err) {
            alert('فشل حذف الرسالة');
        }
    };

    const handlePlanChange = (e, tenantId) => {
        const newPlanId = parseInt(e.target.value);
        if (!newPlanId) return;
        if (window.confirm('هل أنت متأكد من تغيير الخطة؟ سيتم احتساب المدة الجديدة بدءاً من اليوم.')) {
            api.post(`/admin/tenants/${tenantId}/assign-plan?plan_id=${newPlanId}`)
                .then(() => fetchData())
                .catch(() => alert('فشل تغيير الخطة'));
        }
    };

    const getDaysRemaining = (endDate) => {
        if (!endDate) return null;
        const days = Math.ceil((new Date(endDate) - new Date()) / (1000 * 60 * 60 * 24));
        return days;
    };

    const handleArchiveTenant = async (tenantId) => {
        if (!window.confirm("هل أنت متأكد من أرشفة هذه العيادة؟ ستختفي من القائمة النشطة ويتم تعطيل دخول المستخدمين.")) return;
        try {
            await api.delete(`/admin/tenants/${tenantId}`);
            fetchData();
            alert("تمت الأرشفة بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشلت عملية الأرشفة");
        }
    };






    const handleRestoreTenant = async (tenantId) => {
        if (!window.confirm("هل أنت متأكد من استعادة هذه العيادة؟")) return;
        try {
            await api.post(`/admin/tenants/${tenantId}/restore`);
            fetchData();
            alert("تمت الاستعادة بنجاح");
        } catch (error) {
            console.error(error);
            alert("فشلت عملية الاستعادة");
        }
    };

    // Phase 2: User Management Handlers
    const [globalUsers, setGlobalUsers] = useState([]);
    const [usersLoading, setUsersLoading] = useState(false);

    const handleSearchUsers = async (query) => {
        setUsersLoading(true);
        try {
            // If empty query, empty list or default list? 
            // For performance, maybe default list first 50.
            const res = await api.get(`/api/v1/admin/users?search_query=${query || ''}`);
            setGlobalUsers(Array.isArray(res.data) ? res.data : []);
        } catch (err) {
            console.error(err);
            alert("فشل البحث");
        } finally {
            setUsersLoading(false);
        }
    };

    const handleToggleUserStatus = async (userId, currentStatus) => {
        const action = currentStatus ? "تعطيل" : "تفعيل";
        if (!window.confirm(`هل أنت متأكد من ${action} هذا المستخدم؟`)) return;

        try {
            await api.post(`/api/v1/admin/users/${userId}/toggle-status`);
            // Update local state to reflect change instantly
            setGlobalUsers(prev => Array.isArray(prev) ? prev.map(u =>
                u.id === userId ? { ...u, is_active: !currentStatus } : u
            ) : []);
            alert(`تم ${action} المستخدم بنجاح`);
        } catch (err) {
            console.error(err);
            alert("فشل تغيير حالة المستخدم");
        }
    };

    const handleResetPassword = async (tenantId) => {
        try {
            console.log('[DEBUG] Fetching users for tenant:', tenantId);
            const res = await api.get(`/api/v1/admin/system/tenants/${tenantId}/users`);
            console.log('[DEBUG] API Response:', res.data);

            // Temporary Debug Alert (Version 2)
            alert(`[V2 FIX] Found ${res.data?.users?.length || 0} users. \nFirst User: ${JSON.stringify(res.data?.users?.[0])}`);

            const users = res.data.users || [];
            setTenantUsers(users);

            if (users.length === 0) {
                console.warn('[DEBUG] No users found for tenant:', tenantId);
            }

            const tenant = Array.isArray(tenants) ? tenants.find(t => t.id === tenantId) : null;
            setShowPasswordResetModal({ tenantId, tenantName: tenant?.name || 'العيادة' });
            setPasswordResetForm({ user_id: '', new_password: '' });
        } catch (err) {
            console.error('Error in handleResetPassword:', err);
            alert('فشل تحميل مستخدمي العيادة: ' + (err.response?.data?.detail || err.message));
        }
    };

    const handleSubmitPasswordReset = async () => {
        if (!passwordResetForm.user_id || !passwordResetForm.new_password) {
            return alert('الرجاء اختيار المستخدم وإدخال كلمة المرور الجديدة');
        }
        if (passwordResetForm.new_password.length < 6) {
            return alert('كلمة المرور يجب أن تكون 6 أحرف على الأقل');
        }
        if (!window.confirm('هل أنت متأكد من إعادة تعيين كلمة المرور؟')) return;

        try {
            await api.post(`/api/v1/admin/system/users/${passwordResetForm.user_id}/reset-password`, {
                new_password: passwordResetForm.new_password
            });
            setShowPasswordResetModal(null);
            setPasswordResetForm({ user_id: '', new_password: '' });
            alert('تم إعادة تعيين كلمة المرور بنجاح');
        } catch (err) {
            console.error(err);
            alert('فشل إعادة تعيين كلمة المرور');
        }
    };

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-900">
            <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <p className="text-slate-500 font-bold animate-pulse">جاري تحميل لوحة التحكم...</p>
            </div>
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50 dark:bg-slate-950 p-6 lg:p-10 font-sans" dir="rtl">
            <div className="max-w-7xl mx-auto space-y-8">

                {/* Header */}
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                    <div className="flex items-center gap-4">
                        <div className="bg-gradient-to-br from-indigo-500 to-purple-600 p-4 rounded-2xl shadow-lg shadow-indigo-500/20 text-white">
                            <ShieldCheck size={32} />
                        </div>
                        <div>
                            <h1 className="text-3xl font-black text-slate-800 dark:text-white">إدارة النظام</h1>
                            <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">نظرة عامة والتحكم الكامل في الاشتراكات</p>
                        </div>
                    </div>
                    <div className="flex flex-wrap items-center justify-start md:justify-end gap-2 bg-slate-100 dark:bg-slate-800 p-2 rounded-2xl w-full md:w-auto">
                        {[
                            { id: 'dashboard', label: 'الرئيسية', icon: LayoutDashboard },
                            { id: 'tenants', label: 'العيادات', icon: Building2 },
                            { id: 'users', label: 'المستخدمين', icon: Users }, // Phase 2
                            { id: 'plans', label: 'الخطط', icon: CalendarRange },
                            { id: 'payments', label: 'المالية', icon: CreditCard },
                            { id: 'messages', label: 'الرسائل', icon: MessageSquare },
                            { id: 'notifications', label: 'الإشعارات', icon: Bell },
                            { id: 'ai_analytics', label: 'AI Analytics', icon: Activity },
                            { id: 'audit_logs', label: 'السجلات', icon: Activity },
                            { id: 'settings', label: 'الإعدادات', icon: Settings },
                            { id: 'security', label: 'الأمان', icon: ShieldCheck },
                            { id: 'features', label: 'المزايا', icon: Puzzle },
                            { id: 'health', label: 'مراقبة النظام', icon: Activity }
                        ].map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`flex items-center gap-2 px-6 py-3 rounded-xl font-bold text-sm transition-all duration-300 ${activeTab === tab.id
                                    ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-md transform scale-105'
                                    : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                                    }`}
                            >
                                <tab.icon size={18} />
                                {tab.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Content */}
                <div className="animate-fade-in-up">
                    {/* Dashboard Tab */}
                    {activeTab === 'dashboard' && stats && (
                        <DashboardStats stats={stats} />
                    )}

                    {/* Tenants Tab */}
                    {activeTab === 'tenants' && (
                        <TenantsManager
                            tenants={tenants}
                            plans={plans}
                            handlePlanChange={handlePlanChange}
                            setShowPaymentModal={setShowPaymentModal}
                            setPaymentForm={setPaymentForm}
                            getDaysRemaining={getDaysRemaining}
                            handleArchiveTenant={handleArchiveTenant}
                            handleRestoreTenant={handleRestoreTenant}
                            onResetPassword={handleResetPassword}
                        />
                    )}

                    {/* Global Users Tab (Phase 2) */}
                    {activeTab === 'users' && (
                        <UsersManager
                            users={globalUsers}
                            onSearch={handleSearchUsers}
                            onToggleStatus={handleToggleUserStatus}
                            loading={usersLoading}
                        />
                    )}

                    {/* Plans Tab */}
                    {activeTab === 'plans' && (
                        <PlansManager
                            plans={plans}
                            editingPlan={editingPlan}
                            setEditingPlan={setEditingPlan}
                            editedPlanData={editedPlanData}
                            setEditedPlanData={setEditedPlanData}
                            handleSavePlan={handleSavePlan}
                            onRefresh={fetchData}
                        />
                    )}

                    {/* Payments Tab */}
                    {activeTab === 'payments' && (
                        <PaymentsManager
                            payments={payments}
                            tenants={tenants}
                            plans={plans}
                        />
                    )}

                    {/* Support Messages Tab */}
                    {activeTab === 'messages' && (
                        <SupportInbox
                            messages={messages}
                            setMessages={setMessages}
                            handleDeleteMessage={handleDeleteMessage}
                            fetchData={fetchData}
                        />
                    )}

                    {/* Notifications Tab */}
                    {activeTab === 'notifications' && (
                        <NotificationsManager
                            notifForm={notifForm}
                            setNotifForm={setNotifForm}
                            handleSendNotification={handleSendNotification}
                            notifications={notifications}
                            handleDeleteNotification={handleDeleteNotification}
                            tenants={tenants}
                        />
                    )}

                    {/* Audit Logs Tab */}
                    {activeTab === 'audit_logs' && (
                        <AuditLogViewer logs={auditLogs} />
                    )}

                    {/* AI Analytics Tab (Phase 0+1) */}
                    {activeTab === 'ai_analytics' && (
                        <AIAnalyticsDashboard />
                    )}

                    {/* Settings Tab (Phase 3) */}
                    {activeTab === 'settings' && (
                        <SettingsManager settings={systemSettings} fetchData={fetchData} />
                    )}

                    {/* Security Tab (Phase 3) */}
                    {activeTab === 'security' && (
                        <SecurityPanel />
                    )}

                    {/* Features Tab (Phase 3) */}
                    {activeTab === 'features' && (
                        <FeatureManager tenants={tenants} />
                    )}

                    {/* Operational Health (Phase 5) */}
                    {activeTab === 'health' && (
                        <SystemHealth />
                    )}
                </div>
            </div>

            {/* Global Payment Modal - Kept in main since it needs overlay state */}
            {showPaymentModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full max-w-lg shadow-2xl space-y-6">
                        <div className="flex justify-between items-center">
                            <div>
                                <h3 className="text-xl font-bold text-slate-800 dark:text-white">تسجيل دفعة جديدة</h3>
                                <p className="text-slate-500 dark:text-slate-400 text-sm">{showPaymentModal.name}</p>
                            </div>
                            <button
                                onClick={() => setShowPaymentModal(null)}
                                className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:bg-slate-200"
                            >
                                <X size={20} />
                            </button>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">خطة الاشتراك</label>
                                <select
                                    value={paymentForm.plan_id}
                                    onChange={(e) => {
                                        const pid = parseInt(e.target.value);
                                        const p = plans.find(pl => pl.id === pid);
                                        setPaymentForm({ ...paymentForm, plan_id: pid, amount: p ? p.price : '' });
                                    }}
                                    className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                                >
                                    {(plans || []).map(p => (
                                        <option key={p.id} value={p.id}>{p.display_name_ar} ({p.price} ج.م)</option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">المبلغ المدفوع</label>
                                <input
                                    type="number"
                                    value={paymentForm.amount}
                                    onChange={(e) => setPaymentForm({ ...paymentForm, amount: e.target.value })}
                                    className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none font-bold"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">وسيلة الدفع</label>
                                <div className="grid grid-cols-3 gap-3">
                                    {[
                                        { id: 'cash', label: 'نقدي', icon: Banknote },
                                        { id: 'bank_transfer', label: 'تحويل', icon: Landmark },
                                        { id: 'credit_card', label: 'بطاقة', icon: CreditCard }
                                    ].map(method => (
                                        <button
                                            key={method.id}
                                            onClick={() => setPaymentForm({ ...paymentForm, payment_method: method.id })}
                                            className={`flex flex-col items-center justify-center gap-2 p-3 rounded-xl border-2 transition-all ${paymentForm.payment_method === method.id
                                                ? 'border-indigo-500 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600'
                                                : 'border-slate-100 dark:border-slate-800 text-slate-400 hover:border-slate-300'
                                                }`}
                                        >
                                            <method.icon size={20} />
                                            <span className="text-xs font-bold">{method.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <button
                                onClick={handleRecordPayment}
                                className="w-full py-4 bg-emerald-500 hover:bg-emerald-600 text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-500/20 text-lg hover:scale-[1.02] transition-all"
                            >
                                <PlusCircle size={20} />
                                حفظ العملية
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Password Reset Modal */}
            {showPasswordResetModal && (
                <div key={showPasswordResetModal.tenantId} className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full max-w-lg shadow-2xl space-y-6">
                        <div className="flex justify-between items-center">
                            <div>
                                <h3 className="text-xl font-bold text-slate-800 dark:text-white">إعادة تعيين كلمة المرور</h3>
                                <p className="text-slate-500 dark:text-slate-400 text-sm">
                                    {showPasswordResetModal.tenantName}
                                    {passwordResetForm.user_id && (
                                        <span className="text-amber-600 dark:text-amber-400 font-bold mr-1">
                                            {' '}→{' '}
                                            {tenantUsers.find(u => String(u.id) === passwordResetForm.user_id)?.username ||
                                                tenantUsers.find(u => String(u.id) === passwordResetForm.user_id)?.email ||
                                                'مستخدم'}
                                        </span>
                                    )}
                                </p>
                            </div>
                            <button
                                onClick={() => setShowPasswordResetModal(null)}
                                className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:bg-slate-200"
                            >
                                <X size={20} />
                            </button>
                        </div>

                        <div className="space-y-4">
                            {/* VISUAL DEBUGGING - REMOVE AFTER FIX */}
                            <div className="p-4 bg-black text-green-400 font-mono text-xs rounded-xl overflow-auto max-h-40" dir="ltr">
                                <p className="font-bold border-b border-green-800 mb-2">DEBUG V3: API RESPONSE DUMP</p>
                                <p>Tenant ID: {showPasswordResetModal.tenantId}</p>
                                <p>Users Count: {tenantUsers.length}</p>
                                <pre>{JSON.stringify(tenantUsers.slice(0, 3), null, 2)}</pre>
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-slate-500 mb-1.5">المستخدم</label>
                                {tenantUsers.length === 0 ? (
                                    <div className="w-full px-4 py-3 rounded-xl border border-amber-200 bg-amber-50 dark:bg-amber-900/20 dark:border-amber-700 text-amber-700 dark:text-amber-400 text-sm font-bold">
                                        ⚠️ لا يوجد مستخدمين مسجلين لهذه العيادة
                                    </div>
                                ) : (
                                    <select
                                        value={passwordResetForm.user_id}
                                        onChange={(e) => setPasswordResetForm({ ...passwordResetForm, user_id: e.target.value })}
                                        className="w-full px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 focus:ring-2 focus:ring-amber-500 outline-none font-bold"
                                    >
                                        <option value="">اختر المستخدم</option>
                                        {tenantUsers.map(u => (
                                            <option key={u.id} value={u.id}>
                                                {u.username || u.email || `مستخدم #${u.id}`} - {u.role}
                                                {!u.is_active && ' [معطل]'}
                                                {u.account_locked_until && ' [مقفل]'}
                                            </option>
                                        ))}
                                    </select>
                                )}
                                {/* Show selected user username prominently */}
                                {passwordResetForm.user_id && (
                                    <div className="mt-2 px-4 py-2 bg-indigo-50 dark:bg-indigo-900/20 border border-indigo-200 dark:border-indigo-700 rounded-xl">
                                        <span className="text-sm text-slate-500">المستخدم المحدد: </span>
                                        <span className="font-bold text-indigo-700 dark:text-indigo-400">
                                            {tenantUsers.find(u => String(u.id) === passwordResetForm.user_id)?.username || 'غير معروف'}
                                        </span>
                                    </div>
