                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { MessageSquare, Send, Smartphone, AlertCircle, CheckCircle2, Mail, MapPin, Clock } from 'lucide-react';
import { api, submitFeedback } from '../api';
import { useTranslation } from 'react-i18next';

export default function Support() {
    const { t, i18n } = useTranslation();
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [form, setForm] = useState({ subject: '', message: '', priority: 'normal' });
    const [error, setError] = useState('');

    const [supportInfo, setSupportInfo] = useState({
        phone: '+20 120 130 1415',
        whatsapp: '201201301415',
        email: 'support@smartclinic.com',
        working_hours: '9:00 AM - 10:00 PM'
    });

    useEffect(() => {
        const fetchSettings = async () => {
            try {
                // We use the public global-settings endpoint
                const { data } = await api.get('/api/v1/global-settings');
                if (data) {
                    setSupportInfo({
                        phone: data.support_phone || '+20 120 130 1415',
                        whatsapp: data.support_whatsapp || '201201301415',
                        email: data.support_email || 'support@smartclinic.com',
                        working_hours: data.support_working_hours || (i18n.language === 'ar' ? '9:00 ص - 10:00 م' : '9:00 AM - 10:00 PM')
                    });
                }
            } catch (err) {
                console.error("Failed to fetch support info", err);
            }
        };
        fetchSettings();
    }, [i18n.language]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.message) return;

        setLoading(true);
        setError('');
        try {
            await submitFeedback(form);
            setSuccess(true);
            setForm({ subject: '', message: '', priority: 'normal' });
            setTimeout(() => {
                setSuccess(false);
            }, 5000);
        } catch (err) {
            setError(t('static.support.error_send'));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6 animate-fade-in pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white">{t('static.support.title')}</h1>
                    <p className="text-slate-500 mt-1">{t('static.support.subtitle')}</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Contact Information Cards */}
                <div className="space-y-6">
                    <div className="bg-white dark:bg-slate-800 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-white/5">
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-4 flex items-center gap-2">
                            <Smartphone size={20} className="text-indigo-500" />
                            {t('static.support.contact_direct')}
                        </h3>
                        <div className="space-y-4">
                            <a href={`https://wa.me/${supportInfo.whatsapp}`} target="_blank" rel="noreferrer" className="flex items-center gap-3 p-4 rounded-2xl bg-emerald-50 text-emerald-700 hover:bg-emerald-100 transition-colors">
                                <div className="p-2 bg-emerald-200 rounded-full text-emerald-700">
                                    <MessageSquare size={18} />
                                </div>
                                <div className="text-right">
                                    <p className="text-xs font-bold uppercase tracking-wider opacity-70">{t('static.support.whatsapp')}</p>
                                    <p className="font-bold text-lg ltr font-mono">{supportInfo.phone}</p>
                                </div>
                            </a>

                            <div className="flex items-center gap-3 p-4 rounded-2xl bg-indigo-50 text-indigo-700">
                                <div className="p-2 bg-indigo-200 rounded-full text-indigo-700">
                                    <Mail size={18} />
                                </div>
                                <div className="text-right min-w-0 flex-1">
                                    <p className="text-xs font-bold uppercase tracking-wider opacity-70">{t('static.support.email')}</p>
                                    <p className="font-bold font-mono text-sm truncate" title={supportInfo.email}>{supportInfo.email}</p>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="bg-gradient-to-br from-violet-600 to-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-500/20">
                        <Clock size={32} className="mb-4 opacity-80" />
                        <h3 className="text-xl font-bold mb-2">{t('static.support.working_hours')}</h3>
                        <p className="opacity-90 leading-relaxed mb-4">
                            {t('static.support.working_hours_desc')} <span dir="ltr">{supportInfo.working_hours}</span>.
                        </p>
                        <div className="flex items-center gap-2 text-sm font-bold bg-white/20 p-3 rounded-xl backdrop-blur-sm">
                            <CheckCircle2 size={16} />
                            <span>{t('static.support.available_now')}</span>
                        </div>
                    </div>
                </div>

                {/* Contact Form */}
                <div className="lg:col-span-2">
                    <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-lg border border-slate-100 dark:border-white/5 overflow-hidden">
                        <div className="p-8">
                            {success ? (
                                <div className="text-center py-12 animate-bounce-subtle">
                                    <div className="w-20 h-20 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
                                        <CheckCircle2 size={48} />
                                    </div>
                                    <h3 className="text-2xl font-bold mb-2 text-slate-800 dark:text-white">{t('static.support.success_title')}</h3>
                                    <p className="text-slate-500 text-lg">{t('static.support.success_msg')}</p>
                                    <button
                                        onClick={() => setSuccess(false)}
                                        className="mt-8 px-8 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold transition-colors"
                                    >
                                        {t('static.support.send_another')}
                                    </button>
                                </div>
                            ) : (
                                <form onSubmit={handleSubmit} className="space-y-8">
                                    <div className="flex items-center gap-3 mb-6">
                                        <div className="p-3 bg-indigo-100 text-indigo-600 rounded-2xl">
                                            <Send size={24} />
                                        </div>
                                        <h2 className="text-2xl font-bold text-slate-800 dark:text-white">{t('static.support.send_ticket')}</h2>
                                    </div>

                                    {error && (
                                        <div className="flex items-center gap-3 p-4 bg-rose-50 dark:bg-rose-900/20 text-rose-600 dark:text-rose-400 rounded-2xl text-sm font-bold border border-rose-100 dark:border-rose-900/30">
                                            <AlertCircle size={18} />
                                            {error}
                                        </div>
                                    )}

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                        <div className="col-span-2">
                                            <label className="block text-sm font-black uppercase tracking-wider mb-3 pr-1 text-slate-500 dark:text-slate-400">{t('static.support.subject')}</label>
                                            <input
                                                type="text"
                                                required
                                                value={form.subject}
                                                onChange={(e) => setForm({ ...form, subject: e.target.value })}
                                                className="w-full px-6 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 text-slate-800 dark:text-white outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all font-bold text-lg placeholder:font-normal"
                                                placeholder={t('static.support.subject_placeholder')}
                                            />
                                        </div>

                                        <div className="col-span-2">
                                            <label className="block text-sm font-black uppercase tracking-wider mb-3 pr-1 text-slate-500 dark:text-slate-400">{t('static.support.message')}</label>
                                            <textarea
                                                required
                                                rows="8"
                                                value={form.message}
                                                onChange={(e) => setForm({ ...form, message: e.target.value })}
                                                className="w-full px-6 py-5 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 text-slate-800 dark:text-white outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all font-medium text-lg placeholder:font-normal resize-none"
                                                placeholder={t('static.support.message_placeholder')}
                                            />
                                        </div>
                                    </div>

                                    <div className="flex justify-end">
                                        <button
                                            type="submit"
                                            disabled={loading}
                                            className="px-8 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-2xl font-bold flex items-center gap-3 shadow-xl shadow-indigo-500/20 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-50 disabled:scale-100 w-full md:w-auto justify-center"
                                        >
                                            {loading ? (
                                                <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                            ) : (
                                                <>
                                                    <Send size={20} />
                                                    {t('static.support.submit')}
                                                </>
                                            )}
                                        </button>
                                    </div>
                                </form>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { User, Shield, CheckCircle, AlertTriangle } from 'lucide-react';
import { getMe } from '../api';
import GeneralSettings from '@/features/settings/SettingsTabs/GeneralSettings';
import SecuritySettings from '@/features/settings/Profile/SecuritySettings';
import { useTranslation } from 'react-i18next';

export default function UserProfile() {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('general');
    const [message, setMessage] = useState(null);
    const [currentUser, setCurrentUser] = useState(null);

    useEffect(() => {
        loadUserInfo();
    }, []);

    const loadUserInfo = async () => {
        try {
            const res = await getMe();
            setCurrentUser(res.data);
        } catch (err) {
            console.error('Failed to load user info', err);
        }
    };

    const tabs = [
        { id: 'general', label: t('static.user_profile.tabs.general'), icon: User },
        { id: 'security', label: t('static.user_profile.tabs.security'), icon: Shield },
    ];

    if (!currentUser) return <div className="p-8 text-center text-slate-400 font-bold">{t('static.user_profile.loading')}</div>;

    return (
        <div className="min-h-screen bg-slate-50/50 dark:bg-slate-900/50 p-6 flex flex-col md:flex-row gap-6 animate-in fade-in active">

            {/* Sidebar Navigation */}
            <div className="w-full md:w-64 flex-shrink-0">
                <div className="bg-white dark:bg-slate-800 rounded-2xl p-4 shadow-sm border border-slate-100 dark:border-white/5 sticky top-6">
                    <h2 className="text-xl font-bold text-slate-800 dark:text-white px-4 mb-6 flex items-center gap-2">
                        <User className="text-emerald-500" />
                        {t('static.user_profile.menu_title')}
                    </h2>

                    <nav className="space-y-1">
                        {tabs.map(tab => {
                            const Icon = tab.icon;
                            const isActive = activeTab === tab.id;
                            return (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id)}
                                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 font-bold ${isActive
                                        ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30'
                                        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50'
                                        }`}
                                >
                                    <Icon size={20} />
                                    {tab.label}
                                </button>
                            );
                        })}
                    </nav>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1">
                <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-white/5 min-h-[600px] relative overflow-hidden">

                    {/* Header Banner */}
                    <div className="h-32 bg-gradient-to-r from-emerald-500 to-teal-600 relative overflow-hidden">
                        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>
                        <div className="absolute -bottom-6 right-8">
                            <div className="p-4 bg-white dark:bg-slate-800 rounded-2xl shadow-lg border-4 border-white dark:border-slate-800">
                                {activeTab === 'general' && <User size={32} className="text-emerald-600" />}
                                {activeTab === 'security' && <Shield size={32} className="text-emerald-600" />}
                            </div>
                        </div>
                    </div>

                    <div className="p-8 pt-12">

                        {/* Tab Title */}
                        <div className="mb-8">
                            <h2 className="text-2xl font-bold text-slate-800 dark:text-white">
                                {tabs.find(t => t.id === activeTab)?.label}
                            </h2>
                            <p className="text-slate-500 dark:text-slate-400">
                                {activeTab === 'general' && t('static.user_profile.desc.general')}
                                {activeTab === 'security' && t('static.user_profile.desc.security')}
                            </p>
                        </div>

                        {/* TAB CONTENT */}
                        {activeTab === 'general' && (
                            <GeneralSettings
                                currentUser={currentUser}
                                loadUserInfo={loadUserInfo}
                                setMessage={setMessage}
                            />
                        )}

                        {activeTab === 'security' && (
                            <SecuritySettings />
                        )}

                    </div>
                </div>
            </div>

            {/* Toast Message */}
            {message && (
                <div className={`fixed bottom-8 left-8 p-4 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-bottom-10 z-[100] ${message.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-red-500 text-white'}`}>
                    {message.type === 'success' ? <CheckCircle size={24} /> : <AlertTriangle size={24} />}
                    <span className="font-bold text-lg">{message.text}</span>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { getUsers, registerUser, updateUser, deleteUser } from '../api';
import { UserPlus, Trash2, Shield, User, Edit } from 'lucide-react';
import { parseJwt } from '../utils';
import { useTranslation } from 'react-i18next';

export default function UsersManager() {
    const { t } = useTranslation();
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    // Form
    const [newUser, setNewUser] = useState({
        username: '',
        password: '',
        role: 'doctor',
        permissions: [],
        patient_visibility_mode: 'all_assigned'
    });

    // Permission Presets
    const permissionPresets = {
        doctor: ['view_patients', 'edit_patients', 'view_treatments', 'edit_treatments', 'view_calendar'],
        assistant: ['view_patients', 'view_calendar', 'view_treatments'],
        receptionist: ['view_patients', 'view_calendar', 'edit_patients'], // edit_patients for registration
        accountant: ['view_financials', 'view_reports'],
        custom: []
    };

    // Check admin, although App.jsx protects route, this is extra safety
    useEffect(() => {
        loadUsers();
    }, []);

    const loadUsers = async () => {
        try {
            setLoading(true);
            const res = await getUsers();
            setUsers(res.data);
        } catch (err) {
            console.error(err);
            if (err.response && err.response.status === 403) {
                alert('Access Denied');
            }
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (user = null) => {
        if (user) {
            let perms = [];
            try {
                if (user.permissions) {
                    perms = typeof user.permissions === 'string' ? JSON.parse(user.permissions) : user.permissions;
                }
            } catch (e) {
                console.error("Error parsing permissions", e);
            }

            setNewUser({
                id: user.id,
                username: user.username,
                password: '', // Password empty on edit means unchanged
                role: user.role,
                permissions: perms,
                patient_visibility_mode: user.patient_visibility_mode || 'all_assigned'
            });
        } else {
            setNewUser({
                username: '',
                password: '',
                role: 'doctor',
                permissions: [],
                patient_visibility_mode: 'all_assigned'
            });
        }
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        if (!newUser.username) return alert(t('common.messages.fill_all'));
        // Password required only for new users
        if (!newUser.id && !newUser.password) return alert(t('common.messages.fill_all'));

        try {
            const dataToSend = {
                ...newUser,
                permissions: newUser.permissions ? JSON.stringify(newUser.permissions) : ''
            };

            if (newUser.id) {
                await updateUser(newUser.id, dataToSend);
            } else {
                await registerUser(dataToSend);
            }

            setIsModalOpen(false);
            setNewUser({ username: '', password: '', role: 'doctor', permissions: [], patient_visibility_mode: 'all_assigned' });
            loadUsers();
        } catch (err) {
            alert('Failed to save user: ' + (err.response?.data?.detail || err.message));
        }
    };

    const handleDelete = async (id) => {
        if (!id) {
            console.error('Cannot delete user: id is undefined');
            return;
        }
        if (!confirm(t('users.form.delete_confirm'))) return;
        try {
            await deleteUser(id);
            loadUsers();
        } catch (err) {
            alert('Error: ' + (err.response?.data?.detail || err.message));
        }
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800">{t('users.title')}</h2>
                    <p className="text-slate-500">{t('users.subtitle')}</p>
                </div>
                <button
                    onClick={() => handleOpenModal()}
                    className="flex items-center gap-2 px-6 py-3 bg-primary text-white font-bold rounded-xl hover:bg-sky-600 shadow-lg shadow-primary/20 transition-all"
                >
                    <UserPlus size={20} /> {t('users.add_new')}
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {users && users.length > 0 && users.map((user, index) => {
                    const roleConfig = {
                        admin: { bg: 'bg-purple-100 dark:bg-purple-900/30', text: 'text-purple-600', label: `🔐 ${t('users.roles.admin')}`, icon: <Shield size={24} /> },
                        doctor: { bg: 'bg-blue-100 dark:bg-blue-900/30', text: 'text-blue-600', label: `👨‍⚕️ ${t('users.roles.doctor')}`, icon: <User size={24} /> },
                        assistant: { bg: 'bg-teal-100 dark:bg-teal-900/30', text: 'text-teal-600', label: `👩‍⚕️ ${t('users.roles.assistant')}`, icon: <User size={24} /> },
                        receptionist: { bg: 'bg-amber-100 dark:bg-amber-900/30', text: 'text-amber-600', label: `📋 ${t('users.roles.receptionist')}`, icon: <User size={24} /> },
                        accountant: { bg: 'bg-emerald-100 dark:bg-emerald-900/30', text: 'text-emerald-600', label: `💰 ${t('users.roles.accountant')}`, icon: <User size={24} /> },
                        custom: { bg: 'bg-gray-100 dark:bg-gray-700', text: 'text-gray-600', label: `🛠️ ${t('users.roles.custom')}`, icon: <User size={24} /> },
                    };
                    const config = roleConfig[user.role] || roleConfig.doctor;

                    return (
                        <div key={user.id || `user-${index}`} className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-white/5 flex items-center justify-between group hover:shadow-md transition-all">
                            <div className="flex items-center gap-4">
                                <div className={`p-4 rounded-full ${config.bg} ${config.text}`}>
                                    {user.role === 'admin' ? <Shield size={24} /> : <User size={24} />}
                                </div>
                                <div>
                                    <h3 className="font-bold text-lg text-slate-800 dark:text-white">{user.username}</h3>
                                    <span className={`text-xs px-2 py-1 rounded-full font-bold ${config.bg} ${config.text}`}>
                                        {config.label}
                                    </span>
                                </div>
                            </div>
                            {user.role !== 'admin' && (
                                <div className="flex gap-2">
                                    <button onClick={() => handleOpenModal(user)} className="p-2 text-slate-300 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-500/10 rounded-lg transition-colors">
                                        <Edit size={20} />
                                    </button>
                                    <button onClick={() => handleDelete(user.id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-lg transition-colors">
                                        <Trash2 size={20} />
                                    </button>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
                    <div className="bg-white w-full max-w-md rounded-2xl p-6 shadow-2xl animate-in zoom-in duration-200">
                        <h3 className="text-xl font-bold mb-4 text-slate-800">{newUser.id ? t('users.edit_user') : t('users.add_new')}</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('users.form.username')}</label>
                                <input
                                    value={newUser.username}
                                    onChange={e => setNewUser({ ...newUser, username: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                />
                            </div>
                            <div>
                                {newUser.id && <p className="text-xs text-amber-600 mb-1">{t('users.form.password_placeholder')}</p>}
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('users.form.password')}</label>
                                <input
                                    type="password"
                                    value={newUser.password}
                                    onChange={e => setNewUser({ ...newUser, password: e.target.value })}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold text-slate-700 mb-1">{t('users.form.role')}</label>
                                <select
                                    value={newUser.role}
                                    onChange={e => {
                                        const r = e.target.value;
                                        setNewUser({
                                            ...newUser,
                                            role: r,
                                            // Auto-fill permissions based on role, unless admin (full) or custom (empty)
                                            permissions: r === 'admin' ? [] : (permissionPresets[r] || [])
                                        });
                                    }}
                                    className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 outline-none focus:border-primary transition-colors"
                                >
                                    <option value="doctor">👨‍⚕️ {t('users.roles.doctor')}</option>
                                    <option value="assistant">👩‍⚕️ {t('users.roles.assistant')}</option>
                                    <option value="receptionist">📋 {t('users.roles.receptionist')}</option>
                                    <option value="accountant">💰 {t('users.roles.accountant')}</option>
                                    <option value="custom">🛠️ {t('users.roles.custom')}</option>
                                    <option value="admin">🔐 {t('users.roles.admin')}</option>
                                </select>
                                <p className="text-xs text-slate-400 mt-2">
                                    {newUser.role === 'custom' ? t('users.roles.custom') : ''}
                                </p>
                            </div>

                            {/* Data Visibility Mode (For Doctors) */}
                            {newUser.role === 'doctor' && (
                                <div>
                                    <label className="block text-sm font-bold text-slate-700 mb-1">{t('users.form.visibility')}</label>
                                    <select
                                        value={newUser.patient_visibility_mode}
                                        onChange={e => setNewUser({ ...newUser, patient_visibility_mode: e.target.value })}
                                        className="w-full p-3 bg-amber-50 rounded-xl border border-amber-200 outline-none focus:border-amber-500 transition-colors"
                                    >
                                        <option value="all_assigned">{t('users.form.vis_all')}</option>
                                        <option value="appointments_only">{t('users.form.vis_appt')}</option>
                                        <option value="mixed">{t('users.form.vis_mixed')}</option>
                                    </select>
                                    <p className="text-xs text-slate-400 mt-1">{t('users.form.visibility_hint')}</p>
                                </div>
                            )}

                            {/* Granular Permissions (Not for Admin) */}
                            {newUser.role !== 'admin' && (
                                <div className="border-t pt-4 mt-2">
                                    <label className="block text-sm font-bold text-slate-700 mb-2">{t('users.form.detailed_perms')}</label>
                                    <div className="grid grid-cols-2 gap-2 text-sm">
                                        {[
                                            { id: 'view_patients', label: t('users.permissions.view_patients') },
                                            { id: 'edit_patients', label: t('users.permissions.edit_patients') },
                                            { id: 'delete_patients', label: t('users.permissions.delete_patients') },
                                            { id: 'view_treatments', label: t('users.permissions.view_treatments') },
                                            { id: 'edit_treatments', label: t('users.permissions.edit_treatments') },
                                            { id: 'view_calendar', label: t('users.permissions.view_calendar') },
                                            { id: 'manage_lab', label: t('users.permissions.manage_lab') },
                                            { id: 'manage_inventory', label: t('users.permissions.manage_inventory') },
                                            { id: 'view_financials', label: t('users.permissions.view_financials') },
                                            { id: 'view_reports', label: t('users.permissions.view_reports') },
                                            { id: 'manage_users', label: t('users.permissions.manage_users') },
                                            { id: 'manage_settings', label: t('users.permissions.manage_settings') },
                                        ].map(perm => (
                                            <label key={perm.id} className="flex items-center gap-2 cursor-pointer">
                                                <input
                                                    type="checkbox"
                                                    checked={newUser.permissions?.includes(perm.id)}
                                                    onChange={e => {
                                                        const current = newUser.permissions || [];
                                                        if (e.target.checked) {
                                                            setNewUser({ ...newUser, permissions: [...current, perm.id] });
                                                        } else {
                                                            setNewUser({ ...newUser, permissions: current.filter(p => p !== perm.id) });
                                                        }
                                                    }}
                                                    className="rounded text-primary focus:ring-primary"
                                                />
                                                <span className="text-slate-600">{perm.label}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="flex justify-end gap-3 mt-6">
                                <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 hover:bg-slate-100 rounded-lg font-bold text-slate-500">{t('users.form.cancel')}</button>
                                <button onClick={handleSave} className="px-6 py-2 bg-primary text-white font-bold rounded-lg hover:bg-sky-600 shadow-lg shadow-primary/20">{newUser.id ? t('users.form.update') : t('users.form.save')}</button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { api, broadcastNotification, deleteNotification, deleteSupportMessage } from '@/api';
import SupportInbox from '@/features/admin/SuperAdmin/SupportInbox';
import NotificationsManager from '@/features/admin/SuperAdmin/NotificationsManager';
import { MessageSquare } from 'lucide-react';

export default function CommunicationsPage() {
    const [activeTab, setActiveTab] = useState('messages');
    const [messages, setMessages] = useState([]);
    const [notifications, setNotifications] = useState([]);
    const [tenants, setTenants] = useState([]); // Needed for notification targeting

    const [notifForm, setNotifForm] = useState({ title: '', content: '', type: 'info', is_global: true, tenant_id: null });
    const [loading, setLoading] = useState(true);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [msgRes, notifRes, tenRes] = await Promise.all([
                api.get('/support/messages'),
                api.get('/api/v1/notifications/'),
                api.get('/api/v1/admin/tenants')
            ]);
            setMessages(Array.isArray(msgRes.data) ? msgRes.data : []);
            setNotifications(Array.isArray(notifRes.data) ? notifRes.data : []);
            setTenants(Array.isArray(tenRes.data) ? tenRes.data : []);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleDeleteMessage = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذه الرسالة؟')) return;
        try {
            await deleteSupportMessage(id);
            setMessages(prev => prev.filter(m => m.id !== id));
            alert('تم حذف الرسالة بنجاح');
        } catch (err) {
            alert('فشل حذف الرسالة');
        }
    };

    const handleSendNotification = async () => {
        if (!notifForm.title || !notifForm.content) return alert('الرجاء تعبئة العنوان والمحتوى');
        try {
            await broadcastNotification(notifForm);
            setNotifForm({ title: '', content: '', type: 'info', is_global: true, tenant_id: null });
            fetchData();
            alert('تم إرسال الإشعار بنجاح');
        } catch (err) {
            alert('فشل إرسال الإشعار');
        }
    };

    const handleDeleteNotification = async (id) => {
        if (!window.confirm('هل أنت متأكد من حذف هذا الإشعار؟')) return;
        try {
            await deleteNotification(id);
            fetchData();
        } catch (err) {
            alert('فشل حذف الإشعار');
        }
    };

    if (loading) return <div className="p-8 text-center text-slate-500">جاري تحميل الرسائل...</div>;

    return (
        <div className="space-y-6 animate-fade-in-up">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-4">
                    <div className="bg-purple-50 dark:bg-purple-900/20 p-4 rounded-2xl text-purple-600 dark:text-purple-400">
                        <MessageSquare size={32} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-slate-800 dark:text-white">التواصل والدعم</h1>
                        <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">رسائل الدعم الفني والإشعارات</p>
                    </div>
                </div>

                <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                    <button
                        onClick={() => setActiveTab('messages')}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'messages' ? 'bg-white dark:bg-slate-700 shadow text-purple-600' : 'text-slate-500'}`}
                    >
                        الرسائل
                    </button>
                    <button
                        onClick={() => setActiveTab('notifications')}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'notifications' ? 'bg-white dark:bg-slate-700 shadow text-purple-600' : 'text-slate-500'}`}
                    >
                        الإشعارات
                    </button>
                </div>
            </div>

            {activeTab === 'messages' ? (
                <SupportInbox
                    messages={messages}
                    setMessages={setMessages}
                    handleDeleteMessage={handleDeleteMessage}
                    fetchData={fetchData}
                />
            ) : (
                <NotificationsManager
                    notifForm={notifForm}
                    setNotifForm={setNotifForm}
                    handleSendNotification={handleSendNotification}
                    notifications={notifications}
                    handleDeleteNotification={handleDeleteNotification}
                    tenants={tenants}
                />
            )}
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { api } from '@/api';
import PaymentsManager from '@/features/admin/SuperAdmin/PaymentsManager';
import PlansManager from '@/features/admin/SuperAdmin/PlansManager';
import ActiveSubscriptions from '@/features/admin/SuperAdmin/ActiveSubscriptions';
import { CreditCard, PlusCircle, X, Banknote, Landmark, User, Calendar } from 'lucide-react';

export default function FinancePage() {
    const [activeTab, setActiveTab] = useState('payments'); // payments, plans, subscriptions
    const [payments, setPayments] = useState([]);
    const [tenants, setTenants] = useState([]);
    const [plans, setPlans] = useState([]);

    // Payment Modal State
    const [showPaymentModal, setShowPaymentModal] = useState(false);
    const [paymentForm, setPaymentForm] = useState({
        tenant_id: '',
        plan_id: '',
        amount: '',
        payment_method: 'cash',
        paid_by: '',
        payment_date: new Date().toISOString().split('T')[0],
        notes: ''
    });
    const [tenantUsers, setTenantUsers] = useState([]);

    // Plans Editing State
    const [editingPlan, setEditingPlan] = useState(null);
    const [editedPlanData, setEditedPlanData] = useState({});

    const [loading, setLoading] = useState(true);
    const [processing, setProcessing] = useState(false);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [payRes, tenRes, planRes] = await Promise.all([
                api.get('/api/v1/admin/payments'),
                api.get('/api/v1/admin/tenants'), // Needed for filtering payments
                api.get('/api/v1/admin/plans')
            ]);
            setPayments(Array.isArray(payRes.data) ? payRes.data : []);
            setTenants(Array.isArray(tenRes.data) ? tenRes.data : []);
            setPlans(Array.isArray(planRes.data) ? planRes.data : []);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleSavePlan = async (planId) => {
        try {
            await api.put(`/admin/plans/${planId}`, editedPlanData);
            setEditingPlan(null);
            setEditedPlanData({});
            fetchData();
        } catch (err) {
            alert('فشل التعديل');
        }
    };

    const handleClinicChange = async (tenantId) => {
        setPaymentForm(prev => ({ ...prev, tenant_id: tenantId, paid_by: '' }));
        if (!tenantId) {
            setTenantUsers([]);
            return;
        }
        try {
            const res = await api.get(`/admin/system/tenants/${tenantId}/users`);
            // Ensure we always set an array, even if API returns unexpected data
            setTenantUsers(Array.isArray(res.data.users) ? res.data.users : []);
        } catch (err) {
            console.error(err);
            setTenantUsers([]); // Set empty array on error
        }
    };

    const handleRecordPayment = async () => {
        if (!paymentForm.tenant_id || !paymentForm.plan_id || !paymentForm.amount) {
            alert('الرجاء إكمال البيانات الأساسية');
            return;
        }
        setProcessing(true);
        try {
            await api.post('/api/v1/admin/payments', paymentForm);
            setShowPaymentModal(false);
            setPaymentForm({
                tenant_id: '',
                plan_id: '',
                amount: '',
                payment_method: 'cash',
                paid_by: '',
                payment_date: new Date().toISOString().split('T')[0],
                notes: ''
            });
            fetchData();
            alert('تم تسجيل الدفعة بنجاح');
        } catch (err) {
            alert('فشل تسجيل الدفعة');
        } finally {
            setProcessing(false);
        }
    };

    const getDaysRemaining = (endDate) => {
        if (!endDate) return null;
        const days = Math.ceil((new Date(endDate) - new Date()) / (1000 * 60 * 60 * 24));
        return days;
    };

    if (loading) return <div className="p-8 text-center text-slate-500">جاري تحميل البيانات المالية...</div>;

    return (
        <div className="space-y-6 animate-fade-in-up">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-4">
                    <div className="bg-emerald-50 dark:bg-emerald-900/20 p-4 rounded-2xl text-emerald-600 dark:text-emerald-400">
                        <CreditCard size={32} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-slate-800 dark:text-white">الإدارة المالية</h1>
                        <p className="text-slate-500 dark:text-slate-400 font-medium mt-1">المدفوعات وخطط الاشتراك</p>
                    </div>
                </div>

                <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                    <button
                        onClick={() => setActiveTab('payments')}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'payments' ? 'bg-white dark:bg-slate-700 shadow text-emerald-600' : 'text-slate-500'}`}
                    >
                        المدفوعات
                    </button>
                    <button
                        onClick={() => setActiveTab('subscriptions')}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'subscriptions' ? 'bg-white dark:bg-slate-700 shadow text-emerald-600' : 'text-slate-500'}`}
                    >
                        الاشتراكات
                    </button>
                    <button
                        onClick={() => setActiveTab('plans')}
                        className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'plans' ? 'bg-white dark:bg-slate-700 shadow text-emerald-600' : 'text-slate-500'}`}
                    >
                        الخطط
                    </button>
                </div>

                <button
                    onClick={() => {
                        setShowPaymentModal(true);
                        if (plans.length > 0) {
                            setPaymentForm(prev => ({ ...prev, plan_id: plans[0].id, amount: plans[0].price }));
                        }
                    }}
                    className="flex items-center gap-2 px-6 py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-bold shadow-lg shadow-emerald-500/30 transition-all transform hover:scale-105"
                >
                    <PlusCircle size={20} />
                    تسجيل دفعة
                </button>
            </div>

            {activeTab === 'payments' ? (
                <PaymentsManager
                    payments={payments}
                    tenants={tenants}
                    plans={plans}
                    onDelete={async (id) => {
                        if (!window.confirm('هل أنت متأكد من حذف هذه الدفعة؟')) return;
                        try {
                            await api.delete(`/admin/payments/${id}`);
                            fetchData();
                            alert('تم حذف الدفعة بنجاح');
                        } catch (err) {
                            alert('فعل الحذف');
                        }
                    }}
                />
            ) : activeTab === 'subscriptions' ? (
                <ActiveSubscriptions
                    tenants={tenants}
                    plans={plans}
                    getDaysRemaining={getDaysRemaining}
                />
            ) : (
                <PlansManager
                    plans={plans}
                    editingPlan={editingPlan}
                    setEditingPlan={setEditingPlan}
                    editedPlanData={editedPlanData}
                    setEditedPlanData={setEditedPlanData}
                    handleSavePlan={handleSavePlan}
                    onRefresh={fetchData}
                />
            )}

            {/* Enhanced Payment Modal */}
            {showPaymentModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 w-full max-w-xl shadow-2xl space-y-6">
                        <div className="flex justify-between items-center border-b border-slate-100 dark:border-slate-800 pb-4">
                            <div>
                                <h3 className="text-xl font-bold text-slate-800 dark:text-white">تسجيل دفعة جديدة</h3>
                                <p className="text-slate-500 dark:text-slate-400 text-sm">أضف تفاصيل الدفعة المالية للعيادة</p>
                            </div>
                            <button
                                onClick={() => setShowPaymentModal(false)}
                                className="p-2 bg-slate-100 dark:bg-slate-800 rounded-full hover:bg-slate-200"
                            >
                                <X size={20} />
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            {/* Clinic Selection */}
                            <div className="space-y-2">
                                <label className="flex items-center gap-2 text-sm font-bold text-slate-500">
                                    <PlusCircle size={16} /> العيادة
                                </label>
                                <select
