                                    className="w-4 h-4 text-green-600 rounded"
                                />
                                <span className="text-sm font-medium">{t('settings.price_lists.set_default')}</span>
                            </label>

                            <div className="flex gap-3 mt-8">
                                <button
                                    type="button"
                                    onClick={() => setIsModalOpen(false)}
