                                >
                                    {t('settings.price_lists.cancel')}
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700"
                                >
                                    {t('settings.price_lists.save')}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { api } from '@/api';
import { Card, Button, DataTable, Skeleton } from '@/shared/ui';
import { AlertTriangle, RefreshCw, Smartphone, Server, Info } from 'lucide-react';

export default function SystemLogs() {
    const [page, setPage] = useState(0);
    const limit = 50;

    const { data: logs = [], isLoading, refetch } = useQuery({
        queryKey: ['system-logs', page],
        queryFn: async () => {
            const res = await api.get(`/admin/system/logs?skip=${page * limit}&limit=${limit}`);
            // Ensure we always return an array, even if API returns unexpected data
            return Array.isArray(res.data) ? res.data : [];
        },
        keepPreviousData: true
    });

    const columns = [
        {
            header: 'المستوى',
            accessor: 'level',
            render: (level) => (
                <span className={`px-2 py-1 rounded text-xs font-bold ${level === 'ERROR' ? 'bg-red-100 text-red-700' :
                    level === 'WARNING' ? 'bg-amber-100 text-amber-700' :
                        'bg-blue-100 text-blue-700'
                    }`}>
                    {level}
                </span>
            )
        },
        {
            header: 'المصدر',
            accessor: 'source',
            render: (source) => (
                <div className="flex items-center gap-2">
                    {source === 'BACKEND' ? <Server size={14} /> : <Smartphone size={14} />}
                    <span className="text-xs">{source}</span>
                </div>
            )
        },
        {
            header: 'الرسالة',
            accessor: 'message',
            render: (msg) => <span className="font-mono text-xs text-red-600 line-clamp-1" title={msg}>{msg}</span>
        },
        {
            header: 'المسار',
            accessor: 'path',
            render: (path) => <span className="text-xs font-mono text-slate-500">{path}</span>
        },
        {
            header: 'التاريخ',
            accessor: 'created_at',
            render: (date) => <span className="text-xs">{new Date(date).toLocaleString()}</span>
        }
    ];

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold flex items-center gap-2">
                        <AlertTriangle className="text-red-500" />
                        سجل أخطاء النظام
                    </h1>
                    <p className="text-text-secondary text-sm">مراقبة الأخطاء التقنية (Backend & Frontend)</p>
                </div>
                <Button variant="outline" onClick={() => refetch()} disabled={isLoading}>
                    <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
                    تحديث
                </Button>
            </div>

            <Card>
                {isLoading ? (
                    <div className="space-y-4">
                        <Skeleton.Box height="3rem" />
                        <Skeleton.Box height="3rem" />
                        <Skeleton.Box height="3rem" />
                    </div>
                ) : (
                    <DataTable
                        data={logs}
                        columns={columns}
                        emptyMessage="لا توجد أخطاء مسجلة، النظام يعمل بكفاءة! 🎉"
                    />
                )}

                <div className="p-4 border-t border-border flex justify-between items-center">
                    <Button
                        variant="ghost"
                        disabled={page === 0}
                        onClick={() => setPage(p => Math.max(0, p - 1))}
                    >
                        السابق
                    </Button>
                    <span className="text-sm font-mono">صفحة {page + 1}</span>
                    <Button
                        variant="ghost"
                        disabled={logs.length < limit}
                        onClick={() => setPage(p => p + 1)}
                    >
                        التالي
                    </Button>
                </div>
            </Card>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { api } from '@/api';
import SettingsManager from '@/features/admin/SuperAdmin/SettingsManager';
import AuditLogViewer from '@/features/admin/SuperAdmin/AuditLogViewer';
import SecurityPanel from '@/features/admin/SuperAdmin/SecurityPanel';
import { Settings, User, Database, Shield } from 'lucide-react';

export default function SystemPage() {
    const [activeTab, setActiveTab] = useState('settings');
    const [settings, setSettings] = useState([]);
    const [auditLogs, setAuditLogs] = useState([]);
    const [tenants, setTenants] = useState([]);
    const [loading, setLoading] = useState(true);

    // Profile State
    const [profileForm, setProfileForm] = useState({ username: '', email: '', password: '' });

    // Backup State
    const [uploading, setUploading] = useState(false);

    // Google Drive Handlers
    const [googleConnected, setGoogleConnected] = useState(false);
    const [lastBackupStatus, setLastBackupStatus] = useState(null);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [setRes, auditRes, tenantsRes, googleRes] = await Promise.all([
                api.get('/api/v1/admin/settings'),
                api.get('/api/v1/admin/audit-logs'),
                api.get('/api/v1/admin/tenants'),
                api.get('/api/v1/admin/system/backup/google-status').catch(() => ({ data: { connected: false } }))
            ]);
            setSettings(Array.isArray(setRes.data) ? setRes.data : []);
            setAuditLogs(Array.isArray(auditRes.data) ? auditRes.data : []);
            setTenants(Array.isArray(tenantsRes.data) ? tenantsRes.data : []);
            setGoogleConnected(googleRes.data?.connected || false);
            setLastBackupStatus(googleRes.data?.last_backup || null);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();

        // Check for backup status in URL (from OAuth redirect)
        const params = new URLSearchParams(window.location.search);
        const status = params.get('backup_status');
        if (status) {
            if (status === 'success') {
                alert('تم ربط حساب Google Drive بنجاح ✅');
                window.history.replaceState({}, document.title, window.location.pathname);
            } else {
                const error = params.get('error') || 'فشل الربط';
                alert(`حدث خطأ أثناء الربط: ${status}\n${error}`);
            }
        }
    }, []);

    // --- Profile Handlers ---
    const handleUpdateProfile = async (e) => {
        e.preventDefault();
        if (!window.confirm("هل أنت متأكد من تحديث بيانات الدخول؟")) return;
        try {
            await api.put('/admin/system/profile', profileForm);
            alert("تم تحديث الملف الشخصي بنجاح");
            setProfileForm({ username: '', email: '', password: '' }); // Reset or keep? 
        } catch (error) {
            alert("فشل تحديث البيانات");
        }
    };

    // --- Backup Handlers ---
    const handleDownloadBackup = async () => {
        try {
            setUploading(true); // Reuse uploading state for loading indicator
            const response = await api.get('/api/v1/admin/system/backup', {
                responseType: 'blob' // Important for binary files
            });

            // Create download link
            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;

            // Extract filename from headers or default
            const contentDisposition = response.headers['content-disposition'];
            let fileName = 'smart_clinic_backup.db';
            if (contentDisposition) {
                const fileNameMatch = contentDisposition.match(/filename="?(.+)"?/);
                if (fileNameMatch && fileNameMatch.length === 2)
                    fileName = fileNameMatch[1];
            }

            link.setAttribute('download', fileName);
            document.body.appendChild(link);
            link.click();
            link.parentNode.removeChild(link);
            window.URL.revokeObjectURL(url);

        } catch (error) {
            console.error("Backup download failed:", error);
            alert("فشل تحميل النسخة الاحتياطية. يرجى التأكد من الصلاحيات.");
        } finally {
            setUploading(false);
        }
    };

    const handleRestoreBackup = async (event) => {
        const file = event.target.files[0];
        if (!file) return;

        if (!window.confirm("تحذير: استعادة النسخة الاحتياطية ستقوم بحذف جميع البيانات الحالية واستبدالها بالنسخة. هل أنت متأكد تماماً؟")) return;

        const formData = new FormData();
        formData.append('file', file);

        setUploading(true);
        try {
            await api.post('/api/v1/admin/system/restore', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
